// Historical descriptions for key entities
const HISTORICAL_DESCRIPTIONS = {
    // East Asia
    qin: { en: "The Qin dynasty unified China for the first time, establishing a centralized bureaucratic system, standardizing weights, measures, and writing. The Great Wall was connected, and the famous Terracotta Army was created. Despite its short duration, it laid the foundation for imperial China.", cn: "秦朝首次统一中国，建立中央集权的官僚制度，统一度量衡和文字。连接了长城，创造了著名的兵马俑。尽管存在时间短暂，却奠定了帝制中国的基础。" },
    han_west: { en: "The Western Han established the Silk Road, expanded Chinese territory, and developed Confucianism as state ideology. This era saw advances in technology, including paper-making and the seismograph. It's considered a golden age of Chinese civilization.", cn: "西汉开辟丝绸之路，扩大中国版图，确立儒学为国家意识形态。这个时代科技进步显著，包括造纸术和地动仪。被视为中华文明的黄金时代。" },
    han_east: { en: "The Eastern Han continued Han cultural achievements, saw Buddhism enter China, and produced great historians and scientists. It ended with the Yellow Turban Rebellion and fragmentation into the Three Kingdoms.", cn: "东汉延续了汉朝的文化成就，佛教传入中国，产生了伟大的历史学家和科学家。以黄巾起义告终，分裂为三国。" },
    tang: { en: "The Tang dynasty is considered the pinnacle of Chinese civilization, renowned for poetry, art, and cosmopolitan culture. The capital Chang'an was the world's largest city. Tang influence spread across Asia through trade and cultural exchange.", cn: "唐朝被认为是中华文明的巅峰，以诗歌、艺术和国际化文化闻名。首都长安是当时世界最大的城市。唐朝影响通过贸易和文化交流传播到整个亚洲。" },
    n_song: { en: "The Northern Song saw remarkable advances in technology, including movable type printing, gunpowder weapons, and the compass. The economy flourished with paper money and maritime trade. Neo-Confucianism emerged as a major philosophical movement.", cn: "北宋科技进步显著，包括活字印刷术、火药武器和指南针。经济繁荣，出现纸币和海上贸易。新儒学成为主要的哲学运动。" },
    yuan: { en: "The Yuan dynasty, established by Kublai Khan, was part of the vast Mongol Empire. It promoted trade across Eurasia, welcomed foreigners like Marco Polo, and saw advances in drama and painting. The Grand Canal was extended and Beijing became the capital.", cn: "元朝由忽必烈建立，是蒙古帝国的一部分。促进了欧亚大陆的贸易，欢迎马可·波罗等外国人，戏剧和绘画取得进步。大运河得到延伸，北京成为首都。" },
    ming: { en: "The Ming dynasty rebuilt Chinese rule after Mongol domination, constructing the Forbidden City and launching Zheng He's maritime expeditions. It was known for porcelain production, literature, and philosophy. The Great Wall was extensively rebuilt.", cn: "明朝在蒙古统治后重建中国政权，建造紫禁城并发起郑和的航海远征。以瓷器生产、文学和哲学著称。长城得到大规模重建。" },
    qing: { en: "The Qing dynasty, founded by the Manchu, was China's last imperial dynasty. At its height, it ruled the largest territory in Chinese history. It saw population growth, territorial expansion, and later struggled with Western imperialism and internal rebellions.", cn: "清朝由满族建立，是中国最后一个帝制王朝。鼎盛时期统治着中国历史上最大的疆域。经历了人口增长、领土扩张，后期与西方帝国主义和内部叛乱斗争。" },
    china_neolithic: { en: "Neolithic China represents the Yellow River and Central Plains cultural sequence before dynastic kingship, especially Yangshao, Longshan, and Erlitou-adjacent developments. It stays as a whole northern cultural lane beside the Yangtze lane; north-south exchange is carried by links and notes, not by land-bite geometry.", cn: "中国新石器时代表示王朝王权出现前黄河与中原文化序列，尤其是仰韶、龙山及二里头前后的发展。它作为完整北方文化栏与长江文化栏并列；南北交流由联系和说明表达，而不是用土地缺口表达。" },
    south_neolithic: { en: "Southern Cultures cover lower-Yangtze, middle-Yangtze, Lingnan, Liangzhu, Hemudu, and other southern Neolithic worlds. They stay as a whole rice-and-jade cultural lane beside the Yellow River sequence rather than as a cutout owner for northern dynasties.", cn: "南方文化覆盖长江下游、长江中游、岭南、良渚、河姆渡等南方新石器世界。它们作为完整的稻作与玉器文化栏，与黄河序列并列，而不是北方王朝的缺口主人。" },
    steppe_bronze: { en: "The Steppe Bronze Age lane abstracts eastern steppe and Ordos-Mongolian Plateau archaeological horizons before named nomadic confederations. Liaoning and Korean Bronze Age contact is carried by relationship links, so the steppe lane stays whole rather than using a land-bite cutout.", cn: "草原青铜时代栏抽象表示具名游牧联盟出现前的东部草原、鄂尔多斯与蒙古高原考古视野。辽东与朝鲜青铜时代接触由联系线承载，因此草原栏保持完整，而不使用土地缺口。" },
    steppe_nomads: { en: "Early Nomads marks the mounted pastoral and tribal-confederation world that preceded the Xiongnu empire. Frontier contact with Gojoseon is shown through links and notes, not by cutting a Korea-facing bite out of the steppe lane.", cn: "早期游牧表示匈奴帝国出现前的骑马牧业与部族联盟世界。与古朝鲜的边疆接触通过联系和说明表达，而不是在草原栏切出面向朝鲜的缺口。" },
    korea_prehistoric: { en: "Korean Prehistoric covers peninsula-wide Neolithic and Bronze Age communities, including dolmen and bronze traditions before the Gojoseon horizon. The label is cultural rather than a claim of centralized statehood.", cn: "朝鲜史前表示半岛范围的新石器与青铜时代社群，包括支石墓与青铜传统，早于古朝鲜视野。这个标签是文化范围，不声称中央集权国家。" },
    proto_3k: { en: "The Proto-Three Kingdoms period follows Han's destruction of Wiman Joseon and precedes the mature Silla, Goguryeo, and Baekje kingdoms. It captures regional polities and commandery frontiers rather than a single Korean state.", cn: "原三国时代处于汉灭卫满朝鲜之后、成熟的新罗、高句丽、百济之前。它表现区域政权与郡县边疆，而不是单一朝鲜国家。" },
    three_k_korea: { en: "Korea's Three Kingdoms period is the long rivalry among Goguryeo, Baekje, and Silla, with Gaya and other regional powers also important. It is one visible lane here, but the detail panel flags it as a multi-polity system.", cn: "朝鲜三国时代是高句丽、百济、新罗长期竞争的时期，伽倻等区域力量同样重要。图中用一个栏位显示，但详情说明它是多政权体系。" },
    jomon: { en: "Jomon Japan represents long-lived hunter-gatherer, fishing, and village societies of the Japanese archipelago, famous for cord-marked pottery. Peninsula commerce and contact are now carried by relationship links, so the archipelago lane stays whole instead of showing a Korean-owned cutout.", cn: "绳文日本表示日本列岛长期的狩猎采集、渔猎与村落社会，以绳纹陶器著称。半岛贸易与接触现在由关系线承载，因此列岛栏保持完整，而不再显示成由朝鲜承接的缺口。" },
    yayoi: { en: "Yayoi marks the spread of wet-rice agriculture, metallurgy, and new settlement patterns through Japan, strongly connected to Korean-peninsula and continental routes. Those transmissions are shown as cultural links while the Japan lane remains a whole archipelago owner, not a Korean territorial bite.", cn: "弥生表示水稻农业、金属器和新聚落形态在日本扩散，并与朝鲜半岛和大陆路线密切相关。这些传播现在显示为文化联系，而日本栏保持完整列岛主人，并非朝鲜领土切入。" },
    vn_prehistoric: { en: "Vietnamese Prehistoric marks Red River and northern Vietnamese cultural space before the legendary Van Lang sequence. It is intentionally a short cultural owner so the Vietnam lane does not begin with a blank.", cn: "越南史前表示传说中的文郎序列之前，红河与北越区域的文化空间。它有意作为短文化主人出现，使越南栏不会以空白开头。" },
    van_lang: { en: "Van Lang is treated as a legendary-archaeological Red River / Dong Son horizon associated with the Hung kings. The chart keeps it visible while warning that it should not be read as a precisely bordered modern state.", cn: "文郎被处理为与雄王传说相关的红河/东山视野，兼具传说与考古含义。图中保留其可见性，但不应读成边界精确的现代国家。" },
    au_lac: { en: "Au Lac succeeds the Van Lang tradition in northern Vietnam under the Thuc/An Duong Vuong story cycle. It is a tighter Red River polity marker before Nanyue and Han imperial commanderies enter the lane.", cn: "瓯雒承接北越文郎传统，与蜀氏/安阳王叙事相连。它是南越与汉帝国郡县进入此栏前更紧凑的红河政权标记。" },
    nanyue: { en: "Nanyue was a Yue-Han hybrid kingdom centered on Panyu/Guangzhou that also reached into northern Vietnam. It is shown in the Vietnam lane for the Red River connection, while its wider southern China context remains implicit.", cn: "南越是以番禺/广州为中心、兼具越人与汉文化的王国，也伸入北越。它因红河联系显示在越南栏中，其更广的华南背景在说明中保留。" },
    chinese_vn: { en: "Chinese Rule in Vietnam marks the Han-through-Tang commandery and protectorate centuries in the Red River delta. It now stays as a whole colonial-administration lane: the Han, Wu/Jin, Southern Dynasties, Sui, Tang, and Southern Han phases are explained through links and detail text rather than a remote-owner cutout.", cn: "越南北属时期表示汉至唐在红河三角洲的郡县与都护府时代。它现在保持为完整的外来行政栏：汉、吴晋、南朝、隋、唐与南汉阶段由联系和详情解释，而不是画成远程主人缺口。" },
    vn_independence: { en: "The Ngo, Dinh, and Early Le rulers mark the first unstable but real independence phase after 939. The Red River lane is no longer a Chinese commandery, but centralized rule is still being built.", cn: "吴、丁、前黎表示939年以后真实但仍不稳定的第一段独立时期。红河栏不再是中国郡县，但中央集权仍在形成。" },
    ly_dynasty: { en: "The Ly dynasty centralized Dai Viet from Thang Long after 1009, building a Chinese-style civil bureaucracy while defending the Red River state against local fragmentation and southern rivals.", cn: "李朝自1009年以后以升龙为中心整合大越，建立受中国制度影响的文官体系，同时抵御地方割据和南方对手。" },
    tran_dynasty: { en: "The Tran dynasty succeeded the Ly in 1225 and preserved Dai Viet through the 13th-century Mongol/Yuan invasions. It is the high point of Red River military resilience before the Ming reconquest crisis.", cn: "陈朝于1225年承接李朝，并在13世纪蒙古/元朝入侵中保住大越。它是明朝再征服危机前红河国家军事韧性的高点。" },
    ho_ming: { en: "The Ho seizure, Ming invasion, and renewed Chinese administration are compressed here as a rupture between Tran Dai Viet and Le restoration. The block is gray because sovereignty was contested and then foreign-administered.", cn: "胡氏夺权、明朝入侵与重新直接行政在此压缩显示，作为陈朝大越与后黎复国之间的断裂。灰色表示主权争夺并转入外来行政。" },
    le_early: { en: "Early Later Le begins with Le Loi's victory over Ming occupation in 1428. Le Thanh Tong's reforms and 1471 conquest of Champa make this a centralized, expanding Dai Viet phase.", cn: "后黎前期始于黎利1428年驱逐明军后的复国。黎圣宗改革和1471年征服占婆，使其成为中央化且向南扩张的大越阶段。" },
    mac_dai_viet: { en: "The Mac takeover in 1527 interrupts Le rule from Thang Long. It is drawn full-width only for the short moment before the Le loyalist recovery in the south splits the lane.", cn: "莫氏1527年在升龙夺取权力，打断黎朝统治。它只在黎氏忠臣于南方恢复前的短阶段画成全宽。" },
    mac_north: { en: "The Mac northern fragment marks the post-1545 split: the Mac retained the north while restored Le loyalists held the southern counterclaim until Thang Long was recovered.", cn: "莫朝北方片段表示1545年后的分裂：莫氏保有北方，而复兴黎朝势力在南方维持反主张，直到收复升龙。" },
    le_restored_south: { en: "Restored Le South marks the loyalist recovery south of the Red River delta during the long Le-Mac civil war. It keeps the counterclaim visible instead of leaving the lost half blank.", cn: "复兴黎朝南方表示黎氏忠臣在黎莫内战中于红河三角洲以南恢复的据点。它让反主张保持可见，而不是把失去的一半留空。" },
    le_trinh_restored: { en: "After the Le-Trinh side retook Thang Long, Dai Viet is briefly shown full-width before the deeper Trinh-Nguyen division hardens around 1620.", cn: "黎郑一方收复升龙后，大越短暂以全宽显示，直到约1620年更深的郑阮分裂固化。" },
    trinh_le_north: { en: "The Trinh-Le North block shows nominal Le monarchy under Trinh military-political control in Thang Long. It is paired with Nguyen southern rule, so Later Le no longer reads as one stable rectangle.", cn: "郑主/黎帝北方块表示升龙名义上的黎朝君主与实际掌权的郑氏。它与阮氏南方并列，使后黎不再被误读为一个稳定矩形。" },
    nguyen_lords_south: { en: "The Nguyen Lords carried southern Dai Viet from Hue, expanding into Cham and Khmer lands while formally acknowledging Le unity. This is a concrete southern owner, not a blank edge under the Le label.", cn: "阮主以顺化为中心承接大越南方，向占人与高棉旧地扩张，同时名义上承认黎朝统一。它是明确的南方主人，而不是后黎标签下的空边。" },
    tay_son_south: { en: "The Tay Son southern fragment begins with the revolt's destruction of Nguyen power in the south before the brothers defeated the Trinh and briefly reunited Dai Viet.", cn: "西山南方片段始于起义摧毁南方阮氏势力，早于西山兄弟击败郑氏并短暂重新统一大越。" },
    tay_son: { en: "The Tay Son regime briefly reunited Vietnam after defeating the Trinh, Nguyen, and a Qing intervention. It is short but central to the transition from divided Dai Viet to the Nguyen dynasty.", cn: "西山政权在击败郑氏、阮氏和清军干预后短暂统一越南。它虽短暂，却是大越分裂走向阮朝统一的关键转折。" },
    nguyen: { en: "The Nguyen dynasty begins with Gia Long's 1802 reunification and Hue capital. The block now stops when French domination becomes the primary owner, rather than hiding colonial rule inside a royal label.", cn: "阮朝始于嘉隆1802年重新统一并定都顺化。此块现在止于法国支配成为主要主人之时，不再把殖民统治隐藏在王朝标签中。" },
    french_vietnam: { en: "French Vietnam compresses Tonkin, Annam, and Cochinchina under French colonial dominance while the Nguyen court remained nominal in Hue. It carries the lane until the 1945 independence rupture.", cn: "法属越南压缩表示法国支配下的东京、安南和交趾支那，同时阮朝宫廷在顺化保持名义地位。它承接此栏直到1945年独立断裂。" },
    vietnam_mod: { en: "Modern Vietnam begins with the 1945 independence rupture and carries the later revolutionary, divided, war, reunification, and socialist republic periods in one modern block for now.", cn: "现代越南始于1945年的独立断裂，并暂时用一个现代块承接后续革命、分裂、战争、统一和社会主义共和国阶段。" },
    // Europe
    roman_republic: { en: "The Roman Republic developed representative government, law codes, and military innovations that conquered the Mediterranean. Roman citizenship, engineering, and Latin language spread throughout the empire, leaving lasting influence on Western civilization.", cn: "罗马共和国发展了代议制政府、法典和军事创新，征服了地中海地区。罗马公民身份、工程技术和拉丁语传播到整个帝国，对西方文明产生了持久影响。" },
    roman_empire: { en: "The Roman Empire at its height controlled the entire Mediterranean, Western Europe, and beyond. Roman law, roads, aqueducts, and architecture shaped European civilization. The Pax Romana brought unprecedented peace and prosperity.", cn: "罗马帝国鼎盛时期控制整个地中海、西欧及更远地区。罗马法律、道路、输水道和建筑塑造了欧洲文明。罗马和平带来了前所未有的和平与繁荣。" },
    byzantine: { en: "The Byzantine Empire preserved Roman and Greek culture for a millennium after Rome fell. Constantinople was the largest and wealthiest European city. Byzantine art, Orthodox Christianity, and Justinian's law code influenced Eastern Europe profoundly.", cn: "拜占庭帝国在罗马陷落后保存了罗马和希腊文化一千年。君士坦丁堡是欧洲最大最富有的城市。拜占庭艺术、东正教和查士丁尼法典深刻影响了东欧。" },
    germanic_early: { en: "Germanic Cultures mark northern European Bronze and Iron Age cultural horizons before named confederations. The lane is an inhabited cultural owner, not a modern Germany projected backward.", cn: "日耳曼文化表示具名联盟出现前北欧与中欧北部的青铜、铁器时代文化视野。这个栏位是有人居住的文化主人，不是把现代德国倒投到古代。" },
    germanic_tribes: { en: "Germanic Tribes condense many Rhine, Danube, North Sea, and eastern frontier peoples, including Franks, Alemanni, Goths, Saxons, and Lombards. It explains who carries the Germanic lane while Rome fragments, without pretending there was one Germanic state.", cn: "日耳曼部落概括莱茵、多瑙、北海和东部边疆的众多群体，包括法兰克、阿勒曼尼、哥特、撒克逊和伦巴第等。它说明罗马碎裂时谁承接日耳曼栏，但不假装存在单一日耳曼国家。" },
    post_roman_germanic_polities: { en: "Post-Roman Germanic Polities marks the Alemannic, Thuringian, Burgundian, and related east-Rhine successor field after the western imperial collapse. It is deliberately a composite lane, because this was a political mosaic rather than an early German kingdom.", cn: "后罗马日耳曼诸政权表示西方帝国崩解后，阿勒曼尼、图林根、勃艮第及相关莱茵东岸继承势力场。它有意作为复合栏出现，因为这里是政治拼图，而不是早期德国王国。" },
    early_saxon_bavarian_worlds: { en: "Early Saxon and Bavarian Worlds keeps the northern Saxon / Frisian and southern Bavarian-Alpine horizons visible beside the Frankish frontier. The half-lane prevents the post-476 Germanic space from looking empty or already centralized.", cn: "早期撒克逊与巴伐利亚世界让北方撒克逊/弗里斯兰和南方巴伐利亚-阿尔卑斯视野在法兰克边疆旁保持可见。半栏形态避免476年后的日耳曼空间显得空白或已经中央集权。" },
    merovingian_eastern_duchies: { en: "Merovingian Eastern Duchies represents the Frankish-ruled but locally powerful east-Rhine and upper-Danube duchy world: Alemannia, Thuringia, Bavaria, and Austrasian frontier politics. It connects the German lane to Francia without turning it into France or a modern Germany.", cn: "墨洛温东部公国表示法兰克统治下但地方权力仍强的莱茵东岸与多瑙上游公国世界：阿勒曼尼亚、图林根、巴伐利亚及奥斯特拉西亚边疆政治。它把德意志栏接到法兰克，但不把它画成法国或现代德国。" },
    saxon_frontier: { en: "Independent Saxon Frontier marks Old Saxony, Frisian edges, and the northern pagan frontier that remained outside stable Frankish control into the eighth century. It stays beside the Merovingian / Carolingian east so viewers see coexistence and conflict.", cn: "独立撒克逊边疆表示古撒克逊、弗里斯兰边缘及直到八世纪仍未稳定纳入法兰克控制的北方异教边疆。它与墨洛温/加洛林东部并列，使观者能看到并存与冲突。" },
    pippinid_carolingian_east: { en: "Pippinid / Carolingian East marks the post-751 Frankish power transfer before Charlemagne's Saxon and Lombard campaigns fully reshape the eastern lane. It is a short bridge from Merovingian duchies to the visible Carolingian East.", cn: "丕平-加洛林东部表示751年后法兰克权力转移、查理曼的撒克逊和伦巴第战役全面重塑东部栏之前的阶段。它是从墨洛温公国世界通向加洛林东部的短桥。" },
    carolingian_saxon_frontier: { en: "Carolingian Saxon Frontier captures the opening of the Saxon Wars from 772 before the simplified Carolingian East block takes the full German-facing lane. It marks conflict and incorporation in progress, not instant peaceful succession.", cn: "加洛林-撒克逊边疆表示772年撒克逊战争开启，到简化的加洛林东部全栏出现前的过渡。它强调冲突与正在发生的并入，而不是瞬间和平继承。" },
    lusatian: { en: "Lusatian Culture is a Late Bronze and Early Iron Age archaeological horizon around Poland, Lusatia, and neighboring central Europe. It is used as a cultural owner for the Polish lane before historically named Slavic politics appear.", cn: "卢萨蒂亚文化是波兰、卢萨蒂亚及周边中欧地区的青铜时代晚期和铁器时代早期考古视野。它作为波兰栏早期文化主人出现，早于有史料名称的斯拉夫政治。" },
    slavic_west: { en: "West Slavic Tribes represent Polish, Bohemian, Lusatian/Sorbian, and related communities before durable Christian monarchies. The chart treats them as local owners rather than a blank awaiting the Piast state.", cn: "西斯拉夫部落表示波兰、波希米亚、卢萨蒂亚/索布及相关社群，早于稳定的基督教君主国。图中把它们处理为地方主人，而不是等待皮雅斯特国家出现的空白。" },
    steppe_early: { en: "Steppe Cultures abstract the Pontic and forest-steppe worlds before the Scythians become visible in classical sources. This is a mobile pastoral and mixed frontier zone, not empty space.", cn: "草原文化抽象表示斯基泰在古典文献中清晰出现前的黑海北岸草原和森林草原世界。这里是流动牧业与混合边疆空间，不是空地。" },
    scythian: { en: "The Scythians were Iranian-speaking nomadic powers of the Eurasian steppe, especially the Pontic and Crimean zones. Their lane is a steppe-owner layer later transformed by Sarmatian, Slavic, and Rus' worlds in this simplified grid.", cn: "斯基泰人是欧亚草原上的伊朗语游牧力量，尤其活跃于黑海北岸和克里米亚区域。在这个简化网格中，他们是后续萨尔马特、斯拉夫和罗斯世界转化前的草原主人层。" },
    slavic_east: { en: "East Slavic Tribes cover Dnieper, forest-steppe, and northern river-network communities before Kyivan Rus' consolidation. Varangian trade routes and neighboring Finnic, Baltic, and steppe peoples remain part of the context.", cn: "东斯拉夫部落覆盖基辅罗斯整合前第聂伯、森林草原和北方河网社群。瓦良格贸易路线以及相邻的芬兰-乌戈尔、波罗的和草原诸族仍是其背景。" },
    byzantine_early: { en: "Byzantine marks the Eastern Roman continuation in the Greek and Balkan lane. Anatolia, Syria, Egypt, and Italy are handled in separate regional fragments when their territorial history diverges.", cn: "拜占庭表示东罗马在希腊和巴尔干栏的延续。安纳托利亚、叙利亚、埃及和意大利的领土史分化时，由各自地区片段单独处理。" },
    odoacer: { en: "Odoacer's Italian kingdom follows the deposition of Romulus Augustulus in 476. It kept much of the Roman administrative frame while replacing the western imperial court with foederati kingship.", cn: "奥多亚塞的意大利王国始于476年废黜罗慕路斯·奥古斯都之后。它保留许多罗马行政框架，同时以同盟部族王权取代西方帝国宫廷。" },
    ostrogoth: { en: "The Ostrogothic Kingdom under Theodoric ruled Italy from Ravenna with a deliberate Roman-Gothic administrative balance. Its end comes through Justinian's Gothic War, not a clean peaceful succession.", cn: "狄奥多里克治下的东哥特王国以拉文纳为中心统治意大利，并有意维持罗马-哥特行政平衡。它的终结来自查士丁尼的哥特战争，而不是平稳继承。" },
    byzantine_italy: { en: "Byzantine Italy Reconquest is the short full-peninsula phase after Justinian's armies defeated the Ostrogoths. It ends when the Lombard invasion forces the chart to split Italy into Byzantine and Lombard halves.", cn: "拜占庭再征服意大利表示查士丁尼军队击败东哥特后的短暂全半岛阶段。伦巴第入侵后，图中必须把意大利拆成拜占庭和伦巴第两个并存部分。" },
    byzantine_exarchate: { en: "The Byzantine Exarchate represents Ravenna, Rome, and surviving imperial enclaves after the Lombards entered Italy. It fills the left half of the Italy lane so Byzantine survival is visible without pretending it still owned the whole peninsula.", cn: "拜占庭总督区表示伦巴第进入意大利后，拉文纳、罗马及残存帝国飞地。它占据意大利栏左半，使拜占庭存续可见，同时不假装其仍拥有整个半岛。" },
    lombard_italy: { en: "Lombard Italy represents the northern and interior Lombard kingdom and duchies that coexisted with Byzantine Ravenna, Rome, and southern enclaves. The half-lane form is intentional: conquest reduced Byzantine control but did not erase it.", cn: "伦巴第意大利表示与拜占庭拉文纳、罗马和南部飞地并存的北部及内陆伦巴第王国和公国。半栏形态是有意设计：征服削弱拜占庭控制，但没有把它抹掉。" },
    lombard: { en: "The Late Lombard Kingdom marks the period after Ravenna fell and before Charlemagne conquered the Lombards in 774. It is a compressed terminal phase, not a claim that Lombards only appeared in 751.", cn: "晚期伦巴第王国表示拉文纳陷落后、查理曼于774年征服伦巴第前的阶段。这是压缩后的终末阶段，并不声称伦巴第直到751年才出现。" },
    frankish_italy: { en: "Frankish Italy fills the 774-800 transition after Charlemagne conquered the Lombard kingdom but before the imperial coronation. The land has a clear owner here, so the Italy lane no longer leaves an orphan gap.", cn: "法兰克意大利填补774-800年查理曼征服伦巴第王国之后、加冕为帝之前的过渡。这里土地有明确主人，因此意大利栏不再留下无主空档。" },
    anglo_saxon: { en: "Anglo-Saxon England condenses several Germanic and insular kingdoms before the Norman Conquest. It follows post-Roman Britain and keeps the island lane owned without treating early England as one immediate centralized state.", cn: "盎格鲁-撒克逊英格兰概括诺曼征服前多个日耳曼和岛屿王国。它承接后罗马不列颠，使岛屿栏保持有主人，但不把早期英格兰说成即时中央集权国家。" },
    poland_piast: { en: "Piast Poland marks the Christian monarchy that crystallized from West Slavic communities after 966. Gniezno and later Krakow anchor a state-forming lane that had already been culturally occupied.", cn: "皮雅斯特波兰表示966年后从西斯拉夫社群中成形的基督教君主国。格涅兹诺及后来的克拉科夫锚定国家形成栏，而这个栏位此前已由文化主人占据。" },
    kievan_rus: { en: "Kyivan Rus' was the first major East Slavic state, centered on Kyiv after Oleg's seizure of the city in 882. It links river trade, Slavic and Finnic communities, Varangian elites, and Byzantine Christianity.", cn: "基辅罗斯是第一个重要的东斯拉夫国家，882年奥列格夺取基辅后以此为中心。它连接河流贸易、斯拉夫和芬兰-乌戈尔社群、瓦良格精英与拜占庭基督教。" },
    carolingian: { en: "The Carolingian Empire under Charlemagne briefly reunited Western Europe, promoting education and Christianity. The Carolingian Renaissance preserved classical knowledge. Its division created the foundations of modern France and Germany.", cn: "加洛林帝国在查理大帝统治下短暂统一西欧，推动教育和基督教。加洛林文艺复兴保存了古典知识。其分裂奠定了现代法国和德国的基础。" },
    ottoman_peak: { en: "The Ottoman Empire at its peak controlled Southeast Europe, the Middle East, and North Africa. Istanbul was a center of culture and commerce. Ottoman architecture, administration, and military innovations influenced three continents.", cn: "奥斯曼帝国鼎盛时期控制东南欧、中东和北非。伊斯坦布尔是文化和商业中心。奥斯曼建筑、行政管理和军事创新影响了三大洲。" },
    // Middle East
    achaemenid: { en: "The Achaemenid Persian Empire was the largest empire the world had yet seen, stretching from Egypt to India. It pioneered religious tolerance, postal systems, and road networks. The Royal Road facilitated trade and communication.", cn: "阿契美尼德波斯帝国是当时世界上最大的帝国，从埃及延伸到印度。开创了宗教宽容、邮政系统和道路网络。御道促进了贸易和通信。" },
    rashidun: { en: "The Rashidun Caliphate rapidly expanded from Arabia to create one of history's largest empires. It preserved and transmitted Greek and Persian knowledge. Islamic law and Arabic became unifying forces across the Middle East and North Africa.", cn: "正统哈里发从阿拉伯半岛迅速扩张，创建了历史上最大的帝国之一。保存和传播了希腊和波斯知识。伊斯兰法律和阿拉伯语成为中东和北非的统一力量。" },
    abbasid: { en: "The Abbasid Caliphate presided over the Islamic Golden Age, with Baghdad as a center of learning. Advances in mathematics, astronomy, medicine, and philosophy transformed human knowledge. The House of Wisdom translated and preserved classical texts.", cn: "阿拔斯哈里发统治期间是伊斯兰黄金时代，巴格达是学术中心。数学、天文学、医学和哲学的进步改变了人类知识。智慧宫翻译和保存了古典文献。" },
    // South Asia
    maurya: { en: "The Maurya Empire was India's first great empire, unifying most of the subcontinent. Under Ashoka, Buddhism spread widely and non-violent principles were promoted through rock edicts. Mauryan administration influenced later Indian states.", cn: "孔雀帝国是印度第一个伟大帝国，统一了次大陆大部分地区。在阿育王统治下，佛教广泛传播，通过石刻敕令推广非暴力原则。孔雀王朝的行政管理影响了后来的印度国家。" },
    gupta: { en: "The Gupta Empire presided over India's Classical Age, with advances in mathematics (including zero), astronomy, art, and literature. Sanskrit flourished, and Hindu temple architecture developed. This era is considered the golden age of Indian culture.", cn: "笈多帝国统治期间是印度的古典时代，数学（包括零）、天文学、艺术和文学取得进步。梵语繁荣，印度教寺庙建筑发展。这个时代被认为是印度文化的黄金时代。" },
    mughal_peak: { en: "The Mughal Empire created a synthesis of Persian and Indian culture, producing architectural masterpieces like the Taj Mahal. Mughal painting, cuisine, and administrative systems profoundly influenced South Asian civilization.", cn: "莫卧儿帝国创造了波斯和印度文化的融合，产生了泰姬陵等建筑杰作。莫卧儿绘画、美食和行政制度深刻影响了南亚文明。" },
    // Mongolia
    mongol_emp: { en: "The Mongol Empire was the largest contiguous land empire in history, connecting East and West through the Pax Mongolica. Trade, technology, and ideas flowed across Eurasia. Though destructive in conquest, Mongol rule promoted exchange between civilizations.", cn: "蒙古帝国是历史上最大的连续陆地帝国，通过蒙古和平连接东西方。贸易、技术和思想在欧亚大陆流通。尽管征服过程中具有破坏性，但蒙古统治促进了文明之间的交流。" },
    // Japan
    heian: { en: "The Heian period saw the flourishing of Japanese court culture, producing classics like The Tale of Genji. Japanese writing systems developed, and Buddhism merged with native beliefs. This era established many enduring Japanese aesthetic principles.", cn: "平安时代日本宫廷文化繁荣，产生了《源氏物语》等经典作品。日本书写系统发展，佛教与本土信仰融合。这个时代确立了许多持久的日本审美原则。" },
    edo: { en: "The Edo period brought over 250 years of peace under Tokugawa rule. Urban culture flourished with kabuki, ukiyo-e, and haiku. Japan's isolation allowed unique cultural development, while internal trade and education expanded.", cn: "江户时代在德川统治下带来了250多年的和平。城市文化繁荣，包括歌舞伎、浮世绘和俳句。日本的闭关锁国允许独特的文化发展，同时国内贸易和教育扩展。" },
    meiji: { en: "The Meiji Restoration transformed Japan from a feudal society into a modern industrial power in just decades. Western technology, education, and institutions were adopted while maintaining Japanese identity. Japan became Asia's first industrialized nation.", cn: "明治维新在短短几十年内将日本从封建社会转变为现代工业强国。在保持日本特色的同时采用西方技术、教育和制度。日本成为亚洲第一个工业化国家。" },
    // Korea
    joseon: { en: "The Joseon dynasty, Korea's longest-ruling, developed hangul (the Korean alphabet) and Neo-Confucian governance. Distinctive Korean arts, architecture, and cuisine flourished. Joseon scholarship produced advances in science and technology.", cn: "朝鲜王朝是韩国统治时间最长的王朝，发展了韩文（朝鲜字母）和新儒家治理。独特的韩国艺术、建筑和美食繁荣发展。朝鲜学术在科学技术方面取得进步。" },
    // Americas
    maya_classic: { en: "The Maya Classic period saw the height of Maya civilization with advanced mathematics, astronomy, and hieroglyphic writing. Magnificent temple-pyramids were built. The Maya developed the most sophisticated writing system in pre-Columbian Americas.", cn: "玛雅古典时期是玛雅文明的鼎盛时期，拥有先进的数学、天文学和象形文字。建造了宏伟的神庙金字塔。玛雅人发展了前哥伦布美洲最复杂的书写系统。" },
    aztec: { en: "The Aztec Empire built the magnificent city of Tenochtitlan on a lake, with advanced agriculture and engineering. Aztec art, calendar systems, and religious practices were highly developed. At its height, it dominated Mesoamerica through tribute and trade.", cn: "阿兹特克帝国在湖上建造了宏伟的特诺奇蒂特兰城，拥有先进的农业和工程技术。阿兹特克艺术、历法系统和宗教习俗高度发达。鼎盛时期通过贡品和贸易主导中美洲。" },
    inca: { en: "The Inca Empire built an extensive road system through the Andes and developed sophisticated administration without writing. Machu Picchu exemplifies Inca engineering. They created the largest empire in pre-Columbian Americas.", cn: "印加帝国在安第斯山脉建造了广泛的道路系统，在没有文字的情况下发展了复杂的行政管理。马丘比丘是印加工程的典范。他们创建了前哥伦布美洲最大的帝国。" },

    // Additional European entities
    hre: { en: "The Holy Roman Empire was a multi-ethnic complex of territories in Western and Central Europe that developed during the Early Middle Ages. Neither holy, nor Roman, nor an empire according to Voltaire, it nonetheless shaped European politics for nearly a millennium.", cn: "神圣罗马帝国是中世纪早期在西欧和中欧发展起来的多民族领土复合体。按伏尔泰的说法，它既不神圣，也不罗马，更非帝国，但它塑造了欧洲近千年的政治格局。" },
    visigoth: { en: "The Visigothic Kingdom ruled the Iberian Peninsula after the fall of Rome, blending Roman and Germanic traditions. Their law codes influenced medieval European legal systems, and their conversion to Catholicism shaped Spanish religious identity.", cn: "西哥特王国在罗马帝国灭亡后统治伊比利亚半岛，融合了罗马和日耳曼传统。他们的法典影响了中世纪欧洲的法律体系，皈依天主教塑造了西班牙的宗教认同。" },
    frankish: { en: "The Frankish Kingdom united much of Western Europe under the Merovingian and later Carolingian dynasties. The Franks converted to Christianity early, making their kingdom a defender of the Catholic faith and laying foundations for France and Germany.", cn: "法兰克王国在墨洛温王朝和后来的加洛林王朝统治下统一了西欧大部分地区。法兰克人早期皈依基督教，使其王国成为天主教的守护者，奠定了法国和德国的基础。" },

    // Southeast Asian entities
    khmer: { en: "The Khmer Empire is drawn around the Angkor/Cambodian core, with Thai-side influence shown separately. This preserves Angkor's mainland dominance without making Dvaravati or later Tai polities disappear beneath one rectangle.", cn: "高棉帝国绘为吴哥/柬埔寨核心，泰国方向的影响另以片段显示。这样既保留其东南亚大陆强权地位，也不让堕罗钵底或后来的泰族政权被一个矩形吞没。" },
    khmer_thai: { en: "This strip marks Khmer / Lopburi frontier authority and cultural influence in the Chao Phraya / Thai basin before Sukhothai's break from Angkor. It stays whole beside the Angkor core, so influence and outpost rule are not redrawn as a cutout owned by the core block.", cn: "这个条带表示素可泰脱离吴哥之前，高棉/罗斛在湄南河/泰国盆地的边疆权威与文化影响。它在吴哥核心旁保持完整，因此影响与据点统治不会被误画成由核心块承接的缺口。" },
    srivijaya: { en: "Srivijaya began from a Palembang / Sumatran maritime-commercial core controlling the Malacca passage. It stays whole beside Central Javanese Mataram because early coexistence and Shailendra-era links are not a land bite taken from Java; later Java-facing pressure remains on the Kediri edge before the 1025 Chola shock.", cn: "室利佛逝起源于控制马六甲通道的巨港/苏门答腊海上商业核心。它与中爪哇马打兰并列保持完整，因为早期并存和夏连特拉时代联系并不是从爪哇切走土地；1025年朱罗冲击前面向爪哇的压力保留在谏义里边缘。" },
    kalingga_early_java: { en: "Kalingga / Early Central Java fills the Java half-lane after Tarumanagara and before the full Mataram block. Ho-ling / Kalingga, north-central Java ports, and the early Shailendra-Sanjaya horizon keep Java visible beside Srivijaya's Sumatran core without turning maritime links into land ownership.", cn: "诃陵/早期中爪哇填补多罗摩之后、完整马打兰图块之前的爪哇半栏。诃陵/Kalingga、中爪哇北岸港口及早期夏连特拉-山阇耶视野，使爪哇在室利佛逝苏门答腊核心旁保持可见，而不会把海上联系误画成土地所有权。" },
    srivijaya_malaya: { en: "This fragment represents Srivijaya's commercial and naval influence around the Strait of Malacca and Malay Peninsula. It should be read as maritime hegemony, not uniform territorial occupation of Java.", cn: "这个片段表示室利佛逝围绕马六甲海峡和马来半岛的商业、海军影响。它应理解为海上霸权，而非对爪哇的均质领土占领。" },
    mataram_hindu: { en: "Mataram was a central Javanese kingdom of the Kedu / Central Java world, with Borobudur and Prambanan context. It stays whole beside Srivijaya; the chart reads their relationship as contemporary courts and cultural-political links, not Sumatra filling a missing Java strip.", cn: "马打兰是 Kedu 平原/中爪哇世界的王国，与婆罗浮屠和普兰巴南语境相连。它与室利佛逝并列保持完整；图表把二者理解为同时代宫廷与文化政治联系，而不是苏门答腊填补爪哇缺口。" },
    kediri: { en: "Kediri and Singhasari continue the Javanese line between Mataram and Majapahit. The early edge is cut against Srivijaya's still-strong maritime sphere until the Chola shock of 1025, after which the Javanese lane reads more independently.", cn: "谏义里与新柯沙里延续马打兰到满者伯夷之间的爪哇王国脉络。其早期边缘由仍强盛的室利佛逝海上势力承接，直到1025年朱罗冲击后，爪哇栏位才更独立地展开。" },
    malayu_dharmasraya: { en: "Malayu / Dharmasraya keeps the Sumatran Jambi-Batang Hari successor visible after the 1025 Chola shock weakened Palembang. It is drawn as the right half of the island lane beside Kediri/Singhasari Java, while the separate Post-Srivijaya lane carries the Malay Peninsula and Strait mosaic.", cn: "末罗瑜/达摩室利让1025年朱罗冲击削弱巨港之后的苏门答腊占碑-巴当哈里继承世界保持可见。它作为岛屿栏右半与爪哇的谏义里/新柯沙里并列，而后室利佛逝栏另承接马来半岛和海峡拼合体。" },
    post_srivijaya: { en: "Post-Srivijaya Strait States compress Kedah, Temasek, Palembang-facing ports, and other strait polities after the 1025 Chola shock. The Sumatran Jambi-Batang Hari core now has its own Malayu / Dharmasraya half-lane, so this block reads as a maritime strait mosaic rather than hidden Sumatra ownership.", cn: "后室利佛逝海峡诸国压缩表示1025年朱罗冲击后的吉打、淡马锡、面向巨港的港口及其他海峡政权。苏门答腊占碑-巴当哈里核心现在由末罗瑜/达摩室利半栏单独承接，因此此块读作海峡海贸拼合体，而不是隐藏的苏门答腊主人。" },
    sukhothai: { en: "Sukhothai is shown as the early Tai kingdom after the decline of Khmer authority in the Thai basin. Its later tributary phase is separated from Ayutthaya's rise.", cn: "素可泰显示为高棉在泰国盆地权威衰落后的早期泰族王国。其后期附庸/被吸收阶段与阿瑜陀耶兴起分开显示。" },
    sukhothai_late: { en: "Late Sukhothai marks the kingdom's subordinate survival before full absorption into Ayutthaya. It now stays as a rectangular neighboring half-lane: political narrowing is explained by the relationship and detail text, not by a land-bite edge.", cn: "后期素可泰表示其在完全并入阿瑜陀耶前的附属存续。它现在保持为相邻矩形半栏：政治收窄由联系与详情解释，而不是由土地缺口边缘表达。" },
    ayutthaya_rise: { en: "Early Ayutthaya rises beside late Sukhothai, making the Thai transition visible as consolidation rather than clean replacement. The two blocks remain separate hover/detail targets without reciprocal cutout geometry.", cn: "早期阿瑜陀耶与后期素可泰并列出现，使泰国区域转型表现为整合过程，而不是简单替换。两个图块仍是独立 hover/详情目标，但不再互相切缺口。" },
    khmer_late: { en: "Late Khmer marks Angkor's reduced Cambodian core after Sukhothai broke the Thai basin away from Khmer authority. It stays whole as a neighboring Cambodia/Angkor lane; Sukhothai breakaway, Ayutthaya pressure, and the 1431 sack of Angkor are relationship semantics rather than a Tai-owned cutout.", cn: "后期高棉表示素可泰使泰国盆地脱离高棉权威后，吴哥收缩的柬埔寨核心。它保持为完整的柬埔寨/吴哥相邻栏；素可泰脱离、阿瑜陀耶压力和1431年吴哥陷落由联系表达，而不是由泰族政权承接缺口。" },
    ayutthaya: { en: "Ayutthaya became one of Southeast Asia's wealthiest kingdoms and a cosmopolitan trade hub. Its timeline is split around the brief Toungoo/Burmese suzerainty so the chart does not hide political rupture under one rectangle.", cn: "阿瑜陀耶曾是东南亚最富有的王国之一和国际贸易中心。其时间轴围绕短暂的东吁/缅甸宗主权拆分，避免用一个矩形掩盖政治断裂。" },
    ayutthaya_vassal: { en: "This narrow fragment marks Ayutthaya under Toungoo/Burmese suzerainty after the 1569 capture. It stays rectangular beside the Toungoo Siam suzerainty record: conquest and vassalage are carried by relationship links and detail text, not by a land-bite cutout.", cn: "这个窄片段表示1569年陷落后处于东吁/缅甸宗主权下的阿瑜陀耶。它在东吁暹罗宗主权记录旁保持矩形：征服与附庸关系由联系线和详情文字承载，而不是画成土地缺口。" },
    ayutthaya_restored: { en: "Restored Ayutthaya resumes an independent Siamese kingdom after Naresuan's break from Burmese control, lasting until the Burmese sack of 1767.", cn: "复兴阿瑜陀耶表示纳黎萱摆脱缅甸控制后的独立暹罗王国，延续至1767年被缅甸攻陷。" },
    majapahit: { en: "Majapahit is drawn around the eastern Javanese core. Its broad maritime claims and tributary memory are acknowledged in the description, but Malacca and Malay polities remain visible as separate states.", cn: "满者伯夷绘为东爪哇核心。其广阔海上声望和朝贡记忆保留在说明中，但马六甲和马来政权保持为独立可见的国家。" },
    malacca: { en: "The Malacca Sultanate carries the Malay strait after the post-Srivijaya mosaic. Founded by Paramesvara and commanding the India-China sea route, it is a concrete successor owner rather than an empty pause before European arrival.", cn: "马六甲苏丹国承接后室利佛逝拼合体之后的马来海峡。它由拜里米苏拉建立，控制印度至中国的海路，是欧洲到来前的明确主人，而不是空档。" },
    cambodia_post: { en: "Post-Angkor Cambodia is kept as a surviving Cambodian court and lowland kingdom after the 1431 sack of Angkor. Siamese and Vietnamese pressure is carried mostly by relationships and text; only the documented late western loss to Siam is drawn as a time-bounded cutout.", cn: "后吴哥柬埔寨表示1431年吴哥陷落后仍存续的柬埔寨宫廷与低地王国。暹罗与越南压力主要由联系和文字承载；只有有明确来源的晚期西部领土损失才画成限时缺口。" },
    fragmented_burma: { en: "Fragmented Burma is not empty space after Pagan. It compresses Ava, Sagaing, Pinya, Hanthawaddy/Pegu, Shan states, and related river-basin powers before Toungoo reunification.", cn: "分裂缅甸并不是蒲甘之后的空地。它压缩表示东吁再统一前的阿瓦、实皆、彬牙、汉达瓦底/勃固、掸邦及相关河谷政权。" },
    toungoo: { en: "Toungoo is the Myanmar core of Bayinnaung's empire. Its Siamese conquest is shown as a separate short fragment so the Burmese heartland does not visually cover the Philippines or all Thailand.", cn: "东吁表示莽应龙帝国的缅甸核心。其对暹罗的征服另以短片段显示，避免缅甸本土视觉上覆盖菲律宾或整个泰国。" },
    toungoo_siam: { en: "This fragment marks Toungoo/Burmese suzerainty over Ayutthaya after the 1569 conquest. It is intentionally short and narrow because Burmese authority over Siam was real but unstable, but it is not drawn as a cutout owner of a Siamese land bite.", cn: "这个片段表示1569年征服后东吁/缅甸对阿瑜陀耶的宗主权。它故意短且窄，因为缅甸对暹罗的权威真实存在但并不稳定，不过它不会画成暹罗土地切口的主人。" },
    islamic_sultanates: { en: "Islamic Sultanates compress Demak, Banten, Mataram, and other Java/archipelago Muslim polities after Majapahit's decline. The lane deliberately says plural sultanates because this was a competitive coastal and inland field, not one centralized Indonesian state.", cn: "伊斯兰苏丹国压缩表示满者伯夷衰落后的淡目、万丹、马打兰等爪哇/群岛穆斯林政权。这里故意使用复数，因为这是海岸与内陆竞争场域，不是一个中央集权的印度尼西亚国家。" },
    spanish_phil: { en: "Spanish Philippines carries the archipelago after Legazpi's 1565 settlement and Manila's rise as colonial capital. It replaces the barangay lane as an imperial administration, while local communities and beliefs persisted beneath colonial rule.", cn: "西属菲律宾表示1565年黎牙实比建立殖民据点、马尼拉成为殖民首府后的群岛。它以帝国行政承接巴朗盖栏，同时地方社群与信仰仍在殖民统治下延续。" },
    portuguese_malacca: { en: "Portuguese Malacca is the first European owner in the strait lane after the 1511 conquest. It represents the fortified port and sea-lane choke point, not all Malay society or every peninsula interior.", cn: "葡属马六甲表示1511年征服后马六甲海峡栏的第一个欧洲主人。它代表设防港口和海路咽喉，而不是全部马来社会或整个半岛内陆。" },
    toungoo_restored: { en: "Restored Toungoo is the smaller Ava-based Burmese kingdom after Bayinnaung's overextended empire broke apart. The chart keeps the Irrawaddy owner visible so Burma does not become a blank pause before Konbaung.", cn: "东吁复辟表示莽应龙扩张帝国瓦解后，以阿瓦为核心的较小缅甸王国。图中保留伊洛瓦底主人，使缅甸在贡榜之前不成为空档。" },
    voc_java: { en: "VOC Java / Batavia begins with the 1619 capture and rebuilding of Jayakarta as Batavia. The block marks a company-colonial territorial organization growing from trade forts, coercive monopolies, and Javanese political intervention, not a modern Indonesian state.", cn: "荷兰东印度公司爪哇/巴达维亚始于1619年占领并重建雅加达为巴达维亚。此块表示由贸易据点、强制垄断和介入爪哇政治发展出的公司殖民领土组织，而不是现代印度尼西亚国家。" },
    dutch_malacca: { en: "Dutch Malacca succeeds the Portuguese port in 1641 as a VOC strait station. It is a narrow colonial-commercial owner between the Malacca Sultanate legacy and later British Malaya, not a full Dutch claim over all Malaya.", cn: "荷属马六甲在1641年承接葡属港口，成为荷兰东印度公司的海峡据点。它是位于马六甲苏丹国遗产与后来的英属马来亚之间的狭义殖民商业主人，不是荷兰对全马来亚的完整声索。" },
    konbaung: { en: "Konbaung is the last Burmese dynasty, founded by Alaungpaya in 1752. Its late right-edge bite is carried by a British Lower Burma strip after the Anglo-Burmese wars, so the shrinking kingdom reads as colonial takeover, not disappearing land.", cn: "贡榜是缅甸最后一个王朝，由雍籍牙于1752年建立。其晚期右缘缺口由英属下缅甸条带承接，表示英缅战争后的殖民接管，而不是土地消失。" },
    british_burma_coastal: { en: "British Lower Burma / Coastal Burma is a compressed non-contiguous owner for Arakan, Tenasserim, and then Lower Burma before Mandalay fell. It explains why the Konbaung block narrows before full British Burma begins in 1885.", cn: "英属下缅甸/沿海缅甸是若开、丹那沙林以及后来下缅甸的压缩非连续主人，早于曼德勒陷落。它解释贡榜为何在1885年完整英属缅甸出现前已先行变窄。" },
    thonburi: { en: "Thonburi is the short Siamese recovery after Ayutthaya's fall in 1767. It keeps the Chao Phraya owner chain continuous before Rama I moved the court across the river to Bangkok.", cn: "吞武里表示1767年阿瑜陀耶陷落后的短暂暹罗恢复阶段。它让湄南河主人链在拉玛一世迁都曼谷前保持连续。" },
    rattanakosin: { en: "Rattanakosin / Siam-Thailand begins with Bangkok in 1782 and remains the independent Thai core. Its later left-edge cut is filled by French Indochina and post-1954 Indochina states, marking eastern concessions and adjacent owners instead of blank space.", cn: "拉达那哥欣/暹罗-泰国始于1782年的曼谷，并保持泰国独立核心。其后期左缘缺口由法属印度支那及1954年后的印度支那诸国承接，表示东侧割让和邻近主人，而不是空白。" },
    british_malaya: { en: "British Malaya compresses Straits Settlements, Federated Malay States, and Unfederated Malay States into one colonial owner lane after the 1824 transfer of Malacca. It is a composite administration, not a claim that every Malay polity had the same status.", cn: "英属马来亚把1824年马六甲转入英国后形成的海峡殖民地、马来联邦和未联邦马来邦压缩为一个殖民主人栏。它是复合行政，而不是说所有马来政体地位完全相同。" },
    french_indochina: { en: "French Indochina is the colonial federation of Vietnam, Cambodia, and Laos built between the mid-19th century and 1893. In this simplified grid it also fills Siam's eastern cutout, so colonial expansion has a named owner.", cn: "法属印度支那是19世纪中叶至1893年前后形成的越南、柬埔寨、老挝殖民联邦。在这个简化网格中，它也填入暹罗东缘缺口，使殖民扩张拥有具名主人。" },
    british_burma: { en: "British Burma begins after the 1885 fall of Mandalay and the annexation of Upper Burma. It absorbs the earlier coastal/lower-Burma strip into a full colonial lane before independence in 1948.", cn: "英属缅甸始于1885年曼德勒陷落、上缅甸被并吞之后。它把较早的沿海/下缅甸条带并入完整殖民栏，直到1948年独立。" },
    american_phil: { en: "American Philippines follows the 1898 transfer from Spain and the Philippine-American War. The block includes U.S. colonial rule and the Commonwealth path toward the 1946 independent republic.", cn: "美属菲律宾承接1898年西班牙转让以及菲美战争后的阶段。该块包括美国殖民统治和通向1946年独立共和国的自治邦道路。" },
    dutch_indies: { en: "Dutch East Indies is the Netherlands colonial state after the VOC collapse, shown only until Japan's 1942 conquest interrupts Dutch rule. It covers the Java-Sumatra / Indonesian lane, while Malaya and the Philippines remain separate colonial lanes.", cn: "荷属东印度表示荷兰东印度公司瓦解后的荷兰殖民国家，只画到1942年日本占领打断荷兰统治为止。它承接爪哇-苏门答腊/印度尼西亚栏，而马来亚和菲律宾保持独立殖民栏。" },
    japanese_occupied_indonesia: { en: "Japanese-Occupied Indonesia separates the 1942-1945 wartime rupture from Dutch colonial continuity. Japanese military rule destroyed the old colonial order and mobilized Indonesian organizations that shaped the independence revolution.", cn: "日占印度尼西亚把1942-1945年的战时断裂从荷兰殖民连续性中分出。日本军政摧毁旧殖民秩序，并动员出影响独立革命的印度尼西亚组织。" },
    indonesia_revolution: { en: "The Indonesian Revolution begins with the 17 August 1945 proclamation and ends with Dutch recognition of sovereignty in December 1949. This bridge keeps the armed, diplomatic, and constitutional struggle visible instead of jumping directly from Japanese occupation to a settled republic.", cn: "印度尼西亚革命始于1945年8月17日独立宣言，止于1949年12月荷兰承认主权。这个桥接块让武装、外交和宪制斗争保持可见，而不是从日占直接跳到稳定共和国。" },
    indonesia: { en: "Indonesia begins here after Dutch recognition of sovereignty in 1949. The visual lane remains the modern Indonesian republic, separated from Malaysia and the Philippines, while earlier 1945-1949 revolutionary statehood is shown as its own transition phase.", cn: "印度尼西亚在这里从1949年荷兰承认主权后开始。视觉栏表示现代印度尼西亚共和国，与马来西亚和菲律宾分开；1945-1949年的革命建国阶段单独显示。" },
    philippines: { en: "The Philippines block is the post-1946 republic that inherits the American-period island lane. It remains a single archipelago owner in the chart while acknowledging that many islands, languages, and regional identities persist inside it.", cn: "菲律宾表示1946年后的共和国，承接美属时期的群岛栏。图中把它作为一个群岛主人，同时承认内部仍有众多岛屿、语言和区域身份。" },
    myanmar: { en: "Myanmar / independent Burma begins in 1948 after British rule. It owns the postcolonial Irrawaddy and national lane, even though federal, ethnic, and military conflicts make the internal map far more complex than one clean block.", cn: "缅甸/独立缅甸始于1948年英治结束后。它承接后殖民伊洛瓦底与国家栏，即便联邦、族群和军事冲突使内部地图远比一个整块复杂。" },
    indochina_mod: { en: "Indochina States compress independent Vietnam, Laos, and Cambodia after the 1954 Geneva settlement. The block is deliberately composite, replacing French Indochina and continuing to own the strip that Siam/Thailand no longer carries.", cn: "印度支那诸国压缩表示1954年日内瓦安排后的越南、老挝和柬埔寨独立国家。该块有意作为复合主人，取代法属印度支那，并继续承接暹罗/泰国不再拥有的东侧条带。" },
    malaysia: { en: "Malaysia follows Malayan independence and the 1963 federation with Sabah and Sarawak. The visual lane compresses a non-contiguous peninsula-and-Borneo state into one owner, with Singapore's 1965 separation handled in the note rather than as blank land.", cn: "马来西亚承接马来亚独立以及1963年与沙巴、砂拉越组成的联邦。视觉栏把半岛与婆罗洲的非连续国家压缩为一个主人，新加坡1965年分离以说明处理，而不是留成空白。" },
    dai_viet: { en: "Đại Việt was the name of Vietnam during its imperial period. It developed a distinct culture blending Chinese Confucian influences with indigenous traditions, and successfully resisted Mongol invasions three times.", cn: "大越是越南帝国时期的国名。它发展了独特的文化，融合了中国儒家影响和本土传统，并成功抵抗了三次蒙古入侵。" },

    // African entities
    egypt_old: { en: "The Old Kingdom of Egypt, known as the 'Age of the Pyramids', saw the construction of the Great Pyramid of Giza. This era established many of ancient Egypt's cultural and religious foundations that would persist for millennia.", cn: "埃及古王国被称为'金字塔时代'，建造了吉萨大金字塔。这个时代确立了古埃及许多文化和宗教基础，这些基础延续了数千年。" },
    egypt_new: { en: "The New Kingdom was ancient Egypt's most prosperous era, producing famous pharaohs like Tutankhamun and Ramesses II. Egypt reached its greatest territorial extent and created magnificent temples at Karnak and Luxor.", cn: "新王国是古埃及最繁荣的时代，产生了图坦卡蒙和拉美西斯二世等著名法老。埃及达到了最大的领土范围，在卡纳克和卢克索建造了宏伟的神庙。" },
    kush: { en: "The Kingdom of Kush, south of Egypt in Nubia, developed its own pyramid-building tradition and briefly conquered Egypt, establishing the 25th Dynasty. Kush was a major iron-producing center and controlled trade routes between Africa and the Mediterranean.", cn: "库什王国位于埃及以南的努比亚，发展了自己的金字塔建造传统，曾短暂征服埃及，建立了第二十五王朝。库什是主要的铁器生产中心，控制着非洲与地中海之间的贸易路线。" },
    axum: { en: "Axum is drawn as the Ethiopian/Eritrean and Red Sea trading core, not as a block over Nubia. Its Adulis port linked northeastern Africa with Roman, Arabian, and Indian Ocean commerce.", cn: "阿克苏姆绘为埃塞俄比亚/厄立特里亚与红海贸易核心，而不是覆盖努比亚的方块。其阿杜利斯港连接东北非、罗马、阿拉伯与印度洋贸易。" },
    aksum: { en: "Axum is drawn as the Ethiopian/Eritrean and Red Sea trading core, not as a block over Nubia. Its Adulis port linked northeastern Africa with Roman, Arabian, and Indian Ocean commerce.", cn: "阿克苏姆绘为埃塞俄比亚/厄立特里亚与红海贸易核心，而不是覆盖努比亚的方块。其阿杜利斯港连接东北非、罗马、阿拉伯与印度洋贸易。" },
    mali: { en: "The Mali Empire was one of the largest and wealthiest African empires, famous for Mansa Musa's legendary pilgrimage to Mecca that displayed its immense gold wealth. Timbuktu became a major center of Islamic learning and trade.", cn: "马里帝国是最大、最富有的非洲帝国之一，以曼萨·穆萨的传奇麦加朝圣之旅闻名，展示了其巨大的黄金财富。廷巴克图成为伊斯兰学术和贸易的主要中心。" },
    songhai: { en: "The Songhai Empire succeeded Mali as West Africa's dominant power, controlling trans-Saharan trade routes. Under Askia Muhammad, it developed an efficient bureaucracy and made Timbuktu a renowned center of Islamic scholarship.", cn: "桑海帝国继马里之后成为西非的主导力量，控制着跨撒哈拉贸易路线。在阿斯基亚·穆罕默德统治下，发展了高效的官僚体系，使廷巴克图成为著名的伊斯兰学术中心。" },

    // Central Asian entities
    parthia: { en: "The Parthian Empire rivaled Rome for centuries, famous for its mounted archers and the 'Parthian shot'. It controlled the Silk Road trade and blended Greek and Persian cultures, serving as a bridge between East and West.", cn: "帕提亚帝国与罗马帝国对峙数个世纪，以骑射和'帕提亚回射'闻名。它控制丝绸之路贸易，融合希腊和波斯文化，成为东西方之间的桥梁。" },
    sassanid: { en: "The Sasanian Empire was the last great Persian empire before Islam, rivaling Rome and Byzantium. It saw a revival of Persian culture, Zoroastrianism, and art. Many Sasanian traditions were adopted by later Islamic civilization.", cn: "萨珊帝国是伊斯兰教之前最后一个伟大的波斯帝国，与罗马和拜占庭对峙。它见证了波斯文化、琐罗亚斯德教和艺术的复兴。许多萨珊传统被后来的伊斯兰文明采用。" },
    kushan: { en: "The Kushan Empire controlled the central Silk Road, facilitating trade between Rome, Persia, China, and India. Under Kanishka, it became a major patron of Buddhism, spreading the faith throughout Central Asia.", cn: "贵霜帝国控制着丝绸之路中段，促进了罗马、波斯、中国和印度之间的贸易。在迦腻色伽统治下，成为佛教的主要赞助者，在中亚传播佛教。" },
    timurid: { en: "The Timurid Empire, founded by Timur (Tamerlane), created a cultural renaissance in Central Asia and Persia. Samarkand became a center of art and learning. The Timurids later founded the Mughal Empire in India.", cn: "帖木儿帝国由帖木儿（跛子帖木儿）创建，在中亚和波斯创造了文化复兴。撒马尔罕成为艺术和学术中心。帖木儿的后裔后来在印度建立了莫卧儿帝国。" },

    // Additional South Asian entities
    delhi: { en: "The Delhi Sultanate introduced Islam to the Indian subcontinent on a large scale and established Persian as the court language. Despite Mongol threats, it laid foundations for Indo-Islamic architecture and culture.", cn: "德里苏丹国大规模地将伊斯兰教引入印度次大陆，并确立波斯语为宫廷语言。尽管面临蒙古威胁，它奠定了印度-伊斯兰建筑和文化的基础。" },
    // Greek and Hellenistic
    greek_classical: { en: "Classical Greece produced democracy, philosophy, drama, and art that formed the foundation of Western civilization. Athens and Sparta led the Greek world, while thinkers like Socrates, Plato, and Aristotle shaped human thought forever.", cn: "古典希腊产生了民主制、哲学、戏剧和艺术，这些构成了西方文明的基础。雅典和斯巴达领导希腊世界，苏格拉底、柏拉图和亚里士多德等思想家永远地塑造了人类思想。" },
    macedon: { en: "The Kingdom of Macedon under Philip II and Alexander the Great conquered the Persian Empire and spread Greek culture from Egypt to India. Alexander's empire was the largest the world had seen, and Hellenistic culture flourished in his wake.", cn: "马其顿王国在腓力二世和亚历山大大帝统治下征服了波斯帝国，将希腊文化从埃及传播到印度。亚历山大的帝国是当时世界上最大的，希腊化文化在他之后繁荣发展。" },
    ptolemaic: { en: "Ptolemaic Egypt is drawn as the Nile kingdom centered on Alexandria, not as a uniform block over all of Syria. Its disputed Levantine holdings are shown separately because the Syrian Wars repeatedly shifted that frontier.", cn: "托勒密埃及绘为以亚历山大港为中心的尼罗河王国，而不是覆盖整个叙利亚的均质方块。其有争议的黎凡特领地单独显示，因为叙利亚战争反复改变这一边疆。" },
    ptolemaic_levant: { en: "This narrow adjacent frontier lane represents Ptolemaic influence in Phoenicia, Palestine, and Coele-Syria during the Syrian Wars. It is not a cutout from Seleucid Syria; its loss is shown by the Fifth Syrian War relationship when Antiochus III permanently wrested Coele-Syria from the Ptolemies.", cn: "这个相邻窄栏表示叙利亚战争期间托勒密在腓尼基、巴勒斯坦和科伊勒叙利亚的影响。它不是从塞琉古叙利亚切出的缺口；其丧失通过第五次叙利亚战争关系表示，当时安条克三世从托勒密手中长期夺取科伊勒叙利亚。" },
    seleucid: { en: "The early Seleucid Empire is split into an eastern Mesopotamian-Persian core and separate western fragments. This avoids implying that Seleucids ruled Egypt while still showing their huge post-Alexander inheritance.", cn: "早期塞琉古帝国被拆成美索不达米亚-波斯东方核心及若干西部片段。这样既显示其继承亚历山大遗产的巨大规模，也避免暗示塞琉古统治埃及。" },
    seleucid_mesopotamia: { en: "After Parthia detached from the Seleucid sphere, the Seleucid eastern core contracted toward Mesopotamia and Babylonia. This fragment keeps the east visible without covering the independent Parthian Iranian core.", cn: "帕提亚脱离塞琉古势力后，塞琉古东方核心收缩到美索不达米亚和巴比伦尼亚一带。这个片段保留东方存在，但不覆盖独立的帕提亚伊朗核心。" },
    seleucid_anatolia: { en: "This fragment represents Seleucid power and claims in Anatolia before the Roman-Seleucid settlement at Apamea. It now stays whole because Egypt was not the recipient of a missing Anatolian bite; after 188 BCE, Pergamon and other Anatolian powers carry the lane.", cn: "这个片段表示阿帕米亚和约前塞琉古在安纳托利亚的势力与主张。它现在保持完整，因为埃及并不是安纳托利亚缺口的接收者；前188年后由帕加马和其他安纳托利亚势力承接这一栏。" },
    attalid_anatolia: { en: "Pergamon and allied Anatolian kingdoms carry western Asia Minor after Apamea. The block is a composite owner for the Roman-backed Attalid expansion, Rhodian zones, Galatia, Cappadocia, and local kingdoms rather than a blank interval or a Ptolemaic cutout.", cn: "帕加马及安纳托利亚诸国承接阿帕米亚和约后的西亚小亚细亚。这个块是罗马支持下的阿塔罗斯扩张、罗得势力区、加拉太、卡帕多细亚和地方王国的复合主人，而不是空档或托勒密埃及的缺口。" },
    roman_asia_minor: { en: "Roman Asia Minor begins with the Attalid bequest and the formation of Asia province. It bridges Pergamon's end to Pompey's broader eastern settlement, so Anatolia changes owner before the later Roman East block rather than disappearing.", cn: "罗马小亚细亚始于阿塔罗斯遗赠和亚细亚行省形成。它把帕加马终结与庞培后来的东方安排连接起来，使安纳托利亚在后续罗马东方块之前已有清晰主人，而不是消失成空白。" },
    seleucid_syria: { en: "This half-width Syrian frontier lane marks the western Seleucid claim during the wars with Ptolemaic Egypt. It stays rectangular beside the Ptolemaic Levant lane because Coele-Syria was contested, not a reciprocal land bite between two kingdoms.", cn: "这个半宽叙利亚边疆栏表示塞琉古与托勒密埃及战争时期的西部主张。它与托勒密黎凡特栏并列且保持矩形，因为科伊勒叙利亚是争夺区，而不是两个王国彼此切出的土地缺口。" },
    seleucid_late: { en: "Late Seleucid Syria was a rump kingdom after the loss of eastern territories to Parthia and western pressure from Rome. It is now placed in the Levant/Syria column rather than over Egypt.", cn: "后期塞琉古叙利亚是在东方领土失于帕提亚、西方受到罗马压力之后的残余王国。现在它位于黎凡特/叙利亚列，而不是覆盖埃及。" },

    // More Chinese dynasties
    shang: { en: "The Shang dynasty was China's first historically verified dynasty, known for bronze casting, oracle bone inscriptions (the earliest Chinese writing), and ancestor worship. The capital at Yin has yielded remarkable archaeological finds.", cn: "商朝是中国第一个有史料证实的王朝，以青铜铸造、甲骨文（最早的中国文字）和祖先崇拜闻名。殷墟出土了大量考古发现。" },
    zhou_west: { en: "The Western Zhou established the Mandate of Heaven concept, justifying dynastic change. The feudal system developed, and classical Chinese philosophy began to emerge. This era laid cultural foundations for Chinese civilization.", cn: "西周确立了天命观念，为王朝更替提供了合法性。封建制度发展起来，中国古典哲学开始萌芽。这个时代奠定了中华文明的文化基础。" },
    zhou_east: { en: "The Eastern Zhou encompassed the Spring and Autumn and Warring States periods, an era of political fragmentation but intellectual flourishing. Confucius, Laozi, and other philosophers founded schools of thought that still influence East Asia.", cn: "东周包含春秋和战国时期，是政治分裂但思想繁荣的时代。孔子、老子等哲学家创立的学派至今仍影响东亚。" },
    sui: { en: "The Sui dynasty reunified China after centuries of division, rebuilt the Great Wall, and constructed the Grand Canal connecting north and south. Though short-lived, it set the stage for the Tang dynasty's golden age.", cn: "隋朝在数百年分裂后重新统一中国，重建长城，修建了连接南北的大运河。尽管存在时间短暂，却为唐朝的黄金时代奠定了基础。" },

    // Steppe empires
    xiongnu: { en: "The Xiongnu were a steppe confederation whose sphere ran from the Mongolian Plateau and western Manchuria toward Inner Asia. In this lane they replace the generic early-nomad owner and explain why Han China faced a named northern rival rather than an empty frontier.", cn: "匈奴是以蒙古高原为核心、影响伸向满洲西部与内亚的草原联盟。在此栏中，它承接早期游牧主人，说明汉朝北方面对的是具名草原强权，而不是无主边疆。" },
    xianbei: { en: "Xianbei marks the post-Xiongnu steppe owner and the wider tribal world from which the Tuoba branch later founded Northern Wei in north China. The chart keeps the plateau confederation here while showing Northern Wei separately in the China lane.", cn: "鲜卑表示匈奴之后的草原主人，也代表后来拓跋部建立北魏的更大部族世界。图中把草原联盟保留在此栏，同时把北魏作为中国北方政权另列。" },
    rouran: { en: "The Rouran, or Juan-juan, khaganate held the northern steppe before the rise of the Turks. Its block is a named owner of the Mongolian Plateau between Xianbei and Göktürk power, not a generic blank age.", cn: "柔然（蠕蠕）汗国在突厥兴起前占据北方草原。它是鲜卑与突厥之间蒙古高原的具名主人，而不是笼统空档。" },
    gokturk: { en: "The Göktürk Khaganate was the first Turkic state to use that name, controlling the Silk Road from Mongolia to the Black Sea. They developed the earliest known Turkic writing system and influenced all later Turkic peoples.", cn: "突厥汗国是第一个使用该名称的突厥国家，控制着从蒙古到黑海的丝绸之路。他们发展了已知最早的突厥文字系统，影响了后来所有突厥民族。" },
    gokturk_mongolia: { en: "This is the Mongolian-Plateau face of the Göktürk world, centered on the Orkhon and Ötüken steppe. Western Turkic and Central Asian fragments are handled elsewhere so the local owner here stays legible.", cn: "这里表示突厥世界在蒙古高原一侧的主人，核心在鄂尔浑与于都斤草原。西突厥和中亚片段在其他栏处理，使本地草原主人保持清晰。" },
    uyghur_mongolia: { en: "The Uyghur Khaganate held the Orkhon steppe from 744 until the Kyrgyz attack on Karabalghasun in 840. Its collapse redirects Uyghur history toward the Tian Shan and Turfan, instead of making the plateau ownerless.", cn: "回鹘汗国自744年至840年黠戛斯攻破可汗城前占据鄂尔浑草原。其崩溃后回鹘历史转向天山与吐鲁番方向，而不是让高原变成无主空白。" },
    liao: { en: "The Liao dynasty, founded by the Khitan, ruled Manchuria, Inner Mongolia, and northern frontier zones through a dual system for nomadic and sedentary populations. It is the named steppe-imperial owner before the Jurchen and Mongol transitions.", cn: "辽朝由契丹建立，以二元体制治理满洲、内蒙古与北方边疆的游牧和农耕人口。它是女真与蒙古转型前的具名草原帝国主人。" },
    mongol_tribes: { en: "Mongol Tribes represents the post-Liao field of Kereit, Naiman, Merkit, Tatar, Mongol, and related steppe powers before Temujin's 1206 unification. It is a composite owner, not a vacant pre-empire gap.", cn: "蒙古诸部表示辽亡后、铁木真1206年统一前克烈、乃蛮、蔑儿乞、塔塔儿、蒙古等草原力量。它是复合主人，不是帝国出现前的空白。" },
    yuan_early: { en: "Early Yuan marks the Mongol conquest and northern China phase after the fall of Jurchen Jin in 1234 and before Southern Song fell in 1279. It keeps the partial-conquest phase visible instead of jumping straight from Jin to a full Yuan rectangle.", cn: "元（北）表示1234年金亡后至1279年南宋灭亡前的蒙古征服与中国北方阶段。它保留局部征服期，而不是从金朝直接跳到完整元朝矩形。" },
    northern_yuan: { en: "Northern Yuan carries the Mongol imperial court and steppe succession after the loss of Dadu and China proper in 1368. It explains why the Mongolian lane continues as a Mongol polity before Qing incorporation.", cn: "北元承接1368年失去大都与中国本部后的蒙古帝国朝廷和草原继承。它解释蒙古栏在清纳入之前仍由蒙古政权延续。" },

    // Japanese periods
    nara: { en: "The Nara period saw the establishment of Japan's first permanent capital and the adoption of Chinese-style government. Buddhism flourished, and great temples were built. The oldest Japanese histories and poetry collections date from this era.", cn: "奈良时代见证了日本第一个永久首都的建立和中国式政府的采用。佛教繁荣，建造了大型寺庙。日本最古老的历史著作和诗歌集都出自这个时代。" },
    kamakura: { en: "The Kamakura period established Japan's first military government (shogunate). Zen Buddhism spread among the warrior class, and Japan twice repelled Mongol invasions. The samurai code began to take shape during this era.", cn: "镰仓时代建立了日本第一个军事政府（幕府）。禅宗在武士阶层中传播，日本两次击退蒙古入侵。武士道精神在这个时代开始形成。" },
    muromachi: { en: "The Muromachi period, despite civil wars, saw the flowering of Japanese culture including tea ceremony, Noh theater, and ink painting. Zen aesthetics shaped Japanese art, and trade with China brought new cultural influences.", cn: "室町时代尽管经历了内战，却见证了日本文化的繁荣，包括茶道、能剧和水墨画。禅宗美学塑造了日本艺术，与中国的贸易带来了新的文化影响。" },

    // Korean history
    gojoseon: { en: "Gojoseon is treated as Korea's early Bronze/Iron Age kingdom horizon, tied to the Dangun tradition and later Wiman Joseon. Steppe and Xiongnu pressure before the Han conquest in 108 BC is shown through frontier links, so the Korean lane remains a whole adjacent block.", cn: "古朝鲜被处理为朝鲜早期青铜/铁器时代王国视野，与檀君传统和后来的卫满朝鲜相连。汉于前108年征服之前的草原与匈奴压力由边疆联系表达，因此朝鲜栏保持为完整相邻块。" },
    goryeo: { en: "Goryeo unified the Korean peninsula and gave Korea its English name. It is known for celadon pottery, the Tripitaka Koreana (Buddhist scriptures carved on woodblocks), and the invention of metal movable type printing.", cn: "高丽统一了朝鲜半岛，Korea这个英文名称就来源于此。高丽以青瓷、高丽大藏经（雕刻在木版上的佛经）和金属活字印刷的发明闻名。" },

    // Additional enrichment — newly added entries
    xia: { en: "Traditionally regarded as China's first dynasty, the Xia is known largely through later historical texts. Archaeological sites like Erlitou suggest a complex Bronze-Age polity in the Yellow River basin, marking China's transition from Neolithic chiefdoms to organized kingship.", cn: "夏朝传统上被视为中国第一个王朝，主要通过后世史籍记载。二里头等考古遗址揭示出黄河流域一个复杂的青铜时代政体，标志着中国从新石器酋邦向有组织王权的过渡。" },
    zhou_east: { en: "The Eastern Zhou spanned the tumultuous Spring-and-Autumn and Warring States periods. Amid constant warfare the Hundred Schools of Thought arose — Confucius, Mozi, Laozi, Mencius and Xunzi laying the philosophical bedrock of East Asian civilization.", cn: "东周贯穿动荡的春秋与战国时期。在连绵的战乱中，诸子百家兴起——孔子、墨子、老子、孟子、荀子为东亚文明奠定了哲学基石。" },
    warring_states: { en: "The Warring States period saw seven major powers struggle for supremacy. Iron tools, crossbows, mass infantry and canal building transformed warfare and agriculture, culminating in Qin's unification of China in 221 BC.", cn: "战国时代七雄争霸。铁器、弩机、大规模步兵与运河建设改变了战争与农业形态，最终在公元前221年以秦统一中国而告终。" },
    jin_west: { en: "The Western Jin briefly reunified China after the Three Kingdoms period. Intrigue among the imperial family — the War of the Eight Princes — weakened the dynasty, inviting the catastrophic Uprising of the Five Barbarians that fragmented the north.", cn: "西晋短暂结束三国分裂局面。皇族内斗——八王之乱——削弱了王朝，最终引发五胡乱华，导致北方再度陷入分裂。" },
    sui: { en: "The short-lived Sui dynasty reunified China after centuries of division, rebuilt the Great Wall, and excavated the Grand Canal that still defines the nation's trade geography. Its reforms and infrastructure laid the foundations for the Tang golden age.", cn: "短命的隋朝结束数百年分裂，重建长城，开凿了至今仍塑造中国贸易地理的大运河。其改革与基础建设为唐代盛世奠定了基础。" },
    jin_jurchen: { en: "The Jurchen Jin conquered Northern Song in 1127 — the Jingkang Incident — and controlled much of north China. Their rule ended under relentless Mongol pressure in 1234, setting the stage for Mongol domination of all East Asia.", cn: "女真金朝于1127年灭北宋（靖康之变），统治中国北方大部分地区。面对蒙古持续压力，1234年被灭，为蒙古统治整个东亚奠定基础。" },
    khitan_early: { en: "Khitan Early marks the tribal and regional consolidation between the Uyghur collapse and Yelu Abaoji's Liao dynasty. It is a transition owner for the Manchuria-Mongolia steppe rather than an unexplained gap between Uyghur and Liao rule.", cn: "早期契丹表示回鹘崩溃后至耶律阿保机建立辽朝前的部族与区域整合。它是满洲-蒙古草原的过渡主人，而不是回鹘与辽之间的无解释空档。" },
    heian: { en: "Heian is Japan's Kyoto court age after Emperor Kanmu moved the capital in 794. It remains a full Japan-lane owner because the abstraction is about the imperial court and aristocratic order, not a modern border map.", cn: "平安表示桓武天皇794年迁都后的京都宫廷时代。它在日本栏保持整块，因为这里抽象的是朝廷与贵族秩序，而不是现代边界地图。" },
    kamakura: { en: "Kamakura marks the first durable warrior government beside the Kyoto court. Power shifted toward Minamoto, Hojo, and samurai institutions after the Genpei War, so the succession is political rather than a blank territorial rupture.", cn: "镰仓表示京都朝廷旁边第一个稳定武家政权。源氏、北条和武士制度在源平战争后取得实权，因此这里是政治主人转换，而不是疆域空档。" },
    muromachi: { en: "Muromachi begins as the Ashikaga shogunate in Kyoto, but its late right-edge cut is filled by Sengoku daimyo after the Onin War. The chart shows lost shogunal control as another owner's gain, not as empty land.", cn: "室町始于京都的足利幕府；应仁之乱后，其晚期右侧缺口由战国大名承接。图中把幕府失去的控制显示为另一主人取得，而不是空白土地。" },
    sengoku_daimyo: { en: "Sengoku Daimyo is a composite owner for regional warlord domains after the Onin War. It deliberately fills the Muromachi cutout: Japan was fragmented among daimyo, not ownerless, before Oda and Toyotomi reunification.", cn: "战国大名是应仁之乱后地方大名领国的复合主人。它特意填补室町缺口：织田与丰臣统一前，日本是大名割据，而不是无主空地。" },
    azuchi: { en: "Azuchi-Momoyama represents the Oda-Toyotomi unification drive after the last Ashikaga shogun was expelled. Castles, surveys, commerce, and military consolidation turn the Sengoku mosaic back toward a single central owner.", cn: "安土桃山表示末代足利将军被逐后织田-丰臣的统一进程。城郭、检地、商业和军事整合把战国拼图重新推向一个中央主人。" },
    edo: { en: "Edo Japan experienced over 250 years of Tokugawa peace under strict social order and isolation from the outside world. It follows the Sengoku/Azuchi unification sequence as a full owner because Tokugawa authority stabilized the daimyo domain system.", cn: "江户日本在德川幕府治下享有逾250年的和平，社会秩序严密，闭关锁国。它承接战国/安土统一链而恢复整块，因为德川权威稳定了大名藩国体系。" },
    meiji: { en: "Meiji is the post-1868 imperial modernization phase after Tokugawa rule collapsed. It stays separate from later colonial Korea and Taiwan lanes so Japan proper, empire-building, and overseas annexations do not collapse into one rectangle.", cn: "明治表示1868年德川统治瓦解后的帝国近代化阶段。它与后续朝鲜、台湾殖民栏分开，使日本本土、帝国建设和海外兼并不被压成一个矩形。" },
    joseon: { en: "The Joseon dynasty, Korea's longest-ruling, lasted over 500 years. King Sejong the Great commissioned Hangul — a phonetic alphabet designed specifically for the Korean language — and Confucian scholarship defined governance, art and daily life.", cn: "朝鲜王朝是韩国统治最长的王朝，延续500余年。世宗大王创制专为朝鲜语设计的表音字母'韩文'，儒家学问塑造了治理、艺术与日常生活。" },
    // Southeast Asia
    funan: { en: "Funan is drawn as an early lower-Mekong / southern Cambodian state and trade network. Its contact with mainland Thailand belongs in relationship labels and notes, not in a Thai-owned land bite cut from the Mekong core.", cn: "扶南绘为早期下湄公河/柬埔寨南部国家与贸易网络。它与泰国大陆方向的接触应由联系标签和说明表达，而不应把泰国盆地画成从湄公河核心切走的一块土地。" },
    funan_maritime: { en: "This whole fragment represents Funan's maritime and commercial reach toward the Malay Peninsula and Gulf of Thailand. It is intentionally separated from the Mekong core and no longer clipped against the island lanes, because trade ports and influence networks should not visually become direct land ownership.", cn: "这个完整片段表示扶南向马来半岛和泰国湾方向的海上商业影响。它故意与湄公河核心分开，且不再被岛屿栏切出缺口，因为贸易港与影响网络不应被视觉上误读成直接陆地统治。" },
    early_malay_peninsula_polities: { en: "Malay Peninsula Polities fill the post-Funan and pre-Srivijaya strait lane with Langkasuka, Pan Pan, Chitu / Red Earth, Old Kedah, and related port networks. The block is a composite trade-polity field across the peninsula, not empty land and not a single clean empire.", cn: "马来半岛诸政权把扶南之后、室利佛逝之前的海峡栏填成狼牙修、盘盘、赤土/红土、古吉打及相关港口网络。这个图块是跨半岛贸易政权复合场，不是空地，也不是一个边界整齐的单一帝国。" },
    tarumanagara: { en: "Tarumanagara was an early recorded kingdom in western Java, known mainly from inscriptions and Chinese notices. Its separate Java lane keeps island Southeast Asian state formation visible beside Funan's mainland and maritime network.", cn: "多罗摩是西爪哇早期有记录的王国，主要由铭文和中国记载可知。它保留在爪哇栏中，使岛屿东南亚国家形成与扶南的大陆/海贸网络并列可见。" },
    pyu: { en: "The Pyu city-states occupied the Irrawaddy basin with walled cities such as Sri Ksetra and Halin. The lane now runs to the 849 Pagan handoff because Nanzhao-era disruption weakened the Pyu world without making the Irrawaddy basin ownerless.", cn: "骠国城邦位于伊洛瓦底江流域，以室利差呾罗、哈林等有城墙城市为代表。此栏现在延续到849年的蒲甘交接点，因为南诏时代冲击削弱了骠国世界，但并未让伊洛瓦底流域变成无主空地。" },
    chenla: { en: "Chenla is the pre-Angkor Cambodian successor zone after Funan, known through Chinese sources and later Khmer historical reconstruction. The block bridges Funan and Angkor while leaving Dvaravati and Pyu visible as separate neighbors.", cn: "真腊是扶南之后、吴哥之前的柬埔寨继承区域，主要通过中国史料和后世高棉史复原。该图块连接扶南与吴哥，同时让堕罗钵底和骠国作为邻近势力保持可见。" },
    dvaravati: { en: "Dvaravati represents a Mon Buddhist city-state network in central Thailand, famous for Buddhist sculpture and votive art. It is kept distinct from Chenla and Khmer influence so the Thai basin is not treated as empty space or automatic Khmer territory.", cn: "堕罗钵底表示泰国中部的孟族佛教城邦网络，以佛教造像和奉献小像闻名。它与真腊和高棉影响分开显示，使泰国盆地不被当成空白或自动归入高棉领土。" },
    dai_viet: { en: "Đại Việt / Vietnam is the compressed Vietnamese state lane in Southeast Asia. Its orthogonal cutouts show that Champa owned the central-southern coast before 1471, then the Panduranga Cham remnant survived as a narrow non-contiguous strip until Minh Mang's nineteenth-century integration.", cn: "大越/越南是东南亚视角中的越南国家主线。其正交缺口显示1471年前中南部海岸由占婆承接，1471年后宾童龙占婆残余仍以窄小非连续条带延续，直到明命帝时期被整合。" },
    champa: { en: "Champa was a maritime-trading Hindu-Buddhist civilization along central Vietnam's coast. Vijaya fell to Lê Thánh Tông in 1471, but the chart now separates that conquest from the surviving Panduranga Cham remnant instead of treating Cham land as instantly ownerless.", cn: "占婆是中越海岸的海上贸易印度教-佛教文明。1471年毗阇耶被黎圣宗攻破；图中现在把这次征服与继续存在的宾童龙占婆残余分开，而不是把占族土地瞬间画成无主。" },
    cham_panduranga: { en: "Panduranga Cham Remnant represents the southern Cham polity around Phan Rang after the 1471 fall of Vijaya. It is deliberately narrow and non-contiguous: a residual owner, tributary/autonomous field, and resistance zone inside a Vietnamese-expanding frontier.", cn: "宾童龙占婆残余表示1471年毗阇耶陷落后潘郎一带的南部占族政权。它被刻意画成狭窄且非连续的残余主人、附庸/自治场与抵抗区域，嵌在越南扩张边疆之中。" },
    sea_nguyen_french_pressure: { en: "Nguyen + French Pressure marks the uneven 1860s-1880s transition: France held Cochinchina and pressed north while the Hue court still stood. The block prevents the Southeast Asia Vietnam lane from going blank during staged colonization.", cn: "阮朝/法国压力表示19世纪60-80年代不均衡过渡：法国控制交趾支那并向北推进，而顺化朝廷仍存在。该块避免东南亚越南栏在阶段性殖民中变空。" },
    sea_french_vietnam: { en: "French Vietnam keeps Tonkin, Annam, and Cochinchina visible inside French Indochina. It mirrors the Cambodia/Indochina colonial lane but stays in the Vietnam slot so the right side of Southeast Asia does not disappear after 1863.", cn: "法属越南把东京、安南与交趾支那保留在法属印度支那内部。它与柬埔寨/印度支那殖民栏相呼应，但留在越南栏，避免东南亚右侧在1863年后消失。" },
    sea_north_vietnam: { en: "North Vietnam is drawn as the northern half after the 1954 Geneva settlement. The split lane makes the Cold War division visible without pretending one side owned the whole country before reunification.", cn: "北越在1954年日内瓦安排后绘成北半栏。拆分栏让冷战分裂可见，而不是假装统一前某一方拥有整个国家。" },
    sea_south_vietnam: { en: "South Vietnam / PRG is the southern half of the Vietnam lane from 1954 to formal reunification in 1976. It compresses the Republic of Vietnam and the provisional post-1975 southern administration.", cn: "南越/临时革命政府是1954年至1976年正式统一前越南栏的南半。它压缩表示越南共和国以及1975年后的南方临时行政。" },
    sea_unified_vietnam: { en: "Unified Vietnam begins with the formal creation of the Socialist Republic of Vietnam in July 1976. The full-width block shows reunification as a real lane transition rather than a label hidden in a generic Indochina rectangle.", cn: "统一越南始于1976年7月越南社会主义共和国正式成立。全宽块把统一显示为真实栏位转变，而不是藏在泛称印度支那矩形里。" },
    pagan: { en: "The Pagan Kingdom begins at the 849 capital tradition after the Pyu-Nanzhao disruption, then grows into the first major Burmese kingdom. It does not backfill the earlier Pyu centuries, but it carries the Irrawaddy lane into the Bagan temple landscape.", cn: "蒲甘王国从骠国-南诏冲击后的849年建都传统开始，随后发展为首个重要缅甸王国。它不反向覆盖此前数百年的骠国阶段，而是把伊洛瓦底栏承接到蒲甘寺塔景观。" },
    barangays: { en: "Barangays were lowland Philippine kinship communities led by datus, usually small but politically durable. Showing them as a confederated island lane avoids pretending the pre-Spanish Philippines were either empty or a centralized empire.", cn: "巴朗盖是由达图领导的菲律宾低地亲族共同体，规模通常不大但政治上稳定。将其显示为群岛联邦式栏位，避免把西班牙到来前的菲律宾误读为空白或中央集权帝国。" },
    ayutthaya: { en: "Ayutthaya was one of Southeast Asia's wealthiest kingdoms, a cosmopolitan trade hub where Portuguese, Dutch, Japanese and Persian merchants lived side by side. Its sack by the Burmese in 1767 still defines Thai historical memory.", cn: "阿瑜陀耶曾是东南亚最富有的王国，葡萄牙、荷兰、日本与波斯商人云集的国际贸易中心。1767年被缅甸洗劫的记忆至今塑造着泰国民族意识。" },
    // Southeast Asia cultural-owner baselines
    indonesia_prehistoric: { en: "Indonesian Cultures marks the long island Southeast Asian cultural horizon before named Java and Sumatra polities. It is a maritime and Austronesian-linked owner of the island lane, not one kingdom, so Tarumanagara and later Srivijaya emerge from occupied trade worlds rather than blank space.", cn: "印尼文化表示有名的爪哇、苏门答腊政权出现前，岛屿东南亚漫长的文化视野。它是海上与南岛语网络相关的岛屿栏主人，不是单一王国，因此多罗摩和后来的室利佛逝是从有人居住的贸易世界中出现，而不是从空白中出现。" },
    malay_prehistoric: { en: "Malay Cultures represents Malay Peninsula and Strait-region communities before Funan's maritime projection and Srivijaya's Malacca sphere. The lane is an inhabited coastal and exchange corridor, not ownerless space waiting for a mainland state.", cn: "马来文化表示扶南海贸投射和室利佛逝马六甲势力出现前的马来半岛与海峡区域社群。此栏是有人居住的沿海与交换通道，不是等待大陆国家填入的无主空间。" },
    mekong_prehistoric: { en: "Mekong Cultures covers lower-Mekong and Cambodian prehistoric settlement, bronze-age exchange, and early riverine communities before Funan. It keeps the Mekong lane owned by local cultural worlds until a named mandala polity becomes visible.", cn: "湄公河文化表示扶南之前下湄公河与柬埔寨方向的史前聚落、青铜时代交流和早期河流社群。它让湄公河栏在具名曼荼罗政权出现前由本地文化世界占据。" },
    thai_prehistoric: { en: "Thai Basin Cultures covers mainland Thailand before Dvaravati and Sukhothai, including prehistoric farming, metallurgy, and Ban Chiang-style archaeological horizons. It remains an adjacent Chao Phraya / Khorat cultural lane rather than a cutout owner inside Funan.", cn: "泰国盆地文化表示堕罗钵底与素可泰之前的泰国大陆，包括史前农业、冶金和班清式考古视野。它保持为相邻的湄南河/呵叻文化栏，而不是扶南内部缺口的主人。" },
    myanmar_prehistoric: { en: "Myanmar Cultures represents Irrawaddy and central dry-zone communities before Pyu urbanization. The later Pyu city-states therefore read as a transformation of an occupied river-basin lane, not as the first owner of empty land.", cn: "缅甸文化表示骠国城市化之前的伊洛瓦底江与中部干旱区社群。后来的骠国城邦因此读作有人居住的河谷栏位转型，而不是空地上的第一个主人。" },
    philippines_prehistoric: { en: "Philippine Cultures keeps the archipelago lane occupied before datu-led barangays, including early settlement, Austronesian language communities, maritime exchange, and metal-age village growth. It avoids treating the islands as politically silent just because no single empire controlled them.", cn: "菲律宾文化使群岛栏在达图领导的巴朗盖之前保持有人占据，包括早期定居、南岛语社群、海上交流和金属器时代村落发展。它避免因为没有单一帝国控制群岛，就把这里看成政治沉默或空白。" },
    sea_vietnam_prehistoric: { en: "Vietnam Coastal Cultures fills the Southeast Asia Vietnam/Champa lane before it splits into northern Red River and central-southern coastal trajectories. It is a cultural baseline, not a modern Vietnam projected backward.", cn: "越南沿海文化填补东南亚视角中越南/占婆栏早期阶段，早于北部红河与中南部沿海轨迹分化。它是文化基线，不是把现代越南向前投射。" },
    sea_sa_huynh: { en: "Sa Huynh Coast marks the central and southern Vietnamese coastal horizon before Champa becomes visible. Showing it beside northern Viet polities prevents the Cham side of the lane from beginning as blank land.", cn: "沙黄海岸表示占婆清晰出现前越南中南部沿海视野。它与北部越人政体并列，使占婆一侧不会以空白土地开头。" },
    sea_viet_polities: { en: "Red River Viet Polities compress Van Lang, Au Lac, and Nam Viet memory into a northern half-lane. The split warns that northern Vietnamese state formation should not erase Sa Huynh and later Cham coastal worlds.", cn: "红河越人政体把文郎、瓯雒与南越记忆压缩为北部半栏。拆分提醒读者：北部越人国家形成不应抹去沙黄及后来的占族沿海世界。" },
    sea_chinese_jiaozhi: { en: "Jiaozhi / Chinese Rule represents northern Vietnam under Han-through-Tang commandery and protectorate rule. It is kept as a half-lane because central and southern Vietnam followed Sa Huynh and Cham trajectories.", cn: "交趾/北属表示汉至唐郡县与都护府统治下的北越。它保持半栏，因为越南中部和南部走向沙黄与占婆轨迹。" },
    sea_early_viet: { en: "Early Independent Vietnam covers the Ngo, Dinh, and Early Le transition after 939 before Ly centralization. It gives the northern half a named owner while Champa remains visible on the coast.", cn: "早期独立越南覆盖939年后吴、丁、前黎至李朝中央化前的过渡。它让北半栏有具名主人，同时占婆仍在沿海保持可见。" },
    // Europe
    aegean_early: { en: "Early Aegean cultures mark Cycladic, Early Helladic, and island-mainland exchange before palatial Crete. This is a cultural horizon, not a single state, so the lane sets context for later Minoan and Mycenaean owners.", cn: "早期爱琴海文化表示基克拉泽斯、早期希腊本土及岛屿-大陆交流，早于克里特宫殿文明。它是文化视野而非单一国家，为后来的米诺斯和迈锡尼主人铺垫背景。" },
    minoan: { en: "Minoan Crete is the Bronze Age palace civilization centered on Knossos and other Cretan palaces, with maritime trade, fresco art, and Linear A administration. It owns the Aegean lane before Mycenaean mainland power takes over.", cn: "米诺斯克里特是以克诺索斯等宫殿为中心的青铜时代文明，具有海上贸易、壁画艺术与线形文字A行政。它在迈锡尼大陆势力接手前占据爱琴海栏位。" },
    mycenaean: { en: "Mycenaean Greece represents the mainland palace network of Mycenae, Pylos, Tiryns, and Thebes, using Linear B for Greek-language administration. It succeeds the Minoan-dominated Aegean rather than appearing from empty space.", cn: "迈锡尼希腊表示迈锡尼、皮洛斯、梯林斯、底比斯等大陆宫殿网络，并用线形文字B记录希腊语行政。它承接米诺斯主导后的爱琴海，而不是从空白中出现。" },
    greek_dark: { en: "The Greek Dark Age is a contraction after the Late Bronze Age palace collapse. The block preserves continuity through smaller communities, iron use, migration, and oral epic memory before the polis world re-emerges.", cn: "希腊黑暗时代是青铜时代晚期宫殿崩溃后的收缩阶段。该块保留小型社群、铁器、迁徙与口传史诗记忆的连续性，直到城邦世界重新出现。" },
    greek_citystates: { en: "Greek City-States marks the polis world of Athens, Sparta, Corinth, Thebes, and hundreds of smaller communities. Its single lane is a federation-like abstraction of many owners, not a unified Greek kingdom.", cn: "希腊城邦表示雅典、斯巴达、科林斯、底比斯及数百个较小城邦构成的 polis 世界。单栏是对多主人的联邦式抽象，而不是统一希腊王国。" },
    italic_early: { en: "Italic cultures cover pre-Etruscan and early Italic communities across the Italian peninsula. The lane is a cultural baseline before Etruscan urban leagues and Rome become visible political owners.", cn: "早期意大利文化表示伊特鲁里亚之前及早期意大利半岛诸社群。该栏是文化基线，早于伊特鲁里亚城市联盟和罗马成为可见政治主人。" },
    etruscan: { en: "Etruscan Etruria was a city-state civilization in central Italy whose religion, urban forms, and elite culture deeply influenced Rome. It is separate from Rome so pre-Roman Italy is not reduced to a Roman prelude.", cn: "伊特鲁里亚是意大利中部的城邦文明，其宗教、城市形态和贵族文化深刻影响罗马。它与罗马分开显示，避免把罗马前意大利简化成罗马前奏。" },
    gallic_early: { en: "Early Gallic cultures cover Bronze and early Iron Age communities before the historically named Gauls. The lane later narrows into Celtic/La Tene Gaul rather than staying an anonymous placeholder.", cn: "早期高卢文化表示有史料名称的高卢人出现前的青铜时代和早期铁器时代社群。该栏之后转入凯尔特/拉坦诺高卢，而非一直是无名占位。" },
    celtic_gaul: { en: "Celtic Gaul represents independent Gallic tribal polities and La Tene cultural networks before Rome's southern foothold. It remains an owner of the Gaul lane until Roman expansion cuts into it.", cn: "凯尔特高卢表示罗马南部据点出现前的独立高卢部族政权与拉坦诺文化网络。它一直是高卢栏位主人，直到罗马扩张切入。" },
    iberian_early: { en: "Early Iberian cultures mark Bronze Age and Mediterranean-contact societies in the peninsula before the better-attested Iberian and Celtiberian worlds. The label is cultural, not a single kingdom.", cn: "早期伊比利亚文化表示伊比利亚和凯尔特伊比利亚世界更清晰可见前，半岛上的青铜时代及地中海接触社群。该标签是文化范围而非单一王国。" },
    iberian_celtic: { en: "Iberian/Celtic summarizes Iberian, Celtiberian, and related peninsula polities before Rome entered during the Second Punic War. It makes the pre-Roman owner visible before Hispania appears.", cn: "伊比利亚/凯尔特概括第二次布匿战争中罗马进入前的伊比利亚、凯尔特伊比利亚及相关半岛政权，使希斯帕尼亚出现前的罗马前主人可见。" },
    british_early: { en: "Early British cultures cover the long island prehistory before named Iron Age Celtic polities. It is a cultural lane that keeps Britain occupied before Roman and Anglo-Saxon political labels arrive.", cn: "早期不列颠文化表示有名铁器时代凯尔特政权出现前漫长的岛屿史前阶段。它是文化栏位，确保罗马与盎格鲁-撒克逊政治标签出现前的不列颠不是空白。" },
    celtic_britain: { en: "Celtic Britain represents Iron Age tribal polities such as the Catuvellauni, Iceni, and others before Claudius's conquest. Rome takes the lane only from 43 CE onward.", cn: "凯尔特不列颠表示克劳狄征服前的铁器时代部族政权，如卡图维劳尼、爱西尼等。罗马只从公元43年后接手该栏位。" },
    byzantine: { en: "The Byzantine Empire preserved Roman and Greek heritage for a thousand years after the Western fall. Constantinople was Europe's largest city, its Hagia Sophia the greatest dome in Christendom. Byzantine law, liturgy and diplomacy still echo through Eastern Europe.", cn: "拜占庭帝国在西罗马灭亡后保存了罗马与希腊遗产逾千年。君士坦丁堡是欧洲最大的城市，圣索菲亚大教堂是基督教世界最宏伟的穹顶。拜占庭的法律、礼仪与外交至今回响于东欧。" },
    frankish_gaul: { en: "Frankish Gaul carries the post-Roman Gaul lane from Clovis through Merovingian and Carolingian consolidation. It is the owner between Western Roman Gaul and Charlemagne's empire, not an empty post-imperial gap.", cn: "法兰克高卢承接克洛维之后的后罗马高卢栏位，经历墨洛温与加洛林整合。它是西罗马高卢与查理曼帝国之间的主人，而不是帝国崩溃后的空白。" },
    carolingian: { en: "Charlemagne was crowned emperor in 800, symbolically reviving the Western Roman Empire. His court at Aachen sponsored the Carolingian Renaissance — preserving classical manuscripts, standardizing handwriting, and establishing the intellectual foundations of medieval Europe.", cn: "查理曼于800年加冕为帝，象征着西罗马帝国的复兴。其阿亨宫廷赞助了加洛林文艺复兴——保存古典手稿、规范字体，为中世纪欧洲奠定知识基础。" },
    carolingian_germany: { en: "The German-facing Carolingian lane keeps the eastern Frankish lands visible before the 843 partition. It is not a separate empire from Charlemagne's realm, but a same-dynasty fragment needed so East Francia has an explicit predecessor.", cn: "面向德意志的加洛林栏保留843年分割前的东部法兰克土地。它不是独立于查理曼帝国的另一个帝国，而是同一王朝的片段，让东法兰克有明确前身。" },
    w_francia: { en: "West Francia is the western kingdom assigned after the Treaty of Verdun. It carries the post-Carolingian French lane into the Capetian transition instead of treating France as appearing from a blank space.", cn: "西法兰克是《凡尔登条约》后形成的西部王国。它把加洛林之后的法国栏承接到卡佩转型，而不是让法国从空白中突然出现。" },
    e_francia: { en: "East Francia is the eastern kingdom after Verdun, the predecessor lane for the Ottonian and Holy Roman imperial framework. It is an owner of the German slot before modern Germany existed.", cn: "东法兰克是凡尔登分割后的东部王国，是奥托王朝与神圣罗马帝国框架的前身栏。它在现代德国出现之前承接德意志栏位。" },
    lotharingia: { en: "Middle Francia is the long central strip granted to Lothar I, running between the western and eastern kingdoms and into Italy. Its separate block makes the Carolingian breakup a three-owner partition rather than a two-state simplification.", cn: "中法兰克是洛泰尔一世取得的中央长条王国，位于西部与东部王国之间并延伸至意大利。独立图块使加洛林分裂成为三主人分割，而不是两国式简化。" },
    hre: { en: "The Holy Roman Empire — famously dismissed by Voltaire as 'neither holy, nor Roman, nor an empire' — was nonetheless the political framework of Central Europe for a millennium. Its fragmentation shaped the modern map from Switzerland to the Netherlands.", cn: "神圣罗马帝国被伏尔泰讽刺为'既不神圣，也不罗马，更非帝国'，却成为中欧千年的政治框架。其分裂塑造了从瑞士到荷兰的现代欧洲版图。" },
    france_cap: { en: "Capetian France begins with Hugh Capet's election in 987. The block means a growing royal domain and dynastic framework around Paris and Reims, not a modern French state already occupying every later border.", cn: "卡佩法国始于987年休·卡佩当选。这个图块表示围绕巴黎和兰斯逐渐扩张的王室领地与王朝框架，而不是已经拥有现代边界的法国。" },
    france_val: { en: "Valois France covers the Hundred Years' War, recovery under Charles VII, Renaissance monarchy, and the Wars of Religion. It is a centralized kingdom under pressure, not a timeless rectangular France.", cn: "瓦卢瓦法国包含百年战争、查理七世后的恢复、文艺复兴君主制与宗教战争。它是受压力推动而中央化的王国，不是静态矩形的法国。" },
    france_bour: { en: "Bourbon France runs from Henry IV to the revolutionary rupture of 1792. Versailles absolutism, Richelieu's state-building, colonial rivalry, and fiscal crisis belong to this owner before the republican block begins.", cn: "波旁法国从亨利四世延续到1792年的革命断裂。凡尔赛绝对主义、黎塞留式国家建设、殖民竞争与财政危机都属于共和国图块出现前的这一主人。" },
    hre_germany: { en: "The German lane of the Holy Roman Empire represents an imperial framework of duchies, bishoprics, free cities, and electorates after East Francia. It should read as layered authority, not as a centralized modern Germany.", cn: "神圣罗马帝国的德意志栏表示东法兰克之后由公国、主教领、自由城市和选侯构成的帝国框架。它应被理解为层级权威，而不是中央集权的现代德国。" },
    poland_jagiellon: { en: "Poland-Lithuania grows from the 1385 Jagiellonian personal union into the 1569 Commonwealth. The lane abstracts a multiethnic elective monarchy from Baltic to Ruthenian and Lithuanian worlds, ending only when neighboring empires partition it.", cn: "波兰-立陶宛从1385年雅盖隆个人联合发展为1569年的联邦。该栏抽象表示从波罗的海到鲁塞尼亚、立陶宛世界的多民族选举君主国，直到被邻近帝国瓜分才终结。" },
    poland_partition_prussian: { en: "The Prussian and later German partition marks western Commonwealth lands annexed by Prussia and absorbed into German state-building. It is a foreign owner fragment beside the other partition zones, not sovereign Poland.", cn: "普鲁士/德意志分割区表示被普鲁士吞并并纳入德意志国家建设的原联邦西部土地。它是与其他分割区并列的外来主人片段，不是主权波兰。" },
    poland_partition_austrian: { en: "The Austrian partition marks Galicia and related Habsburg holdings after the Commonwealth was erased. It is a non-contiguous owner fragment in the simplified grid because Austria has no full lane here.", cn: "奥地利分割区表示联邦被抹去后加利西亚等哈布斯堡领地。由于这个简化网格没有完整奥地利栏，它被绘为非相邻主人片段。" },
    poland_partition_russian: { en: "The Russian partition marks the eastern and later Congress Poland sphere under imperial Russian dominance. Its right edge visually meets the Russia lane so Poland's loss is paired with a clear neighboring gain.", cn: "俄国分割区表示东部及后来的会议王国波兰处于俄罗斯帝国支配下。它的右缘与俄罗斯栏相接，使波兰失地对应明确的邻国所得。" },
    mongol_europe: { en: "Mongol Europe is modeled as Golden Horde suzerainty over Rus principalities after the sack of Kyiv, centered on tribute, investiture, and steppe power from Sarai. It is not drawn as mass Mongol settlement of all eastern Europe.", cn: "欧洲蒙古统治被建模为基辅陷落后金帐汗国对罗斯诸公国的宗主权，核心是来自萨莱的贡赋、册封与草原权力。它不是把整个东欧画成蒙古人大规模定居区。" },
    ottoman_balkans: { en: "Ottoman Balkans represents Rumelia and Balkan provinces after Ottoman expansion across southeastern Europe. It is the Balkan owner beside the Anatolian Ottoman core, with later independence movements splitting out from it.", cn: "奥斯曼巴尔干表示奥斯曼扩张进入东南欧后的鲁米利亚与巴尔干诸省。它是安纳托利亚奥斯曼核心旁的巴尔干主人，后来的独立运动从中分出。" },
    england_medieval: { en: "Medieval England was shaped by the Norman Conquest of 1066, which fused Anglo-Saxon, Danish and Norman cultures. Magna Carta (1215), common law, parliamentary government, and the English language itself emerged from this turbulent era.", cn: "中世纪英格兰由1066年的诺曼征服塑造，融合了盎格鲁-撒克逊、丹麦与诺曼文化。《大宪章》（1215）、普通法、议会制政府与英语本身均诞生于这一动荡时代。" },
    england_tudor: { en: "Tudor England begins with Henry VII's victory after the Wars of the Roses and ends with Elizabeth I. The block is an English kingdom centered on dynastic consolidation, the Reformation, naval expansion, and Renaissance court culture before the Stuart succession joined the English and Scottish crowns.", cn: "都铎英格兰始于亨利七世在玫瑰战争后取胜，止于伊丽莎白一世。该块表示以王朝整合、宗教改革、海军扩张和文艺复兴宫廷文化为核心的英格兰王国，早于斯图亚特继承把英格兰与苏格兰王冠连接起来。" },
    england_stuart: { en: "Stuart Britain marks the 1603 Union of the Crowns, civil-war rupture, Commonwealth interlude, Restoration, and Glorious Revolution before the 1707 parliamentary union. It is a composite British-crown phase, not yet the kingdom of Great Britain.", cn: "斯图亚特英国表示1603年王冠联合、内战断裂、共和国插曲、复辟与光荣革命，止于1707年议会联合。它是复合的英伦王冠阶段，尚不是大不列颠王国。" },
    great_britain: { en: "The Kingdom of Great Britain begins with the 1707 union of England and Scotland. It carries the Hanoverian and Georgian island state until the 1801 union with Ireland creates the United Kingdom.", cn: "大不列颠王国始于1707年英格兰与苏格兰联合。它承接汉诺威与乔治时代的岛屿国家，直到1801年与爱尔兰联合形成联合王国。" },
    united_kingdom: { en: "The United Kingdom of Great Britain and Ireland begins with the 1801 Act of Union and runs here until the 1922 Irish Free State split. Later British continuity is drawn as a narrower Great Britain core plus a detached Northern Ireland fragment.", cn: "大不列颠及爱尔兰联合王国始于1801年联合法案，并在此延续到1922年爱尔兰自由邦分出。后续英国连续性改画为较窄的大不列颠核心加上非连续的北爱尔兰片段。" },
    uk_great_britain_core: { en: "After 1922, the United Kingdom is no longer drawn as if all Ireland remained inside it. This block carries Great Britain and the Westminster state, while Northern Ireland is shown as a separate retained fragment and the Irish state owns the missing island share.", cn: "1922年之后，联合王国不再被画成仍拥有整个爱尔兰。该块承接大不列颠与威斯敏斯特国家，北爱尔兰作为保留片段单独显示，爱尔兰国家承接失去的岛屿份额。" },
    northern_ireland_uk: { en: "Northern Ireland is shown as a deliberately narrow, non-contiguous UK fragment after partition. It remains connected to the British state but is not merged into the Great Britain core block.", cn: "北爱尔兰在分治后被有意显示为很窄的非连续英国片段。它仍连接英国国家，但不被并入大不列颠核心块。" },
    irish_free_state: { en: "The Irish Free State marks the 26-county dominion created after the Anglo-Irish Treaty. It fills the part of the old United Kingdom that did not remain with Northern Ireland.", cn: "爱尔兰自由邦表示《英爱条约》后形成的26郡自治领。它承接旧联合王国中没有留在北爱尔兰的部分。" },
    ireland_republic: { en: "Ireland / the Republic continues the Irish state after the 1937 constitutional break and the later 1949 republic declaration. It is the named owner of the island share no longer held by the United Kingdom.", cn: "爱尔兰/共和国承接1937年宪法转折及1949年共和国宣布后的爱尔兰国家。它是英国不再拥有的岛屿份额的具名主人。" },
    spain: { en: "Early modern Spain built a global monarchy after the Reconquista and sponsored the conquest of the Aztec and Inca empires. The block now stops before the Peninsular War so occupation and resistance are not hidden inside one continuous rectangle.", cn: "近代早期西班牙在收复失地运动后建立全球君主国，并推动对阿兹特克和印加的征服。此处方块在半岛战争前结束，以免把占领与抵抗隐藏在一个连续矩形中。" },
    spain_peninsular: { en: "During the Peninsular War, Spain did not simply disappear into Napoleon's empire. This half-width fragment marks Spanish resistance, the Cadiz government, and Bourbon legitimacy alongside French occupation.", cn: "半岛战争期间，西班牙并非简单消失在拿破仑帝国中。这个半宽片段表示西班牙抵抗、加的斯政府与波旁合法性，与法军占领区并列。" },
    spain_restored: { en: "After Napoleon's defeat, Ferdinand VII was restored and Spain entered a turbulent modern era of monarchy, republic, dictatorship, and constitutional monarchy. The long block keeps the prior broad national continuity while separating the occupied years.", cn: "拿破仑失败后，斐迪南七世复辟，西班牙进入君主制、共和国、独裁与君主立宪交替的现代时期。这个长方块保留原先宽泛的国家连续性，同时把被占领年份分离出来。" },
    napoleon: { en: "The First French Empire is now drawn as the French imperial core, not as a single rectangle swallowing Britain and Spain. Napoleon's legal, metric, military, and administrative reforms spread through conquest and client states, but those zones are shown separately.", cn: "法兰西第一帝国现在绘为法国帝国核心，而不是吞没英国和西班牙的单一矩形。拿破仑的法律、度量衡、军事和行政改革经由征服与附庸国扩散，但这些区域在图中分开表示。" },
    napoleon_italy: { en: "Napoleonic Italy represents the client Kingdom of Italy and French imperial structures in northern and central Italy. Its right-edge notch is filled by the French imperial core to show a dependent satellite system rather than ownerless contraction.", cn: "拿破仑意大利表示意大利王国附庸体制及法国在意大利北部、中部的帝国结构。右侧缺口由法国帝国核心承接，表示附庸体系而非无主收缩。" },
    french_annexed_italy: { en: "French-annexed Italy separates the territories directly incorporated into the French imperial system, such as Liguria, Tuscany, Rome, and related Adriatic or Illyrian edges, from the client Kingdom of Italy. It closes the former thin blank strip without pretending all Italy was one kingdom.", cn: "法国并入意大利把利古里亚、托斯卡纳、罗马及相关亚得里亚/伊利里亚边缘这些直接并入法兰西帝国体系的地区，与附庸意大利王国分开。它填补旧的细白缝，但不假装全意大利都是一个王国。" },
    italian_restoration_transition: { en: "The Italian Restoration Transition covers the 1814-1815 collapse of the Napoleonic client kingdom before the Congress of Vienna settlement hardened the restored Italian states and Austrian Lombardy-Venetia. It is a short occupation and negotiation bridge, not an empty year.", cn: "意大利复辟过渡表示1814-1815年拿破仑附庸王国崩溃后、维也纳会议安排固定复辟意大利诸邦与奥地利伦巴第-威尼西亚之前的阶段。它是短暂占领与谈判桥段，不是一年空白。" },
    napoleon_rhine: { en: "The Confederation of the Rhine was a German client confederation under Napoleon's aegis from 1806 to 1813. Its left-edge notch is filled by the French imperial core, marking protector dominance without treating the whole confederation as annexed France.", cn: "莱茵邦联是1806至1813年处于拿破仑庇护下的德意志附庸邦联。左侧缺口由法国帝国核心承接，表示庇护支配，而不是把整个邦联画成被法国吞并。" },
    napoleon_iberia: { en: "This half-width fragment marks French occupation and Bonapartist Spain during the Peninsular War. It is intentionally placed beside Spanish resistance rather than over it, showing a contested occupation rather than total replacement.", cn: "这个半宽片段表示半岛战争中的法军占领与波拿巴派西班牙。它故意与西班牙抵抗区并列，而不是覆盖后者，以表示争夺中的占领而非完全替代。" },
    prussia_austria_german_powers: { en: "Prussia and Austria remain visible beside the Rhine Confederation because they were not members of Napoleon's German client union. The narrow strip marks the German great-power pole that later helped overturn French hegemony.", cn: "普鲁士与奥地利在莱茵邦联旁保持可见，因为它们并非拿破仑德意志附庸联盟成员。这个窄条标示后来推翻法国霸权的德意志大国轴心。" },
    german_liberation_wars: { en: "The German Liberation Wars bridge the collapse of the Rhine Confederation and the 1815 German Confederation. It represents Prussian, Austrian, and German-state coalition mobilization after Leipzig, not a restored Holy Roman Empire.", cn: "德意志解放战争连接莱茵邦联崩溃与1815年德意志邦联成立。它表示莱比锡战役后普鲁士、奥地利和德意志诸邦的联盟动员，而不是神圣罗马帝国复活。" },
    german_confed: { en: "The German Confederation is a loose post-Vienna framework of many German states, dominated by Austrian and Prussian rivalry. It now ends at the 1866 rupture instead of running all the way to imperial unification.", cn: "德意志邦联是维也纳会议后的松散多邦国框架，受奥地利与普鲁士竞争主导。它现在止于1866年的断裂，而不是直接延伸到帝国统一。" },
    north_german_confed: { en: "The North German Confederation marks the Prussian-led federal state north of the Main after the Austro-Prussian War. It carries most of the German lane toward the 1871 Empire while southern states remain separate.", cn: "北德意志邦联表示普奥战争后美因河以北、由普鲁士主导的联邦国家。它承接德国栏的大部分并走向1871年帝国，同时南德诸邦仍保持分离。" },
    south_german_states: { en: "The South German States block keeps Bavaria, Wurttemberg, Baden, and southern Hesse visible outside the North German Confederation before they joined the imperial settlement in 1871.", cn: "南德诸邦图块保留巴伐利亚、符腾堡、巴登和南黑森在1871年加入帝国安排前不属于北德意志邦联的状态。" },
    german_empire: { en: "The German Empire begins with Prussian-led unification in 1871 and ends with defeat and revolution in 1918. It is distinct from the earlier confederation and the later Weimar republic.", cn: "德意志帝国始于1871年普鲁士主导的统一，止于1918年战败与革命。它不同于更早的邦联，也不同于后来的魏玛共和国。" },
    weimar: { en: "The Weimar Republic carries Germany's post-imperial democratic experiment between World War I and the Nazi takeover. It prevents the German lane from jumping directly from empire to dictatorship.", cn: "魏玛共和国承接一战后、纳粹夺权前的德国民主实验。它避免德意志栏从帝国直接跳到独裁。" },
    russia_empire: { en: "The Russian Empire was the largest contiguous state in Europe, spanning eleven time zones. Peter the Great westernized its elite; Catherine expanded south; by 1900 it produced Tolstoy, Tchaikovsky, Mendeleev — before revolution swept it away in 1917.", cn: "俄罗斯帝国是欧洲最大的连续疆域国家，横跨11个时区。彼得大帝推行西化改革；叶卡捷琳娜南扩版图；至1900年孕育出托尔斯泰、柴可夫斯基、门捷列夫——1917年革命终结其命运。" },
    ussr: { en: "The Soviet Union was the first socialist state — industrial powerhouse, superpower, and Cold War antagonist of the United States. Collapsing in 1991, it left fifteen successor states and a geopolitical shockwave that still reverberates today.", cn: "苏联是首个社会主义国家——工业强国、超级大国、美国冷战对手。1991年解体，留下15个继承国及至今仍在回响的地缘政治冲击。" },
    // Middle East
    sumer: { en: "Sumer was the world's first urban civilization — inventing cuneiform writing, the wheel, the sailboat, and mathematics. Uruk, Eridu, and Ur were the first cities; Gilgamesh, legendary king of Uruk, is the oldest hero in world literature.", cn: "苏美尔是世界首个城市文明——发明楔形文字、车轮、帆船与数学。乌鲁克、埃里都、乌尔是人类最早的城市；乌鲁克传奇之王吉尔伽美什是世界文学中最古老的英雄。" },
    proto_elamite_susiana: { en: "Proto-Elamite Susiana keeps Susa and the Iranian Plateau visible before named Elamite dynasties. It marks writing, exchange, and settlement evidence rather than a modern-style state.", cn: "原始埃兰苏西亚纳让具名埃兰王朝之前的苏萨与伊朗高原保持可见。它表示文字、交换与聚落证据，而不是现代式国家。" },
    early_elam_awan: { en: "Early Elam / Awan represents the fragmentary Susa-Anshan and Awan horizon before Akkadian pressure. It fills the Iranian lane cautiously as an early Elamite world, not a precise bordered kingdom.", cn: "早期埃兰/阿万表示阿卡德压力出现前资料零散的苏萨-安善与阿万视野。它谨慎承接伊朗栏，作为早期埃兰世界，而非边界精确的王国。" },
    akkad: { en: "Sargon of Akkad welded the Sumerian city-states into history's first multi-ethnic empire. It is now drawn as a Mesopotamian core, with eastern pressure on Elam separated into a narrow fragment instead of a full Persian-lane rectangle.", cn: "阿卡德的萨尔贡将苏美尔城邦铸成史上首个多民族帝国。现在图中将其绘为美索不达米亚核心，把对埃兰的东向压力拆成窄片段，而非覆盖整个波斯栏。" },
    akkad_elam_pressure: { en: "Akkadian rulers campaigned east and brought parts of Elam into their orbit, but Elam was not simply identical with Akkad. This narrowed rectangular fragment marks domination pressure toward Susa/Anshan; the campaign meaning is carried by relationships and text, not by a land-bite cutout.", cn: "阿卡德诸王曾向东远征，并把部分埃兰纳入势力范围，但埃兰并不等同于阿卡德。这个窄矩形片段表示通向苏萨/安善的支配压力；战役含义由联系和文字承载，而不是画成土地切口。" },
    elam_akkad: { en: "Elam is kept visible as a rectangular lane beside Akkadian pressure because it was a southwestern Iranian civilization centered on Susa/Anshan, culturally tied to Mesopotamia but not just a Mesopotamian province.", cn: "埃兰以矩形栏保留在阿卡德压力旁，因为它是以苏萨/安善为中心的伊朗西南文明，与美索不达米亚联系紧密但并非单纯的美索不达米亚省份。" },
    gutian: { en: "The Gutian interlude marks the disrupted Mesopotamian owner after Akkadian collapse. It is a rough Zagros-linked domination phase remembered negatively in later Sumerian tradition, but the land is still occupied and politically contested rather than blank.", cn: "古提插曲表示阿卡德崩溃后美索不达米亚的混乱承接者。它是与扎格罗斯相关、在后世苏美尔传统中常被负面记忆的支配阶段，但土地仍被占据和争夺，并非空白。" },
    elam_gutian: { en: "Elam during the Gutian and Ur III transition keeps the Susa/Anshan side of the map owned while Mesopotamia changes hands. The adjacent lane shows a real neighboring civilization, not unused space left by Akkad's collapse.", cn: "古提至乌尔第三过渡期的埃兰让苏萨/安善一侧在美索不达米亚易主时仍有主人。相邻栏表示真实邻近文明，而不是阿卡德崩溃后留下的空地。" },
    ur_iii: { en: "Ur III, or the Neo-Sumerian kingdom, restored a southern Mesopotamian state after the Gutian interval. Ur-Nammu and Shulgi rebuilt administration around Ur, so this block is a restoration and consolidation rather than a timeless rectangle.", cn: "乌尔第三王朝又称新苏美尔王国，在古提插曲后恢复了南美索不达米亚国家。乌尔纳姆与舒尔吉围绕乌尔重建行政，因此这个块表示复兴与整合，而不是静态矩形。" },
    isin_larsa: { en: "The Isin-Larsa period is the city-dynasty world after Ur III fell: Isin, Larsa, Eshnunna, and Babylon competed for irrigation cities, trade routes, and royal legitimacy. It bridges Ur III and Old Babylon so the lane does not become ownerless between empires.", cn: "伊辛-拉尔萨时期是乌尔第三崩溃后的城邦王朝世界：伊辛、拉尔萨、埃什嫩纳和巴比伦争夺灌溉城市、贸易路线与王权合法性。它连接乌尔第三与古巴比伦，使帝国之间的栏位不变成无主空白。" },
    old_babylon: { en: "Old Babylon is now the Mesopotamian Babylonian core. Hammurabi's reach toward Elam is shown separately as a short campaign, so Elam is not hidden for the whole Old Babylonian period.", cn: "古巴比伦现在表示美索不达米亚的巴比伦核心。汉谟拉比对埃兰的伸展另以短期战役表示，因此埃兰不再在整个古巴比伦时期被遮住。" },
    old_babylon_elam_campaign: { en: "This short fragment represents Hammurabi's defeat of Elam and temporary military pressure into the Zagros/Susa sphere. It remains a whole half-lane beside Babylon and continuing eastern Elam; links carry the campaign relationship instead of an owner-filled cutout.", cn: "这个短片段表示汉谟拉比击败埃兰并短暂向扎格罗斯/苏萨范围施压。它作为完整半栏与巴比伦及东侧延续的埃兰并列；战役关系由联系线表达，而不是主人填补缺口。" },
    elam_old: { en: "Old Elam is drawn as the Susa/Anshan sphere before Hammurabi's coalition war. It stops at the conquest-pressure interval rather than being covered by Babylon.", cn: "古埃兰表示汉谟拉比联盟战争前的苏萨/安善范围。它在征服压力区间前结束，而不是被巴比伦覆盖。" },
    old_elam_east_continuity: { en: "Old Elam East keeps the Susa/Anshan side visible during Hammurabi's short western pressure. The campaign no longer makes eastern Elam look ownerless.", cn: "古埃兰东部延续让汉谟拉比短期西侧压力期间的苏萨/安善侧保持可见。战役不再让东部埃兰看起来无主。" },
    elam_old_reasserted: { en: "After Old Babylon weakened, Elam reasserted its independence and remained a distinct southwestern Iranian power into the Middle Elamite horizon.", cn: "古巴比伦衰弱后，埃兰重新取得独立，并作为独立的伊朗西南强权延续到中埃兰阶段。" },
    anatolia_early: { en: "Anatolian Cultures marks Neolithic, Chalcolithic, and Early Bronze Age communities before a named Hittite state appears. It is a cultural owner of the Anatolia lane, not a single kingdom, so places such as Catalhoyuk, Alaca Hoyuk, and early trade towns do not read as blank land.", cn: "安纳托利亚文化表示赫梯国家出现前的新石器、铜石并用与早期青铜时代社群。它是安纳托利亚栏的文化主人，不是单一王国，因此加泰土丘、阿拉贾霍裕克和早期贸易城镇不会被读成空地。" },
    hattians: { en: "The Hattians / Hatti-speaking central Anatolian world preserves the local predecessor horizon around Hattusa and Kanesh before Hittite kingship. The block is a cultural-polity bridge rather than an empty pre-Hittite placeholder.", cn: "哈梯人/哈梯语中安纳托利亚世界保留赫梯王权前哈图沙、卡尼什周边的本地前身视野。该块是文化-政治桥梁，而不是赫梯之前的空白占位。" },
    hittite_kingdom: { en: "The early Hittite kingdom grew from central Anatolia around Hattusa. It is drawn as an Anatolian core rather than a broad rectangle across Egypt, because its early power was not an Egyptian occupation.", cn: "早期赫梯王国以哈图沙为中心在安纳托利亚发展。这里将其绘为安纳托利亚核心，而不是横跨埃及的大矩形，因为其早期权力并不表示占领埃及。" },
    hittite_empire: { en: "The Hittite Empire became a major Late Bronze Age power under rulers such as Suppiluliuma I and Muwatalli II. Its Syrian sphere is separated from the Anatolian core so the chart does not imply that Hittites ruled Egypt.", cn: "赫梯帝国在苏庇路里乌玛一世、穆瓦塔里二世等统治者时期成为青铜时代晚期强权。图中把叙利亚势力区与安纳托利亚核心分开，避免暗示赫梯统治埃及。" },
    hittite_syria: { en: "Hittite Syria marks the northern Syrian vassal and frontier sphere around Kadesh and allied city-states. It stays whole beside Egyptian Levant because the Kadesh struggle was a frontier contest, not an Egyptian land cutout owned by Hatti.", cn: "赫梯叙利亚表示卡迭石及相关盟邦周边的北叙利亚附庸与边疆势力。它与埃及黎凡特并列且保持完整，因为卡迭石争夺是边疆竞争，而不是由赫梯承接的埃及土地缺口。" },
    kassites: { en: "Kassite Babylonia keeps the Mesopotamian lane owned after the Hittite sack of Babylon. It represents a long Middle Babylonian dynasty, Dur-Kurigalzu, kudurru boundary stones, and diplomacy or conflict with Assyria and Elam.", cn: "喀西特巴比伦让赫梯洗劫巴比伦后的美索不达米亚栏仍有主人。它表示漫长的中巴比伦王朝、杜尔-库里加尔祖、界碑，以及与亚述和埃兰的外交或冲突。" },
    elam_middle: { en: "Middle Elam is the Susa/Anshan power beside Kassite Babylonia. It includes royal building, Chogha Zanbil, and later Elamite pressure that helped end Kassite rule, so the Iranian lane is an active neighbor rather than background.", cn: "中埃兰是喀西特巴比伦旁侧的苏萨/安善强权。它包括王室建设、乔加赞比尔，以及后来促成喀西特统治终结的埃兰压力，因此伊朗栏是活跃邻国，而非背景空白。" },
    egypt_early: { en: "Egypt (Old-Middle) compresses Early Dynastic, Old Kingdom, First Intermediate, and Middle Kingdom Nile state-building into one readable owner lane. The block means pharaonic Nile continuity from Memphis to Thebes/Lisht, not uniform control of every neighboring desert or Levantine zone.", cn: "埃及（古-中王国）把早王朝、古王国、第一中间期和中王国的尼罗河国家形成压缩为一条可读主人栏。该块表示从孟菲斯到底比斯/利什特的法老埃及连续性，不表示均质控制所有邻近沙漠或黎凡特区域。" },
    canaanite: { en: "Canaanite keeps the Bronze Age southern Levant occupied by coastal, highland, and city-state networks before Egyptian hegemony. It is a multi-owner cultural and urban corridor between Egypt, Anatolia, and Mesopotamia, not a modern-style nation-state.", cn: "迦南让埃及霸权出现前的青铜时代南黎凡特由沿海、高地和城邦网络占据。它是连接埃及、安纳托利亚和美索不达米亚的多主人文化与城市走廊，而非现代民族国家。" },
    late_bronze_levant_city_states: { en: "Late Bronze Levant City-States is a short bridge between the older Canaanite lane and New Kingdom Egyptian hegemony. It keeps Byblos, Hazor, Megiddo, Ugarit-facing trade, and other local city networks visible during the transition instead of leaving the coast and highlands blank.", cn: "晚青铜黎凡特城邦是迦南旧栏与埃及新王国霸权之间的短桥。它让比布鲁斯、夏琐、米吉多、面向乌加里特的贸易及其他地方城市网络在转折期保持可见，而不是把海岸与高地留空。" },
    mitanni_syria: { en: "Mitanni / Hurrian Syria marks the northern Syrian and Upper Mesopotamian sphere before Hittite domination. It represents Mitanni influence, Hurrian elites, Ugarit-era diplomacy, and the Syria contest with Egypt and Hatti, not a southern Levant or Arabian owner.", cn: "米坦尼/胡里安叙利亚表示赫梯支配前的北叙利亚与上美索不达米亚势力范围。它代表米坦尼影响、胡里安精英、乌加里特时代外交，以及埃及与哈梯之间的叙利亚竞争，而不是南黎凡特或阿拉伯主人。" },
    arabia_prehistoric: { en: "Arabian Cultures fills the peninsula lane before the incense-route kingdoms. It represents oasis, pastoral, coastal, and early exchange networks across a simplified Arabia lane, so the desert is not visualized as ownerless.", cn: "阿拉伯文化填补乳香贸易诸王国出现前的半岛栏。它表示绿洲、牧业、沿海与早期交换网络在简化阿拉伯栏中的存在，因此沙漠不会被画成无主空间。" },
    levant_transition: { en: "The Levant collapse transition marks the messy interval after Egyptian dominance and the Late Bronze city-state order fractured, before Philistine, Israelite, Phoenician/Canaanite, and neighboring Iron Age polities fully crystallized. It stays whole because collapse and multi-owner emergence are not a land bite returned to Egypt or northern Syria.", cn: "黎凡特崩溃转型表示埃及霸权和青铜晚期城邦秩序瓦解后、非利士、以色列、腓尼基/迦南及相邻铁器时代政权完全成形前的混乱区间。它保持完整，因为崩溃和多主人兴起不是由埃及或北叙利亚承接的土地缺口。" },
    levant_iron: { en: "The Iron Age Southern Levant contains emerging Israelite, Philistine, Phoenician/Canaanite, and neighboring polities. It is narrowed so Syro-Hittite northern Syria can remain visible beside it.", cn: "南黎凡特铁器时代包括兴起中的以色列、非利士、腓尼基/迦南及邻近政权。它被窄化，以便北叙利亚的叙利亚-赫梯诸国并列可见。" },
    neo_hittite: { en: "Neo-Hittite Anatolia is a set of Luwian and post-Hittite city-kingdoms such as Carchemish, Melid, Tabal, and Que. The block is intentionally a regional mosaic after imperial collapse, later squeezed by Assyrian and Anatolian powers.", cn: "新赫梯安纳托利亚表示赫梯帝国崩溃后的卢维语和后赫梯城邦王国，如卡尔基米什、梅利德、塔巴尔和奎。这个块有意表示区域拼合体，后来被亚述与安纳托利亚诸势力挤压。" },
    neo_hittite_syria: { en: "Syro-Hittite city-kingdoms in northern Syria and southeast Anatolia survived after the Hittite imperial collapse until Assyrian expansion absorbed the region.", cn: "叙利亚-赫梯城邦王国在赫梯帝国崩溃后存续于北叙利亚和安纳托利亚东南，直到亚述扩张吞并该区域。" },
    egypt_3ip: { en: "Third Intermediate and Late Egypt compresses divided Tanis-Thebes rule, Libyan dynasties, Kushite intervention, and Saite recovery before Persian conquest. It is still an owned Nile lane, but no longer a single New Kingdom empire.", cn: "埃及第三中间期与后期压缩表示塔尼斯-底比斯分治、利比亚王朝、库施介入和赛斯复兴，直到波斯征服。它仍是有主人的尼罗河栏，但不再是单一的新王国帝国。" },
    babylon_dark: { en: "Post-Kassite Babylonia covers the Isin II and related Babylonian dynastic sequence after Elamite raids ended Kassite rule. The label no longer means a blank dark age: Babylonian kingship, Marduk cult memory, and Assyrian pressure continue in the lane.", cn: "后喀西特巴比伦表示埃兰袭击终结喀西特统治后的伊辛第二王朝及相关巴比伦王朝序列。这个标签不再表示空白黑暗时代：巴比伦王权、马尔杜克崇拜记忆与亚述压力仍在栏中延续。" },
    elam_neo: { en: "Neo-Elam keeps Susiana and the Elamite successor world visible before Assyrian devastation and the rise of Persis/Anshan. It is the owner of the Iranian lane during Babylonia's post-Kassite and Assyrian-pressure centuries.", cn: "新埃兰让苏西亚纳与埃兰继承世界在亚述破坏和波斯/安善兴起之前保持可见。它是后喀西特巴比伦和亚述压力时期伊朗栏的主人。" },
    assyria: { en: "The Neo-Assyrian Empire perfected brutal but effective imperial governance. Its Mesopotamian core is now narrowed beside Babylonia's vassal/revolt phases instead of hiding Babylon under one Assyrian rectangle.", cn: "新亚述帝国将残酷但高效的帝国治理推向极致。其美索不达米亚核心现在与巴比伦尼亚附庸/起义阶段并列窄化显示，而不是用一个亚述矩形隐藏巴比伦。" },
    assyria_levant: { en: "Assyrian Levant marks the western provincial and tributary field after Tiglath-pileser III's campaigns in Syria, Philistia, Damascus, and Israel. It is separated from the Mesopotamian core so the chart can show Assyrian rule reaching the Levant without hiding Babylonia's vassal and revolt lanes.", cn: "亚述黎凡特表示提格拉特帕拉沙尔三世在叙利亚、非利士、大马士革与以色列一带征服后形成的西部行省和朝贡场。它与美索不达米亚核心分开，使图表能显示亚述抵达黎凡特，同时不遮住巴比伦尼亚的附庸与起义栏。" },
    babylon_assyrian_vassal: { en: "Babylonia under Assyrian domination remained a southern Mesopotamian problem zone with its own political memory, not simply empty space beneath the Assyrian core.", cn: "亚述支配下的巴比伦尼亚仍是具有自身政治记忆的南美索不达米亚问题区，而不是亚述核心下的空白。" },
    neo_babylon_revolt: { en: "Nabopolassar's Babylonian revolt began in 626 BCE while Assyria still survived. The half-lane fragment shows the revolt beside the Assyrian remnant until Nineveh/Harran fell.", cn: "那波帕拉萨尔的巴比伦起义始于前626年，当时亚述仍存续。这个半栏片段让起义与亚述残余并列，直到尼尼微/哈兰陷落。" },
    neo_babylon: { en: "The Neo-Babylonian Empire under Nebuchadnezzar II rebuilt Babylon into a dazzling imperial city. It now begins as the post-Assyrian Mesopotamian empire, while the earlier revolt and Levant expansion are shown separately.", cn: "新巴比伦帝国在尼布甲尼撒二世治下将巴比伦重建为辉煌帝都。现在它从亚述崩溃后的美索不达米亚帝国阶段开始，早期起义和黎凡特扩张另行显示。" },
    neo_babylon_levant: { en: "Neo-Babylonian Levant carries the Syria-Palestine lane after Assyria's collapse and the Babylonian victory at Carchemish. It highlights Nebuchadnezzar II's western campaigns, Judah's fall, and the Babylonian Captivity before Cyrus and the Achaemenids took Babylon in 539 BCE.", cn: "新巴比伦黎凡特承接亚述崩溃和迦基米什战役后叙利亚-巴勒斯坦栏。它强调尼布甲尼撒二世的西方战役、犹大灭亡与巴比伦之囚，直到居鲁士与阿契美尼德在前539年夺取巴比伦。" },
    persis_anshan: { en: "Persis / Anshan marks the southwestern Iranian predecessor zone from which Cyrus and the Achaemenid Persian core emerged beside reduced Late Elam/Susiana.", cn: "波斯/安善表示居鲁士与阿契美尼德波斯核心兴起的伊朗西南前身区域，与收缩的晚期埃兰/苏西亚纳并列。" },
    elam_susiana: { en: "Late Elam / Susiana preserves Elamite continuity after Assyrian devastation while showing that central authority had shrunk before the Achaemenid takeover.", cn: "晚期埃兰/苏西亚纳保留亚述破坏后的埃兰延续，同时显示阿契美尼德接管前中央权威已明显收缩。" },
    arabia_ancient: { en: "Arabian Kingdoms marks the rise of South Arabian and incense-route polities such as Saba, Qataban, Hadramawt, and related oasis systems. It owns the Arabia lane through trade and regional kingdoms rather than pretending one peninsula-wide state existed.", cn: "阿拉伯诸国表示萨巴、卡塔班、哈德拉毛等南阿拉伯及乳香路线政权和相关绿洲体系的兴起。它以贸易和区域王国占据阿拉伯栏，而不是假装存在一个覆盖全半岛的国家。" },
    nabataean_early: { en: "Early Arabian / Nabataean routes mark the north Arabian and caravan-trade transition before the mature Petra kingdom. The lane links South Arabian incense networks with the Levant and Egypt instead of leaving a gap before Nabataea.", cn: "早期阿拉伯/纳巴泰路线表示成熟佩特拉王国之前的北阿拉伯和商队贸易转型。该栏把南阿拉伯乳香网络与黎凡特、埃及连接起来，而不是在纳巴泰之前留下空缺。" },
    nabataean: { en: "The Nabataean kingdom centered on Petra and Hegra turned caravan trade, water engineering, and desert routes into a durable political system. It ends with Roman annexation in 106, but that annexation covers the northwest province, not the whole peninsula.", cn: "以佩特拉和黑格拉为中心的纳巴泰王国把商队贸易、水利工程和沙漠路线组织成稳定政治体系。它在106年被罗马并吞，但该并吞对应西北行省，而不是整个半岛。" },
    arabia_roman: { en: "Roman Arabia now means Arabia Petraea, the former Nabataean northwest province after 106. It is deliberately half-width because Rome did not own all Arabia; the other half remains a visible independent Arabian lane.", cn: "罗马阿拉伯现在指106年后由原纳巴泰西北地区形成的阿拉伯佩特拉行省。它刻意保持半宽，因为罗马没有拥有整个阿拉伯；另一半由独立阿拉伯栏继续可见。" },
    arabia_independent_late: { en: "Independent Arabia carries the peninsula's southern, interior, oasis, and pastoral worlds beside Roman Arabia Petraea. This non-Roman half-lane is the owner of the simplified gap: Himyarite/South Arabian, Najran, oasis, and tribal politics continued outside the Roman province.", cn: "阿拉伯独立诸势力承接与罗马阿拉伯佩特拉并存的南部、内陆、绿洲和牧业世界。这个非罗马半栏就是简化缺口的主人：希木叶尔/南阿拉伯、奈季兰、绿洲和部族政治仍在罗马行省之外延续。" },
    arabia_late: { en: "Late Antique Arabia summarizes Himyarite, Ghassanid, Lakhmid, oasis, holy-city, and tribal networks before Islam. It is a confederated cultural-political lane, not a single state, but it keeps Arabia inhabited and connected before the Rashidun base appears.", cn: "晚期阿拉伯概括伊斯兰兴起前的希木叶尔、加萨尼、拉赫姆、绿洲、圣城与部族网络。它是联邦式文化-政治栏，不是单一国家，但能让正统哈里发基础区出现前的阿拉伯保持有人、有联系。" },
    sasanian: { en: "The Sasanian Empire was late antiquity's other superpower, rivalling Rome and Byzantium for four centuries. Zoroastrianism became state religion; chess, polo, and royal protocol spread westward; its fall to Arab armies (651) reshaped Eurasia.", cn: "萨珊帝国是古典晚期的另一超级大国，与罗马/拜占庭对峙四百年。琐罗亚斯德教定为国教；国际象棋、马球与宫廷礼仪西传；公元651年亡于阿拉伯，重塑欧亚。" },
    umayyad: { en: "Umayyad Damascus is now the Syrian-Levantine core of the caliphate, not a catch-all block for every province. Egypt, Iraq, Persia/Khorasan, Arabia, North Africa, Iberia, and Central Asia appear as separate fragments or regional lanes.", cn: "倭马亚大马士革现在表示哈里发的叙利亚-黎凡特核心，而不是包下所有行省的大块。埃及、伊拉克、波斯/呼罗珊、阿拉伯、北非、伊比利亚和中亚以独立片段或区域栏显示。" },
    umayyad_iraq: { en: "Umayyad Iraq marks the Kufa/Basra and Mesopotamian provincial lane inherited from the Rashidun conquests, separated from Damascus and running beside Persia/Khorasan as a same-caliphate administrative lane.", cn: "倭马亚伊拉克表示继承正统哈里发征服成果的库法/巴士拉和美索不达米亚行省栏；它与大马士革分开，并与波斯/呼罗珊作为同一哈里发内的并列行政栏显示。" },
    umayyad_persia: { en: "Umayyad Persia/Khorasan shows the eastern Iranian and Khorasan administration that supplied frontier campaigns toward Central Asia and Sindh, not a reciprocal bite into Iraq.", cn: "倭马亚波斯/呼罗珊表示伊朗东部和呼罗珊行政区，并连接向中亚与信德推进的边疆战役；它不是切入伊拉克的相互缺口。" },
    umayyad_egypt: { en: "Umayyad Egypt is the Fustat/Nile province after the Rashidun conquest, kept separate from Syria and Arabia so the western caliphate no longer appears as one rectangle. It is paired to the Damascus core by relationship, not by cutout geometry.", cn: "倭马亚埃及表示正统哈里发征服后的福斯塔特/尼罗河行省，并与叙利亚和阿拉伯分开，使西部哈里发不再显示成一个矩形。它通过关系与大马士革核心成对，而不是通过缺口几何成对。" },
    umayyad_arabia: { en: "Umayyad Arabia preserves the Hejaz and Arabian holy-cities lane under caliphal authority, distinct from the Damascus core and Egypt. It stays whole; the Damascus connection is a political relationship, not an edge bite at the region boundary.", cn: "倭马亚阿拉伯保留哈里发权威下的汉志和阿拉伯圣城栏，区别于大马士革核心和埃及。它保持完整；与大马士革的连接是政治关系，不是区域边界上的缺口。" },
    umayyad_africa: { en: "Umayyad Ifriqiya/Maghreb represents the North African province after the fall of Carthage and the 705 provincial settlement, the launch zone for the 711 Iberian conquest. It stays whole because Christian Nubia was a separate middle-Nile lane, not the owner of a North African cutout.", cn: "倭马亚易弗里基叶/马格里布表示迦太基陷落和705年行省化后的北非，是711年征服伊比利亚的出发区域。它保持完整，因为基督教努比亚是独立的尼罗河中游栏，不是北非缺口的主人。" },
    fatimid: { en: "The Shia Fatimid Caliphate founded Cairo (969) and al-Azhar University — the world's longest continuously operating university. They controlled the Red Sea trade and nurtured a brilliant scholarly culture in medicine, astronomy and philosophy.", cn: "什叶派法蒂玛哈里发建立开罗（969年）与艾资哈尔大学——世界上持续运作时间最长的大学。他们掌控红海贸易，在医学、天文学、哲学上孕育出辉煌的学术文化。" },
    safavid: { en: "The Safavid Empire made Twelver Shia Islam Iran's state religion — an identity that endures today. Shah Abbas I's Isfahan was nicknamed 'Half the World'; Persian miniature painting, carpet-weaving, and architecture reached their peak.", cn: "萨法维帝国将十二伊玛目什叶派立为伊朗国教——这一身份延续至今。阿拔斯大帝的伊斯法罕被誉为'半个世界'；波斯细密画、地毯织造与建筑艺术达到顶峰。" },
    ottoman_peak: { en: "At its zenith under Suleiman the Magnificent, the Ottoman Empire stretched from Vienna to Yemen, Algiers to Baghdad. Istanbul's skyline was defined by Sinan's mosques. The millet system allowed religious communities extraordinary autonomy for centuries.", cn: "奥斯曼帝国在苏莱曼大帝治下达到鼎盛，版图从维也纳到也门、从阿尔及尔到巴格达。伊斯坦布尔天际线由锡南的清真寺定义。米利特制度使宗教社群数个世纪以来享有非凡自治权。" },
    sasanian_mesopotamia: { en: "Sasanian Mesopotamia is separated from the Iranian core because Iraq fell into the early Islamic conquest before the last Sasanian ruler died in 651. The fragment stays whole beside the Iranian core; their shared empire is carried by a political link rather than a cut edge.", cn: "萨珊美索不达米亚与伊朗核心分开，因为伊拉克在末代萨珊君主651年死亡前已进入早期伊斯兰征服进程。这个片段在伊朗核心旁保持完整；二者同属帝国体系由政治联系表达，而不是切边表达。" },
    sasanian: { en: "The Sasanian Persian core survived the first Rashidun advances into Iraq. It is now drawn beside, not underneath, Rashidun Iraq until the eastern conquest closes the Sasanian state in 651.", cn: "萨珊波斯核心在正统哈里发最初进入伊拉克后仍然存在。它现在与正统哈里发伊拉克并列显示，直到651年东部征服终结萨珊国家。" },
    byzantine: { en: "Byzantine Anatolia remains the imperial core after Syria, Palestine, and Egypt are split into their own conquest-era fragments. This avoids treating the Levant and Egypt as still uniformly Byzantine during Rashidun expansion.", cn: "拜占庭安纳托利亚表示叙利亚、巴勒斯坦和埃及被拆成征服期片段后的帝国核心。这样避免在正统哈里发扩张时仍把黎凡特和埃及当作均质拜占庭领土。" },
    byzantine_egypt: { en: "Byzantine Egypt is drawn only until the Arab conquest and surrender process around 641. It remains a whole Nile province lane paired to the Constantinople/Anatolian core by relationship, because Egypt's transition occurred on a different timetable.", cn: "拜占庭埃及只绘到641年前后的阿拉伯征服和投降过程。它作为完整尼罗河行省栏通过关系与君士坦丁堡/安纳托利亚核心成对，因为埃及的转变时间表不同。" },
    byzantine_levant: { en: "Byzantine Levant marks Syria and Palestine before Yarmouk and the Rashidun conquest. It stays whole beside the Byzantine core so the Levant transition is visible without a land-bite fill.", cn: "拜占庭黎凡特表示耶尔穆克和正统哈里发征服前的叙利亚、巴勒斯坦。它在拜占庭核心旁保持完整，使黎凡特转变可见，而不使用土地缺口填补。" },
    byzantine_anatolia: { en: "Byzantine Anatolia is the reduced imperial heartland after Syria, Egypt, and Iraq had moved into the early caliphate. Its defensive theme system and Taurus frontier kept Anatolia as a Byzantine owner until the Seljuk victory at Manzikert opened the next Anatolian phase.", cn: "拜占庭安纳托利亚表示叙利亚、埃及和伊拉克进入早期哈里发体系后收缩出的帝国腹地。其军区制与托罗斯边疆使安纳托利亚继续作为拜占庭主人存在，直到塞尔柱在曼齐刻尔特取胜打开下一阶段。" },
    rashidun_early: { en: "Rashidun Arabia is the Medina/Arabian base of the caliphate. The conquest fronts are now separate fragments in Iraq, the Levant, Egypt, and Persia rather than one instant all-region rectangle.", cn: "正统哈里发阿拉伯表示麦地那/阿拉伯基础区。各征服前线现在拆为伊拉克、黎凡特、埃及、波斯片段，而不是一个瞬间覆盖全区的大矩形。" },
    rashidun: { en: "Rashidun Iraq represents the Mesopotamian conquest after Qadisiyyah and Ctesiphon. It sits beside Sasanian Persia before 651, then beside Rashidun Persia as a parallel same-caliphate lane.", cn: "正统哈里发伊拉克表示卡迪西亚和泰西封之后的美索不达米亚征服。651年前它与萨珊波斯并列，651年后与正统哈里发波斯作为同一哈里发的并列栏显示。" },
    rashidun_levant: { en: "Rashidun Levant represents Syria-Palestine after Yarmouk. Its split from Egypt and Persia makes the staggered conquest sequence visible while links, not cutout fills, pair it to the Medina caliphal base.", cn: "正统哈里发黎凡特表示耶尔穆克战役后的叙利亚-巴勒斯坦。它与埃及、波斯拆开后，可以看出征服的分阶段顺序；它与麦地那哈里发基础的关系由联系线表达，而不是缺口填补。" },
    rashidun_egypt: { en: "Rashidun Egypt begins after the Byzantine Egyptian phase, showing that Egypt's conquest followed the Syrian and Iraqi campaigns rather than happening simultaneously. It remains a whole Nile lane rather than a bite into Anatolia or the Levant.", cn: "正统哈里发埃及接续拜占庭埃及阶段，显示埃及征服晚于叙利亚和伊拉克战役，而非同时发生。它保留为完整尼罗河栏，而不是切入安纳托利亚或黎凡特的缺口。" },
    rashidun_persia: { en: "Rashidun Persia begins only after the Sasanian collapse. It prevents the timeline from backfilling a decade-plus eastern war as immediate full control, while staying a parallel caliphal lane beside Iraq.", cn: "正统哈里发波斯只在萨珊崩溃后开始，避免把十多年东方战争回填成即时全面控制，同时作为伊拉克旁边的并列哈里发栏显示。" },
    abbasid: { en: "Abbasid Baghdad is the Iraq core of the early caliphate. The chart now separates Khorasan and Persia so later Tahirid autonomy is visible.", cn: "阿拔斯巴格达是早期哈里发在伊拉克的核心。图中现在拆出呼罗珊和波斯，使后来的塔希尔自治可见。" },
    abbasid_persia: { en: "Abbasid Persia marks direct eastern administration before the Tahirid Khorasan governorship became durable. It stays as a whole Iranian/Khorasan lane paired to Baghdad by relationship, ending before the Tahirid fragment starts.", cn: "阿拔斯波斯表示塔希尔呼罗珊总督区稳定形成前的东方直接行政阶段。它作为完整伊朗/呼罗珊栏通过关系与巴格达成对，并在塔希尔片段开始前结束。" },
    tahirid: { en: "The Tahirids were Abbasid-recognized governors in Khorasan who became a durable regional dynasty. They are kept as a whole Khorasan lane, with caliphal suzerainty shown by relationships rather than carved geometry.", cn: "塔希尔王朝是受阿拔斯承认的呼罗珊总督，逐渐成为稳定地方王朝。图中保留完整呼罗珊栏，并用联系表示哈里发宗主权，而不是用切割几何表达。" },
    saffarid: { en: "The Saffarids rose from Sistan under Ya'qub ibn Layth and displaced Tahirid authority in eastern Iran. The block is now a whole Sistan-Khorasan lane; Abbasid acknowledgement and Baghdad's caliphal core are carried by relationship text, not by a Baghdad-owned cutout.", cn: "萨法尔王朝由雅古布·伊本·莱斯从锡斯坦兴起，并取代塔希尔在伊朗东部的权威。该块现在保持为完整的锡斯坦-呼罗珊栏；阿拔斯承认与巴格达哈里发核心由关系文字表达，而不是画成巴格达拥有的缺口。" },
    samanid_iran: { en: "The Samanids ruled a Persianate Bukhara-centered state in Transoxiana and Khorasan. They are drawn as a whole eastern Iranian successor to the Saffarids; Abbasid roots and caliphal recognition remain relationship semantics beside Baghdad, not a left-edge land bite.", cn: "萨曼王朝统治以布哈拉为中心、覆盖河中与呼罗珊的波斯化国家。图中它作为萨法尔之后的完整伊朗东方继承栏显示；其阿拔斯渊源与哈里发承认保留为巴格达旁的关系语义，而不是左侧土地缺口。" },
    ghaznavid_iran: { en: "The Ghaznavids grew from Ghazna into Khorasan and northern India. This Middle Eastern fragment marks their Iranian-Khorasan phase before the Seljuks won the Battle of Dandanqan in 1040.", cn: "伽色尼王朝从加兹尼扩张到呼罗珊和北印度。中东栏中的这个片段表示其伊朗-呼罗珊阶段，止于1040年塞尔柱赢得怛旦那干战役。" },
    seljuk_persia: { en: "The Great Seljuk Empire controlled Iran and Mesopotamia while projecting power into Syria and Anatolia. The chart keeps Seljuk Persia distinct from Rum so the Anatolian branch does not flatten the Iranian core into one rectangle.", cn: "大塞尔柱帝国控制伊朗和美索不达米亚，并向叙利亚和安纳托利亚投射权力。图中把塞尔柱波斯与罗姆分开，避免安纳托利亚分支把伊朗核心压成一个矩形。" },
    seljuk_rum: { en: "The Sultanate of Rum was the Anatolian Seljuk successor after Manzikert. It occupies the Anatolia lane beside Persian Seljuk and later Ottoman phases rather than being hidden inside the same block.", cn: "罗姆苏丹国是曼齐刻尔特之后的安纳托利亚塞尔柱继承政权。它占据安纳托利亚栏，与塞尔柱波斯和后来的奥斯曼并列，而不是藏在同一个图块里。" },
    khwarazmian: { en: "The Khwarazmian Empire replaced the last Seljuk power in Iran before colliding with the Mongols. Its short block is intentionally explicit because the 1220 Mongol shock should have a named owner to conquer.", cn: "花剌子模帝国取代伊朗最后的塞尔柱权力，随后与蒙古相撞。这个短块被明确保留，因为1220年的蒙古冲击需要一个具名的被征服主人。" },
    post_ilkhan_persia: { en: "Post-Ilkhanid Persia compresses the Muzaffarid, Injuid, Chobanid, Sarbadar, Kartid, and other regional powers that filled Iran after the Ilkhanate collapsed. It corrects the old false impression that Timurid rule began immediately in 1335.", cn: "后伊利汗波斯压缩表示伊利汗国崩溃后填补伊朗空间的穆扎法尔、因朱、楚邦、萨尔巴达尔、卡尔提等地方势力。它修正了旧图中仿佛帖木儿统治在1335年立即开始的误导。" },
    jalairid: { en: "The Jalayirids succeeded the Ilkhanid order in Iraq and Azerbaijan from a Baghdad-Tabriz axis. They fill the western owner strip beside post-Ilkhanid and Timurid Persia.", cn: "札剌亦儿王朝从巴格达-大不里士轴线继承伊利汗之后的伊拉克与阿塞拜疆秩序。它填入后伊利汗与帖木儿波斯旁的西部主人窄带。" },
    timurid_persia: { en: "Timurid Persia begins with Timur's conquest of Herat in 1383, not with the Ilkhanid collapse. Its left-edge cut is filled by Jalayirid and Aq Qoyunlu owners to show that western Iraq/Azerbaijan remained a separate contested field.", cn: "帖木儿波斯从1383年帖木儿攻取赫拉特开始，而不是从伊利汗崩溃开始。其左侧缺口由札剌亦儿和白羊王朝承接，表示西部伊拉克/阿塞拜疆仍是独立争夺场。" },
    aq_qoyunlu: { en: "Aq Qoyunlu was a Turkmen confederation and short-lived empire in Iran, Iraq, eastern Anatolia, Armenia, and Azerbaijan under Uzun Hasan. In the grid it carries the western Turkmen owner lane before Safavid Iraq.", cn: "白羊王朝是土库曼联盟，并在乌尊·哈桑时期形成短暂帝国，涉及伊朗、伊拉克、东安纳托利亚、亚美尼亚和阿塞拜疆。图中它承接萨法维伊拉克之前的西部土库曼主人栏。" },
    safavid_iraq: { en: "Safavid Iraq marks the Safavid hold over Baghdad and Iraq before Suleiman's Ottoman capture of Baghdad in 1534. It is a separate same-empire west/Iraq lane paired to the Safavid Iranian core, not a cutout owner inside that core.", cn: "萨法维伊拉克表示1534年苏莱曼夺取巴格达前，萨法维对巴格达和伊拉克的控制。它是与萨法维伊朗核心并列的同帝国西部/伊拉克栏，而不是嵌在核心里的缺口主人。" },
    afsharid: { en: "Afsharid Iran is narrowed to Nader Shah's imperial phase and the immediate post-Nader struggle before Zand power stabilized the south and west. This avoids letting one long rectangle hide the 18th-century fragmentation.", cn: "阿夫沙尔伊朗被收窄为纳迪尔沙的帝国阶段及其死后的短期争夺，直到赞德势力稳定南部和西部。这样避免一个长矩形掩盖18世纪的分裂。" },
    afsharid_khorasan: { en: "Afsharid Khorasan preserves the northeastern remnant after Karim Khan Zand took most of Iran except Khorasan. Its right-side bite is filled by Zand Iran, making the contraction visible as another owner's gain.", cn: "阿夫沙尔呼罗珊保留卡里姆汗赞德控制除呼罗珊以外大部分伊朗后的东北残余。其右侧缺口由赞德伊朗填充，使收缩表现为另一主人的取得。" },
    zand: { en: "The Zand dynasty under Karim Khan ruled most of Iran except Khorasan from Shiraz and brought a respite after decades of war. It is drawn beside the Afsharid Khorasan remnant rather than left as a missing piece.", cn: "赞德王朝在卡里姆汗时期以设拉子为中心统治除呼罗珊以外的大部分伊朗，并在长期战争后带来喘息。它与阿夫沙尔呼罗珊残余并列显示，而不是作为缺失的一块。" },
    qajar_rise: { en: "Qajar Rise marks Agha Mohammad Khan's consolidation after the defeat of the last Zand claimant and before his 1796 coronation. It fills the two-year transition instead of leaving a tiny ownerless gap.", cn: "卡扎尔兴起表示阿迦·穆罕默德汗击败最后的赞德竞争者后、1796年加冕前的整合期。它填补两年转型，而不是留下细小无主空白。" },
    qajar: { en: "The Qajar dynasty unified Iran under Agha Mohammad Khan in 1796 and ruled from Tehran until 1925. The full-width block begins only after the Zand and Afsharid remnant phases have been explicitly resolved.", cn: "卡扎尔王朝在1796年由阿迦·穆罕默德汗统一伊朗，并以德黑兰为中心统治至1925年。全宽图块只在赞德与阿夫沙尔残余阶段被明确解决后开始。" },
    egypt_khedivate: { en: "Khedivate Egypt marks the autonomous Muhammad Ali dynasty under nominal Ottoman suzerainty after 1867. It ends when Britain declared a protectorate during World War I, so the later monarchy is no longer mislabeled as simply British Egypt.", cn: "赫迪夫埃及表示1867年后穆罕默德·阿里王朝在奥斯曼名义宗主权下的自治阶段。它止于一战期间英国宣布保护国，从而避免把后来的埃及王国简单标成英属埃及。" },
    ottoman_late: { en: "Late Ottoman Anatolia is the imperial core after the empire had already lost or separated many European, Egyptian, Levantine, and Arabian lanes. It explains the road from constitutional crisis and World War I defeat to the Turkish republic without reabsorbing every Arab province into one rectangle.", cn: "晚期奥斯曼安纳托利亚表示帝国在已经失去或分离许多欧洲、埃及、黎凡特和阿拉伯栏之后的核心。它解释从宪政危机与一战失败走向土耳其共和国的道路，而不是把所有阿拉伯省份重新塞进一个矩形。" },
    anatolian_national_movement: { en: "The Anatolian National Movement fills the post-armistice lane between the late Ottoman core and the republic. It represents occupied/contested Anatolia, the Ankara assembly, and the Turkish War of Independence rather than a stable late Ottoman rectangle or an early republic.", cn: "安纳托利亚民族运动填补晚期奥斯曼核心与共和国之间的停战后栏位。它表示被占领/争夺的安纳托利亚、安卡拉议会与土耳其独立战争，而不是稳定的晚期奥斯曼矩形或提前出现的共和国。" },
    egypt_british: { en: "British Protectorate Egypt covers 1914-1922, when Britain formally ended Ottoman suzerainty and made the sultanate a protectorate. The chart now separates this from the Kingdom of Egypt after 1922, where British influence remained strong but the constitutional label changed.", cn: "英属埃及保护国覆盖1914-1922年，当时英国正式终结奥斯曼宗主权并把苏丹国变为保护国。图中现在把它与1922年后的埃及王国分开；后者仍受英国强烈影响，但宪制身份已经改变。" },
    egypt_kingdom: { en: "The Kingdom of Egypt begins with the 1922 declaration of independence and King Fuad I. It remains visually between British protectorate rule and the 1952 Free Officers revolution instead of being hidden inside either block.", cn: "埃及王国始于1922年独立声明和福阿德一世称王。它在视觉上位于英国保护国统治与1952年自由军官革命之间，而不是被隐藏在任一图块里。" },
    iraq_british: { en: "British Mandate Iraq represents the post-Ottoman Mesopotamian mandate and the Hashemite monarchy under British supervision before League of Nations independence in 1932.", cn: "英属伊拉克托管表示奥斯曼之后的美索不达米亚托管地，以及1932年国际联盟承认独立前受英国监督的哈希姆君主国。" },
    iraq_kingdom: { en: "The Kingdom of Iraq separates the Hashemite monarchy from the later republic. It runs from League of Nations independence in 1932 to the 1958 revolution, with Baghdad kept as the state center.", cn: "伊拉克王国把哈希姆君主制与后来的共和国分开。它从1932年国际联盟承认独立延续到1958年革命，并以巴格达为国家中心。" },
    iraq_republic: { en: "The Republic of Iraq begins with the 1958 overthrow of the monarchy and covers the later military, Baathist, and republican state phases through AD 2000. This avoids calling the 1932-1958 kingdom a republic.", cn: "伊拉克共和国始于1958年推翻君主制，覆盖此后至公元2000年的军事、复兴党和共和国国家阶段。这样避免把1932-1958年的王国误称为共和国。" },
    turkey: { en: "The Republic of Turkey begins in 1923 after the Ottoman defeat and the Turkish War of Independence. Its Anatolian republic lane is deliberately separate from Arab mandate states, Egypt, Iraq, and Arabia.", cn: "土耳其共和国始于1923年，在奥斯曼战败和土耳其独立战争之后形成。其安纳托利亚共和国栏刻意与阿拉伯托管地、埃及、伊拉克和阿拉伯半岛分开。" },
    pahlavi: { en: "Pahlavi Iran follows the Qajar dynasty from 1925 to the 1979 revolution. Reza Shah and Mohammad Reza Shah pursued centralization, state modernization, and later the White Revolution, while opposition to autocracy and foreign influence grew.", cn: "巴列维伊朗承接1925年后的卡扎尔王朝，止于1979年革命。礼萨沙与穆罕默德·礼萨沙推动中央集权、国家现代化和后来的白色革命，同时反对专制与外国影响的力量不断增长。" },
    iran_islamic: { en: "Islamic Iran begins with the 1979 revolution that overthrew the Pahlavi monarchy and established an Islamic republic. It stays in the Iranian lane because the territorial state continues while the regime type changes sharply.", cn: "伊朗伊斯兰共和国始于1979年革命，该革命推翻巴列维君主制并建立伊斯兰共和国。它保留在伊朗栏中，因为领土国家延续，但政体发生剧烈变化。" },
    post_ottoman_syria: { en: "Post-Ottoman Syria fills the central Levant strip after Ottoman withdrawal and before French occupation in 1920. It represents the Damascus / OETA North / Faisal Arab-government transition, deliberately separate from British Palestine and Transjordan.", cn: "奥斯曼后叙利亚填补奥斯曼撤出后、1920年法国占领前的中部黎凡特窄栏。它表示大马士革、占领区北部与费萨尔阿拉伯政府的过渡阶段，并刻意与英属巴勒斯坦和外约旦分开。" },
    french_levant_mandate: { en: "French Mandate Syria-Lebanon fills the central Levant lane between Ottoman Syria and postwar Syrian/Lebanese independence. It keeps Syria and Lebanon visible beside British Palestine and Transjordan instead of leaving the simplified grid empty.", cn: "法属叙利亚-黎巴嫩托管填入奥斯曼叙利亚与战后叙利亚/黎巴嫩独立之间的中部黎凡特栏。它让叙利亚和黎巴嫩在英属巴勒斯坦与外约旦旁保持可见，而不是让简化网格空着。" },
    post_ottoman_transjordan: { en: "Post-Ottoman Transjordan marks the eastern Jordan valley and plateau after Ottoman withdrawal, through OETA / Arab Kingdom of Syria / local-government uncertainty. It is deliberately a transition field, not a mature mandate state.", cn: "奥斯曼后外约旦表示奥斯曼撤出后，约旦河以东河谷与高原经历占领区行政、阿拉伯叙利亚王国和地方政府不确定性的阶段。它有意作为转型场，而不是成熟托管国家。" },
    early_transjordan_emirate: { en: "Early Transjordan Emirate starts with Abdullah's 1921 Amman government before Britain's 1923 recognition. It shares the later mandate color so the border hides visually, but remains a separate hover/detail record for the state-building transition.", cn: "早期外约旦埃米尔国始于阿卜杜拉1921年在安曼建立政府，早于英国1923年承认。它与后续托管外约旦同色以隐藏视觉边界，但保留独立悬浮与详情记录，用来说明建国转型。" },
    syria_lebanon_independence: { en: "Syria and Lebanon Independence is a short bridge after French troops left in 1946 and before the chart's broader post-1948 Levant composite begins. The tiny block prevents a two-year ownerless gap.", cn: "叙利亚与黎巴嫩独立是1946年法军撤离后、图中更宽的1948年后黎凡特复合块开始前的短桥。这个极短图块避免出现两年无主空档。" },
    jordan_independence: { en: "Independent Transjordan / Jordan bridges the 1946 end of the mandate to the post-1948 Levant composite. It marks Hashemite sovereignty east of the Jordan rather than leaving a narrow blank strip.", cn: "独立外约旦/约旦连接1946年托管结束与1948年后黎凡特复合块。它标记约旦河以东的哈希姆主权，而不是留下窄小空白。" },
    levant_modern: { en: "Modern Levant States is a composite lane for the post-1948 state field of Israel/Palestine, Jordan, Syria, and Lebanon. It is intentionally a regional owner bundle, not a single country; the detail panel explains the abstraction.", cn: "现代黎凡特诸国是1948年后以色列/巴勒斯坦、约旦、叙利亚和黎巴嫩国家场的复合栏。它有意作为区域主人束，而不是单一国家；详情面板说明这种抽象。" },
    egypt_modern: { en: "Modern Egypt begins with the 1952 Free Officers revolution and the republic that followed. It succeeds the monarchy, not the British protectorate directly, and keeps the Nile state lane distinct from Levant and Arabian politics.", cn: "现代埃及始于1952年自由军官革命及随后共和国。它承接王国，而不是直接承接英国保护国，并使尼罗河国家栏与黎凡特和阿拉伯政治保持区分。" },
    abbasid_west: { en: "Abbasid Egypt-Levant shows western provinces without double-covering Arabia. Arabia remains a separate caliphal lane.", cn: "阿拔斯埃及-黎凡特显示西部省份，同时不重复覆盖阿拉伯；阿拉伯保留为单独哈里发栏。" },
    arabia_abbasid: { en: "Abbasid Arabia marks caliphal authority, pilgrimage, and Holy Cities patronage in the Hejaz and wider Arabian sphere. The lane is separate from Baghdad and Egypt-Levant so Arabia remains a visible owner, not a hidden province under a broad western rectangle.", cn: "阿拔斯阿拉伯表示汉志及更广阿拉伯范围内的哈里发权威、朝觐路线和圣城庇护。该栏与巴格达及埃及-黎凡特分开，使阿拉伯保持可见主人，而不是藏在宽大的西部矩形之下。" },
    arabia_fragmented: { en: "Fragmented Arabia covers the long post-Abbasid interval of Sharifian, Qarmatian, tribal, oasis, Yemeni, and interior Arabian powers before the Ottoman-Hejaz / Najd split. It is intentionally a regional field, not ownerless space between caliphate and Saudi/Ottoman labels.", cn: "分裂时期阿拉伯表示阿拔斯直接控制之后、奥斯曼汉志/内志分栏之前，谢里夫、卡尔马特、部族、绿洲、也门和内陆阿拉伯诸势力长期并存。它有意作为区域势力场，而不是哈里发与沙特/奥斯曼标签之间的无主空白。" },
    post_diriyah_najd: { en: "Post-Diriyah Najd fills the interregnum after Egyptian-Ottoman forces destroyed the First Saudi State in 1818 and before Turki bin Abdullah restored Saudi rule from Riyadh in 1824. It is a pressure-and-local-rule field beside Ottoman Hejaz, not a clean annexed province or a land-bite cutout.", cn: "德拉伊耶后纳季德填补1818年埃及-奥斯曼军队摧毁第一沙特国家后、图尔基·本·阿卜杜拉1824年从利雅得恢复沙特统治前的间隔。它是与奥斯曼汉志并列的压力与地方统治场，而不是简单并吞的行省或土地缺口。" },
    abbasid_core: { en: "Later Abbasid Baghdad is preserved as the caliphal seat while regional powers grow around it. Mongol and Ilkhanid Persia no longer cover Baghdad before 1258.", cn: "后期阿拔斯巴格达作为哈里发驻地保留，同时周边地方势力崛起。蒙古和伊利汗波斯不再在1258年前覆盖巴格达。" },
    tulunid: { en: "Tulunid Egypt-Levant marks Ahmad ibn Tulun's autonomous military regime in Egypt and Syria. It stayed nominally Abbasid but built an independent army, a new capital at al-Qata'i, and a Nile-centered power base before the Abbasid reconquest in 905.", cn: "图伦埃及-黎凡特表示艾哈迈德·伊本·图伦在埃及和叙利亚建立的自治军政体。它名义上仍属阿拔斯，却拥有独立军队、盖塔伊新都和尼罗河权力基础，直到905年阿拔斯重新征服。" },
    abbasid_egypt: { en: "Abbasid Restoration Egypt-Levant is the short direct-rule bridge after the Tulunids were defeated and before the Ikhshidid governorship became another autonomous military dynasty. It prevents 905-935 from being hidden inside a century-long generic rectangle.", cn: "阿拔斯复归埃及-黎凡特是图伦王朝被击败后、伊赫什德总督权力形成又一个自治军政王朝之前的短暂直接统治桥梁。它避免905-935年被藏在一个泛称的百年矩形里。" },
    ikhshidid_egypt_levant: { en: "Ikhshidid Egypt-Levant marks the Fergana-origin Turkish military dynasty that ruled Egypt and Syria under nominal Abbasid authority from 935 to 969. Kafur's regency and Fatimid pressure make this the real bridge between Abbasid restoration and Fatimid Cairo.", cn: "伊赫什德埃及-黎凡特表示935至969年在阿拔斯名义权威下统治埃及和叙利亚、源自费尔干纳的突厥军政王朝。卡富尔摄政与法蒂玛压力使它成为阿拔斯复归和法蒂玛开罗之间的真实桥梁。" },
    fatimid: { en: "Fatimid Egypt is the Cairo core of the Ismaili Shi'i caliphate. Its Levantine claims and contests are split out so Crusader and Ayyubid transitions remain legible.", cn: "法蒂玛埃及是伊斯玛仪派什叶哈里发的开罗核心。其黎凡特主张与争夺被拆出，使十字军和阿尤布转折保持清晰。" },
    fatimid_levant: { en: "Fatimid Levant marks the southern Syria and Palestine sphere before the First Crusade. It ends before the Crusader States fragment rather than being covered by it.", cn: "法蒂玛黎凡特表示第一次十字军东征前的南叙利亚和巴勒斯坦范围，并在十字军国家片段开始前结束，而不是被其遮盖。" },
    syria_muslim_polities: { en: "Muslim Syria marks the Seljuk, atabeg, and especially Zangid Syrian field that coexisted with the Crusader States. It stays as a whole inland half-lane beside Latin Jerusalem, Antioch, Tripoli, and Edessa; frontier pressure is carried by relationship links, not land-bite geometry.", cn: "穆斯林叙利亚表示与十字军国家并存的塞尔柱、阿塔贝格，尤其是赞吉系叙利亚势力场。它作为完整内陆半栏与拉丁耶路撒冷、安条克、的黎波里和埃德萨并列；边疆压力由关系线承载，而不是土地缺口几何。" },
    crusader_states: { en: "The Crusader States fragment marks the Latin Levant before Saladin's victory at Hattin. It is half-width beside Muslim Syria because Latin rule never meant all Syria became a single crusader province, but the adjacency is not drawn as a cutout.", cn: "十字军国家片段表示萨拉丁哈丁胜利前的拉丁黎凡特。它在穆斯林叙利亚旁保持半宽，因为拉丁统治并不意味着整个叙利亚成为单一十字军省份，但这种并列不再画成缺口。" },
    ayyubid: { en: "Ayyubid Egypt is Saladin's Egyptian base. The Syrian-Palestinian campaign zone is split into a second fragment beside surviving Crusader coastal holdings.", cn: "阿尤布埃及是萨拉丁的埃及基础。叙利亚-巴勒斯坦战役区另拆成片段，与仍存十字军沿海据点并列。" },
    ayyubid_levant: { en: "Ayyubid Levant shows the Muslim Syrian-Palestinian inland sphere after Hattin as a rectangular half-lane. The reduced Crusader coast remains beside it as a separate coastal record rather than a land-bite filler.", cn: "阿尤布黎凡特以矩形半栏显示哈丁战役后的穆斯林叙利亚-巴勒斯坦内陆范围。收缩后的十字军沿海在旁侧作为独立沿海记录保留，而不是土地切边的填补者。" },
    crusader_coast: { en: "The Crusader Coast represents reduced Latin coastal holdings after Hattin, ending with the Mamluk capture of Acre in 1291. Its inland neighbor shifts from Ayyubid to Mamluk Syria in 1260, carried by relationship links rather than land-bite geometry.", cn: "十字军沿海表示哈丁战役后收缩的拉丁沿海据点，至1291年马穆鲁克攻陷阿卡结束。其内陆邻居在1260年由阿尤布转为马穆鲁克叙利亚，这一变化由关系线承载，而不是土地缺口几何。" },
    mamluk: { en: "Mamluk Egypt is the Cairo core of the sultanate. Early Mamluk Syria is split beside the surviving Crusader coast, then the full Levant block appears after Acre.", cn: "马穆鲁克埃及是苏丹国的开罗核心。早期马穆鲁克叙利亚与仍存的十字军沿海并列，阿卡陷落后才显示完整黎凡特块。" },
    mamluk_syria_early: { en: "Early Mamluk Syria fills the inland Damascus/Syria half-lane after Ayn Jalut in 1260. It remains a whole rectangular lane beside the Crusader coast, so Acre, Tyre, and the remaining Latin strip stay visible until 1291 without becoming land-bite fillers.", cn: "早期马穆鲁克叙利亚填入1260年艾因贾鲁特之后的大马士革/叙利亚内陆半栏。它在十字军沿海旁保持完整矩形栏，使阿卡、提尔及残余拉丁沿海条带直到1291年仍清晰可见，但不变成土地切边的填补者。" },
    mamluk_levant: { en: "Mamluk Levant begins as a full rectangular block after Acre's fall in 1291, marking Syria-Palestine after the end of Crusader rule in the Middle East. Egypt remains a separate Mamluk core lane rather than a cutout inside the Levant record.", cn: "马穆鲁克黎凡特作为完整矩形块始于1291年阿卡陷落后，表示十字军在中东统治终结后的叙利亚-巴勒斯坦。埃及仍是单独的马穆鲁克核心栏，而不是黎凡特记录里的缺口。" },
    mongol_me: { en: "Mongol Persia marks the Iranian conquest pressure before Hulegu's Ilkhanate. Baghdad remains Abbasid until the 1258 sack.", cn: "蒙古波斯表示旭烈兀伊利汗国之前在伊朗方向的征服压力；巴格达直到1258年陷落前仍属阿拔斯。" },
    ilkhanate: { en: "Ilkhanate Persia is the Iranian core founded by Hulegu. Iraq is split out after Baghdad falls so the 1256 founding does not prematurely swallow Abbasid Baghdad.", cn: "伊利汗波斯是旭烈兀建立的伊朗核心。伊拉克在巴格达陷落后另行拆出，避免1256年建国就提前吞掉阿拔斯巴格达。" },
    ilkhanate_iraq: { en: "Ilkhanate Iraq begins with the sack of Baghdad in 1258, marking Mongol control of Mesopotamia after the Abbasid collapse. It stays as a whole Iraq lane paired to Ilkhanate Persia by relationship, not by land-bite geometry.", cn: "伊利汗伊拉克始于1258年巴格达陷落，表示阿拔斯崩溃后的蒙古美索不达米亚控制。它作为完整伊拉克栏通过关系与伊利汗波斯成对，而不是通过土地缺口几何成对。" },
    ottoman_peak: { en: "Ottoman Iraq begins with Suleiman's capture of Baghdad in 1534. The label is kept on the old ID, but the visual block now means the Iraq fragment, not all Ottoman lands.", cn: "奥斯曼伊拉克始于1534年苏莱曼夺取巴格达。此旧 ID 保留，但视觉图块现在表示伊拉克片段，而非全部奥斯曼领土。" },
    ottoman_west: { en: "The Ottoman western block is now the Anatolian / imperial core after Selim I, while Egypt, Syria-Palestine, the Hejaz, and Arabia are separate fragments. This avoids treating Ottoman suzerainty and direct provincial rule as one rectangle.", cn: "奥斯曼西部图块现在表示塞利姆一世之后的安纳托利亚/帝国核心；埃及、叙利亚-巴勒斯坦、汉志与阿拉伯另列片段。这样避免把奥斯曼宗主权和直接行省统治画成同一个矩形。" },
    ottoman_egypt: { en: "Ottoman Egypt marks the province after Selim I's 1517 conquest, before the French occupation and Muhammad Ali's autonomous viceroyalty reshaped the Nile lane. It is a whole province lane paired to the Ottoman core by relationship, not by an owner-filled notch.", cn: "奥斯曼埃及表示塞利姆一世1517年征服后的埃及行省，早于法国占领和穆罕默德·阿里自治副王统治重塑尼罗河栏。它是通过关系与奥斯曼核心成对的完整行省栏，而不是主人填补的缺口。" },
    french_egypt: { en: "French Egypt marks Napoleon's short 1798-1801 occupation. It is a brief invasion fragment, not a durable dynasty.", cn: "法国占领埃及表示拿破仑1798-1801年的短暂占领。它是短期入侵片段，而非稳定王朝。" },
    ottoman_egypt_restored: { en: "Restored Ottoman Egypt covers the short post-French transition before Muhammad Ali became Ottoman viceroy in 1805. It remains a whole Nile transition block linked to the Ottoman core instead of a cutout fill.", cn: "复归奥斯曼埃及表示法国撤离后、穆罕默德·阿里1805年成为奥斯曼副王前的短暂过渡。它保持为完整尼罗河过渡块，并通过联系连接奥斯曼核心，而不是缺口填补。" },
    muhammad_ali_egypt: { en: "Muhammad Ali's Egypt was nominally Ottoman but increasingly autonomous. It is paired to the Ottoman core by relationship while preserving Egypt as a whole Nile lane.", cn: "穆罕默德·阿里埃及名义上属奥斯曼，却日益自治。它通过关系与奥斯曼核心成对，同时保留为完整尼罗河栏。" },
    ottoman_levant_early: { en: "Early Ottoman Levant marks Syria and Palestine after the Mamluk defeat, before Egyptian forces occupied Syria in the 1830s.", cn: "早期奥斯曼黎凡特表示马穆鲁克战败后的叙利亚和巴勒斯坦，早于1830年代埃及军队占领叙利亚。" },
    egyptian_levant_occupation: { en: "Egyptian Levant marks Muhammad Ali and Ibrahim Pasha's occupation of Syria-Palestine from 1831 until the 1840 European intervention restored Ottoman control. It stays a whole occupation lane tied to Cairo by relationship, while Ottoman Hejaz remains a neighboring holy-cities lane.", cn: "埃及占领黎凡特表示1831年至1840年欧洲干预恢复奥斯曼控制前，穆罕默德·阿里和易卜拉欣帕夏占据叙利亚-巴勒斯坦。它保持为完整占领栏，并通过关系连接开罗；奥斯曼汉志仍是相邻圣城栏。" },
    ottoman_levant: { en: "Late Ottoman Levant resumes after the 1840 settlement and runs to the World War I collapse, separated from Egypt and the Arabia lane.", cn: "晚期奥斯曼黎凡特接续1840年解决方案，延续至一战崩溃，并与埃及和阿拉伯栏分开。" },
    ottoman_hejaz: { en: "Ottoman Hejaz shows overlordship over Mecca, Medina, Jeddah, and pilgrimage routes through the Sharifs of Mecca, not direct rule over all Arabia. It is drawn as a whole holy-cities half-lane beside Najd/interior Arabia, without land-bite geometry.", cn: "奥斯曼汉志表示通过麦加谢里夫对麦加、麦地那、吉达和朝觐路线的宗主权，而非直接统治整个阿拉伯。它作为完整圣城半栏与纳季德/阿拉伯内陆并列显示，不再画土地缺口。" },
    arabia_interior: { en: "Arabian Interior preserves Najd and local Arabian polities beside Ottoman Hejaz, making clear that the peninsula was not one directly ruled Ottoman province. Its adjacency is carried by relationships and detail text, not a cutout border.", cn: "阿拉伯内陆保留纳季德及地方阿拉伯政权，与奥斯曼汉志并列，说明半岛并非一个直接统治的奥斯曼省份。它的并列关系由关系线和详情文字表达，而不是缺口边界。" },
    first_saudi_state: { en: "The First Saudi State in Diriyah represents the Saudi-Wahhabi power that challenged Ottoman authority in Arabia until its destruction in 1818. It stays in the Najd half-lane beside, not carved into, Ottoman Hejaz.", cn: "第一沙特国家以德拉伊耶为核心，表示挑战奥斯曼阿拉伯权威的沙特-瓦哈比政权，直到1818年被摧毁。它保留在纳季德半栏，与奥斯曼汉志并列，而不是切进汉志图块。" },
    second_saudi_state: { en: "The Second Saudi State keeps Riyadh/Najd continuity visible between the Diriyah collapse and the Rashidi takeover. Nominal Ottoman suzerainty is shown through links and notes rather than land-bite geometry.", cn: "第二沙特国家保留德拉伊耶崩溃后到拉希德势力接管前的利雅得/纳季德连续性。名义奥斯曼宗主权通过关系线和注释说明，而不画成土地缺口。" },
    rashidi_arabia: { en: "Rashidi Arabia marks Jabal Shammar's brief dominance over Najd after the second Saudi collapse, before Ibn Saud's 1902 return. Its Ottoman alignment is a political relationship, not a carved ownership edge.", cn: "拉希德阿拉伯表示第二沙特国家崩溃后、伊本·沙特1902年回归前，沙马尔山对纳季德的短暂主导。它与奥斯曼的结盟是政治关系，不是切边所有权。" },
    saudi_unification: { en: "Saudi Unification is the Najd and interior half-lane of Ibn Saud's state-building, from the 1902 recovery of Riyadh toward the 1932 kingdom. The post-1925 Hejaz is shown beside it as a separate Saudi-controlled lane, with no land-bite cutout.", cn: "沙特统一是伊本·沙特建国过程中的纳季德与内陆半栏，从1902年夺回利雅得通向1932年王国；1925年后的汉志在旁边作为单独的沙特控制栏显示，不画土地缺口。" },
    saudi_hejaz_nejd: { en: "Saudi Hejaz-Nejd fills the holy-cities half-lane after Hashemite Hejaz fell in 1925 and before the 1932 Kingdom of Saudi Arabia. It hides the same-color border with Najd visually, but keeps Hejaz as its own hover and detail record.", cn: "沙特汉志-内志填补哈希姆汉志1925年覆灭后、1932年沙特阿拉伯王国成立前的圣城半栏。它与内志同色以隐藏视觉边界，但汉志仍保留自己的悬浮与详情记录。" },
    hashemite_hejaz: { en: "Hashemite Hejaz marks the Arab Revolt and Sharifian kingdom in the holy-cities lane after Ottoman authority broke in 1916. It remains a whole half-lane beside interior Arabia before Saudi conquest.", cn: "哈希姆汉志表示1916年奥斯曼权威崩解后，阿拉伯起义和谢里夫王国在圣城栏中的阶段。它在沙特征服前作为完整半栏与阿拉伯内陆并列。" },
    seljuk_rum_late: { en: "Late Seljuk Rum marks the final central-Anatolian remnant after the sultanate had fragmented under Mongol pressure. It is half-width beside Osman's beylik, not a full block covering the Ottoman origin zone.", cn: "晚期罗姆苏丹国表示蒙古压力下苏丹国分裂后的中安纳托利亚残余。它与奥斯曼贝伊国半宽并列，而不是完整覆盖奥斯曼起源地区。" },
    ottoman_early: { en: "The Ottoman Beylik is drawn as Osman's northwestern Anatolian principality during the last years of Seljuk Rum. This shows origin by coexistence and frontier expansion, not instant replacement.", cn: "奥斯曼贝伊国绘为罗姆苏丹国末年奥斯曼在安纳托利亚西北的诸侯国。这样显示的是并存和边疆扩张，而不是瞬间替代。" },
    ottoman_anatolia: { en: "Ottoman Anatolia expands after the Seljuk Rum phase ends and before Constantinople's capture. It bridges the small beylik and the later imperial Ottoman block.", cn: "奥斯曼安纳托利亚表示罗姆苏丹阶段结束后、君士坦丁堡陷落前的扩张，连接小贝伊国和后来的奥斯曼帝国图块。" },
    levant_mandate: { en: "The Palestine Mandate is narrowed to the western Levant half-lane. Transjordan, Hejaz, and Saudi Arabia are represented separately so the mandate does not visually occupy Arabia.", cn: "巴勒斯坦托管地窄化到西黎凡特半栏。外约旦、汉志和沙特阿拉伯单独显示，因此托管地不会视觉上占据阿拉伯。" },
    transjordan_mandate: { en: "Transjordan is a mandate-era fragment east of the Jordan, placed between Palestine and Arabia rather than covering the Hejaz or Saudi lane.", cn: "外约旦是约旦河以东的托管期片段，放在巴勒斯坦与阿拉伯之间，而不覆盖汉志或沙特栏。" },
    saudi_arabia: { en: "Saudi Arabia begins as an independent kingdom in 1932. It occupies the Arabia lane immediately, while mandate Transjordan remains a separate northern-neighbor fragment linked by a frontier relationship.", cn: "沙特阿拉伯自1932年作为独立王国开始，并立即占据阿拉伯栏；托管外约旦作为独立的北部邻近片段保留，并通过边疆关系连接。" },
    saudi_arabia_full: { en: "Saudi Arabia after Transjordan's mandate phase occupies the Arabia lane without being covered by the British mandate block.", cn: "外约旦托管阶段后，沙特阿拉伯占据阿拉伯栏，不再被英国托管图块覆盖。" },
    // South Asia
    early_harappan_indus: { en: "Early Harappan Core fills the Indus / Punjab-Sindh lane before the mature urban civilization. It represents the Regionalization Era: Ravi, Hakra, Amri, Kot Diji, Rehman Dheri, Kalibangan, and related village-to-town networks developing toward the 2600 BC integration horizon, not a fully formed empire projected backward.", cn: "早期哈拉帕核心填补成熟城市文明之前的印度河、旁遮普-信德栏。它表示区域化时代：Ravi、Hakra、Amri、Kot Diji、Rehman Dheri、Kalibangan 等村落到城镇网络逐步走向公元前2600年前后的整合，而不是把成熟帝国向前投射。" },
    early_harappan_fringe: { en: "Early Harappan Fringe marks the eastern, Rajasthan-Aravalli, Ghaggar-Hakra, and Gujarat-facing contact zone before the mature Harappan spread. Ganeshwar-Jodhpura copper, Kalibangan / Sothi-Siswal style horizons, and early Gujarat contacts make this an inhabited interaction lane beside Ganges-Yamuna and southern cultures.", cn: "早期哈拉帕边缘表示成熟哈拉帕扩展之前，面向东方、拉贾斯坦-阿拉瓦利、Ghaggar-Hakra 与古吉拉特的接触带。Ganeshwar-Jodhpura 铜业、Kalibangan / Sothi-Siswal 风格视野和早期古吉拉特联系，使这里成为恒河-亚穆纳与南方文化旁的有人互动栏。" },
    indus_valley: { en: "The mature Indus Valley Civilization is now drawn around its Harappan urban core in the Indus, Punjab, and Sindh zone. Planned cities such as Harappa and Mohenjo-daro, standardized weights, drainage, and an undeciphered script made it one of the Bronze Age's great urban systems.", cn: "成熟印度河文明现在绘在哈拉帕城市核心所在的印度河、旁遮普与信德区域。哈拉帕、摩亨佐-达罗等规划城市、标准度量衡、排水系统与未解文字，使其成为青铜时代重要城市文明之一。" },
    ganges_chalcolithic: { en: "Ganges-Yamuna cultures represent Neolithic and Chalcolithic communities east of the Harappan horizon. They occupy their own eastern cultural half-lane beside the Harappan fringe; contact is carried by relationship links rather than by cutout ownership.", cn: "恒河-亚穆纳文化表示哈拉帕视野以东的新石器至铜石并用时代社群。它们在哈拉帕边缘区旁占据自己的东方文化半栏；接触关系由联系线承载，而不是用缺口主人表示。" },
    south_prehistoric: { en: "Southern cultures mark the long pre-state Neolithic, ash-mound, megalithic, and regional settlement worlds of peninsular India. The lane is a cultural owner, not a kingdom, preserving southern continuity before Mauryan, Satavahana, Pallava, and Tamil polities.", cn: "南印度文化标示半岛印度长期的新石器、灰丘、巨石墓与区域聚落世界。它是文化主人而非王国，用来保留孔雀、百乘、帕拉瓦与泰米尔诸邦之前的南方连续性。" },
    pre_sangam_tamilakam: { en: "Pre-Sangam Tamilakam bridges the late Iron Age / megalithic and early historic Tamil country at the Mauryan frontier. It marks local chiefs, trade, writing, and emerging Chera-Chola-Pandya references as a cautious cultural-political owner, not a centralized kingdom or Mauryan province.", cn: "前桑伽姆泰米尔地承接孔雀边疆旁的晚期铁器/巨石墓与早期历史泰米尔南方。它表示地方首领、贸易、文字和逐渐可见的哲罗-朱罗-潘地亚线索，是谨慎的文化-政治主人，不是中央集权王国，也不是孔雀行省。" },
    bengal_early: { en: "Early Bengal keeps the Vanga/Banga and lower Ganges-delta horizon visible before clearer Mauryan and Gupta-era incorporation. The block avoids treating eastern India as an empty margin before imperial states reach it.", cn: "早期孟加拉保留文伽/邦伽与恒河下游三角洲在孔雀、笈多等帝国纳入前的视野。该块避免把东方印度在帝国到来前画成空白边缘。" },
    indus_fringe: { en: "The Harappan fringe marks eastern and southern site horizons toward the Yamuna and Gujarat. It stays a whole adjacent cultural lane; Ganges-Yamuna and southern contacts are shown by relationship links and notes, not by clipped ownership geometry.", cn: "哈拉帕边缘区标示通向亚穆纳河与古吉拉特的东南遗址带。它保持为完整相邻文化栏；与恒河-亚穆纳和南方文化的接触由联系线和说明表达，而不是画成土地缺口。" },
    late_harappan_nw: { en: "Late Harappan Northwest carries the post-urban Harappan successor horizon in Punjab, Sindh, and the Indus zone between the mature cities and the Vedic northwest. It is a regional archaeological owner, not a restored empire or an empty interval.", cn: "晚期哈拉帕西北承接成熟城市衰退后旁遮普、信德与印度河区域的后城市化继承视野，位于成熟哈拉帕与吠陀西北之间。它是区域考古主人，不是复兴帝国，也不是空白时段。" },
    late_harappan_fringe: { en: "Late Harappan Fringe marks eastern and Gujarat-facing successor cultures after the mature Harappan network fragmented. Regionalization and contraction are shown by succession and trade links while the fringe remains a whole cultural lane.", cn: "晚期哈拉帕边缘区标示成熟哈拉帕网络碎裂后通向东方与古吉拉特的继承文化。区域化与收缩由继承、贸易联系线表达，边缘区本身保持完整文化栏。" },
    lanka_prehistoric: { en: "Lankan Prehistory marks pre-Anuradhapura communities, long-distance island exchange, and early settlement continuity. It gives Sri Lanka an owner before the island becomes a named kingdom in the grid.", cn: "兰卡史前表示阿努拉德普勒之前的岛屿社群、远距离交流与早期聚落连续性。它让斯里兰卡在成为具名王国前也有清楚主人。" },
    vedic: { en: "The Vedic period is drawn as a northern Ganges-Yamuna / Aryavarta cultural zone rather than a single block across all India. It follows the eastern side of the Late Harappan and Ganges-Yamuna owner chain while the northwest Vedic sphere, Bengal, and the south remain visible separately.", cn: "吠陀时代被绘为恒河-亚穆纳河与雅利安地的北印度文化区，而不是覆盖全印度的方块。它接续晚期哈拉帕与恒河-亚穆纳主人链的东方侧，同时西北吠陀、孟加拉与南方保持独立可见。" },
    vedic_nw: { en: "Vedic Northwest preserves the older Sapta Sindhu / Punjab geography beside the later Ganges-Yamuna Vedic lane. This makes the eastward shift of Vedic settlement visible instead of merging all Vedic space into one rectangle.", cn: "吠陀西北保留较早的七河/旁遮普地理，并与较晚恒河-亚穆纳吠陀栏并列。这样能看出吠陀聚落向东转移，而不是把所有吠陀空间合成一个矩形。" },
    mahajanapadas: { en: "The Mahajanapadas were competing north Indian states, especially across the Ganges plain. Keeping the block narrow preserves the difference between Magadha/Kosala/Vatsa-type polities, Bengal, Gandhara, and southern cultures.", cn: "十六国是北印度诸国竞争的时代，尤其集中在恒河平原。窄化后能区分摩揭陀、拘萨罗、跋蹉等政体与孟加拉、犍陀罗和南方文化。" },
    gandhara: { en: "Gandhara is the northwestern crossroads around Taxila, Peshawar, Swat, and Kabul routes. It is kept separate from the Ganges states because Achaemenid, Macedonian, Mauryan, and Central Asian connections followed a different frontier rhythm.", cn: "犍陀罗是塔克西拉、白沙瓦、斯瓦特与喀布尔通道一带的西北十字路口。它与恒河诸国分开，因为阿契美尼德、马其顿、孔雀与中亚联系有不同的边疆节奏。" },
    bengal_mahaj: { en: "Bengal States keep Vanga/Banga and the lower Ganges delta visible during the Mahajanapada era. The early record is sparse, so the block is a cautious eastern owner that later feeds into Mauryan Bengal rather than a blank margin.", cn: "孟加拉诸国在十六国时代保留文伽/邦伽与恒河下游三角洲的可见性。早期资料稀疏，所以该块是谨慎的东方主人，之后进入孔雀孟加拉，而不是空白边缘。" },
    maurya: { en: "Under Ashoka the Great, the Maurya Empire unified a huge part of the subcontinent, but the chart now separates the Magadhan core, Bengal, northwest frontier, and Deccan reach so southern autonomy is not hidden beneath one rectangle.", cn: "孔雀帝国在阿育王治下统一次大陆大部分地区，但图中现在拆出摩揭陀核心、孟加拉、西北边疆和德干伸展，以免南方自主性被一个大矩形遮住。" },
    maurya_bengal: { en: "Mauryan Bengal represents the lower Ganges and eastern imperial zone, linked to the broader Mauryan state but not visually merged into the northern core.", cn: "孔雀孟加拉表示恒河下游与东方帝国区，它属于更大的孔雀国家，但不在视觉上并入北部核心。" },
    maurya_deccan: { en: "Mauryan Deccan is a narrowed reach into the plateau, stopping short of treating the Tamil south as direct Mauryan territory. It stays as a rectangular Deccan half-lane beside Tamilakam rather than cutting a land-bite edge into the south.", cn: "孔雀德干表示孔雀势力伸入高原的范围，但避免把泰米尔南方当作孔雀直接领土。它作为德干半栏与泰米尔地并列，而不是在南方切出土地缺口。" },
    deccan_post_maurya: { en: "Early Deccan states fill the interval between Mauryan retreat and Satavahana consolidation. The block is deliberately modest: it marks regional owners and trade routes without inventing a single unified Deccan empire or a land-bite into Tamilakam.", cn: "早期德干诸邦填补孔雀退却与百乘整合之间的阶段。该块刻意保持适度：它标示区域主人和贸易路线，而不虚构一个统一德干帝国，也不在泰米尔地切出土地缺口。" },
    shunga: { en: "Shunga marks the Magadha-centered successor after the Mauryan court collapsed in 185 BCE. It is kept in the northern core lane while Indo-Greek and Saka pressure is shown separately in the northwest.", cn: "巽伽表示前185年孔雀宫廷崩溃后以摩揭陀为中心的继承政权。它保留在北印度核心栏，而印度-希腊和塞人压力另在西北显示。" },
    kanva: { en: "Kanva is the brief Brahman successor to the Shungas in Magadha. The block keeps the Gangetic core owned before the compressed post-Kanva / Saka-Kushan transition, rather than letting the lane fall blank.", cn: "甘婆是巽伽之后在摩揭陀短暂存在的婆罗门继承王朝。该块在后甘婆/塞人-贵霜转型前承接恒河核心，避免栏位空白。" },
    indo_greek: { en: "The Indo-Greek block is the northwestern Hellenistic frontier around Afghanistan, Gandhara, Punjab, and Pakistan, not all India. Its late right-edge bite is filled by Indo-Scythian/Saka pressure, making the loss of territory visible as another owner's gain.", cn: "印度-希腊块表示阿富汗、犍陀罗、旁遮普和今巴基斯坦一带的西北希腊化边疆，而不是整个印度。晚期右缘缺口由印度-塞人/Saka 压力填充，使失地表现为另一主人的取得。" },
    indo_scythian: { en: "Indo-Scythian / Saka compresses northwestern and western Indian Saka power into the simplified northern lane after Kanva. It also fills the Indo-Greek and early Indo-Parthian notches as a non-contiguous pressure owner.", cn: "印度-塞人/Saka 把甘婆之后西北和西印度的塞人权力压缩进简化北方栏。它也作为非相邻压力主人填充印度-希腊与早期印度-帕提亚的缺口。" },
    indo_parthian: { en: "Indo-Parthian marks the Gondophernes-era Arachosia-Kabul-Gandhara field. The early edge still shows Saka pressure, then the northwest lane becomes a full Indo-Parthian owner before Kushan consolidation.", cn: "印度-帕提亚表示 Gondophernes 时代的阿拉霍西亚、喀布尔、犍陀罗场域。早期边缘仍显示塞人压力，随后西北栏在贵霜整合前成为完整的印度-帕提亚主人。" },
    sangam_early: { en: "The Sangam kingdoms mark the Tamil south and early Chera-Chola-Pandya world. They stay as a whole Tamilakam half-lane beside Mauryan, early Deccan, Satavahana, and post-Satavahana neighbors; adjacency, trade, and frontier contact are carried by relationship links rather than land-bite geometry.", cn: "桑伽姆诸国表示泰米尔南方及早期哲罗、朱罗、潘地亚世界。它作为完整泰米尔地半栏与孔雀、早期德干、百乘和后百乘邻居并列；相邻、贸易和边疆接触由关系线表达，而不是画成土地缺口。" },
    anuradhapura: { en: "Anuradhapura is Sri Lanka's long early historic kingdom and Buddhist capital zone. It stays in its own island lane because South Indian contact and invasions mattered, but did not make the island a mainland appendix.", cn: "阿努拉德普勒是斯里兰卡长期的早期历史王国和佛教首都区。它保留在独立岛屿栏中，因为南印度接触和入侵很重要，但并不意味着岛屿只是大陆附属。" },
    bengal_post_maurya: { en: "Post-Maurya Bengal keeps the lower Ganges delta visible after imperial contraction and before Gupta incorporation. It marks an eastern regional field rather than a gap between northern empires.", cn: "后孔雀孟加拉保留帝国收缩后、笈多纳入前的恒河下游三角洲。它表示东方区域场域，而不是北方帝国之间的空档。" },
    satavahana: { en: "Satavahana power is shown as a Deccan polity rather than a full southern-India cover. The narrowed rectangular half-lane leaves room for Tamil southern polities without implying that either side owns a missing bite of the other.", cn: "百乘王朝显示为德干政权，而非覆盖整个南印度的方块。窄化的矩形半栏为泰米尔南方诸邦留出空间，但不暗示双方互相拥有对方的缺口。" },
    post_satavahana_deccan: { en: "Post-Satavahana Deccan marks the short third-century successor field after Satavahana decline and before the early Pallava southern lane. Abhira, Andhra Ikshvaku, early Vakataka, Chutu, and local Deccan-Andhra powers make this an owned transition, not a blank pause or a cutout inside Tamilakam.", cn: "后百乘德干表示百乘衰落后、早期帕拉瓦南方栏之前的三世纪短暂继承场。阿毗罗、安得拉伊克什瓦库、早期伐迦陀迦、丘图及地方德干-安得拉势力共同承接这里，而不是空白暂停，也不是泰米尔地内部的切口。" },
    kushan: { en: "The Kushan Empire ruled a Silk Road crossroads linking Gandhara, Afghanistan, Central Asia, and northern India. The Indian and northwest fragments are separated so the Deccan and Bengal are not accidentally swallowed.", cn: "贵霜帝国控制连接犍陀罗、阿富汗、中亚与北印度的丝路枢纽。图中分开北印度与西北片段，避免误把德干和孟加拉吞入其中。" },
    kushan_nw: { en: "Kushan Northwest is the Gandhara-Bactria-Afghanistan side of Kushan power, paired with but not identical to the northern Indian fragment. This keeps Buddhist Gandharan art and Silk Road routes anchored in their frontier corridor.", cn: "贵霜西北是贵霜权力中的犍陀罗、巴克特里亚和阿富汗侧翼，与北印度片段相配但不相同。这样把佛教犍陀罗艺术与丝路路线锚定在边疆走廊。" },
    gupta: { en: "The Gupta Empire was India's Classical Age, but its core is now drawn around Magadha and the Ganges plain, with Bengal separated and Pallava south left visible.", cn: "笈多帝国是印度古典时代，但其核心现在绘在摩揭陀与恒河平原，孟加拉分列，南方帕拉瓦保持可见。" },
    gupta_bengal: { en: "Gupta Bengal marks the eastern reach of Gupta authority in the lower Ganges and Bengal region, separated from the Magadhan core.", cn: "笈多孟加拉标示笈多权威在恒河下游与孟加拉地区的东方范围，与摩揭陀核心分开。" },
    pallava_early: { en: "Early Pallava marks the first durable southern successor lane after the Satavahana-Sangam transition. It bridges Tamil and Deccan politics before the southern lane splits between Badami Chalukya and Kanchipuram Pallava owners.", cn: "早期帕拉瓦表示百乘-桑伽姆转折后南方较稳定的继承栏。它连接泰米尔与德干政治，之后南方栏拆分为巴达米遮娄其与建志补罗帕拉瓦两个主人。" },
    kidarite: { en: "Kidarite Gandhara is the late-antique northwest successor after Kushan power in the Kabul-Gandhara corridor. It is a frontier owner, not a blank pause before the Hephthalite and Shahi phases.", cn: "寄多罗犍陀罗表示贵霜之后喀布尔-犍陀罗走廊的晚古西北继承者。它是边疆主人，不是嚈哒和沙希阶段前的空白暂停。" },
    hephthalite_india: { en: "Hephthalite / Huna pressure in northwest India follows the Kidarite corridor and precedes the Shahi frontier. The simplified block marks a real late-antique disruption without swallowing the whole subcontinent.", cn: "嚈哒/匈那对西北印度的压力接续寄多罗走廊，并早于沙希边疆。这个简化块表示真实的晚古冲击，但不吞并整个次大陆。" },
    late_gupta: { en: "Late Guptas keep Magadha and the middle-Ganges post-Gupta owner visible between the classical Gupta core and Harsha. The north does not become ownerless after 550.", cn: "后笈多保留古典笈多核心之后、戒日之前摩揭陀与恒河中游的继承主人。550年后的北方并不是无主空档。" },
    bengal_post_gupta: { en: "Post-Gupta Bengal compresses Gauda, Vanga, and lower-Ganges regional powers before the Pala rise. It gives the eastern lane a named owner instead of treating Bengal as a vacant margin.", cn: "后笈多孟加拉压缩显示高达、文伽与恒河下游地方势力，早于波罗兴起。它让东方栏有具名主人，而不是把孟加拉当成空白边缘。" },
    chalukya_deccan: { en: "Badami Chalukya Deccan takes the western and central Deccan half-lane from the mid-6th century. The adjacent Pallava half-lane shows southern rivalry as interlocking owners rather than one oversized rectangle.", cn: "巴达米遮娄其德干自6世纪中叶占据西部与中部德干半栏。相邻帕拉瓦半栏把南方竞争显示为相互嵌合的主人，而不是一个过大的矩形。" },
    pallava: { en: "Kanchipuram Pallava is now the Tamil-southeastern half of the southern lane, paired with Chalukya and Rashtrakuta Deccan owners. Its temple, trade, and Ceylon-facing connections remain visible without erasing the plateau.", cn: "建志补罗帕拉瓦现在是南方栏的泰米尔-东南半栏，与遮娄其和罗湿陀罗拘陀德干主人并列。其寺庙、贸易与面向锡兰的联系仍可见，但不再抹去高原。" },
    rashtrakuta_deccan: { en: "Rashtrakuta Deccan replaces the Badami Chalukya side after the mid-8th century and presses toward both Kannauj and Kanchi. It fills the Deccan half-lane during the Pala-Pratihara-Chola world.", cn: "罗湿陀罗拘陀德干在8世纪中叶后取代巴达米遮娄其一侧，并向曲女城和建志补罗方向施压。它在波罗-瞿折罗-朱罗世界中填充德干半栏。" },
    shahi: { en: "The Shahi kingdoms hold the Kabul-Gandhara-Punjab frontier after Kushan and Hephthalite phases. Their lane explains why the northwest did not pass directly from ancient empires to Ghaznavid control.", cn: "沙希诸国占据贵霜和嚈哒之后的喀布尔、犍陀罗、旁遮普边疆。该栏解释西北并非从古代帝国直接跳到伽色尼统治。" },
    harsha: { en: "Harsha briefly reunifies much of northern India from the Thanesar-Kannauj axis after the Late Guptas. The block is short because the empire did not survive as a durable all-India state.", cn: "戒日在后笈多之后，以萨他泥湿伐罗-曲女城轴线短暂统一北印度大部。该块很短，因为这个帝国没有作为持久的全印度国家延续。" },
    post_harsha: { en: "Post-Harsha states mark the regional north Indian field between Harsha's death and the Pratihara-Pala-Rashtrakuta age. It is a named transition, not a blank gap.", cn: "后戒日诸国表示戒日去世后到瞿折罗-波罗-罗湿陀罗拘陀时代之间的北印度地方势力场。它是具名过渡，而不是空白缺口。" },
    pratiharas: { en: "The Gurjara-Pratihara block carries the northwestern and Kannauj-centered imperial contender during the tripartite struggle. It narrows the old 'North India' idea into a concrete owner beside Pala Bengal and Rashtrakuta Deccan.", cn: "瞿折罗-普腊蒂哈腊块表示三方争霸中以西北和曲女城为中心的帝国竞争者。它把旧式“北印度”概念收窄为具体主人，并与波罗孟加拉和罗湿陀罗拘陀德干并列。" },
    pala: { en: "The Pala Empire anchors Bengal and Bihar as a Buddhist imperial center from the 8th to 12th centuries. Keeping it in the eastern lane makes Bengal a major owner, not a side note to northwestern or southern powers.", cn: "波罗帝国把孟加拉和比哈尔锚定为8至12世纪的佛教帝国中心。将其保留在东方栏中，使孟加拉成为主要主人，而非西北或南方强权的附注。" },
    chola_rise: { en: "Rising Chola marks the Tamil half-lane after the Pallava decline but before the mature imperial Chola phase. Rashtrakuta Deccan remains beside it, so Chola expansion does not falsely occupy the whole south from day one.", cn: "兴起朱罗表示帕拉瓦衰落后、成熟朱罗帝国阶段前的泰米尔半栏。罗湿陀罗拘陀德干仍在旁侧，因此朱罗扩张不会从第一天就被误画成覆盖整个南方。" },
    western_chalukya: { en: "Western Chalukya / Kalyani carries the Deccan half-lane after Rashtrakuta collapse. Its long rivalry with the Cholas is shown as adjacent ownership instead of an invisible background to Chola maritime power.", cn: "西遮娄其/羯罗尼在罗湿陀罗拘陀崩溃后承接德干半栏。它与朱罗长期竞争，被显示为相邻主人，而不是朱罗海权背后的隐形背景。" },
    chola: { en: "Imperial Chola now occupies the Tamil-maritime half-lane beside Deccan powers. Rajaraja and Rajendra's Sri Lanka, Bay of Bengal, and Southeast Asian reach is shown without erasing Kalyani Chalukya and later Deccan successors.", cn: "朱罗帝国现在占据泰米尔-海上半栏，并与德干强权并列。罗阇罗阇与罗阇因陀罗通向斯里兰卡、孟加拉湾和东南亚的伸展得到显示，同时不抹去羯罗尼遮娄其和后来的德干继承者。" },
    chola_lanka: { en: "Chola Lanka marks the South Indian Chola occupation after the fall of Anuradhapura. It is a real island transfer in the grid, not an ownerless interruption between Anuradhapura and Polonnaruwa.", cn: "朱罗锡兰表示阿努拉德普勒陷落后南印度朱罗势力对岛屿的占领。它是网格中的真实岛屿转移，而不是阿努拉德普勒与波隆纳鲁沃之间的无主中断。" },
    deccan_successors: { en: "Deccan Successors compress Yadava, Hoysala, Kakatiya, and related plateau powers after Western Chalukya decline. It is a deliberate multi-owner label used to fill the simplified lane honestly before Delhi pressure arrives.", cn: "德干继承诸邦压缩显示西遮娄其衰落后的耶娑婆、曷萨拉、迦迦提耶等高原势力。它是有意设计的多主人标签，用来在德里压力到来前诚实填充简化栏位。" },
    ghaznavid_india: { en: "Ghaznavid India marks the Lahore-Punjab and northwest frontier sphere after the defeat of the Shahis. It is a concrete Indo-Afghan owner, not just a series of raids floating outside the grid.", cn: "伽色尼印度表示击败沙希后的拉合尔-旁遮普与西北边疆范围。它是具体的印阿主人，而不只是网格外漂浮的一系列劫掠。" },
    rajputs: { en: "Rajput states carry northwestern and Ganges-side regional power after Pratihara decline and before Delhi Sultanate consolidation. The label is plural by design: it names the owner field without inventing one unified kingdom.", cn: "拉杰普特诸邦承接瞿折罗衰落后、德里苏丹国整合前的西北与恒河侧地方权力。这个标签刻意用复数：它命名主人场，而不虚构一个统一王国。" },
    sena: { en: "Sena Bengal replaces the Pala eastern lane in the 12th century. The block makes Bengal's local Hindu dynasty visible before Ghurid-linked expansion and Delhi governorships enter the delta.", cn: "塞纳孟加拉在12世纪取代波罗东方栏。该块让古尔/德里势力进入三角洲前的孟加拉本地印度教王朝保持可见。" },
    ghurid: { en: "The Ghurid block is the short but decisive northwest bridge between Ghaznavid Lahore and the Delhi Sultanate. Its brevity reflects conquest momentum rather than an ownerless transition.", cn: "古尔块是伽色尼拉合尔与德里苏丹国之间短暂但关键的西北桥梁。它的短促表示征服动能，而不是无主过渡。" },
    polonnaruwa: { en: "Polonnaruwa restores a Lankan kingdom after Vijayabahu I expelled Chola forces. The capital remains in the island lane because the restored kingdom inherited the Chola administrative center and reshaped it into a Buddhist royal city.", cn: "波隆纳鲁沃表示维阇耶巴忽一世驱逐朱罗势力后恢复的兰卡王国。它继续位于岛屿栏中，因为复兴王权继承了朱罗行政中心，并将其重塑为佛教王城。" },
    lanka_transitional: { en: "Lankan Kingdoms compress the post-Polonnaruwa island into Dambadeniya, Yapahuwa, Gampola, Kotte, Jaffna, and early Kandyan successor worlds. It is a multi-owner island phase, not an empty gap before Europeans arrive.", cn: "兰卡诸国把波隆纳鲁沃之后的岛屿压缩为丹巴德尼耶、亚帕胡瓦、甘波拉、科特、贾夫纳与早期康提等继承世界。它是多主人岛屿阶段，而不是欧洲人到来前的空白。" },
    portuguese_lanka: { en: "Portuguese Ceylon is now a coastal / maritime block beside the Kandyan interior. The Portuguese held a large part of the island through forts, ports, cinnamon, and client politics, but the highlands were not blank and not simply Portuguese.", cn: "葡属锡兰现在是与康提内陆并列的沿海/海上图块。葡萄牙通过堡垒、港口、肉桂贸易和附庸政治控制岛屿重要部分，但高地既不是空白，也不应简单算作葡萄牙领土。" },
    kandyan_kingdom: { en: "The Kandyan Kingdom carries the central highlands and interior Lankan resistance beside Portuguese, Dutch, and early British coastal power. It is intentionally drawn as an adjacent owner block so colonial contraction and expansion have a visible counterpart.", cn: "康提王国承接中部高地与兰卡内陆抵抗，并与葡萄牙、荷兰和早期英国沿海权力并列。它被刻意画成相邻主人块，让殖民势力的伸缩有可见承接方。" },
    dutch_lanka: { en: "Dutch Ceylon represents VOC rule over coastal and maritime provinces after the Dutch displaced the Portuguese. The Kandyan block remains beside it because the VOC did not turn the whole island into a single Dutch rectangle.", cn: "荷属锡兰表示荷兰东印度公司取代葡萄牙后的沿海与海上省份。康提图块保留在旁边，因为荷兰公司并没有把整座岛变成一个单一荷兰矩形。" },
    british_lanka: { en: "British Coastal Ceylon begins with the 1796 takeover of Dutch possessions. It stays narrow until 1815 because the Kandyan kingdom still occupied the interior highlands.", cn: "英属沿海锡兰始于1796年英国接收荷兰属地。它在1815年前保持窄块，因为康提王国仍占据内陆高地。" },
    british_lanka_unified: { en: "Unified British Ceylon begins after the 1815 Kandyan Convention brought Kandy under the British crown. Only from this point does the island lane become a full-width British colonial block.", cn: "统一英属锡兰始于1815年《康提协定》将康提置于英国王冠之下。只有从这一点开始，岛屿栏才成为全宽的英国殖民图块。" },
    sri_lanka: { en: "Sri Lanka marks the independent island state after 1948, renamed from Ceylon and made a republic in 1972. It inherits the unified island lane after colonial rule rather than appearing from a blank space.", cn: "斯里兰卡表示1948年后的独立岛屿国家，原名锡兰，1972年成为共和国。它继承殖民统治后的统一岛屿栏，而不是从空白中出现。" },
    delhi_sultanate: { en: "The Delhi Sultanate is drawn as a northern Indo-Islamic core with separate Bengal, northwest, and Deccan fragments. This keeps Vijayanagara and southern polities from being falsely covered by one sultanate rectangle.", cn: "德里苏丹国绘为北印度伊斯兰核心，并拆出孟加拉、西北和德干片段。这样毗奢耶那伽罗和南方诸政权不会被一个苏丹国矩形错误覆盖。" },
    delhi_bengal: { en: "Delhi Bengal represents the sultanate-linked Bengal governorship phase before Bengal consolidated as an independent sultanate.", cn: "德里属孟加拉表示孟加拉在独立苏丹国巩固前，与德里苏丹国体系相连的总督阶段。" },
    delhi_nw: { en: "Delhi Northwest marks Punjab and the northwest frontier under the sultanate. It remains separate from Delhi's Ganges core because invasions, garrisons, and frontier politics followed a different rhythm.", cn: "德里西北标示苏丹国治下的旁遮普和西北边疆。它与德里恒河核心分开，因为入侵、驻防和边疆政治有不同节奏。" },
    delhi_deccan: { en: "Delhi Deccan marks the Khalji and early Tughluq reach into the plateau. It stays as a whole pressure lane beside Pandya and other southern powers; raids, tribute, and temporary control are carried by relationship links rather than a cutout.", cn: "德里德干标示卡尔吉与早期图格鲁克伸入高原的势力。它作为完整压力栏与潘地亚等南方势力并列；突袭、朝贡和短期控制由联系线表达，而不是由缺口表达。" },
    pandya: { en: "Pandya is kept as a Tamil southern kingdom beside Delhi's Deccan reach. The chart no longer cuts a Delhi-owned bite into the Pandya block; the southern crisis and later Vijayanagara transition are explained by links and detail text.", cn: "潘地亚作为泰米尔南方王国与德里德干片段并列。图中不再把德里拥有的缺口切入潘地亚块；南方危机与后续毗奢耶那伽罗转型由联系和详情解释。" },
    vijayanagara: { en: "Vijayanagara was the great southern Indian empire after 1336. It now stands clear of Delhi's northern block, matching its role as an independent Deccan-southern power.", cn: "毗奢耶那伽罗是1336年后南印度伟大帝国。现在它不再被德里北方方块压住，更符合其独立的德干-南方强权角色。" },
    bengal_sultanate: { en: "The Bengal Sultanate represents an independent deltaic power after the weakening of Delhi control, before Mughal incorporation in the late 16th century.", cn: "孟加拉苏丹国表示德里控制削弱后、16世纪后期并入莫卧儿之前的独立三角洲强权。" },
    mughal_peak: { en: "The Mughal imperial core after Akbar is now separated from Bengal and the Deccan. This keeps Akbar and Shah Jahan's northern empire visible without erasing Vijayanagara or the Deccan Sultanates.", cn: "阿克巴之后的莫卧儿帝国核心现在与孟加拉和德干分开。这样既显示阿克巴、沙贾汗时代的北方帝国，又不抹去毗奢耶那伽罗或德干苏丹国。" },
    mughal_bengal: { en: "Mughal Bengal marks the rich eastern province after Mughal conquest, important for revenue, riverine trade, and later Company expansion.", cn: "莫卧儿孟加拉表示征服后的富庶东方省份，对税收、河网贸易以及后来公司扩张都极为重要。" },
    bengal_nawabs: { en: "The Bengal Nawabs were semi-autonomous rulers before the East India Company's victory at Plassey shifted Bengal into colonial control.", cn: "孟加拉纳瓦卜是在东印度公司普拉西战役胜利前的半自治统治者，之后孟加拉转入殖民控制。" },
    mughal: { en: "The Mughal Empire combined Persian culture, Turko-Mongol statecraft, and Indian resources into one of history's wealthiest empires. The Taj Mahal, the Peacock Throne, Urdu language, and mughlai cuisine are all its legacies.", cn: "莫卧儿帝国融合波斯文化、突厥-蒙古治术与印度资源，缔造史上最富有的帝国之一。泰姬陵、孔雀宝座、乌尔都语与莫卧儿菜肴皆为其遗产。" },
    mughal_max: { en: "Aurangzeb's late Mughal core is now drawn separately from the Deccan, Bengal, and northwest frontier. The empire reached its greatest extent, but the same campaigns and administrative strain made the post-1707 break-up visible.", cn: "奥朗则布后期的莫卧儿核心现在与德干、孟加拉和西北边疆分开显示。帝国虽达最大范围，但这些战事和行政压力也让1707年后的碎裂更清楚。" },
    mughal_deccan: { en: "Mughal Deccan marks Aurangzeb's annexation of the Deccan sultanates and costly southern campaigns. It is a whole conquered/contested plateau fragment paired with the Mughal core by links, not an hourglass cut by Bengal or the northern core.", cn: "莫卧儿德干表示奥朗则布并入德干苏丹国及代价高昂的南方战事。它是完整的被征服/争夺高原片段，通过联系与莫卧儿核心成对，而不是被孟加拉或北方核心切成沙漏形。" },
    mughal_bengal_late: { en: "Late Mughal Bengal keeps the Bengal Subah visible between Aurangzeb's peak and the semi-autonomous nawab phase that consolidated around Murshidabad.", cn: "晚期莫卧儿孟加拉让孟加拉苏巴在奥朗则布极盛与穆尔希达巴德纳瓦卜半自治阶段之间保持可见。" },
    mughal_nw_max: { en: "The Mughal northwest fragment represents Punjab, Lahore, Kabul-route, and frontier authority during the empire's maximum phase, before Durrani pressure and regional fragmentation.", cn: "莫卧儿西北片段表示极盛期的旁遮普、拉合尔、喀布尔通道和边疆权威，早于杜兰尼压力与区域碎裂。" },
    mughal_nw: { en: "Mughal Northwest keeps Punjab, Lahore, Kabul routes, and frontier garrisons distinct from the Ganges imperial core. It is a non-core fragment, not unused space beside the empire.", cn: "莫卧儿西北把旁遮普、拉合尔、喀布尔通道和边疆驻防从恒河帝国核心中分开。它是非核心片段，而不是帝国旁边的空白。" },
    deccan_sultanates: { en: "The Deccan Sultanates represent Bijapur, Golconda, Ahmadnagar, and related plateau courts before Aurangzeb's annexations. The block is a multi-state owner of the Deccan, not a blank waiting for Mughal conquest.", cn: "德干苏丹国表示奥朗则布并吞前的比贾普尔、戈尔孔达、艾哈迈德讷格尔等高原宫廷。该块是德干的多国家主人，而不是等待莫卧儿征服的空白。" },
    mughal_decline: { en: "After Aurangzeb's death, the Mughal court remained symbolically central but lost practical control to Maratha expansion, Bengal autonomy, and northwest fracture. The right-edge bite is filled by Maratha power so contraction reads as transfer, not vacant land.", cn: "奥朗则布死后，莫卧儿宫廷仍有象征中心地位，但实际控制让位于马拉塔扩张、孟加拉自治与西北碎裂。右缘缺口由马拉塔承接，使收缩读作权力转移，而非无主土地。" },
    maratha: { en: "The Maratha Empire / confederacy rose from the Deccan and became the major post-Mughal claimant across much of India before defeat by the East India Company in 1818. Here it is the visible owner that takes over former Mughal political space.", cn: "马拉塔帝国/联盟自德干兴起，在1818年败于东印度公司前成为后莫卧儿印度最重要的竞争者之一。这里它作为接手原莫卧儿政治空间的可见主人。" },
    durrani_punjab: { en: "Durrani Punjab/Northwest marks Afghan pressure and rule in the Punjab-Kashmir-Sindh frontier after the Mughal northwest broke away. It bridges Nadir Shah's shock, Ahmad Shah Durrani, Panipat, and the later Sikh takeover.", cn: "杜兰尼旁遮普/西北表示莫卧儿西北断裂后，阿富汗势力在旁遮普、克什米尔、信德边疆的压力与统治。它连接纳迪尔沙冲击、艾哈迈德沙·杜兰尼、帕尼帕特以及后来的锡克接管。" },
    mughal_nw_late: { en: "Late Mughal Northwest is the short remaining Punjab frontier phase before Durrani authority replaces the Mughal claim. It prevents the northwest lane from going ownerless between 1707 and 1739.", cn: "晚期莫卧儿西北是杜兰尼权威取代莫卧儿主张前，旁遮普边疆短暂的残余阶段。它避免1707到1739年之间的西北栏变成无主空白。" },
    british_bengal: { en: "British Bengal begins after Plassey as Company power moves from trade privilege to territorial revenue and administration. It remains a separate Company territorial lane; the Diwani grant and Crown handoff carry its link to the nominal Mughal court.", cn: "英属孟加拉始于普拉西战役之后，公司权力从贸易特权转向领土税收和行政。它保持为独立的公司领土栏；与名义莫卧儿宫廷的关系由迪瓦尼授予和王冠交接联系表达。" },
    mughal_rump: { en: "The Mughal rump is a Delhi-centered titular monarchy under Maratha and then Company/British pressure. British Bengal remains a separate Company territorial lane; Plassey, the 1765 Diwani grant, and 1858 abolition are carried by links and notes rather than a Bengal-filled cutout.", cn: "莫卧儿残余是以德里为中心的名义君主制，先处在马拉塔、后处在公司/英国压力下。英属孟加拉保留为独立公司领土栏；普拉西、1765年迪瓦尼授予和1858年终结由联系与说明表达，而不是孟加拉填入莫卧儿缺边。" },
    sikh: { en: "The Sikh Empire under Ranjit Singh unified much of Punjab and the northwest after Durrani retreat. It is the named owner between Afghan power and British annexation, not a gap before the Raj.", cn: "兰季特·辛格治下的锡克帝国在杜兰尼退潮后统一旁遮普与西北大部。它是阿富汗势力与英国兼并之间的具名主人，而不是英属印度前的空档。" },
    british_south: { en: "Company India South marks East India Company supremacy in the Deccan and south after the Third Anglo-Maratha War. The Maratha block narrows into a named colonial successor rather than disappearing into blank space.", cn: "公司印度南方表示第三次英马战争后东印度公司在德干与南方的优势。马拉塔块收缩为具名殖民继承者，而不是消失成空白。" },
    british_nw: { en: "Company Punjab/Northwest follows the Sikh Wars and the 1849 annexation of Punjab. It is a short but important bridge from Sikh sovereignty to Crown-era Punjab/NW rule.", cn: "公司旁遮普/西北承接锡克战争和1849年旁遮普兼并。它是锡克主权通向王冠时期旁遮普/西北统治的短暂但关键桥段。" },
    british_raj: { en: "The British Raj core begins with Crown rule in 1858. It now shows direct British provincial administration separately from Bengal, Punjab/NW, southern provinces, and princely states under paramountcy.", cn: "英属印度核心始于1858年英国王冠直接统治。现在它把直接英属省份与孟加拉、旁遮普/西北、南方省份以及宗主权下的土邦分开显示。" },
    raj_south_provinces: { en: "Southern British India represents the Madras/Bombay and Deccan provincial sphere under direct colonial administration, placed beside rather than over the princely states.", cn: "南方英属印度表示马德拉斯、孟买及德干的直接殖民省份范围，与土邦并列而不是覆盖土邦。" },
    raj_princely_states: { en: "The princely states were nominally autonomous Indian-ruled states under British paramountcy. Their half-lane shows indirect rule rather than direct British provincial government.", cn: "印度土邦是在英国最高宗主权下名义自治、由印度君主统治的邦国。半栏显示间接统治，而非英属省份直接行政。" },
    raj_bengal: { en: "Raj Bengal keeps Bengal and the eastern provinces visible as a separate colonial lane, which makes the 1947 East Bengal / East Pakistan transition legible.", cn: "英属孟加拉把孟加拉和东方省份作为单独殖民栏保留，使1947年东孟加拉/东巴基斯坦转折更易读。" },
    raj_punjab_nw: { en: "Raj Punjab/NW marks the annexed Sikh/Punjab and northwest frontier sphere under British rule, leading visually into West Pakistan after partition.", cn: "英属旁遮普/西北表示英治下的锡克、旁遮普及西北边疆范围，并在视觉上衔接分治后的西巴基斯坦。" },
    india: { en: "Independent India inherits the central, southern, and many princely-state lanes after 1947. Its broad block is postcolonial consolidation, not a claim that all partitioned land stayed inside India.", cn: "独立印度在1947年后继承中央、南方以及许多土邦栏位。其较宽图块表示后殖民整合，而不是声称所有分治土地仍在印度内。" },
    pakistan: { en: "Pakistan begins as a non-contiguous state with western provinces and East Bengal/East Pakistan separated by India. The late left-edge bite is filled by Bangladesh to show the 1971 eastern-wing secession as a named owner transfer.", cn: "巴基斯坦成立时是由西部省份和东孟加拉/东巴基斯坦组成、被印度隔开的非连续国家。后段左缘缺口由孟加拉国承接，表示1971年东翼脱离是具名主人转移。" },
    east_pakistan: { en: "East Pakistan was Pakistan's eastern wing from 1947 to 1971, geographically separated from West Pakistan and centered on Bengal/Dhaka. It is a deliberate remote fragment, not a neighboring rectangle glued to West Pakistan.", cn: "东巴基斯坦是1947至1971年巴基斯坦的东翼，与西巴基斯坦地理上相隔，以孟加拉/达卡为中心。它是刻意显示的远隔片段，而不是贴在西巴基斯坦旁边的邻接矩形。" },
    bangladesh: { en: "Bangladesh succeeds East Pakistan after the 1971 Liberation War. It fills the former eastern wing so the Pakistan contraction is read as independence and transfer to a named republic.", cn: "孟加拉国在1971年解放战争后继承东巴基斯坦。它承接原东翼，使巴基斯坦收缩读作独立与转入具名共和国。" },
    // Central Asia
    bmac: { en: "BMAC / Oxus Civilization is treated as a Bronze Age oasis network around Margiana and Bactria, not a blanket steppe state. It stays as a whole oasis lane; northern pasture worlds remain adjacent records connected through steppe-oasis trade and cultural links, not owner-filled land bites.", cn: "中亚青铜文化/BMAC被处理为马尔吉亚纳与巴克特里亚一带的青铜时代绿洲网络，而不是覆盖草原的国家。它保持为完整绿洲栏；北方牧地世界作为相邻记录存在，通过草原-绿洲贸易和文化联系连接，而不是土地缺口主人。" },
    kazakh_bronze: { en: "Steppe Cultures names the northern Central Asian pastoral and metallurgical horizon before the Saka/Scythian lane. It is an adjacent inhabited cultural lane linked to BMAC by exchange, not a fill piece inside the oasis network.", cn: "草原文化表示塞人/斯基泰栏之前的北中亚牧业与冶金视野。它是与 BMAC 通过交换相连的相邻有人文化栏，不是绿洲网络内部的填充块。" },
    mountain_bronze: { en: "Mountain Cultures compress the Tien Shan, Pamir, Ferghana, and Zarafshan foothill exchange zone. The label follows sites such as Sarazm: pastoral mountain groups, farming valleys, metal routes, and oasis neighbors all meet here, so the block is deliberately cultural rather than royal.", cn: "山地文化压缩表示天山、帕米尔、费尔干纳与泽拉夫尚山麓交换带。这个标签参考萨拉兹姆等遗址：山地牧民、农耕谷地、金属路线和绿洲邻居在这里交汇，因此图块刻意是文化圈而非王国。" },
    afghan_prehistoric: { en: "Afghan Cultures is the Bronze Age and earlier Afghan highland / Helmand / Badakhshan owner layer before Achaemenid satrapal rule. It keeps Mundigak, Shortughai, lapis routes, and Oxus contacts visible without inventing a single ancient Afghan state.", cn: "阿富汗文化表示阿契美尼德总督统治前的青铜时代及更早阿富汗高地、赫尔曼德与巴达赫尚主人层。它让蒙迪加克、肖尔图盖、青金石路线和奥克苏斯联系保持可见，而不虚构一个古代阿富汗统一国家。" },
    sogdiana_early: { en: "Early Sogdiana marks the Zarafshan and Kashka-Darya oasis corridor before Achaemenid incorporation. It remains a whole oasis lane beside late Bronze Age and Saka/Scythian steppe neighbors; steppe-oasis contact is carried by relationship links and notes, not land-bite geometry.", cn: "早期粟特标示阿契美尼德并入前的泽拉夫尚与卡什卡达里亚绿洲走廊。它在晚期青铜草原与塞人/斯基泰草原栏旁保持完整；草原-绿洲接触由联系线和说明承载，而不是用缺边几何表达。" },
    scythians: { en: "Scythians/Saka marks the Iron Age steppe successor after the Bronze Age pastoral cultures. In this Central Asian lane it is the visible northern neighbor to Achaemenid and Greco-Bactrian oasis power; frontier contact is carried by links, not by filling a bite inside the oasis lane.", cn: "斯基泰/塞人表示青铜时代牧业文化之后的铁器时代草原继承者。在中亚栏中，它是阿契美尼德与希腊-巴克特里亚绿洲权力的可见北方邻居；边疆接触由联系线表达，而不是画成绿洲内部的一块填边。" },
    persian_ca: { en: "This Achaemenid northern fragment represents Sogdiana, Margiana, and Transoxiana-facing satrapal control. It stays as a whole oasis/frontier lane beside the Saka steppe, because Persian administration met nomadic frontiers rather than turning them into a neat land-bite boundary.", cn: "这个阿契美尼德北部片段表示粟特、马尔吉亚纳和面向河中的总督区控制。它作为完整绿洲/边疆栏与塞人草原并列，因为波斯行政面对的是游牧边疆，而不是形成可被整齐切出的土地缺口边界。" },
    persian_ca_south: { en: "This paired Achaemenid fragment represents Bactria, Arachosia, and the Hindu Kush / Afghan approaches as a whole satrapal lane. It is paired to the northern Achaemenid Sogdiana fragment by a political relationship, not carved into a Saka-filled land bite.", cn: "这个配对的阿契美尼德片段把巴克特里亚、阿拉霍西亚和兴都库什/阿富汗通道作为完整总督区栏显示。它通过政治联系与北部阿契美尼德粟特片段成对，而不是被切成由塞人填补的土地缺口。" },
    greco_bactria: { en: "Greco-Bactria is shown as a Hellenistic Bactrian-Oxus power after Alexander and the Seleucids. Saka and Yuezhi pressure is carried by links and notes, so the oasis lane stays whole instead of being carved into steppe-owned land bites.", cn: "希腊-巴克特里亚显示为亚历山大与塞琉古之后的希腊化巴克特里亚-奥克苏斯强权。塞人与月氏压力由联系线和说明承载，因此绿洲栏保持完整，而不是被画成草原主人填补的土地缺口。" },
    greco_bactria_south: { en: "The southern Greco-Bactrian / Indo-Greek projection follows the Hindu Kush and Kabul-Gandhara routes. It remains a whole paired route lane beside the Oxus core, so Afghanistan and northwestern India are not reduced to one rectangle.", cn: "南部希腊-巴克特里亚/印度-希腊投影沿兴都库什与喀布尔-犍陀罗通道展开。它作为完整的配对通道栏位于奥克苏斯核心旁，使阿富汗和西北印度不被压成一个矩形。" },
    kushan_ca: { en: "The northern Kushan fragment follows the Yuezhi takeover of Bactria and the Oxus route. Kangju remains visible as a neighboring Syr Darya polity through border and trade links, not as a cutout inside Kushan Bactria.", cn: "北部贵霜片段承接月氏进入巴克特里亚和奥克苏斯通道。康居通过边疆与贸易联系作为相邻锡尔河政权保持可见，而不是作为贵霜巴克特里亚内部的缺口。" },
    kushan_ca_south: { en: "The southern Kushan fragment represents Kabul, Gandhara, and the northwestern Indian route where Kanishka-era Buddhism and Gandharan art flourished. It is paired with the Bactrian fragment rather than merged across the steppe.", cn: "南部贵霜片段表示喀布尔、犍陀罗和西北印度通道，迦腻色伽时期的佛教和犍陀罗艺术在此繁荣。它与巴克特里亚片段配对，而不是横跨草原合并。" },
    kidarites: { en: "The northern Kidarite fragment marks post-Kushan Bactrian power in late antiquity. It stays separate from the steppe pressure lane because the Kidarite world was a frontier successor, not a clean full-steppe replacement.", cn: "北部寄多罗片段表示后贵霜时代晚古巴克特里亚权力。它与草原压力栏分开，因为寄多罗世界是边疆继承者，而不是整条草原的整齐替代。" },
    hephthalite_transoxiana: { en: "Hephthalite Transoxiana fills the Sogdiana-Margiana oasis lane after Kidarite power. It is a Hephthalite-linked northern/western owner layer beside the Bactria-Tokharistan core, not empty land between Kushan successors and the Arab conquest.", cn: "嚈哒河中填补寄多罗之后的粟特-马尔吉亚纳绿洲栏。它是与嚈哒相关的北部/西部主人层，与巴克特里亚-吐火罗斯坦核心并列，而不是贵霜继承者和阿拉伯征服之间的空地。" },
    sogdian_turkic_oases: { en: "Sogdian-Turkic Oases marks Samarkand, Bukhara, Panjikent, Chach, and neighboring city-principalities under Western Turkic, On Ok, Turgesh, and intermittent Tang suzerainty. The local Sogdian civic and mercantile layer stays visible instead of becoming a blank strip or an over-wide steppe khaganate.", cn: "粟特-突厥绿洲表示撒马尔罕、布哈拉、片治肯特、赭时及邻近城邦，在西突厥、十姓、突骑施以及间歇性唐宗主权下的格局。本地粟特城市和商贸层保持可见，而不是变成空条或被拉宽成草原汗国。" },
    arab_sogdian_contest: { en: "Arab-Sogdian Contest is the Qutayba-era conquest and resistance phase in Transoxiana. Bukhara, Samarkand, Khwarezm, local Sogdian elites, Turgesh allies, tribute, garrisons, and repeated rebellions make this a contested transition before the later caliphal provincial lane.", cn: "阿拉伯-粟特争夺表示屈底波时代河中征服与抵抗阶段。布哈拉、撒马尔罕、花剌子模、本地粟特贵族、突骑施盟友、贡赋、驻军和反复叛乱，使这里成为后续哈里发省区栏之前的争夺性过渡。" },
    kidarites_south: { en: "The southern Kidarite fragment follows Bactria, Kabul, and Gandhara routes. It stays whole beside the northern Kidarite and steppe fragments; late-antique pressure is shown through links and notes rather than reciprocal cut edges.", cn: "南部寄多罗片段沿巴克特里亚、喀布尔与犍陀罗通道展开。它在北部寄多罗和草原片段旁保持完整；晚古压力由联系线和说明表示，而不是相互切边。" },
    abbasid_ca: { en: "Abbasid Central Asia represents Transoxiana after the Abbasid revolution and before durable local dynasties took over. The Turkic steppe and Karluk-Turgesh frontier remain relationship neighbors, not cutout owners inside the Abbasid oasis lane.", cn: "阿拔斯中亚表示阿拔斯革命后、地方王朝稳定接管前的河中区域。突厥草原与葛逻禄-突骑施边疆作为关系邻居存在，而不是阿拔斯绿洲栏内部的缺口主人。" },
    qara_khanid: { en: "The Qara-Khanid block shows the Turkic Muslim takeover of Transoxiana after the Samanid collapse. Kimek/Kipchak steppe power stays as a neighboring frontier lane, not a filled land bite inside Qara-Khanid oasis rule.", cn: "喀喇汗图块显示萨曼瓦解后突厥穆斯林政权接管河中。基马克/钦察草原作为相邻边疆栏存在，而不是填入喀喇汗绿洲统治内部的土地缺口。" },
    qara_khanid_fergana: { en: "Qara-Khanid Fergana Edge carries the Fergana, western Tien Shan, and Semirechye-facing half-lane after the Samanid collapse. It fills the mountain corridor without widening the Kimek steppe or the Transoxiana core into the wrong geography.", cn: "喀喇汗费尔干纳边缘承接萨曼瓦解后的费尔干纳、西天山与面向七河的半栏。它填补山地通道，而不把基马克草原或河中核心错误拉宽到这里。" },
    ghaznavid_khorasan: { en: "Ghaznavid Khorasan shows the Balkh, Herat, Nishapur, and upper Oxus side of the former Samanid southern sphere before Dandanaqan. It is paired with the Ghazna core, but kept separate so Afghanistan and Khorasan do not collapse into one rectangle.", cn: "伽色尼呼罗珊显示怛旦那干之前，前萨曼南部范围中的巴尔赫、赫拉特、尼沙普尔与上奥克苏斯一侧。它与加兹尼核心成对，但保持分栏，避免把阿富汗与呼罗珊压成一个矩形。" },
    seljuk_ca: { en: "The northern Seljuk fragment marks Oghuz-Seljuk power around Merv, Khorasan, and Transoxiana-facing routes after 1040. The Kimek/Kipchak steppe remains a frontier neighbor carried by links and notes, not by a filled cutout.", cn: "北部塞尔柱片段表示1040年后围绕木鹿、呼罗珊和河中通道的乌古斯-塞尔柱权力。基马克/钦察草原作为边疆邻居由联系线和说明承载，而不是填入缺口。" },
    seljuk_ca_south: { en: "The southern Seljuk projection represents Khorasan, Herat, and the Afghan approaches before Ghurid and Khwarazmian successors split the area. It is deliberately non-contiguous in the grid and is paired to the northern Seljuk lane by relationship, not by steppe-owned cutouts.", cn: "南部塞尔柱投影表示古尔和花剌子模继承格局出现前的呼罗珊、赫拉特与阿富汗通道。在网格中它被刻意处理为不连续片段，并通过关系线与北部塞尔柱栏成对，而不是通过草原主人缺口成对。" },
    mongol_ca: { en: "The short Mongol Central Asia block marks the conquest shock of 1220-1227 across Khwarazmian territory. It is intentionally brief before the region separates into Chagatai, Golden Horde, and later Timurid pieces.", cn: "短促的蒙古中亚块表示1220-1227年征服花剌子模领土的冲击。它故意很短，随后区域分化为察合台、金帐与后来的帖木儿片段。" },
    golden_horde: { en: "The Golden Horde lane represents the Dasht-i Qipchaq / northern steppe successor world. It now runs beside Chagatai and Timurid oasis states as a neighboring Jochid steppe ulus, not as a cutout owner inside their Transoxiana cores.", cn: "金帐栏表示钦察草原/北方草原继承世界。它现在作为相邻的术赤草原兀鲁思与察合台、帖木儿绿洲国家并列，而不是它们河中核心内部的缺口主人。" },
    chagatai: { en: "The Chagatai northern fragment represents the Mongol successor ulus around Transoxiana-facing and Ili routes. Its Golden Horde relationship is a neighboring steppe frontier, so the block stays whole rather than showing a Jochid-owned bite.", cn: "北部察合台片段表示面向河中和伊犁通道的蒙古继承兀鲁思。它与金帐的关系是相邻草原边疆，因此图块保持完整，而不是显示成术赤系填入的一块缺口。" },
    chagatai_south: { en: "The southern Chagatai projection marks oasis and mountain-route authority toward Mawarannahr, Kashgar, and Afghanistan-facing passages before Timur's rise.", cn: "南部察合台投影表示帖木儿兴起前朝向河中、喀什噶尔和阿富汗通道的绿洲与山路权威。" },
    timurid: { en: "Timur the Lame (Tamerlane) forged an empire from Delhi to Damascus through unparalleled destruction, yet this northern fragment is specifically the Samarkand / Transoxiana core. Golden Horde and Kazakh steppe worlds stay as frontier neighbors, not owners of a missing Timurid strip.", cn: "跛子帖木儿以无与伦比的破坏缔造了从德里到大马士革的帝国，但这个北部片段专指撒马尔罕/河中核心。金帐与哈萨克草原世界作为边疆邻居存在，而不是帖木儿缺口的主人。" },
    timurid_south: { en: "The southern Timurid fragment represents Herat, Khorasan, and Afghan routes under Shah Rukh and later Timurid courts. It keeps the Herat renaissance visible as a separate imperial fragment without making the Golden Horde a southern cutout owner.", cn: "南部帖木儿片段表示沙哈鲁及后期帖木儿宫廷治下的赫拉特、呼罗珊和阿富汗通道。它把赫拉特复兴作为独立帝国片段保留下来，但不再把金帐草原画成南部缺口主人。" },
    kimek: { en: "Kimek/Kipchak is the northern steppe owner after the Uyghur collapse. It keeps Dasht-i Qipchaq visible beside Samanid, Qara-Khanid, Seljuk, and Khwarazmian oasis powers until the Mongol conquest absorbs the steppe into successor uluses.", cn: "基马克/钦察表示回鹘瓦解后的北方草原主人。它让钦察草原在萨曼、喀喇汗、塞尔柱与花剌子模等绿洲权力旁保持可见，直到蒙古征服后被并入继承兀鲁思。" },
    kazakh_khanate: { en: "The Kazakh Khanate / Hordes occupy the steppe successor lane after the Golden Horde. Fergana and Kokand stay whole in their own valley lane; Syr Darya, Tien Shan, and oasis-valley contacts are carried by relationship links, not a filled cutout.", cn: "哈萨克汗国/诸玉兹占据金帐之后的草原继承栏。费尔干纳与浩罕在自己的谷地栏保持完整；锡尔河、天山以及绿洲-谷地接触由联系线表达，而不是画成被填补的缺口。" },
    shaybanid: { en: "Bukhara Khanate compresses the Shaybanid, Astrakhanid, and early Uzbek khanate sequence in Transoxiana. Its Khorezm-facing cut is filled by Khiva so Bukhara is not drawn as if it owned the whole Uzbek-khanate world.", cn: "布哈拉汗国压缩显示河中的昔班尼、阿斯特拉罕尼及早期乌兹别克汗国序列。面向花剌子模的切口由希瓦填入，避免把布哈拉画成拥有整个乌兹别克汗国世界。" },
    khiva: { en: "Khiva Khanate represents the Khorezm / lower Amu Darya oasis polity. Kazakh and later Russian steppe power stays in the neighboring steppe lane, so Khiva reads as an oasis khanate beside the northern pasture world rather than a block with a steppe-filled bite.", cn: "希瓦汗国表示花剌子模/阿姆河下游绿洲政权。哈萨克及后来的俄属草原权力保留在相邻草原栏，因此希瓦读作毗邻北方牧地世界的绿洲汗国，而不是被草原填入缺口的图块。" },
    fergana_begliks: { en: "Fergana Begliks marks the local valley and mountain owners between Timurid fragmentation and the rise of Kokand. It stays whole beside the Afghan-route lane: Kabul and Kandahar contacts are relationship semantics, not an Afghan cutout inside Fergana.", cn: "费尔干纳诸伯克表示帖木儿碎裂后、浩罕兴起前的谷地与山地地方主人。它在阿富汗通道栏旁保持完整：喀布尔、坎大哈联系由关系语义表达，而不是把阿富汗画成费尔干纳内部缺口。" },
    kokand: { en: "Kokand / Fergana Khanate begins with the Ming Uzbek rise in Fergana before Kokand became the capital. Its Kazakh/Russian steppe contacts and Afghan-route adjacency are carried by lanes and relationship links, so Kokand remains a whole Fergana block rather than an Afghan-filled cutout.", cn: "浩罕/费尔干纳汗国从乌兹别克明格部在费尔干纳兴起开始，早于浩罕成为首府。它与哈萨克/俄属草原的接触及阿富汗通道相邻关系由栏位和联系线承载，因此浩罕保持完整的费尔干纳图块，而不是由阿富汗填入缺口。" },
    mughal_afghan: { en: "Mughal Afghanistan keeps Kabul, Kandahar, and the Afghan approaches visible as a Timurid-Mughal frontier before the Hotak revolt at Kandahar. It is a southern imperial fragment beside Fergana, not a cutout owner inside the Transoxiana khanate mosaic.", cn: "莫卧儿阿富汗把喀布尔、坎大哈和阿富汗通道作为霍塔克起义前的帖木儿-莫卧儿边疆保留下来。它是费尔干纳旁的南部帝国片段，而不是河中汗国拼图内部的缺口主人。" },
    hotak_afghanistan: { en: "Hotak Afghanistan marks the Ghilzay Pashtun revolt at Kandahar in 1709 and the short Afghan power that briefly reached Isfahan. It prevents the 1720s Afghan lane from being mislabeled as a quiet Mughal frontier.", cn: "霍塔克阿富汗表示1709年坎大哈的吉尔吉普什图起义，以及一度进入伊斯法罕的短暂阿富汗强权。它避免1720年代阿富汗栏被误读成平静的莫卧儿边疆。" },
    afsharid_afghan: { en: "Afsharid Afghanistan is the short Nadir Shah phase after the Hotak fall and before Ahmad Shah Durrani was elected at Kandahar. It is a transition owner, not a blank pause before the Afghan state.", cn: "阿夫沙尔阿富汗表示霍塔克覆灭后、艾哈迈德沙·杜兰尼在坎大哈被推举前的纳迪尔沙短暂阶段。这是过渡主人，不是阿富汗国家出现前的空白暂停。" },
    durrani: { en: "Durrani Empire begins in 1747 when Ahmad Shah Durrani was elected at Kandahar after Nadir Shah's assassination. It is the founding Afghan imperial lane, with reach from the Amu Darya toward Khorasan, Punjab, Sindh, and Kashmir.", cn: "杜兰尼帝国始于1747年纳迪尔沙遇刺后艾哈迈德沙·杜兰尼在坎大哈被推举。它是阿富汗帝国的奠基栏，影响从阿姆河伸向呼罗珊、旁遮普、信德和克什米尔。" },
    afghanistan_early: { en: "Barakzai Afghanistan starts with Dost Mohammad's Kabul ascendancy in 1826. The block compresses 19th-century Afghan consolidation, Anglo-Afghan wars, and Great Game pressure before full foreign-policy independence.", cn: "巴拉克宰阿富汗始于1826年多斯特·穆罕默德在喀布尔崛起。该块压缩19世纪阿富汗整合、英阿战争与大博弈压力，直到完全外交独立之前。" },
    afghanistan: { en: "Independent Afghanistan begins with the 1919 foreign-policy break under Amanullah and continues through the later monarchy, republic, Soviet intervention, civil war, and Taliban-era fragmentation compressed into one modern lane for now.", cn: "独立阿富汗从1919年阿马努拉时期摆脱英国外交控制开始；后续君主制、共和国、苏联干预、内战与塔利班时期暂时压缩在同一个现代栏中。" },
    bukhara: { en: "The Bukhara Emirate continues the Mangit emirate after the Uzbek khanate phase. Its Khiva-facing edge is filled by Khiva and then Russian Khiva, while the emirate itself survives as a Russian protectorate until the 1920 revolution.", cn: "布哈拉酋长国延续乌兹别克汗国阶段之后的曼吉特酋长国。面向希瓦的边缘由希瓦及后来的俄属希瓦承接，而酋长国本身作为俄国保护国存续到1920年革命。" },
    russian_kazakh: { en: "Russian Kazakh marks imperial incorporation of the Kazakh steppe and abolition of horde autonomy. Kokand remains visible in the separate Fergana lane until 1876, so Russian steppe rule does not imply instant control of the valley khanate or require a Kokand-filled bite.", cn: "俄属哈萨克表示俄罗斯帝国并入哈萨克草原并废除诸玉兹自治。浩罕在独立的费尔干纳栏一直可见到1876年，因此俄国草原统治不暗示立刻控制谷地汗国，也不需要画成浩罕填入的缺口。" },
    russian_khiva: { en: "Russian Khiva represents the post-1873 protectorate in Khorezm. The Qongrat khans remain as local rulers under Russian control before the Khorezm People's Soviet Republic replaces the protectorate.", cn: "俄属希瓦表示1873年后的花剌子模保护国。昆格拉特汗仍作为地方统治者处于俄国控制之下，直到花剌子模人民苏维埃共和国取代保护国。" },
    russian_kokand: { en: "Russian Fergana marks the annexed Kokand / Fergana oblast phase after 1876. It carries the mountain-valley lane into the Turkestan Soviet transition rather than leaving the collapsed khanate as a blank strip.", cn: "俄属费尔干纳表示1876年兼并浩罕后的费尔干纳州阶段。它把山地-谷地栏承接到突厥斯坦苏维埃过渡，而不是让灭亡的汗国留下空条。" },
    yuezhi: { en: "The Yuezhi are treated as a migration-phase steppe group before the Kushan rise. Their pressure on Bactria is visible through succession and frontier links, while the migration lane stays a whole adjacent record.", cn: "月氏被处理为贵霜兴起前的迁徙阶段草原群体。它们对巴克特里亚的压力通过继承与边疆联系呈现，而迁徙栏本身保持为完整的相邻记录。" },
    wusun_ili: { en: "The Wusun / Ili Steppe block fills the Han-era Semirechye and Ili-Chu pasture corridor beside Kangju and Kushan Bactria. It is a named nomadic polity layer, not an empty strip between larger empires.", cn: "乌孙/伊犁草原块填补汉代康居与贵霜巴克特里亚旁的七河、伊犁-楚河牧地走廊。它是具名游牧政权层，而不是大帝国之间的空条。" },
    kangju: { en: "Kangju occupies a narrow Syr Darya / steppe sub-lane beside Yuezhi, Kushan, Wusun, and later Kidarite fields. Its relationships are border and exchange relationships, so the Kangju block stays whole instead of ending in a Kidarite-owned notch.", cn: "康居占据月氏、贵霜、乌孙和后期寄多罗场域旁的锡尔河/草原窄栏。它们之间是边疆与交流关系，因此康居图块保持完整，而不是以寄多罗承接的缺口结束。" },
    kidarites_steppe: { en: "This narrow steppe fragment marks Kidarite-linked pressure in the northern Central Asian lane while older Kangju and Ili-steppe traditions remain visible beside it. The overlap is a frontier relationship, not a land-bite merge.", cn: "这个窄草原片段表示寄多罗相关力量在中亚北部栏的压力，同时保留旁侧仍可见的康居与伊犁草原传统。这里是边疆关系，不是土地缺口合并。" },
    rouran_gaoche_steppe: { en: "Rouran-Gaoche Steppe fills the northern Syr Darya / Kazakh-Dzungarian half-lane after Kangju fades and before the Göktürk takeover. It is a cautious Rouran-linked, Gaoche/Tiele, and western-steppe field, not a claim that one precisely bounded state ruled the entire corridor.", cn: "柔然-高车草原填补康居淡出后、突厥接管前的北部锡尔河/哈萨克-准噶尔半栏。它是谨慎的柔然相关、高车/铁勒及西部草原场域，而不是声称一个边界精确的国家统治整条走廊。" },
    late_antique_ili_steppe: { en: "This late-antique Ili-Chu steppe layer is deliberately composite and paired with the Rouran-Gaoche northern strip. Together they mark Rouran-linked, Tiele, and other nomadic fields before the Göktürk takeover while avoiding false border precision.", cn: "这个晚古伊犁-楚河草原层刻意采用复合表述，并与北侧柔然-高车窄栏成对。二者共同表示突厥接管前的柔然相关、铁勒及其他游牧场域，同时避免虚假的边界精确感。" },
    hephthalite: { en: "The Hephthalite block is now the Bactria / Tokharistan / Afghanistan core. Its final notch is filled by Göktürk pressure from the northern steppe, matching the Turk-Sasanian destruction of Hephthalite power.", cn: "嚈哒图块现在表示巴克特里亚/吐火罗斯坦/阿富汗核心。末段凹口由北方草原的突厥压力填入，符合突厥-萨珊联手摧毁嚈哒权力的语义。" },
    post_hephthalite_tokharistan: { en: "Post-Hephthalite Tokharistan fills the Bactria / Oxus half-lane after the Turk-Sasanian defeat of the Hephthalite empire. Sasanian influence, Hephthalite principalities, and early Western Turkic pressure coexisted here, so the block is a cautious frontier mosaic rather than an empty gap or a widened steppe khaganate.", cn: "后嚈哒吐火罗斯坦填补突厥-萨珊击破嚈哒帝国之后的巴克特里亚/奥克苏斯半栏。萨珊影响、嚈哒诸侯和早期西突厥压力在此并存，因此这个图块是谨慎的边疆拼合体，而不是空档，也不是被拉宽的草原汗国。" },
    tokhara_yabghus: { en: "The Tokhara Yabghus mark the Western Turkic ruling house established in Tokharistan under Tong Yabghu Qaghan's expansion. Kunduz, Balkh, Badakhshan, Guzgan, Bamiyan, and adjacent routes stay visible as a south-Oxus political and trade corridor before the Arab pressure phase.", cn: "吐火罗叶护表示统叶护可汗南扩后在吐火罗斯坦建立的西突厥统治家族。昆都士、巴尔赫、巴达赫尚、俱蜜、巴米扬及相邻通道在阿拉伯压力阶段前作为奥克苏斯以南的政治与贸易走廊保持可见。" },
    upper_oxus_principalities: { en: "Upper Oxus Principalities keeps Badakhshan, Khuttal, Chaghaniyan, and neighboring Tokharistan mountain corridors visible after the first Arab incursions. Tribute, raids, and caliphal pressure did not instantly turn this peripheral highland zone into a blank strip or a simple Abbasid rectangle.", cn: "上奥克苏斯诸侯保留阿拉伯初期推进之后的巴达赫尚、胡塔勒、查噶尼扬及相邻吐火罗斯坦山地通道。贡赋、袭击与哈里发压力并不等于这个外围高地区域立刻变成空条或单纯的阿拔斯矩形。" },
    gokturk: { en: "The Göktürk Khaganate is narrowed to the steppe and Ili-Chu / western Turkic axis in this Central Asia grid. Its first notch is filled by the still-surviving Hephthalite core before the Turkic takeover becomes visually complete.", cn: "突厥汗国在中亚网格中窄化为草原与伊犁-楚河/西突厥轴线。其起始凹口由仍存的嚈哒核心承接，直到突厥接管在视觉上完整成形。" },
    karluk_turgesh_frontier: { en: "Karluk-Turgesh Frontier marks the Zhetysu, Chu-Talas, Issyk-Kul, and Fergana-edge zone after Göktürk collapse. It shows Turgesh remnants, Karluk western Yabghu power, and local Sogdian-Turkic corridors beside the Uyghur steppe and Abbasid Transoxiana.", cn: "葛逻禄-突骑施边疆表示突厥崩解后的七河、楚河-塔拉斯、伊塞克湖与费尔干纳边缘地带。它把突骑施残余、葛逻禄西部叶护力量和本地粟特-突厥通道放在回鹘草原与阿拔斯河中之间。" },
    afghan_turkic: { en: "Turk Shahi Afghanistan keeps Kabul, Kapisa, Zabul, and the Hindu Kush approaches visible after Hephthalite power broke. It is a local mountain-frontier owner, not an empty interval before Islam.", cn: "突厥沙希阿富汗保留嚈哒势力崩解后的喀布尔、迦毕试、赞布尔与兴都库什通道。它是本地山地边疆主人，而不是伊斯兰到来前的空档。" },
    kabul_zabul_frontier: { en: "Kabul-Zabul Frontier replaces the old blanket label 'Islamic Afghanistan.' Arab forces reached Sistan and raided toward Kabul and Zabul, but Kabul Shahis and Zunbils remained visible local owners for centuries.", cn: "喀布尔-赞布尔边疆取代旧的笼统标签“伊斯兰阿富汗”。阿拉伯军队进入锡斯坦并向喀布尔、赞布尔推进，但喀布尔沙希与赞比勒仍作为本地主人延续数世纪。" },
    saffarid_afghan: { en: "Saffarid Afghanistan marks the Sistan-based expansion after c. 870, when Islam became much more entrenched in Afghanistan. It fills the gap before the Ghaznavid rise at Ghazna.", cn: "萨法尔阿富汗表示约870年后以锡斯坦为基地的扩张，此时伊斯兰在阿富汗更深入扎根。它填补加兹尼王朝兴起前的空档。" },
    samanid: { en: "The Samanid Transoxiana core remains centered on Bukhara and Samarkand. Khorasan is shown separately so the Ghaznavid rise at Ghazna can appear beside, not under, the late Samanids.", cn: "萨曼河中核心仍以布哈拉、撒马尔罕为中心。呼罗珊另行显示，使伽色尼在加兹尼兴起时能与晚期萨曼并列，而不是被盖住。" },
    samanid_south: { en: "This fragment marks the Samanid Khorasan / Herat-Balkh sphere. Its late Ghazna-side notch is filled by the Ghaznavids, who began as Samanid governors before becoming autonomous.", cn: "这个片段表示萨曼的呼罗珊/赫拉特-巴尔赫范围。其晚期加兹尼侧凹口由伽色尼填入；伽色尼最初是萨曼总督，随后逐渐自治。" },
    ghaznavid_ca: { en: "The Ghaznavid Central Asia block is now the Ghazna / Afghanistan core, with Khorasan expansion and later losses described rather than drawn over all Samanid territory.", cn: "中亚中的伽色尼图块现在表示加兹尼/阿富汗核心；呼罗珊扩张和后续丧失以说明呈现，而不是覆盖全部萨曼领土。" },
    ghurid_khorasan_contest: { en: "Ghurid Khorasan Contest fills the Herat-Balkh / upper-Oxus corridor after the 1186 Ghaznavid extinction and before the 1194 Khwarazmian handoff. It marks Ghurid westward pressure and contested Khorasan, not stable control of all Khorasan from the first year.", cn: "古尔呼罗珊争夺填补1186年伽色尼终结之后、1194年花剌子模接手之前的赫拉特-巴尔赫/上奥克苏斯走廊。它表示古尔向西的压力与呼罗珊争夺，而不是从第一年起稳定统治全部呼罗珊。" },
    ghurid_ca: { en: "The Ghurid fragment is kept in the Ghur / Herat / Afghanistan lane. It coexists with Khwarazmian pressure in Khorasan until the 1215 takeover, with that transition carried by links rather than a land-bite cutout.", cn: "古尔片段保留在古尔/赫拉特/阿富汗栏。它与花剌子模在呼罗珊方向的压力并存，直到1215年前后被接管；这一转变由联系线表达，而不是土地缺口。" },
    khwarazm_south: { en: "This Khwarazmian Khorasan fragment represents western pressure and expansion beside the Ghurid Afghan core before the 1215 takeover. It stays whole because pressure is not the same thing as owning a cutout inside Ghur.", cn: "这个花剌子模呼罗珊片段表示1215年接管前，古尔阿富汗核心旁的西向压力与扩张。它保持完整，因为压力不等于拥有古尔内部的缺口。" },
    khwarazm_afghan: { en: "This short takeover fragment begins after the Ghurid collapse, marking Khwarazmian occupation of the Afghan/Ghurid sphere before the Mongol invasion. Its pairing with Khorasan is political and chronological, not a reciprocal cutout.", cn: "这个短促接管片段始于古尔崩溃后，表示蒙古入侵前花剌子模占据阿富汗/古尔势力范围。它与呼罗珊片段的关系是政治和时间上的配对，不是相互缺口。" },
    bukharan_psr: { en: "The Bukharan People's Soviet Republic is shown as a short full-lane revolutionary transition after the emirate was overthrown in 1920. Because its left edge is the chart boundary, the diagram does not invent a missing neighbor before the Uzbek SSR.", cn: "布哈拉人民苏维埃共和国显示为1920年酋长国被推翻后的短暂完整栏位过渡。由于其左缘就是图表边界，图中不虚构一个乌兹别克苏维埃共和国之前的缺失邻国。" },
    khorezm_psr: { en: "The Khorezm People's Soviet Republic marks the Khiva/Khorezm transition after Russian protectorate rule and before the 1924-25 incorporation into Uzbek and Turkmen republican structures.", cn: "花剌子模人民苏维埃共和国表示希瓦/花剌子模从俄国保护国统治转入1924-25年乌兹别克、土库曼共和国结构前的过渡。" },
    kazakh_assr_early: { en: "The Kazakh lane begins with the Kirghiz/Kazakh ASSR phase from 1920. It stays separate from the later union-republic status granted to the Kazakh SSR in 1936.", cn: "哈萨克栏从1920年的吉尔吉斯/哈萨克自治苏维埃共和国阶段开始，并与1936年升格为加盟共和国的哈萨克苏维埃共和国分开。" },
    turkestan_transition: { en: "This fragment keeps the Turkestan ASSR, Fergana-Semirechye transition, and Basmachi conflict visible before the Soviet map was redrawn into national republics.", cn: "这个片段保留突厥斯坦自治苏维埃共和国、费尔干纳-七河过渡与巴斯马奇冲突，早于苏联把地图重划为民族共和国。" },
    uzbek_ssr: { en: "The Uzbek SSR represents the 1924 Soviet national delimitation of Transoxiana. It is separated from Turkmen, Kazakh, Tajik, and Kyrgyz lanes so Soviet Central Asia is not one uniform block.", cn: "乌兹别克苏维埃共和国表示1924年苏联对河中的民族划界。它与土库曼、哈萨克、塔吉克和吉尔吉斯栏分开，避免把苏联中亚画成一个均质大块。" },
    turkmen_ssr: { en: "The Turkmen SSR occupies the Khorezm / Turkmenistan lane from the 1924 delimitation to 1991 independence.", cn: "土库曼苏维埃共和国占据花剌子模/土库曼斯坦栏，从1924年划界延续到1991年独立。" },
    kazakh_ssr: { en: "The Kazakh SSR begins when Kazakhstan became a union republic in 1936. The steppe lane remains distinct from Uzbekistan and Turkmenistan.", cn: "哈萨克苏维埃共和国始于1936年哈萨克斯坦成为加盟共和国。草原栏与乌兹别克斯坦、土库曼斯坦保持区分。" },
    tajik_assr: { en: "The Tajik ASSR is a half-lane within the Soviet mountain corridor from 1924 to 1929, before Tajikistan became a full union republic.", cn: "塔吉克自治苏维埃共和国是1924至1929年苏联山地走廊中的半栏，早于塔吉克斯坦升格为加盟共和国。" },
    tajik_ssr: { en: "The Tajik SSR is drawn as its own half-lane from 1929 to 1991, making the mountainous Tajik republic visible beside Kyrgyzstan instead of merging both into one rectangle.", cn: "塔吉克苏维埃共和国自1929至1991年绘成独立半栏，使山地塔吉克共和国与吉尔吉斯斯坦并列可见，而不是合成一个矩形。" },
    kyrgyz_soviet_early: { en: "The Kyrgyz Soviet early phase covers the Kara-Kirghiz autonomous oblast and later Kirghiz ASSR before union-republic status in 1936.", cn: "早期吉尔吉斯苏维埃阶段包括卡拉-吉尔吉斯自治州和后来的吉尔吉斯自治苏维埃共和国，早于1936年加盟共和国地位。" },
    kyrgyz_ssr: { en: "The Kirghiz SSR is separated from Tajikistan after 1936, preserving the five-republic Soviet Central Asia structure.", cn: "吉尔吉斯苏维埃共和国自1936年后与塔吉克斯坦分开，保留苏联中亚五个共和国的结构。" },
    uzbekistan: { en: "Independent Uzbekistan continues the Transoxiana / Uzbek lane after the Soviet collapse in 1991.", cn: "独立乌兹别克斯坦延续1991年苏联解体后的河中/乌兹别克栏。" },
    turkmenistan: { en: "Independent Turkmenistan continues the Turkmen SSR lane after 1991, rather than being hidden inside a generic post-Soviet Central Asia block.", cn: "独立土库曼斯坦延续1991年后的土库曼苏维埃共和国栏，而不是隐藏在泛称的后苏联中亚大块中。" },
    kazakhstan: { en: "Independent Kazakhstan continues the steppe republic lane after the Soviet collapse, with the long ASSR-to-SSR sequence visible before it.", cn: "独立哈萨克斯坦延续苏联解体后的草原共和国栏，前方保留自治共和国到加盟共和国的长序列。" },
    tajikistan: { en: "Independent Tajikistan occupies the Tajik half-lane after 1991, keeping it distinct from Kyrgyzstan.", cn: "独立塔吉克斯坦占据1991年后的塔吉克半栏，与吉尔吉斯斯坦保持区分。" },
    kyrgyzstan: { en: "Independent Kyrgyzstan occupies the Kyrgyz half-lane after 1991, continuing the Kirghiz SSR sequence.", cn: "独立吉尔吉斯斯坦占据1991年后的吉尔吉斯半栏，延续吉尔吉斯苏维埃共和国序列。" },
    parthia: { en: "The Parthian Empire began from the northeastern Iranian region of Parthia before expanding westward. It is drawn first as an Iranian core so the chart does not imply Mesopotamian control from 247 BC.", cn: "帕提亚帝国起源于伊朗东北部的帕提亚地区，之后才向西扩张。图中先绘为伊朗核心，避免暗示公元前247年起就控制美索不达米亚。" },
    parthia_mesopotamia: { en: "This fragment represents Parthian control of Babylonia and Mesopotamia after Seleucid retreat. It stays as a whole Mesopotamian lane beside the Iranian Parthian core; the relationship link carries the imperial attachment and later Roman-Parthian frontier context.", cn: "这个片段表示塞琉古退却后帕提亚对巴比伦尼亚和美索不达米亚的控制。它在伊朗帕提亚核心旁保持完整美索不达米亚栏；关系线承载帝国归属和后来的罗马-帕提亚边疆语境。" },
    roman_east: { en: "The Roman East first entered the Near Eastern grid through Anatolia and Syria, not through Egypt. Egypt is drawn separately from 30 BC so the final decades of Ptolemaic independence remain visible.", cn: "罗马东方最初通过安纳托利亚和叙利亚进入近东格局，而不是通过埃及。埃及从公元前30年起单独绘制，以保留托勒密独立的最后数十年。" },
    roman_levant: { en: "Roman Syria and the Levant became the western imperial frontier facing Parthia and later Sasanian Persia. It is split from Anatolia and Egypt to avoid a single rectangular eastern empire.", cn: "罗马叙利亚和黎凡特成为面对帕提亚及后来萨珊波斯的帝国西部边疆。它与安纳托利亚、埃及分开，避免形成一个单一矩形的东方帝国。" },
    roman_egypt: { en: "Roman Egypt begins after Cleopatra VII's death and Octavian's takeover in 30 BC. Drawing it separately prevents Roman East from covering Ptolemaic Egypt too early.", cn: "罗马埃及始于克利奥帕特拉七世去世和屋大维接管的公元前30年。单独绘制可避免罗马东方过早覆盖托勒密埃及。" },
    // Africa
    egypt_old: { en: "Old Kingdom Egypt — the Age of Pyramids — built the Great Pyramid of Giza, one of the Seven Wonders and the tallest human structure for 3,800 years. Pharaonic ideology, hieroglyphs, and the vast administrative bureaucracy were perfected here.", cn: "埃及古王国——金字塔时代——建造吉萨大金字塔，七大奇迹之一，3800年间人类最高建筑。法老意识形态、象形文字与庞大的行政官僚体系皆在此完善。" },
    egypt_new: { en: "New Kingdom Egypt reached its military and cultural zenith under Thutmose III and Ramesses II. The Nile Valley core is drawn separately from Levantine hegemony so the map-like width does not imply one uniform territorial block.", cn: "新王国埃及在图特摩斯三世与拉美西斯二世治下达到军事与文化顶峰。图中把尼罗河核心与黎凡特霸权分开，避免宽度暗示一个均质领土块。" },
    egypt_levant: { en: "Egyptian Levant marks New Kingdom hegemony, garrisons, and tribute relationships in the southern Levant. It stays whole beside Hittite Syria; the Kadesh conflict and treaty are shown through links and events rather than mutual cutout ownership.", cn: "埃及黎凡特表示新王国在南黎凡特的霸权、驻军和朝贡关系。它与赫梯叙利亚并列且保持完整；卡迭石冲突与和约通过关系线和事件呈现，而不是互相填补缺口。" },
    horn_prehistoric: { en: "Horn Cultures marks northern Ethiopian, Eritrean, Red Sea, and highland communities before D'mt becomes visible. It is a cultural owner for the Horn lane, not an early empire projected backward.", cn: "非洲之角文化表示达姆特清晰出现前，埃塞俄比亚北部、厄立特里亚、红海与高地社群。它是非洲之角栏位的文化主人，不是向前投射的早期帝国。" },
    nubia_prehistoric: { en: "Nubian Cultures keeps the middle Nile occupied before Kerma, covering A-Group / pre-Kerma and related early Nile communities. The later Kerma kingdom grows out of this inhabited corridor rather than replacing a blank slot.", cn: "努比亚文化使克尔马之前的尼罗河中游保持有人占据，涵盖 A-Group / 前克尔马及相关早期尼罗河社群。后来的克尔马王国从这条有人居住的走廊中成长，而不是替代空白栏位。" },
    maghreb_prehistoric: { en: "Maghreb Cultures abstracts Saharan and North African pastoral, rock-art, and oasis-edge worlds before Phoenician coastal colonies. It signals long occupation through climate shifts rather than a vacant North Africa.", cn: "马格里布文化抽象表示腓尼基沿海殖民地出现前，撒哈拉与北非的牧业、岩画和绿洲边缘世界。它强调气候变迁中的长期居住，而不是空置的北非。" },
    sahel_prehistoric: { en: "Sahel Cultures represents mobile herders, hunter-gatherers, early village systems, and Tichitt-linked complexity before the Ghana/Wagadu lane. It is a pre-imperial cultural owner across the Sahara-savanna transition.", cn: "萨赫勒文化表示加纳/瓦加杜栏出现前，流动牧民、采猎者、早期村落系统以及与 Tichitt 相关的复杂社会。它是撒哈拉-稀树草原过渡带中的帝国前文化主人。" },
    coast_prehistoric: { en: "Guinea Coast Cultures marks forest-savanna and coastal communities before the Nok and later Yoruba/Edo/Akan political lanes. The label keeps the coast inhabited without inventing one unified coastal kingdom.", cn: "几内亚湾文化表示诺克以及后来的约鲁巴、埃多、阿坎政治栏出现前，森林-稀树草原和沿海社群。该标签让海岸保持有人占据，同时不虚构统一沿海王国。" },
    nok: { en: "Nok Culture is shifted into its better-attested early Iron Age horizon, centered on central Nigeria and famous for terracotta sculpture and early ironworking. It is a cultural owner between broad Guinea Coast communities and later forest kingdoms.", cn: "诺克文化被调整到更有依据的早期铁器时代视野，以尼日利亚中部为核心，以陶塑和早期冶铁闻名。它是广义几内亚湾文化与后续森林王国之间的文化主人。" },
    coast_post_nok: { en: "Post-Nok Cultures bridges the poorly documented centuries after the Nok terracotta horizon and before Ife becomes a visible Yoruba sacred and artistic center. It prevents the Guinea Coast lane from going blank between archaeological horizons.", cn: "后诺克文化衔接诺克陶塑视野之后、伊费作为约鲁巴宗教与艺术中心清晰出现之前的资料稀疏世纪。它避免几内亚湾栏在考古视野之间变成空白。" },
    igbo_ukwu_forest: { en: "Igbo-Ukwu & Forest Communities keeps the lower Niger and wider Guinea forest lane occupied beside Ife during the early medieval centuries. It is anchored by Igbo-Ukwu's 9th-century bronze, bead, and ritual finds, while explicitly remaining a composite cultural-regional owner rather than one kingdom.", cn: "伊博乌库/森林社群让中世纪早期的下尼日尔与更广阔几内亚森林栏在伊费旁保持有主人。它以9世纪伊博乌库的青铜、珠饰和仪式遗存为锚点，但明确是复合文化-区域主人，而不是一个王国。" },
    southern_prehistoric: { en: "Southern African Cultures marks long-lived hunter-gatherer, pastoral, and rock-art worlds before Bantu-speaking farming and ironworking communities become visible in this simplified lane.", cn: "南部非洲文化表示班图语农业与冶铁社群在此简化栏中清晰出现前，长期存在的采猎、牧业与岩画世界。" },
    east_africa_littoral_cultures: { en: "East African Littoral Cultures fills the Indian Ocean coast before written sources name specific ports. It represents inhabited coastal communities and exchange corridors, not a single state projected back into prehistory.", cn: "东非滨海文化填补文字史料命名具体港口之前的印度洋海岸。它表示有人居住的沿海社群与交换走廊，而不是把单一国家投射到史前。" },
    azania_rhapta_trade: { en: "Azania / Rhapta marks the Periplus-era East African coast, where Indian Ocean merchants described ports, monsoon routes, and goods moving between Africa, Arabia, and India. The sparse record is treated as a trade-cultural owner.", cn: "阿扎尼亚/拉普塔表示《厄立特里亚海航行记》时代的东非海岸，印度洋商人记录了港口、季风航线以及非洲、阿拉伯、印度之间的货物流动。资料稀疏，因此作为贸易-文化主人处理。" },
    zanj_early_ports: { en: "Zanj Early Ports covers the 8th-10th century coast as Islamic-era settlements and coral-stone urban forms begin to appear at places such as Manda, Kilwa, Pemba, and Zanzibar. It bridges Azania and the mature Swahili Coast.", cn: "赞吉早期港口表示8-10世纪沿海，曼达、基尔瓦、奔巴、桑给巴尔等地开始出现伊斯兰时代聚落和珊瑚石城市形态。它连接阿扎尼亚与成熟的斯瓦希里海岸。" },
    kerma: { en: "Kerma is the early Nubian kingdom around the third cataract, shown as the Nile lane owner before New Kingdom Egypt pushes south. This avoids leaving the pre-Kush Nubian slot as an unnamed gap.", cn: "克尔马是第三瀑布一带的早期努比亚王国，显示为新王国埃及南下之前尼罗河栏位的主人，避免把库什之前的努比亚留成无名空白。" },
    egypt_nubia: { en: "Egyptian Nubia represents New Kingdom control of Lower and Upper Nubian corridors through forts, gold zones, and the viceroy of Kush. It inherits Kerma's lane because the lost Nubian width is now explicitly occupied by Egypt.", cn: "埃及属努比亚表示新王国通过堡垒、黄金产区与库什总督控制上下努比亚走廊。它承接克尔马栏位，说明失去的努比亚宽度已由埃及占据。" },
    kush: { en: "Kush is the Napata-centered Nubian successor after Egyptian New Kingdom power withdrew from the middle Nile. It later conquered Egypt as the Twenty-fifth Dynasty, then hands the same Nubian lane toward Meroe rather than ending in a blank.", cn: "库什是埃及新王国势力退出尼罗河中游后，以纳帕塔为中心的努比亚继承主人。它后来以第二十五王朝征服埃及，之后把同一努比亚栏位转交给麦罗埃，而不是留下空白。" },
    dmt: { en: "D'mt marks the early northern Ethiopian/Eritrean highland polity linked to South Arabian trade. It gives the Horn of Africa an owner before the Axumite and pre-Axumite phases.", cn: "达姆特表示埃塞俄比亚/厄立特里亚北部高地的早期政权，并与南阿拉伯贸易相连，使非洲之角在阿克苏姆及前阿克苏姆阶段之前已有明确主人。" },
    pre_axum: { en: "Pre-Axumite highland polities occupy the Horn lane between D'mt and Axum. The label is a transitional owner rather than an empty placeholder.", cn: "前阿克苏姆高地政权占据达姆特与阿克苏姆之间的非洲之角栏位。它是过渡性主人，而不是空白占位。" },
    meroe: { en: "Meroe is the later Kushite capital zone and Nile-Red Sea trade heartland after Napata. It continues the Nubian lane after earlier Kush, rather than leaving the slot ownerless before Christian Nubia.", cn: "麦罗埃是纳帕塔之后的库什晚期都城区域与尼罗河-红海贸易核心。它延续早期库什之后的努比亚栏位，而不是在基督教努比亚之前留下无主段。" },
    phoenician_africa: { en: "Phoenician Colonies represents early Levantine maritime footholds such as Utica and other North African ports before Carthage dominates the lane. The block is a coastal colonial/trade network, not all inland Maghreb.", cn: "腓尼基殖民地表示迦太基主导该栏之前，乌提卡等黎凡特海上据点和北非港口。该块是沿海殖民/贸易网络，不是整个内陆马格里布。" },
    carthage: { en: "Carthage is the Punic North African sea power centered on the Gulf of Tunis. Its fall is now paired with Roman Africa so the North African slot changes owner instead of disappearing.", cn: "迦太基是以突尼斯湾为中心的布匿北非海上强权。它的灭亡现在与罗马非洲相接，使北非栏位更换主人，而不是突然消失。" },
    roman_africa: { en: "Roman Africa keeps the Carthage/Ifriqiya lane under Roman provincial rule, especially around grain, olive oil, and the urban Christian cities of North Africa. It is a successor owner, not a blank after 146 BC.", cn: "罗马非洲把迦太基/易弗里基叶栏位置于罗马行省统治下，重点包括谷物、橄榄油和北非基督教城市。它是公元前146年后的继承主人，而不是空白。" },
    vandals: { en: "The Vandal Kingdom carries the Carthage-centered North African lane after Western Roman authority collapsed there. It is a Germanic naval kingdom in former Roman Africa, not an ownerless pause before Byzantium.", cn: "汪达尔王国承接西罗马在北非瓦解后以迦太基为中心的栏位。它是在原罗马非洲形成的日耳曼海上王国，而不是拜占庭到来前的空档。" },
    byzantine_africa: { en: "Byzantine Africa marks Justinian's reconquest of the Vandal kingdom and later imperial North African administration around Carthage. It fills the lane until the Arab conquest, rather than treating the post-Vandal coast as empty.", cn: "拜占庭非洲表示查士丁尼再征服汪达尔王国后，以迦太基为中心的帝国北非行政区。它填补到阿拉伯征服前的栏位，而不是把汪达尔之后的海岸当作空白。" },
    abbasid_africa: { en: "Abbasid Ifriqiya represents North Africa's formal transfer into the Abbasid caliphal order after the Umayyad period, before local Aghlabid autonomy makes the province more independent.", cn: "阿拔斯易弗里基叶表示倭马亚阶段后北非名义上转入阿拔斯哈里发秩序，早于艾格莱卜自治使该行省更独立。" },
    aghlabid: { en: "The Aghlabids were Abbasid-recognized emirs ruling Ifriqiya from Kairouan, strong enough to build a local dynasty and launch Mediterranean campaigns while still fitting the Islamic North African chain.", cn: "艾格莱卜王朝是在凯鲁万统治易弗里基叶的阿拔斯承认埃米尔，既形成地方王朝并发动地中海战事，又仍属于伊斯兰北非继承链。" },
    fatimid_africa: { en: "Fatimid Ifriqiya is the North African phase of the Fatimid movement before its center shifted to Egypt. It succeeds the Aghlabids and feeds into the later Maghreb / Almoravid sequence rather than creating a blank transition.", cn: "法蒂玛易弗里基叶是法蒂玛运动在迁往埃及前的北非阶段。它承接艾格莱卜，并接入后来的马格里布/穆拉比特序列，而不是制造空白过渡。" },
    axum: { en: "Axum, in the Ethiopian and Eritrean highlands with Red Sea access through Adulis, was a major northeastern African trading power. The block is narrowed so it does not imply Axumite rule over Christian Nubia.", cn: "阿克苏姆位于埃塞俄比亚与厄立特里亚高地，并通过阿杜利斯连接红海，是东北非重要贸易强权。图块已窄化，避免暗示阿克苏姆统治基督教努比亚。" },
    aksum: { en: "Axum, in the Ethiopian and Eritrean highlands with Red Sea access through Adulis, was a major northeastern African trading power. The block is narrowed so it does not imply Axumite rule over Christian Nubia.", cn: "阿克苏姆位于埃塞俄比亚与厄立特里亚高地，并通过阿杜利斯连接红海，是东北非重要贸易强权。图块已窄化，避免暗示阿克苏姆统治基督教努比亚。" },
    zagwe: { en: "Zagwe is the Ethiopian highland dynasty between Axumite decline and the Solomonic restoration. The Lalibela rock-hewn churches anchor the lane, so the Horn does not disappear for the medieval centuries.", cn: "扎格韦是阿克苏姆衰落与所罗门王朝复兴之间的埃塞俄比亚高地王朝。拉利贝拉岩凿教堂锚定这一栏位，使中世纪非洲之角不会消失。" },
    ethiopia_modern: { en: "Modern Ethiopian Empire marks Tewodros, Menelik II, and Haile Selassie state-building in the highlands. The 1936-41 Italian occupation is shown as an explicit owner-filled bite rather than hidden inside a smooth imperial rectangle.", cn: "现代埃塞俄比亚帝国表示特沃德罗斯、孟尼利克二世与海尔·塞拉西时期的高地国家建设。1936-1941年的意大利占领被显示为明确的主人填充缺口，而不是藏在平滑帝国矩形中。" },
    italian_east_africa: { en: "Italian East Africa is a short colonial occupation fragment that fills Ethiopia's 1936-41 cutout. It is intentionally narrow and temporary because Ethiopian sovereignty was interrupted but restored during World War II.", cn: "意属东非是填补埃塞俄比亚1936-1941年缺口的短期殖民占领片段。它故意狭窄且短暂，因为埃塞俄比亚主权被中断，但在二战中恢复。" },
    ethiopia_derg: { en: "Derg-era Ethiopia succeeds the imperial state after the 1974 revolution. The lane stays Ethiopian, but the category and details change from monarchy to revolutionary republic and military-socialist rule.", cn: "德尔格时期埃塞俄比亚承接1974年革命后的帝国国家。栏位仍是埃塞俄比亚，但类别与说明从君主制转为革命共和国和军事社会主义统治。" },
    bantu_expansion: { en: "The Bantu expansion is intentionally labeled as a migration and language-agriculture spread, not a state. It fills the southern lane as a historical process owner while named kingdoms appear later inside the same space.", cn: "班图扩张被刻意标为迁徙及语言-农业传播，而不是国家。它作为历史过程占据南部栏位，之后具体王国会在同一空间中出现。" },
    nubia_christian: { en: "Christian Nubia covers the Nile kingdoms of Nobatia, Makuria, and Alodia after Meroe. The long block is kept separate from Axum and Egypt because it was a durable owner of the middle Nile corridor.", cn: "基督教努比亚表示麦罗埃之后的诺巴提亚、马库里亚与阿洛迪亚尼罗河王国。长条与阿克苏姆、埃及分开，因为它长期拥有尼罗河中游走廊。" },
    funj_early: { en: "Early Funj marks the Sennar-centered order that followed the collapse of Alodia around the Blue Nile. It keeps the Nile lane full before Darfur is split out as a neighboring western owner in the simplified grid.", cn: "早期丰吉表示阿洛迪亚崩解后，以森纳尔和青尼罗河为中心形成的秩序。在达尔富尔被拆成相邻西部主人之前，它使尼罗河栏位保持完整而非空白。" },
    funj: { en: "Funj / Sennar Core narrows the later sultanate to the Nile and Blue Nile heartland while Darfur remains an adjacent western Sudan owner. Kordofan and Darfur pressure are carried by relationships and notes, not by cutting a Darfur-owned bite into Sennar.", cn: "丰吉/森纳尔核心把后期苏丹国收窄到尼罗河和青尼罗河心脏地带，而达尔富尔作为相邻的西部苏丹主人保留。科尔多凡和达尔富尔压力由关系与说明承载，不再把达尔富尔画成切入森纳尔的一块。" },
    darfur_sultanate: { en: "Darfur Sultanate is drawn as a complete western Sudan lane beside Sennar and later Turco-Egyptian Nile Sudan. Its frontier shifts and 1874 incorporation are shown through links, avoiding a misleading left-edge bite.", cn: "达尔富尔苏丹国绘为森纳尔以及后来的土埃尼罗河苏丹旁边的完整西部苏丹栏。边疆变化和1874年并入通过联系线表达，避免误导性的左缘缺口。" },
    sudan_egyptian_nile: { en: "Turco-Egyptian Nile Sudan represents Muhammad Ali's conquest of Sennar and the Nile corridor before Darfur was incorporated. Darfur stays as a separate adjacent lane until the later full-width Egyptian Sudan block.", cn: "土埃尼罗河苏丹表示穆罕默德·阿里征服森纳尔和尼罗河走廊、但尚未并入达尔富尔的阶段。达尔富尔在后续全宽埃及属苏丹之前保持为相邻的独立栏。" },
    sudan_egyptian: { en: "Egyptian Sudan becomes full-width only after Darfur came under Egyptian rule in the 1870s. The short block deliberately follows the narrower Nile phase, showing incorporation instead of pretending Egypt owned all simplified Sudan from 1821.", cn: "埃及属苏丹只在19世纪70年代达尔富尔归入埃及统治后才变成全宽。这个短块刻意接在较窄的尼罗河阶段之后，显示并入过程，而不是假装埃及自1821年起就拥有整个简化苏丹。" },
    mahdist: { en: "The Mahdist State replaces Egyptian Sudan after the capture of Khartoum in 1885. It is treated as a Sudan-wide theocratic owner until the Anglo-Egyptian reconquest at Omdurman in 1898.", cn: "马赫迪国在1885年占领喀土穆后取代埃及属苏丹。它在1898年恩图曼战役后的英埃再征服之前，被视为覆盖苏丹的神权政权主人。" },
    sudan_british: { en: "Anglo-Egyptian Sudan is shown as a colonial condominium after the 1898 reconquest, with British dominance behind the shared Anglo-Egyptian legal form. It succeeds the Mahdist block rather than appearing as an unrelated colonial rectangle.", cn: "英埃共管苏丹表示1898年再征服后的殖民共管体制，在英埃共享名义背后以英国支配为主。它承接马赫迪国，而不是突然出现的无关殖民矩形。" },
    sudan: { en: "Independent Sudan begins in 1956 after the condominium period. In this simplified 2000-ending dataset it carries the Sudan lane before South Sudan's later independence, which is outside the current time range.", cn: "独立苏丹始于1956年共管时期结束后。在这个截止2000年的简化数据集中，它承接苏丹栏位；南苏丹之后的独立超出当前时间范围。" },
    ghana_empire: { en: "The Ghana Empire controlled a crucial Sahelian position between Saharan salt traders and West African gold producers. Its gold-salt connection now points to the Abbasid world without relying on a missing shorthand ID.", cn: "加纳帝国控制撒哈拉盐商与西非黄金产区之间的关键萨赫勒位置。其黄金-盐贸易连接现在指向阿拔斯世界，不再依赖缺失的简写 ID。" },
    ghana_late: { en: "Late Ghana marks the weakened Wagadu / Soninke order after Almoravid disruption, provincial breakaways, and Susu pressure. It keeps the Sahel lane owned between the old Ghana Empire and Mali instead of treating the transition as a blank.", cn: "晚期加纳表示穆拉比特冲击、属地脱离和苏苏压力之后衰弱的瓦加杜/索宁克秩序。它承接加纳帝国与马里之间的萨赫勒栏，而不是把转型期留成空白。" },
    almoravid: { en: "The Almoravid block now represents the Maghreb/Saharan Berber imperial core. Ghana's disruption is kept as historical pressure rather than drawn as a uniform Almoravid occupation of the whole Sahel.", cn: "穆拉比特图块现在表示马格里布/撒哈拉柏柏尔帝国核心。加纳受到冲击作为历史压力保留，而不是绘成穆拉比特对整个萨赫勒的均质占领。" },
    almohad: { en: "The Almohads are drawn as a North African and Andalusian empire centered in the Maghreb, not as a full Sahelian state. This keeps Ghana/Mali transitions visible separately.", cn: "穆瓦希德绘为以马格里布为中心的北非与安达卢斯帝国，而不是完整的萨赫勒国家。这样能让加纳/马里转型单独可见。" },
    mali: { en: "The Mali Empire's Mansa Musa undertook a 1324 pilgrimage to Mecca so lavish it crashed the gold economy of Egypt for a decade. Timbuktu under Mali became a world center of Islamic scholarship; Mali's wealth drew Europeans to explore West Africa.", cn: "马里帝国曼萨·穆萨1324年的麦加朝圣极尽奢华，使埃及黄金经济崩溃十年。马里治下的廷巴克图成为伊斯兰学术的世界中心；马里的富庶吸引欧洲人探索西非。" },
    mali_empire: { en: "Mali is drawn as an upper Niger / Sahelian trading empire linked to Mamluk Egypt through trans-Saharan commerce and Mansa Musa's 1324 hajj. It no longer visually covers forest/coastal kingdoms such as Benin, Ife, and Oyo.", cn: "马里绘为上尼日尔/萨赫勒贸易帝国，通过跨撒哈拉贸易和1324年曼萨·穆萨朝圣与马穆鲁克埃及相连。它不再视觉覆盖贝宁、伊费、奥约等森林/沿海王国。" },
    swahili_coast: { en: "The Swahili Coast was a chain of Indian Ocean city-states such as Mogadishu, Malindi, Mombasa, and Kilwa. It stays as a whole coastal trade lane; Mapungubwe, Great Zimbabwe, and Mutapa are adjacent inland gold/ivory hinterlands connected by trade links and notes, not coast-side land bites.", cn: "斯瓦希里海岸是一系列印度洋城邦网络，如摩加迪沙、马林迪、蒙巴萨和基尔瓦。它保持为完整沿海贸易栏；马蓬古布韦、大津巴布韦、穆塔帕是相邻的内陆黄金/象牙腹地，由贸易联系和说明连接，而不是海岸土地缺口。" },
    portuguese_swahili_coast: { en: "Portuguese East Africa Coast shows the fort-and-port phase after the Portuguese disrupted Swahili commercial autonomy. The label is deliberately coastal: Portuguese power did not become a full inland owner of East Africa.", cn: "葡属东非海岸表示葡萄牙打断斯瓦希里商业自治后的堡垒与港口阶段。标签刻意限定为沿海：葡萄牙权力并未成为东非完整内陆主人。" },
    omani_zanzibar_coast: { en: "Omani-Zanzibar Coast begins with Omani displacement of Portuguese strongholds and grows into the Zanzibar sultanate's 19th-century trading empire. It keeps the Swahili coast owned before formal European protectorates.", cn: "阿曼-桑给巴尔海岸始于阿曼取代葡萄牙据点，并发展为19世纪桑给巴尔苏丹国贸易帝国。它使正式欧洲保护国之前的斯瓦希里海岸保持具名主人。" },
    colonial_east_africa_coast: { en: "Colonial East Africa Coast compresses British, German, and Portuguese coastal partition after Zanzibar's mainland authority was reduced. It is a composite colonial owner, not one empire with uniform administration.", cn: "殖民东非海岸压缩表示桑给巴尔大陆权威被削弱后，英国、德国与葡萄牙对沿海的瓜分。它是复合殖民主人，不是一个行政均质的帝国。" },
    east_africa_coastal_transition: { en: "East Africa Independence Transition captures the uneven 1960s-1970s handoff: Kenya and Tanzania were independent earlier, while Portuguese Mozambique remained colonial until 1975. The lane stays filled without pretending independence was simultaneous.", cn: "东非独立过渡表示1960-70年代不均衡交接：肯尼亚和坦桑尼亚较早独立，而葡属莫桑比克直到1975年才结束殖民。此栏保持填充，同时不假装独立同时发生。" },
    east_africa_modern_coast: { en: "Modern East African Coast is a composite post-1975 Indian Ocean littoral lane for Somalia, Kenya, Tanzania, Mozambique, and related coastal states. It restores the coast as a modern regional owner after the colonial chain.", cn: "现代东非海岸是1975年后印度洋滨海复合栏，涵盖索马里、肯尼亚、坦桑尼亚、莫桑比克及相关沿海国家。它在殖民链之后恢复海岸的现代区域主人。" },
    mapungubwe: { en: "Mapungubwe is shown as an inland southern African kingdom connected to the Indian Ocean trade system through gold, ivory, glass beads, and elite hilltop settlement. It is an adjacent inland polity, not a fill piece inside the Swahili Coast.", cn: "马蓬古布韦显示为南部非洲内陆王国，通过黄金、象牙、玻璃珠和山顶精英聚落连接印度洋贸易体系。它是相邻内陆政权，不是斯瓦希里海岸内部的填充块。" },
    great_zimbabwe: { en: "Great Zimbabwe is the later inland gold-trade power linked to the Swahili Coast. The stone city and its trade links make the coast-inland relationship visible through connections, not through a carved coast block.", cn: "大津巴布韦是与斯瓦希里海岸相连的较晚内陆黄金贸易强权。石城及其贸易联系通过联系线表达海岸-内陆关系，而不是把海岸块切开。" },
    mutapa: { en: "Mutapa continues the Zimbabwe plateau gold-trade world after Great Zimbabwe. Its Swahili Coast relationship is shown by coast-hinterland trade links; the later Cape frontier is kept as a separate southern strip, not a Mutapa land bite.", cn: "穆塔帕延续大津巴布韦之后的津巴布韦高原黄金贸易世界。它与斯瓦希里海岸的关系由海岸-内陆贸易联系表达；后来的开普边疆保留为独立南部窄栏，而不是穆塔帕内部土地缺口。" },
    southern_interior_cultures: { en: "Southern Interior Cultures keeps the southeastern and interior southern African strip occupied beside Mutapa before the Cape colonial frontier begins. It compresses Nguni, Sotho-Tswana, Khoekhoe, San, and related communities as an adjacent inhabited lane, not a cutout owner.", cn: "南部内陆文化让开普殖民边疆开始之前、穆塔帕旁的东南部与内陆南部非洲窄栏保持有人。它压缩表示恩古尼、索托-茨瓦纳、科伊科伊、桑人等相关社群，是相邻有人栏，不是缺口主人。" },
    southern_fragmented: { en: "Southern Kingdoms compress Nguni, Sotho-Tswana, Khoekhoe, San, and other regional owners after the Zimbabwe plateau sequence and before the Zulu kingdom becomes the visible eastern owner. The Cape-Boer-British frontier is adjacent, not filling a carved edge.", cn: "南部诸国压缩表示津巴布韦高原序列之后、祖鲁王国成为可见东部主人之前的恩古尼、索托-茨瓦纳、科伊科伊、桑人等区域主人。开普-布尔-英国边疆是相邻窄栏，不填补被切出的边缘。" },
    cape_boer_colonies: { en: "Cape / Boer / British frontier is a composite adjacent strip for the Cape colony, trekker republics, and British-frontier expansion. It starts from the southwestern Cape/Natal frontier sequence and does not own missing pieces of Mutapa, Southern Kingdoms, or Zulu blocks.", cn: "开普/布尔/英国边疆是复合相邻窄栏，表示开普殖民地、布尔共和国与英国边疆扩张。它从西南开普/纳塔尔边疆序列展开，不拥有穆塔帕、南部诸国或祖鲁图块缺失的部分。" },
    zulu: { en: "The Zulu Kingdom is drawn as the eastern/southeastern African owner beside a Cape-Boer-British frontier strip, not as all southern Africa. British and Boer pressure is shown by relationships and adjacency, without land-bite geometry.", cn: "祖鲁王国绘为东部/东南非洲主人，与开普-布尔-英国边疆窄栏并列，而不是整个南部非洲。英国与布尔压力由关系线和相邻栏表达，不画土地缺口。" },
    colonial_south: { en: "Colonial Southern Africa is the post-1897 composite colonial lane, folding British South Africa, former Boer republics, and related southern settler administrations into one simplified owner after Zulu independence was crushed.", cn: "殖民南部非洲是1897年后的复合殖民栏，把英属南非、原布尔共和国及相关南部定居者行政区压缩为祖鲁独立被压制后的一个简化主人。" },
    southern_modern: { en: "Southern States carry the post-1961 southern African lane as a composite modern owner, including South Africa's republic era and neighboring independence movements/states in this simplified strip.", cn: "南部非洲诸国作为复合现代主人承接1961年后的南部非洲栏，包括南非共和国时代以及本简化窄条中的邻近独立运动/国家。" },
    maghreb_sultanates: { en: "The Maghreb Sultanates summarize the Marinid, Zayyanid, Hafsid, and related post-Almohad order. The single lane is an abstraction of several neighboring owners, not an empty post-imperial space.", cn: "马格里布苏丹国概括穆林、扎扬、哈夫斯等穆瓦希德之后的格局。单栏是多个相邻主人抽象合并后的结果，而不是帝国之后的空白。" },
    morocco_tunisia_sultanates: { en: "Morocco and Tunisia remain as a composite non-contiguous Maghreb owner beside early French Algeria. This strip is not one state; it preserves the still-unconquered or protectorate-forming western and eastern Maghreb before the French North African lane widens.", cn: "摩洛哥与突尼斯作为复合、非连续马格里布主人，显示在早期法属阿尔及利亚旁边。这个窄条不是单一国家；它保留法国北非栏扩大前尚未被征服或正在形成保护国的东西马格里布。" },
    french_maghreb: { en: "French North Africa begins with Algeria in 1830 and widens only after protectorates in Tunisia and Morocco. Its early edge is owner-filled by Morocco and Tunisia so French expansion reads as staged conquest, not instant ownership of all Maghreb.", cn: "法属北非始于1830年的阿尔及利亚，并在突尼斯、摩洛哥保护国形成后才扩大。其早期边缘由摩洛哥与突尼斯填充，使法国扩张读作阶段性征服，而不是瞬间拥有整个马格里布。" },
    maghreb_modern: { en: "Modern Maghreb states carry the North African lane after the colonial sequence, with Morocco and Tunisia already independent before Algeria's 1962 threshold in this simplified timeline.", cn: "现代马格里布诸国承接殖民序列之后的北非栏位；在本简化时间线的1962年阿尔及利亚门槛前，摩洛哥和突尼斯已先行独立。" },
    ethiopia_sol: { en: "The Solomonic Ethiopian Empire continues the highland Horn lane after Zagwe, with Orthodox court culture and repeated frontier wars against Ifat and Adal. Its width is an owner of the highland core, not all East Africa.", cn: "所罗门王朝埃塞俄比亚帝国承接扎格韦之后的高地非洲之角栏位，具有东正教宫廷文化，并多次与伊法特、阿达尔发生边疆战争。其宽度表示高地核心主人，而非整个东非。" },
    songhai: { en: "Songhai is kept in the Niger bend / Sahel lane: it dominated trans-Saharan trade through Gao, Timbuktu, and Djenné, but it should not visually erase the forest/coastal kingdoms to the south.", cn: "桑海保留在尼日尔河弯/萨赫勒栏：它通过加奥、廷巴克图和杰内主导跨撒哈拉贸易，但不应视觉抹去南方森林/沿海王国。" },
    arma_timbuktu: { en: "Arma / Timbuktu Pashalik is the western Niger-bend owner after the Moroccan conquest of Songhai. Dendi Songhai survives as an adjacent eastern Songhai successor, so their relationship is shown by frontier and succession links rather than a Dendi-filled bite in the Arma block.", cn: "阿尔马/廷巴克图帕夏政权表示摩洛哥征服桑海之后尼日尔河弯西部的主人。登迪桑海作为相邻的东部桑海继承者延续，因此两者关系由边疆与继承联系表达，而不是把登迪画成阿尔马图块里的填充缺口。" },
    bambara_states: { en: "Bambara / Segu States carry the western and central upper Niger after the Arma order weakened. Dendi and then Sokoto remain adjacent eastern Sahel / Hausa-side records, not owners of a carved eastern edge inside Segu-Kaarta.", cn: "班巴拉/塞古诸国承接阿尔马秩序衰弱后的西部和中部上尼日尔。登迪以及后来的索科托保留为相邻的东部萨赫勒/豪萨侧记录，而不是塞古-卡尔塔东缘缺口的主人。" },
    songhai_dendi: { en: "Dendi Songhai represents the southeast Songhai successor after 1591, near the Niger-Borgu frontier. It is a narrow surviving-owner lane beside Arma and Bambara, not a reciprocal cutout inside either western neighbor.", cn: "登迪桑海表示1591年后位于尼日尔-博尔古边疆附近的东南桑海继承政权。它是阿尔马和班巴拉旁的狭窄延续主人栏，而不是任一西侧邻居里的反向缺口。" },
    toucouleur_empire: { en: "The Toucouleur / Umarian Empire carries the mid-19th-century western Sudan after Umar Tall's jihad conquered Segu and Macina. Sokoto remains a neighboring eastern Hausa-Fulani lane, while the western Sahel handoff to France is carried by conquest links.", cn: "图库洛尔/乌马尔帝国承接19世纪中期乌马尔·塔尔圣战征服塞古和马西纳后的西苏丹。索科托保留为相邻的东部豪萨-富拉尼栏，而西部萨赫勒转入法国由征服联系表达。" },
    benin_early: { en: "Early Benin is placed in the middle Edo forest/coastal sub-lane beside Ife and early Akan / Volta forest owners. The layout shows related Guinea Coast polities without implying they occupied the same territory.", cn: "早期贝宁放在中部埃多森林/沿海子栏，与伊费和早期阿坎/沃尔特森林主人并列。布局显示几内亚湾诸政权的关联，而不暗示它们占据同一块领土。" },
    akan_volta_early: { en: "Early Akan / Volta Forest represents the sparse but important state-formation corridor west of the Niger forest kingdoms. It keeps the Gold Coast / Volta side visible before the better-attested Akan and Asante sequence.", cn: "早期阿坎/沃尔特森林表示尼日尔森林王国以西资料稀疏但重要的国家形成走廊。它让黄金海岸/沃尔特一侧在更清晰的阿坎与阿散蒂序列之前保持可见。" },
    gold_coast_akan_states: { en: "Akan / Gold Coast States compress early Bono, Banda, Ga/Ewe, Gonja, and related forest/coastal formations before the Asante union. It is a plural owner for the western Guinea Coast rather than a blank or a premature Asante block.", cn: "阿坎/黄金海岸诸国压缩表示阿散蒂联盟之前的早期博诺、班达、加/埃维、贡贾及相关森林-沿海形成过程。它是西几内亚湾的复数主人，而不是空白或提前出现的阿散蒂块。" },
    benin: { en: "Benin represents the Edo kingdom in the western African forest region, centered on Benin City. It now occupies the middle Guinea Coast strip, separated from Ashanti / Akan to the west and Oyo / Dahomey to the east.", cn: "贝宁表示以贝宁城为中心的埃多王国，位于西非森林区域。它现在占据几内亚湾中部窄栏，与西侧阿散蒂/阿坎和东侧奥约/达荷美分开。" },
    oyo: { en: "Oyo is a Yoruba empire north of Lagos in southwestern Nigeria, strongest in the 17th and 18th centuries. It is kept as a separate coastal/forest sub-lane rather than merged with Benin or Ashanti.", cn: "奥约是位于今尼日利亚西南、拉各斯以北的约鲁巴帝国，17至18世纪最强。它被保留为独立的沿海/森林子栏，而不是与贝宁或阿散蒂合并。" },
    ashanti: { en: "Ashanti/Asante is centered on Kumasi and the Akan forest zone of present-day Ghana. Its narrow placement avoids conflating it with Benin, Oyo, or the northern Sokoto Caliphate.", cn: "阿散蒂/阿善提以库马西和今加纳阿坎森林区为中心。窄化布局避免把它与贝宁、奥约或北方索科托哈里发混同。" },
    dahomey_late: { en: "Dahomey carries the Abomey-centered kingdom after Oyo's decline opened space on the western Bight of Benin. It prevents the late 19th-century coastal strip from going blank before French conquest.", cn: "达荷美承接奥约衰落后贝宁湾西侧出现空间时，以阿波美为中心的王国。它避免19世纪后期沿海窄栏在法国征服之前变成空白。" },
    british_niger_coast_transition: { en: "British Niger Coast is a short transition strip after the 1897 Benin expedition and before the broader 1902 colonial West Africa lane. It marks British coastal Nigeria/Southern Nigeria consolidation without swallowing French Dahomey or Ashanti early.", cn: "英属尼日尔海岸是1897年贝宁远征之后、1902年更宽殖民西非栏之前的短期过渡。它标记英属尼日利亚海岸/南尼日利亚整合，但不提前吞掉法属达荷美或阿散蒂。" },
    french_dahomey: { en: "French Dahomey is the short protectorate/colonial transition after the defeat of Behanzin and the French conquest of Dahomey. Keeping it beside British coastal Nigeria makes late colonial partition visible before the composite colonial lane begins.", cn: "法属达荷美表示贝汉津战败和法国征服达荷美之后的短期保护国/殖民过渡。它与英属尼日利亚海岸并列，使晚期殖民瓜分在复合殖民栏开始前可见。" },
    sokoto: { en: "Sokoto is the eastern Hausaland-Fulani side of the Sahel lane, not the whole post-1804 West African Sahel. Bambara, Toucouleur, and French West African phases remain adjacent western records; they do not fill a carved Sokoto edge.", cn: "索科托表示萨赫勒栏东侧的豪萨兰-富拉尼部分，而不是1804年后整个西非萨赫勒。班巴拉、图库洛尔和法属西非阶段保留为相邻的西侧记录，不填补索科托的切边。" },
    french_west: { en: "French West Africa is narrowed to the French western and central Sahel after the conquest of the Toucouleur sphere. Sokoto and then British Northern Nigeria remain a separate eastern lane, with the boundary expressed by frontier links rather than owner-fill geometry.", cn: "法属西非收窄为法国征服图库洛尔范围之后的西部和中部萨赫勒。索科托以及后来的英属北尼日利亚保留为东侧独立栏，其边界由边疆联系表达，而不是由主人填充几何表达。" },
    british_northern_nigeria: { en: "British Northern Nigeria carries the former Sokoto/Hausaland side after the 1903 British conquest and indirect-rule protectorate. It is kept beside French West Africa as an adjacent colonial lane, not as a cutout owner or a swallowed French fragment.", cn: "英属北尼日利亚承接1903年英国征服和间接统治保护国之后的原索科托/豪萨兰一侧。它作为相邻殖民栏与法属西非并列，而不是缺口主人，也不是被法属块吞掉的片段。" },
    british_west: { en: "Colonial West Africa is a composite Guinea Coast colonial lane after 1902. The label is deliberately broader than British West Africa because the simplified full-width strip also covers neighboring coastal colonial contexts such as French Dahomey.", cn: "殖民西非是1902年后的几内亚湾沿海复合殖民栏。此标签刻意比“英属西非”更宽，因为简化的满宽窄条也压缩了法属达荷美等相邻沿海殖民语境。" },
    sahel_modern: { en: "Modern Sahel States represent the post-1960 francophone western and central Sahel succession from French West Africa. Northern Nigeria is separated into a neighboring modern-republic fragment to preserve the colonial-to-modern owner chain.", cn: "现代萨赫勒诸国表示1960年后从法属西非继承而来的法语区西部和中部萨赫勒。尼日利亚北部被拆成相邻现代共和国片段，以保留殖民到现代的主人链。" },
    nigeria_north_modern: { en: "Northern Nigeria is shown as the modern republic-side successor to British Northern Nigeria within the simplified Sahel lane. It is a regional fragment of Nigeria, not a separate sovereign state.", cn: "尼日利亚北部显示为简化萨赫勒栏中英属北尼日利亚的现代共和国侧继承者。它是尼日利亚的区域片段，不是独立主权国家。" },
    west_modern: { en: "West African States is a composite postcolonial owner for the Guinea Coast lane after British and other colonial structures give way to independent republics and monarchies.", cn: "西非诸国是几内亚湾沿海栏在英国等殖民结构让位给独立共和国与君主制后的复合后殖民主人。" },
    // Americas
    meso_prehistoric: { en: "Archaic Mesoamerica marks village formation, maize agriculture, and the deep cultural substrate before named Olmec centers appear. It is a cultural owner, not a centralized state.", cn: "中美洲古风时期表示村落形成、玉米农业和奥尔梅克中心出现前的深层文化基础。它是文化主人，而不是中央集权国家。" },
    central_america_prehistoric: { en: "Early Central American and Maya-lowland cultures fill the mainland lane before the Olmec-Maya interaction zone becomes visible. The chart treats this as inhabited cultural space, not an empty gap.", cn: "早期中美洲与玛雅低地文化填补奥尔梅克-玛雅互动带出现前的大陆栏位。图中把这里视为有人居住的文化空间，而不是空白缺口。" },
    early_maya_formative: { en: "Early Maya/Formative communities occupy the Maya-lowland lane beside the Olmec influence strip. The split makes interaction visible without implying annexation or a missing territorial bite.", cn: "早期玛雅/形成期社群占据玛雅低地栏，旁边是奥尔梅克影响带。这种拆分显示互动，但不暗示吞并或缺失领土切口。" },
    olmec: { en: "The Olmec block is now the Gulf Coast heartland in Veracruz and Tabasco, not all of Mesoamerica. Its broader cultural influence on later Maya and central Mexican traditions is noted without covering them.", cn: "奥尔梅克图块现在表示韦拉克鲁斯与塔巴斯科一带的墨西哥湾沿岸核心，而非整个中美洲。其对后来玛雅和中墨西哥传统的文化影响保留在说明中，但不覆盖它们。" },
    olmec_maya_influence: { en: "This narrow strip marks Olmec-style exchange and cultural influence into early Maya and southern Mesoamerican zones. It stays whole because influence is not territorial ownership.", cn: "这个窄带表示奥尔梅克风格交流及其对早期玛雅和中美洲南部区域的文化影响。它保持完整，因为影响不等于领土所有。" },
    andes_prehistoric: { en: "Early Andean cultures represent the long coastal-highland sequence before Chavín, including ceremonial centers, fishing-farming exchange, and regional traditions that later horizons inherited.", cn: "早期安第斯文化表示查文之前漫长的海岸-高地序列，包括仪式中心、渔业-农业交换和后续诸视野继承的区域传统。" },
    brazil_prehistoric: { en: "Precolonial Brazil is shown as an Indigenous cultural lane across Amazonian, coastal, and interior societies. It is a diversity label, not a single state.", cn: "前殖民巴西以亚马孙、沿海和内陆原住民社会的文化栏显示。它是多样性标签，而不是单一国家。" },
    na_prehistoric: { en: "Native North American cultures before the mound-building lane include Archaic, Woodland, Southwestern, Plains, and coastal traditions. The abstraction keeps the land inhabited without inventing one empire.", cn: "土墩建造者栏之前的北美原住民文化包括古风、林地、西南、平原和沿海传统。抽象方式保留有人居住的土地，而不虚构单一帝国。" },
    canada_prehistoric: { en: "First Nations and Inuit predecessor cultures fill the northern lane before French imperial contact, emphasizing long occupation across Arctic, Subarctic, Pacific, Plains, and St. Lawrence worlds.", cn: "第一民族和因纽特前身文化填补法国帝国接触前的北方栏，强调北极、亚北极、太平洋、平原和圣劳伦斯诸世界的长期居住。" },
    carib_prehistoric: { en: "Caribbean island cultures represent pre-Columbian canoe networks, Arawakan/Taino developments, cassava agriculture, and island societies before the Spanish Caribbean lane begins in 1492.", cn: "加勒比岛屿文化表示前哥伦布时代的独木舟网络、阿拉瓦克/泰诺发展、木薯农业和1492年西属加勒比开始前的岛屿社会。" },
    chavin: { en: "Chavín is the early Andean religious and artistic horizon centered on Chavín de Huántar. It is drawn as an Andean cultural-political owner before the Early Intermediate regional cultures.", cn: "查文是以查文德万塔尔为中心的早期安第斯宗教与艺术视野。它在早期中间期区域文化之前作为安第斯文化-政治主人显示。" },
    teotihuacan: { en: "Teotihuacan is drawn as the Basin of Mexico urban core. Its trade and cultural influence spread widely, including into the Maya world, but the Maya remain a separate polity lane.", cn: "特奥蒂瓦坎绘为墨西哥盆地城市核心。其贸易和文化影响广泛传播，包括进入玛雅世界，但玛雅仍保持为独立政权栏。" },
    teotihuacan_maya_contact: { en: "This narrow fragment marks Teotihuacan-Maya contact and influence, especially elite and ritual links, rather than territorial rule over the whole Maya lowlands.", cn: "这个窄片段表示特奥蒂瓦坎与玛雅之间的接触和影响，尤其是精英与仪式联系，而不是对整个玛雅低地的领土统治。" },
    maya_preclassic: { en: "Maya Preclassic culture is kept in the Maya/Central America lane, parallel to Olmec, Zapotec/Isthmian, and central Mexican developments while still acknowledging shared Mesoamerican influence.", cn: "玛雅前古典文化保留在玛雅/中美洲栏，与奥尔梅克、萨波特克/地峡和中墨西哥发展并列，同时承认共同的中美洲文化影响。" },
    preclassic: { en: "Preclassic Mesoamerica now reads as a central Mexican / broader Formative lane beside separate Maya development and Zapotec-Isthmian centers. Regionalism and contact are shown without a false cutout owner.", cn: "前古典中美洲现在表示中墨西哥及更广泛形成期栏位，与独立的玛雅发展和萨波特克-地峡中心并列。区域化与接触被显示出来，但不制造虚假的缺口主人。" },
    zapotec_preclassic: { en: "Zapotec/Isthmian Preclassic centers such as Monte Albán and Oaxaca-area polities appear as their own southern Mesoamerican lane, not as a filler for a Maya or Olmec territorial cutout.", cn: "萨波特克/地峡前古典中心，如蒙特阿尔班和瓦哈卡区域政权，作为自己的中美洲南部栏出现，而不是玛雅或奥尔梅克领土切口的填充物。" },
    early_intermediate: { en: "The Andean Early Intermediate period marks post-Chavín regional florescence, including Moche, Nazca, Recuay, and other coastal-highland cultures rather than one empire.", cn: "安第斯早期中间期表示查文之后的区域繁荣，包括莫切、纳斯卡、雷夸伊等海岸-高地文化，而非一个帝国。" },
    moundbuilders: { en: "Mound Builders summarizes Adena, Hopewell, Mississippian, and related earthwork traditions, with Cahokia as the later major center. It fills North America with regional societies rather than blank space.", cn: "土墩建造者概括阿德纳、霍普韦尔、密西西比及相关土方传统，后期以卡霍基亚为重要中心。它以区域社会填补北美，而不是留白。" },
    maya_classic: { en: "The Classic Maya (AD 250-900) developed the Americas' most sophisticated writing system and city-state courts. It is drawn separately from Teotihuacan because influence and contact were not the same as annexation.", cn: "古典玛雅（250-900年）发展出美洲最复杂的文字系统和城邦宫廷。它与特奥蒂瓦坎分开绘制，因为影响和接触不等于吞并。" },
    epiclassic: { en: "Epiclassic Central Mexico is no longer a blank rectangle after Teotihuacan. It marks competing city-state centers such as Xochicalco and Cholula, with southern Mesoamerican networks shown beside it as their own lane rather than as a land-bite cutout.", cn: "末古典中墨西哥不再是特奥蒂瓦坎之后的空白矩形。它表示霍齐卡尔科、乔卢拉等竞争性城邦中心；中美洲南部网络以自己的并列栏显示，而不是土地缺口。" },
    epiclassic_southern_mesoamerica: { en: "This narrow corridor represents the Xochicalco / Gulf / Oaxaca contact field between central Mexico and the surviving Classic Maya. It is a network lane for exchange, fortified centers, and regional continuity, not a cutout owner or one state.", cn: "这个窄走廊表示中墨西哥与仍存古典玛雅之间的霍齐卡尔科/海湾/瓦哈卡接触场。它是交流、设防中心和区域延续的网络栏，不是缺口主人，也不是单一国家。" },
    middle_horizon: { en: "The Andean Middle Horizon is represented by Wari and Tiwanaku integration across highland and coastal networks. It is an imperial/cultural horizon rather than a single seamless state.", cn: "安第斯中期视野以瓦里和蒂瓦纳库对高地与海岸网络的整合表示。它是帝国/文化视野，而非无缝单一国家。" },
    toltec: { en: "The Toltec/Tula block is narrowed to central Mexico. Toltec-Maya artistic and religious connections are shown as influence rather than as a single empire covering the Maya world.", cn: "托尔特克/图拉图块窄化为中墨西哥核心。托尔特克-玛雅的艺术和宗教联系作为影响显示，而不是覆盖玛雅世界的单一帝国。" },
    toltec_maya_contact: { en: "This fragment represents Toltec-Maya contact and the Chichen Itza / Yucatan-style exchange zone, not direct Toltec occupation of all Maya polities.", cn: "这个片段表示托尔特克-玛雅接触以及奇琴伊察/尤卡坦式交流区，而不是托尔特克直接占据所有玛雅政权。" },
    maya_post: { en: "Postclassic Maya polities in Yucatan and the highlands persisted beside Toltec and later Aztec powers. The half-width placement keeps that survival visible through the Aztec collapse boundary.", cn: "后古典玛雅政权在尤卡坦和高地持续存在，与托尔特克和后来的阿兹特克并立。半宽布局把这种存续延伸到阿兹特克崩溃边界。" },
    late_intermediate: { en: "The Late Intermediate Andes covers regional kingdoms and chiefdoms after Wari/Tiwanaku, especially Chimú and highland polities that preceded Inca expansion from Cuzco.", cn: "安第斯晚期中间期表示瓦里/蒂瓦纳库之后的区域王国与酋邦，尤其是奇穆和印加自库斯科扩张前的高地政权。" },
    postclassic: { en: "Post-Toltec central Mexico is drawn as a plural city-state field rather than an empty pause before the Aztec Triple Alliance. Azcapotzalco, Texcoco, Cholula, and neighboring altepetl-style powers competed until the 1428 break.", cn: "托尔特克之后的中墨西哥绘为复数城邦场，而不是阿兹特克三国同盟前的空档。阿斯卡波察尔科、特斯科科、乔卢拉及相邻阿尔特佩特尔式政权竞争，直到1428年的转折。" },
    postclassic_southern_mesoamerica: { en: "The Cholula / Mixtec-Puebla / Zapotec corridor is a visible network lane between central Mexico and Maya polities after Tula declined. It makes regionalism, style, religion, and trade visible without drawing a land-bite cutout.", cn: "图拉衰落后，乔卢拉/米斯特克-普埃布拉/萨波特克走廊作为中墨西哥与玛雅政权之间的可见网络栏。它显示区域主义、风格、宗教与贸易，但不画土地缺口。" },
    aztec: { en: "The Aztec Triple Alliance is drawn as a central Mexican imperial core centered on Tenochtitlan. Tribute pressure toward southern Mexico is shown separately so Maya polities are not erased.", cn: "阿兹特克三国同盟绘为以特诺奇蒂特兰为中心的中墨西哥帝国核心。向墨西哥南部的朝贡压力另行显示，避免抹去玛雅政权。" },
    aztec_southern_tribute: { en: "This narrowed tributary fragment marks Aztec pressure into southern Mexico and adjacent Mesoamerican zones. It is kept whole because tribute hegemony is not the same as owning the Maya lane.", cn: "这个窄化朝贡片段表示阿兹特克向墨西哥南部和相邻中美洲区域施加的压力。它保持完整，因为朝贡霸权不等于拥有玛雅栏位。" },
    maya_conquest_transition: { en: "After Tenochtitlan fell, the Maya / Central America lane becomes a contested conquest-frontier rather than an ownerless pause: K'iche', Yucatan, Peten, and other Maya polities persisted while Spanish campaigns pushed inward.", cn: "特诺奇蒂特兰陷落后，玛雅/中美洲栏不是无主停顿，而是征服边疆：基切、尤卡坦、佩滕及其他玛雅政权仍在，西班牙战役逐步推进。" },
    spanish_carib: { en: "The Spanish Caribbean is now a separate Caribbean lane beginning with Columbus in 1492, instead of occupying the Maya/Central America lane.", cn: "西属加勒比现在放在独立的加勒比栏，自1492年哥伦布到达开始，而不是占据玛雅/中美洲栏。" },
    new_spain: { en: "New Spain is drawn first as the Mexico-centered colonial core after the fall of Tenochtitlan. Central America is shown separately because it was administered through a distinct captaincy-general structure within the wider viceroyalty.", cn: "新西班牙首先绘为特诺奇蒂特兰陷落后的墨西哥殖民核心。中美洲另行显示，因为它在更大的总督辖区内通过相对独立的都督辖区治理。" },
    new_spain_central_america: { en: "This narrowed fragment marks the Spanish Central American colonial core after the Captaincy General of Guatemala coalesces. It deliberately leaves a parallel Maya holdout lane until Nojpeten falls in 1697.", cn: "这个窄化片段表示危地马拉都督辖区形成后的西班牙中美洲殖民核心。它有意给玛雅残存势力留下并行栏，直到1697年诺赫佩滕陷落。" },
    maya_late_independent: { en: "Independent Maya holdouts, especially the Itza and neighboring Peten lowland groups, persisted beside Spanish Central America for more than a century and a half after the Aztec collapse.", cn: "玛雅独立残存势力，尤其是伊察及佩滕低地相邻群体，在阿兹特克崩溃后仍与西班牙中美洲并存一个半世纪以上。" },
    new_spain_central_america_late: { en: "After the Spanish capture of Nojpeten in 1697, the simplified Central American colonial lane can return to full width until independence in 1821.", cn: "1697年西班牙攻占诺赫佩滕后，简化的中美洲殖民栏可以恢复全宽，一直延续到1821年独立。" },
    viceroyalty_peru: { en: "The Viceroyalty of Peru is a Lima-centered Spanish Andean colonial owner after the Inca conquest. In this simplified lane it compresses a changing imperial geography, including later losses to New Granada and Rio de la Plata, until the independence wars hand the slot to postcolonial Andean republics.", cn: "秘鲁总督区表示印加征服后以利马为中心的西属安第斯殖民主人。在这个简化栏中，它压缩了不断变化的帝国地理，包括后来让出新格拉纳达和拉普拉塔方向的范围，直到独立战争把该栏交给后殖民安第斯共和国。" },
    granada_plata_viceroyalties: { en: "New Granada + Rio de la Plata is a deliberately composite, non-contiguous owner strip. It marks the northern and southern viceroyalties split from Peru in the Bourbon era, so Peru's late colonial contraction has named recipients instead of a blank bite.", cn: "新格拉纳达 + 拉普拉塔是有意设置的复合、非连续主人窄条。它表示波旁改革时代从秘鲁拆出的北方和南方总督辖区，使秘鲁后期殖民收缩有具名承接者，而不是空白缺口。" },
    brazil_colony: { en: "Colonial Brazil carries the Portuguese American lane from the 1500 claim through sugar, gold, slavery, inland expansion, and the Rio de Janeiro capital shift. It hands the same simplified owner-space to the Brazilian Empire in 1822 rather than ending in a blank.", cn: "殖民巴西承接葡萄牙美洲栏，从1500年的宣称延伸到糖业、金矿、奴隶制、内陆扩张以及迁都里约热内卢。1822年它把同一简化主人空间交给巴西帝国，而不是留下空白。" },
    new_france: { en: "New France marks the French St. Lawrence, Great Lakes, Acadian, and interior trade world. The block is a northern colonial network rather than all Canada, and its 1763 transfer is linked to British North America.", cn: "新法兰西表示法国在圣劳伦斯河、五大湖、阿卡迪亚和内陆贸易世界中的殖民网络。该块是北方殖民网络，不等于整个加拿大；1763年的转移连接到英属北美。" },
    thirteen_col: { en: "The Thirteen Colonies represent Britain's Atlantic seaboard colonies from Jamestown to independence. They occupy the future United States lane while Native Nations and later continental expansion remain separate historical pressures.", cn: "十三殖民地表示英国在大西洋沿岸的殖民地，从詹姆斯敦到独立。它们占据后来的美国栏，同时原住民诸部和后来的大陆扩张作为不同历史压力保留。" },
    british_na: { en: "British North America is the post-1763 northern colonial order, absorbing former French Canada while the revolting thirteen colonies leave a separate United States lane. It continues until Confederation creates Canada in 1867.", cn: "英属北美表示1763年后的北方殖民秩序，吸收原法属加拿大，同时反叛的十三殖民地脱离为单独的美国栏。它延续到1867年加拿大联邦成立。" },
    usa_early: { en: "Early United States covers the republic from independence through constitution-making, the Louisiana Purchase, forced westward expansion, and the 1848 Mexican Cession threshold. The later United States block begins after this continental turn.", cn: "早期美国表示从独立、制宪到路易斯安那购地、强制性西进扩张以及1848年墨西哥割让门槛前后的共和国。后续美国块从这个大陆性转折之后开始。" },
    western_borderlands: { en: "Western Borderlands is a composite frontier owner beside the early United States: Indigenous polities, Spanish and French claims, then Mexican northern territories. It fills the pre-1848 western strip so U.S. expansion reads as transfer from named owners, not empty land.", cn: "西部边疆是早期美国旁的复合边疆主人：原住民政权、西班牙与法国宣称，后来为墨西哥北部领土。它填补1848年前的西部窄条，使美国扩张读作从具名主人手中转移，而不是进入空地。" },
    brazil_empire: { en: "The Brazilian Empire is the monarchy created by independence from Portugal under Pedro I and then Pedro II. It keeps Brazil in one owner chain through territorial consolidation, slavery's abolition, and the 1889 republican coup.", cn: "巴西帝国是由佩德罗一世、后由佩德罗二世维系的独立君主国。它让巴西在同一主人链中穿过疆域整合、废奴和1889年共和政变。" },
    andean_republics: { en: "Andean Republics is explicitly a composite owner: Peru, Bolivia, Ecuador, Colombia, and neighboring post-Spanish republics share the compressed Andean slot after the collapse of viceregal rule. It is not a single state, but it prevents the post-1824 Andes from becoming ownerless.", cn: "安第斯共和国明确是复合主人：秘鲁、玻利维亚、厄瓜多尔、哥伦比亚及相邻后西班牙共和国共同承接总督统治崩解后的压缩安第斯栏。它不是单一国家，但避免1824年后的安第斯变成无主地。" },
    usa: { en: "The United States block begins after the 1848 continental expansion threshold and carries the republic through Civil War, industrialization, overseas power, world wars, civil rights, and Cold War superpower status.", cn: "美国块从1848年前后的大陆扩张门槛后开始，贯穿内战、工业化、海外强权、两次世界大战、民权运动和冷战超级大国地位。" },
    canada: { en: "Canada begins with the 1867 Confederation from British North American colonies. The block marks a self-governing dominion and later fully sovereign federal state rather than a simple continuation of New France.", cn: "加拿大始于1867年英属北美殖民地的联邦化。该块表示自治领以及后来的完全主权联邦国家，而不是新法兰西的简单延续。" },
    brazil: { en: "Republican Brazil succeeds the empire after 1889, carrying the Brazilian lane through oligarchic republics, Vargas, Brasilia, military rule, and democratic restoration before the dataset ends.", cn: "巴西共和国在1889年后承接帝国，带着巴西栏穿过寡头共和国、瓦加斯时代、巴西利亚、军政府统治和民主恢复，直到当前数据集结束。" },
    colonial_carib: { en: "The colonial Caribbean is separated from Central America because the island world became a multi-imperial plantation and maritime zone contested by Spain, Britain, France, the Netherlands, and Denmark.", cn: "殖民加勒比与中美洲分开，因为岛屿世界成为西班牙、英国、法国、荷兰、丹麦争夺的多帝国种植园与海上区域。" },
    central_america_mexican_interlude: { en: "The brief 1821-1823 Mexican imperial interlude is made explicit so Central America does not disappear between Spanish rule and the United Provinces.", cn: "1821-1823年的短暂墨西哥帝国插曲被明确画出，使中美洲不会在西班牙统治与中美洲联合省之间消失。" },
    central_america: { en: "Central America begins after independence from Spain and the short Mexican imperial interlude. It is no longer hidden under Caribbean or Mexican rectangles.", cn: "中美洲从摆脱西班牙并经历短暂墨西哥帝国插曲后开始显示。它不再被加勒比或墨西哥矩形遮住。" },
    caribbean: { en: "Modern Caribbean states are kept in their own island lane after decolonization, distinct from Central America and Mexico.", cn: "现代加勒比国家在去殖民化后保留于自己的岛屿栏，与中美洲和墨西哥区分。" },
    native_nations: { en: "Native Nations are no longer drawn across the Canada lane. This keeps the current North American simplification from implying that one United States-side rectangle also represents New France or Canada.", cn: "原住民诸部不再跨到加拿大栏。这样可避免当前北美简化模型暗示美国一侧的矩形也代表新法兰西或加拿大。" },
    inca: { en: "The Inca Empire was the largest in pre-Columbian America, administered without writing using the khipu (knotted cords) for records, and connected by 40,000 km of roads through the Andes. Machu Picchu, their royal retreat, was never found by the Spanish.", cn: "印加帝国是前哥伦布时代美洲最大的帝国，以结绳（奇普）代替文字进行管理，安第斯山脉上修筑了4万公里道路。皇家秘所马丘比丘从未被西班牙人发现。" },
    // More context entries
    han_west: { en: "The Western Han consolidated China's imperial identity — Confucianism became state orthodoxy, paper was invented, the Silk Road opened, and Emperor Wu pushed borders deep into Central Asia. The term 'Han Chinese' comes from this dynasty.", cn: "西汉巩固了中国的帝国身份——儒学成为官方正统，造纸术发明，丝绸之路开通，汉武帝将疆域深推入中亚。'汉人'之称源于此朝。" },
    tang: { en: "The Tang dynasty is often called China's golden age. Chang'an was the world's largest city, drawing merchants, monks, and diplomats from across Eurasia. Poetry (Li Bai, Du Fu, Wang Wei), woodblock printing, the civil-service exam and Buddhist art all flourished.", cn: "唐朝常被称为中国的黄金时代。长安是当时世界最大的城市，吸引欧亚大陆各地的商人、僧侣与使节。诗歌（李白、杜甫、王维）、雕版印刷、科举与佛教艺术皆在此时兴盛。" },
    jin_west: { en: "Western Jin starts as the Sima clan's north-China / Cao-Wei successor core. It sits beside the surviving Eastern Wu lane and the Jin-held former Shu fragment until the 280 conquest of Wu.", cn: "西晋起初表示司马氏在中国北方、继承曹魏的核心区。它在280年灭吴前与仍存的东吴栏、以及晋控原蜀地片段并列。" },
    jin_west_unified: { en: "This unified Western Jin phase begins only after Wu fell in 280. It is kept full-width because the southern lane no longer had a separate owner after the conquest; the next fragmentation is shown by the Sixteen Kingdoms and Eastern Jin split.", cn: "这个西晋统一阶段只从280年吴亡后开始。它保持全宽，因为征服后南方栏不再有独立主人；下一次分裂由十六国与东晋的分栏显示。" },
    liu_bei_shu_domain: { en: "Liu Bei's Shu domain is a one-year visual bridge after the Han abdication and before the Shu-Han imperial proclamation. It keeps the Sichuan/Hanzhong southwest owned without backdating the formal Shu-Han dynasty.", cn: "刘备蜀地是在汉室禅让后、蜀汉正式称帝前的一年视觉承接。它让四川/汉中西南保持有主人，而不把正式蜀汉王朝提前。" },
    shu_han: { en: "Shu Han is now its own southwest half-lane from 221 to the Wei conquest in 263. Its fall narrows the anti-Wei southern field before Eastern Wu finally falls in 280.", cn: "蜀汉现在作为221年至263年魏灭蜀之间的西南半栏单独显示。它的灭亡先让反魏南方格局变窄，早于280年东吴最终灭亡。" },
    sun_quan_wu_domain: { en: "Sun Quan's Wu domain bridges the lower Yangtze south from the Han abdication to Wu's 222 declaration. It is a territorial-control bridge, not a claim that the formal Wu empire started early.", cn: "孙权吴地承接从汉室禅让到222年吴国正式宣示之间的长江下游南方。它表示地域控制承接，并不声称正式吴帝国提前建立。" },
    eastern_wu: { en: "Eastern Wu holds the lower Yangtze and far-southern half-lane until Western Jin conquers it in 280. The block stays beside Wei/Jin-held former Shu after 263 so Wu's survival is visible.", cn: "东吴占据长江下游和南方半栏，直到280年为西晋所灭。263年后它仍与魏/晋控制的原蜀地并列，因此吴的继续存在清楚可见。" },
    wei_shu_commanderies: { en: "Wei-held Shu commanderies fill the former Shu-Han half-lane after the 263 conquest and before Sima Jin replaces Wei in 266. Same-color adjacency lets this read as Wei expansion rather than empty land.", cn: "魏控蜀地填入263年灭蜀后、266年司马晋代魏前的原蜀汉半栏。同色相邻使它读作曹魏扩张，而不是空白土地。" },
    jin_shu_commanderies: { en: "Jin-held Shu commanderies carry the former Shu half-lane from the 266 Jin takeover until Wu falls in 280. It makes the southwest part of Jin while Eastern Wu remains a separate owner.", cn: "晋控蜀地承接266年晋代魏后至280年吴亡前的原蜀半栏。它让西南归入西晋，同时东吴仍作为独立主人存在。" },
    cao_wei: { en: "Cao Wei is the northern Three Kingdoms successor after Cao Pi ended Eastern Han rule. It stays in the north lane, then visually gains the former Shu fragment in 263 instead of becoming instant unified China.", cn: "曹魏表示曹丕终结东汉后形成的北方三国继承政权。它保留在北方栏，并在263年视觉取得原蜀地片段，而不是瞬间变成统一中国。" },
    early_sixteen_kingdoms: { en: "Early Sixteen Kingdoms is the first northern-China fragmentation field after Western Jin lost the north in 316. It names the Han-Zhao, Later Zhao, Former Liang, Former Yan and related owner field without pretending there was one continuous state.", cn: "十六国前期表示316年西晋失去北方后的第一段华北割据场。它概括汉赵、后赵、前凉、前燕等主人，而不假装存在一个连续国家。" },
    former_qin_guanzhong: { en: "Former Qin Core marks the Di-led Fu clan regime rising from Chang'an and Guanzhong before it absorbed the remaining northern rivals. The adjacent rival block keeps the north owner-filled without giving Former Qin too much territory too early.", cn: "前秦核心表示氐族苻氏政权在长安/关中兴起、尚未吞并北方诸国前的阶段。旁侧的诸国块让北方保持有主人，同时不提前夸大前秦疆域。" },
    rival_north_kingdoms: { en: "Rival Northern Kingdoms keeps the remaining Sixteen Kingdoms field visible beside the rising Former Qin until 376. It is a composite owner for Former Yan, Former Liang, Dai, and other courts rather than blank land.", cn: "北方诸国在376年前与兴起的前秦并列，保留十六国格局中其他主人。它是前燕、前凉、代国等政权的复合主人，而不是空白土地。" },
    former_qin_north_unified: { en: "Former Qin North shows Fu Jian's short northern unification after 376. It deliberately stays in the northern lane beside Eastern Jin, because Fei River was not a full conquest of southern China.", cn: "前秦北方表示苻坚376年后短暂统一北方。它刻意保留在北方栏并与东晋并列，因为淝水之战前后都不是对南方中国的完整征服。" },
    post_fei_north_kingdoms: { en: "Post-Fei River North is the brief breakup field after Former Qin's defeat in 383. It prevents a gap between Former Qin collapse and the Tuoba Northern Wei rise.", cn: "淝水后北方表示383年前秦受挫后迅速瓦解的短暂割据场。它避免前秦崩解与拓跋北魏兴起之间出现空白。" },
    northern_wei_rise: { en: "Northern Wei Rise starts the Tuoba state before it unified all northern China. It owns one side of the northern lane while later Sixteen Kingdoms survivors remain visible until 439.", cn: "北魏崛起表示拓跋国家在统一北方前的阶段。它占据北方栏一侧，同时让十六国后期残余主人持续可见至439年。" },
    later_sixteen_kingdoms: { en: "Later Sixteen Kingdoms is the post-386 mosaic of Later Qin, Later Yan, Xia, Northern Liang, and related regimes. It is the explicit counterpart that Northern Wei absorbs in 439.", cn: "十六国后期表示386年后后秦、后燕、夏、北凉等政权拼图。它是439年被北魏吸收的明确对应主人。" },
    e_jin: { en: "Eastern Jin is the Jiankang refugee court in the lower Yangtze after the north fell. It carries southern dynastic legitimacy and the Red River commandery connection beside the changing northern owner sequence.", cn: "东晋是北方失守后建康的流亡朝廷。它在不断变化的北方主人序列旁承接南方正统与红河郡县联系。" },
    n_wei: { en: "Northern Wei, founded by the Tuoba/Xianbei, expands from the pre-439 rise block into full northern rule in 439 and becomes the strongest northern dynasty before it split into eastern and western successor courts.", cn: "北魏由拓跋/鲜卑建立，从439年前的崛起块扩展为北方统一政权，并在分裂为东西继承朝廷前成为最强北朝。" },
    eastern_wei: { en: "Eastern Wei is the Ye-centered eastern successor after the Northern Wei split. It keeps the richer eastern half of the north visible before Gao Yang replaced it with Northern Qi in 550.", cn: "东魏是北魏分裂后以邺为中心的东部继承政权。它在550年高洋建立北齐前承接较富庶的东半北方。" },
    western_wei_bridge: { en: "The Chang'an Wei bridge covers the short western-court transition after the 534 Northern Wei split and before the formal Western Wei line. It prevents the west from becoming a one-year blank.", cn: "长安魏承接表示534年北魏分裂后、西魏正式成形前的短暂西部朝廷过渡，避免西侧出现一年空白。" },
    western_wei: { en: "Western Wei is the Chang'an-centered western successor to Northern Wei, dominated by Yuwen Tai's military-political coalition before Northern Zhou replaced it.", cn: "西魏是以长安为中心的北魏西部继承政权，由宇文泰的军政集团主导，并由北周取代。" },
    northern_qi: { en: "Northern Qi succeeds Eastern Wei at Ye and owns the eastern half of northern China until Northern Zhou conquers it in 577.", cn: "北齐在邺承接东魏，拥有北方东半，直到577年被北周攻灭。" },
    northern_zhou: { en: "Northern Zhou succeeds Western Wei in the west. It remains a western half-lane until its 577 conquest of Northern Qi turns it into the full northern owner.", cn: "北周在西部承接西魏。它在577年灭北齐前保持为西半栏主人，之后扩展为完整北方主人。" },
    northern_zhou_unified: { en: "Northern Zhou Unified North shows the brief 577-581 moment when the Zhou court controlled northern China before Yang Jian founded Sui.", cn: "北周统一北方表示577至581年北周控制北方中国、早于杨坚建立隋朝的短暂阶段。" },
    sui: { en: "Sui Core covers the northern dynasty founded in 581 before the final southern conquest. It remains beside Chen until the 589 reunification.", cn: "隋核心表示581年建立、尚未完成南方征服的北方王朝。它在589年统一前与陈并列。" },
    sui_unified: { en: "Sui Unified begins after the 589 conquest of Chen. It stays full-width because Chen no longer exists as a contemporaneous owner to fill a notch.", cn: "隋统一始于589年灭陈之后。此后它保持全宽，因为陈已不再作为同时期主人来承接缺口。" },
    liu_song_south: { en: "Liu Song is the first Southern Dynasty after Eastern Jin, holding the Jiankang-centered southern lane from 420 to 479.", cn: "刘宋是东晋之后第一个南朝，在420至479年承接以建康为中心的南方栏。" },
    southern_qi: { en: "Southern Qi succeeds Liu Song at Jiankang and keeps southern political continuity visible during Northern Wei pressure.", cn: "南齐在建康承接刘宋，使北魏压力下的南方政治连续性保持可见。" },
    liang_dynasty: { en: "Liang is the long southern Jiankang dynasty from 502 to the mid-6th-century crisis, before Chen becomes the last southern owner.", cn: "梁是502年起延续较久的建康南朝，在6世纪中叶危机后由最后的南方主人陈承接。" },
    chen_dynasty: { en: "Chen is the last Southern Dynasty. It owns the south until Sui conquered Jiankang in 589 and reunified China.", cn: "陈是最后一个南朝，拥有南方直到589年隋攻取建康并重新统一中国。" },
    later_liang_north: { en: "Later Liang is the first northern Five Dynasties owner after Zhu Wen ended Tang rule in 907. It keeps the Central Plain transition explicit instead of folding all post-Tang years into one gray block.", cn: "后梁是朱温907年终结唐朝后北方五代的第一个主人。它让中原过渡保持明确，而不是把所有唐后年份压进一个灰块。" },
    later_tang_north: { en: "Later Tang replaces Later Liang in 923 and briefly projects stronger northern authority, including the 925 conquest of Former Shu.", cn: "后唐于923年取代后梁，并短暂展现较强北方权威，包括925年灭前蜀。" },
    later_jin_north: { en: "Later Jin follows the 936 overthrow of Later Tang with Khitan/Liao support. Its cession of the Sixteen Prefectures keeps the northern frontier story visible.", cn: "后晋在936年借契丹/辽支持推翻后唐而起。其割让燕云十六州，使北方边疆故事保持可见。" },
    later_han_north: { en: "Later Han is the short 947-951 northern regime after the Khitan withdrawal from Kaifeng. Its fall produces both Later Zhou and the Northern Han holdout.", cn: "后汉是947至951年契丹退出开封后的短促北方政权。它的崩解同时通向后周和北汉残余。" },
    later_zhou_north: { en: "Later Zhou is the last of the Five Dynasties. It narrows beside Northern Han, then gives way to Zhao Kuangyin's Song in 960.", cn: "后周是五代最后一朝。它与北汉并列收窄，随后于960年让位给赵匡胤建立的宋。" },
    northern_han_taiyuan: { en: "Northern Han is the Taiyuan holdout after Later Han's fall. It survives beside Later Zhou and early Song until Song conquest in 979.", cn: "北汉是后汉灭亡后的太原残余政权。它在后周和北宋初年旁侧延续，直到979年为宋所灭。" },
    n_song: { en: "Northern Song Core is drawn as the Kaifeng-centered state founded in 960. Its early right-edge cutout is filled by Northern Han until 979, so Song does not visually own Taiyuan too early.", cn: "北宋核心绘为960年以开封为中心建立的政权。其早期右缘缺口由北汉承接至979年，因此宋不会在视觉上过早拥有太原。" },
    ten_kingdoms_early: { en: "Early Ten Kingdoms Mosaic keeps the southern regional field visible immediately after Tang collapse, before Southern Han is separated as the Lingnan/Vietnam-facing owner.", cn: "十国早期拼图保留唐亡后最初的南方区域格局，早于南汉被拆出为面向岭南/越南的主人。" },
    ten_kingdoms_core: { en: "Ten Kingdoms Core covers the non-Lingnan southern regimes before Song expansion: Wu-Yue, Min, Chu, Shu, Southern Tang predecessors, and related courts.", cn: "十国核心表示宋扩张前非岭南的南方诸政权：吴越、闽、楚、蜀、南唐前身及相关朝廷。" },
    southern_han_lingnan: { en: "Southern Han / Lingnan is the Guangzhou-centered southern owner that best carries the late Chinese-rule edge of the Vietnam lane before 938, while remaining visible until Song conquered it in 971.", cn: "南汉/岭南是以广州为中心的南方主人，最适合承接938年前越南北属后期边缘，并一直可见到971年为宋所灭。" },
    remaining_ten_kingdoms_963: { en: "Remaining Ten Kingdoms after Song's 960 founding shows southern states still outside Kaifeng's control until the first Song southern conquests begin.", cn: "宋兴后的十国余部表示960年宋建立后仍未受开封控制的南方诸国，直到宋最初的南方征服开始。" },
    song_jingnan_wuping: { en: "Song Jingnan/Wuping Bridge marks the first small southern absorption in 963. It starts the widening of Song's southern lane without pretending that all southern kingdoms had fallen.", cn: "宋荆南/武平承接表示963年宋最早吸收的南方小片段。它开启宋南方栏变宽，但不假装所有南方诸国都已灭亡。" },
    remaining_ten_kingdoms_965: { en: "Remaining Ten Kingdoms before Later Shu falls keeps the still-independent southern field visible between the 963 and 965 Song conquests.", cn: "后蜀灭亡前的十国余部保留963与965年宋征服之间仍独立的南方格局。" },
    song_shu_jingnan: { en: "Song Shu/Jingnan Consolidation widens after the 965 conquest of Later Shu, while Southern Han and Jiangnan/Wu-Yue holdouts remain separate.", cn: "宋蜀地/荆南整合在965年灭后蜀后变宽，同时南汉和江南/吴越残余仍然分开。" },
    southern_tang_wuyue_holdouts: { en: "Southern Tang and Wu-Yue Holdouts represent the lower-Yangtze and coastal kingdoms still outside Song control after the western and Lingnan fronts begin to collapse.", cn: "南唐/吴越残余表示西部和岭南战线开始崩解后，仍在宋控制之外的长江下游与沿海诸国。" },
    song_lingnan_jiangnan: { en: "Song Lingnan/Jiangnan Push widens after the 971 conquest of Southern Han, leaving Southern Tang and Wu-Yue as the main southern holdouts.", cn: "宋岭南/江南推进在971年灭南汉后变宽，只剩南唐和吴越成为主要南方残余。" },
    southern_tang_wuyue_holdouts_late: { en: "Late Southern Tang and Wu-Yue Holdouts keep the lower-Yangtze and coastal kingdoms visible after Song absorbs Lingnan but before Jiangnan falls.", cn: "后期南唐/吴越残余在宋吸收岭南之后、江南陷落之前保留长江下游和沿海诸国的可见性。" },
    song_jiangnan_wuyue: { en: "Song Jiangnan Consolidation widens again after the 975/976 Southern Tang conquest, leaving Wu-Yue and Qingyuan as the final southern holdouts.", cn: "宋江南整合在975/976年灭南唐后再次变宽，只剩吴越和清源作为最后南方残余。" },
    wuyue_qingyuan_holdouts: { en: "Wu-Yue / Qingyuan Holdouts preserve the last southeastern owners before they submitted to Song in 978.", cn: "吴越/清源残余保留978年归宋前最后的东南主人。" },
    n_song_south: { en: "Song Southern Consolidation begins after Wu-Yue and Qingyuan submit in 978. It complements the Kaifeng core without backdating Song rule over the south to 960.", cn: "宋南方整合始于978年吴越和清源归宋后。它补足开封核心，但不把宋对南方的统治倒推到960年。" },
    kofun: { en: "Kofun marks the tomb-mound and Yamato-polity phase of early Japan. It is a Japanese archipelago owner in its own lane, while Korea-side contact remains visible through the adjacent Three Kingdoms of Korea.", cn: "古坟时代表示早期日本的陵墓文化与大和政权阶段。它是日本列岛栏中的主人，而与朝鲜半岛的联系仍由相邻的朝鲜三国显示。" },
    asuka: { en: "Asuka marks the Yamato court's Buddhist and reform era around the Nara basin. Korean and Chinese models enter through Buddhism, clan politics, and Taika-style centralization before the permanent Nara capital.", cn: "飞鸟时代表示奈良盆地周边大和朝廷的佛教与改革阶段。佛教、氏族政治和大化式中央集权把朝鲜与中国模式引入日本，早于固定的奈良都城。" },
    unified_silla: { en: "Unified Silla is shortened to the pre-918 phase, before Wang Geon's Goryeo became the main rival in the Later Three Kingdoms transition.", cn: "统一新罗缩短为918年前阶段，即王建的高丽成为后三国过渡中主要对手之前。" },
    late_silla: { en: "Late Silla is a narrowed court-continuity fragment after Goryeo's founding. It remains visible until the voluntary surrender to Goryeo in 935.", cn: "晚新罗是高丽建立后保留的新罗宫廷连续性窄片段。它持续到935年自愿归附高丽。" },
    goryeo: { en: "Early Goryeo begins with Wang Geon in 918 but is drawn as a half-lane core until the peninsula was unified. It does not replace Silla before the 935 surrender and Later Baekje's 936 fall.", cn: "早期高丽始于918年王建建国，但在半岛统一前绘为半栏核心。它不会在935年新罗归附、936年后百济灭亡前取代新罗。" },
    goryeo_unified: { en: "Unified Goryeo begins after Silla's surrender and Later Baekje's fall, marking the peninsula-wide kingdom that ruled until 1392.", cn: "统一高丽始于新罗归附和后百济灭亡之后，表示统治至1392年的半岛统一王国。" },
    yuan: { en: "The Yuan dynasty, founded by Kublai Khan, integrated China into the Mongol world system. Under Pax Mongolica, Marco Polo and Ibn Battuta travelled freely; the Grand Canal was extended; Beijing became the capital of a unified China for the first time.", cn: "元朝由忽必烈建立，使中国融入蒙古世界体系。在蒙古和平之下，马可·波罗与伊本·白图泰畅行无阻；大运河得到延伸；北京首次成为统一中国的首都。" },
    ming: { en: "The Ming dynasty restored Han Chinese rule after Mongol domination. The Forbidden City was built, the Great Wall rebuilt in brick, and Zheng He's seven voyages reached East Africa — decades before Columbus. Ming porcelain and novels remain world treasures.", cn: "明朝在蒙古统治后恢复汉人政权。建造紫禁城，以砖石重建长城，郑和七下西洋远及东非——比哥伦布早数十年。明代瓷器与小说至今是世界瑰宝。" },
    southern_ming: { en: "Southern Ming keeps the post-1644 Ming-loyalist courts visible in south China. It sits beside Qing southern campaigns because the Qing takeover was a process, not instant nationwide replacement.", cn: "南明保留1644年后中国南方明朝遗臣政权的可见性。它与清南方征服片段并列，因为清的接管是过程，不是瞬间全国替换。" },
    qing_beijing: { en: "Qing North China Core begins when the Manchus took Beijing in 1644. Southern Ming, Qing southern campaigns, and Tungning / Zheng Taiwan stay in their own geographic lanes; Taiwan is linked through the Taiwan Strait and conquest relationships, not drawn as a Beijing-core cutout.", cn: "清华北核心始于1644年满洲军入主北京。南明、清南方推进与明郑台湾保留在各自地理栏；台湾通过台湾海峡与征服关系关联，而不是画成北京核心的缺口。" },
    qing_south_campaigns: { en: "Qing Southern Campaigns marks the Qing military and administrative front in south China from the 1644 Beijing takeover to the 1683 Taiwan campaign. It sits beside Southern Ming and then the Three Feudatories lanes rather than replacing them as one settled mainland rectangle.", cn: "清南方征服表示1644年入主北京后至1683年攻台前，清在南方中国推进的军事与行政前线。它与南明、随后与三藩南方栏并列，而不是用一个稳定大陆矩形直接覆盖所有区域。" },
    three_feudatories_south: { en: "Three Feudatories South keeps the semi-autonomous Wu Sangui, Geng Jingzhong, and Shang family domains visible after Yongli's death. This mainland southern lane is separate from Zheng / Tungning Taiwan in the island column.", cn: "三藩南方保留永历终结后吴三桂、耿精忠、尚氏等半自治藩镇势力的可见性。这个大陆南方栏与台湾岛栏中的明郑台湾分开。" },
    qing_south_reconsolidation: { en: "Qing South Reconsolidation marks Kangxi's post-1681 mainland settlement after the Three Feudatories were suppressed, just before the 1683 Taiwan campaign completed the chart's Qing China handoff.", cn: "清南方再整合表示康熙平三藩后、1683年攻台前的大陆南方收束阶段，作为图中清中国本部整合前的短桥。" },
    qing: { en: "Qing Consolidated China begins after the 1683 fall of the Zheng/Tungning base on Taiwan. China proper stays visually whole; Qing Manchuria, Mongolia, and Taiwan remain separate lanes with relationships and details rather than cutout geometry.", cn: "清中国本部整合始于1683年明郑台湾基地灭亡之后。中国本部在视觉上保持完整；清属满洲、蒙古和台湾保留独立栏位，并通过联系与详情表达，而不是通过缺口几何表达。" },
    manchuria_early_peoples: { en: "Early Manchurian Peoples is a cultural-owner baseline for the forest, river, and plain societies of Northeast Asia before named states dominate the lane. It is not a centralized kingdom, but it prevents the Manchuria column from reading as empty land.", cn: "早期满洲诸族是具名国家占主导前东北亚森林、河流与平原社群的文化主人基线。它不是中央集权王国，但避免满洲栏被读成空地。" },
    fuyu_manchuria: { en: "Fuyu / Buyeo marks the Sungari basin polity and related northeastern communities before Goguryeo, Mohe, and later Balhae reshape the Manchuria-Korea borderland.", cn: "扶余/夫余表示松花江流域政权及相关东北社群，早于高句丽、靺鞨和后来的渤海重塑满洲-朝鲜边地。" },
    goguryeo_manchuria: { en: "Goguryeo North keeps the Manchurian side of Goguryeo visible after Fuyu. The Korean lane still shows the compressed Three Kingdoms system, so this is a non-contiguous companion fragment rather than a new single-state rectangle.", cn: "高句丽北部保留扶余之后高句丽在满洲一侧的可见性。朝鲜栏仍显示压缩的三国体系，因此这是非相邻伴随片段，不是新的单一国家大矩形。" },
    tang_mohe_manchuria: { en: "Tang-Mohe Transition covers the short post-Goguryeo northern frontier before Parhae/Balhae consolidated around the Songhua valley. The owner is transitional rather than blank.", cn: "唐-靺鞨过渡表示高句丽灭亡后、渤海在松花江流域整合前的短期北方边疆。这里是过渡主人，而不是空白。" },
    bohai_manchuria: { en: "Bohai / Parhae is the post-Goguryeo state in northern Manchuria and northern Korea. It anchors the Manchuria lane before Khitan Liao rule instead of leaving the pre-926 period empty.", cn: "渤海/Parhae 是高句丽之后位于北满洲和朝鲜北部的国家。它在契丹辽统治前锚定满洲栏，而不是留下926年前空白。" },
    liao_manchuria: { en: "Liao Manchuria is the Manchurian face of the Khitan Liao world. The steppe lane still carries Liao as a broader imperial owner, while this companion block fills the Northeast lane explicitly.", cn: "辽属满洲表示契丹辽世界在满洲一侧的面貌。草原栏仍承接更广的辽帝国主人，此伴随块则明确填入东北栏。" },
    jurchen_jin_manchuria: { en: "Jurchen Jin Manchuria marks the homeland and early imperial base of the Jurchen Jin before and alongside its north-China rule. It makes the Jin transition a named owner in both Manchuria and China proper.", cn: "女真金满洲表示女真金的故地与早期帝国基地，并与其华北统治并列。它让金的转型在满洲与中国本部两侧都有具名主人。" },
    yuan_liaoyang_manchuria: { en: "Yuan Liaoyang marks Mongol/Yuan administration over Manchuria after the fall of Jurchen Jin. It fills the Northeast lane as a province-like imperial fragment instead of treating Mongol rule as only a steppe block.", cn: "元辽阳表示女真金灭亡后蒙古/元朝对满洲的行政统辖。它把东北栏填成类似行省的帝国片段，而不是只用草原块表示蒙古统治。" },
    ming_liaodong_jurchens: { en: "Ming Liaodong / Jurchen Guards is a composite owner for Ming Liaodong rule, Jurchen guard networks, and the deteriorating late-Ming frontier before Nurhaci's Later Jin consolidated the lane.", cn: "明辽东/女真卫所是明辽东统治、女真卫所网络与晚明边疆弱化的复合主人，直到努尔哈赤后金整合此栏。" },
    later_jin_manchu: { en: "Later Jin marks Nurhaci's Jurchen/Manchu state in Manchuria before the Qing dynastic name was adopted. Its left-edge notch is filled by Ming China, showing the frontier pressure before the Qing transition.", cn: "后金表示努尔哈赤在满洲建立、尚未改称清的女真/满洲国家。左侧缺口由明朝中国承接，显示改清之前的边界压力。" },
    qing_manchuria: { en: "Qing Manchuria keeps the Manchu homeland and northeastern frontier visible beside China proper and Mongolia. It prevents the Qing rectangle from hiding frontier incorporation under one broad block.", cn: "清属满洲让满洲故地与东北边疆在中国本部和蒙古旁保持可见，避免用一个宽清朝矩形掩盖不同边疆整合过程。" },
    roc_manchuria: { en: "ROC Manchuria marks the early republican Northeast before the post-Yuan warlord fracture. It bridges Qing frontier collapse and the later Fengtian / Northeast Army phases.", cn: "民国东北表示袁世凯身后军阀割裂前的早期共和国东北，连接清朝边疆瓦解与后续奉系/东北军阶段。" },
    fengtian_manchuria: { en: "Fengtian Manchuria shows Zhang Zuolin's Manchurian warlord base. It was tied to Japanese railway and military pressure, but it was not the same thing as a settled Nanjing-controlled province.", cn: "奉系东北表示张作霖在满洲的军阀基础。它与日本铁路和军事压力相连，但不等同于南京政府稳定控制的省区。" },
    northeast_army_manchuria: { en: "Northeast Army Manchuria marks Zhang Xueliang's rule after alignment with Nanjing, ending when Japanese forces drove the Northeast Army out in 1931.", cn: "东北军东北表示张学良易帜后维持的东北格局，止于1931年日军驱逐东北军并占领该地。" },
    japanese_manchuria: { en: "Japanese Manchuria is the brief occupation phase after the Mukden Incident and before Manchukuo was proclaimed. It is separate from Japan proper and from later occupied China proper.", cn: "日本占领满洲表示九一八事变后、伪满洲国成立前的短暂占领阶段。它与日本本土和后来的日占中国本部分开。" },
    manchukuo: { en: "Manchukuo was proclaimed as an independent state but functioned as a Japanese-controlled puppet state under Puyi. The separate lane keeps this status distinct from both Japan proper and Chinese wartime fragments.", cn: "伪满洲国名义上宣布独立，实质上是日本控制、以溥仪为元首的傀儡国家。独立栏位使其区别于日本本土和中国战时片段。" },
    soviet_manchuria: { en: "Soviet-Occupied Manchuria marks the short 1945-46 military occupation after the Soviet offensive destroyed Japanese power in the region.", cn: "苏军占领满洲表示1945-46年苏军进攻摧毁日本在当地力量后的短期军事占领。" },
    northeast_liberated_area: { en: "Northeast Liberated Area shows the Communist base and contested civil-war theatre in Manchuria before the PRC incorporated the mainland Northeast in 1949.", cn: "东北解放区表示1949年中华人民共和国纳入大陆东北前，中共在满洲形成的根据地和内战争夺空间。" },
    qing_mongolia: { en: "Qing Inner Mongolia represents early submission and alliance with southern/eastern Mongol groups after 1635. Khalkha / Outer Mongolia remains separate until 1691.", cn: "清属内蒙古表示1635年后南部、东部蒙古诸部与清的早期归附和同盟关系。喀尔喀/外蒙古在1691年前仍另行显示。" },
    khalkha_mongols: { en: "Khalkha Mongols keeps Outer Mongolia visible before the 1691 submission to Qing rule. It sits beside early Qing Inner Mongolia instead of being swallowed by it.", cn: "喀尔喀蒙古保留1691年归附清朝前的外蒙古可见性。它与早期清属内蒙古并列，而不是被后者吞没。" },
    qing_mongolia_full: { en: "Qing Mongolia begins after Khalkha submission in 1691 and ends with the 1911 independence break. This separates frontier incorporation from the earlier Beijing and China-proper Qing phases.", cn: "清属蒙古始于1691年喀尔喀归附，止于1911年的独立断裂。它把边疆整合与更早的清北京/中国本部阶段分开。" },
    mongolia_bogd: { en: "Bogd Khanate Mongolia marks the 1911 break from Qing rule and the contested autonomy / sovereignty period before the Mongolian People's Republic.", cn: "博克多汗国蒙古表示1911年脱离清朝后的断裂，以及蒙古人民共和国成立前主权与自治地位受争议的时期。" },
    mongolia_mod: { en: "Modern Mongolia begins with the Mongolian People's Republic in 1924 and continues through the 1992 democratic constitutional transition. It represents Outer Mongolia's state lane, not every Mongol-inhabited region.", cn: "现代蒙古始于1924年蒙古人民共和国，并延续至1992年的民主宪政转型。它表示外蒙古国家栏，而不是所有蒙古族居住区域。" },
    roc: { en: "Early ROC is now the short Beiyang/Yuan Shikai republic before the post-1916 warlord fracture. Later Republican China is split into warlord, Nationalist, wartime, civil-war, and Taiwan phases.", cn: "早期民国现在表示1916年军阀割据前的北洋/袁世凯共和国。后续民国中国拆分为军阀、国民政府、抗战、内战与台湾阶段。" },
    early_republic_south: { en: "Early Republic South keeps southern and central provinces visible between the 1912 Qing abdication and Yuan Shikai's 1916 death. It represents a nominal republican/provincial field shaped by the Nanjing provisional government, Yuan's Beiyang presidency, and anti-Yuan struggles, not settled KMT or Nanjing rule.", cn: "早期民国南方把1912年清帝退位后至1916年袁世凯去世前的南方与中部省区保留下来。它表示由南京临时政府、袁世凯北洋总统制与反袁斗争共同塑造的名义民国/省区场，而不是稳定的国民党或南京政府统治。" },
    warlord_north: { en: "Beiyang / Warlord North shows northern military governments after Yuan Shikai. It is separate from southern warlord and Nationalist bases because no single republic controlled the whole country.", cn: "北洋/北方军阀表示袁世凯后的北方军事政权。它与南方军阀和国民党基地分开，因为没有一个共和国政权真正控制全国。" },
    warlord_south: { en: "Southern Warlords / KMT Bases keeps south-China provincial militarists and Nationalist revolutionary bases visible during the warlord era.", cn: "南方军阀/国民党基地保留军阀时代南方地方军政势力和国民革命基地的可见性。" },
    roc_nanjing: { en: "The Nationalist Government block begins after the Northern Expedition. It is a consolidation phase with continuing provincial militarism, not a perfectly uniform territorial state.", cn: "国民政府图块始于北伐之后。它是仍伴随地方军政割据的整合阶段，而不是完全均质的领土国家。" },
    roc_wartime: { en: "Nationalist Wartime China is narrowed to the interior / Chongqing government during the war against Japan. Japanese-occupied China is shown beside it.", cn: "战时国民政府窄化为抗日战争期间的内地/重庆政权。日占中国在旁侧显示。" },
    japanese_occupied_china: { en: "Japanese-Occupied China marks the occupied coastal, northern, and lower-Yangtze zones during 1937-45. It is a wartime occupation fragment, not Japan proper.", cn: "日占中国表示1937-45年被占领的沿海、华北与长江下游区域。这是战时占领片段，不是日本本土。" },
    roc_postwar: { en: "Postwar Nationalist China shows Nationalist-held cities and transport corridors after Japan surrendered, before Communist victory on the mainland in 1949.", cn: "战后国民政府表示日本投降后国民党控制的城市和交通线核心，直到1949年共产党在大陆取胜前。" },
    ccp_liberated_areas: { en: "CCP Liberated Areas marks Communist-held northern hinterlands during the resumed civil war, beside the Nationalist postwar government. The Northeast base is shown separately in the Manchuria lane.", cn: "中共解放区表示内战重启期间共产党控制的北方腹地，与战后国民政府并列。东北根据地另在满洲栏显示。" },
    prc: { en: "PRC China Proper begins in 1949 after Communist victory on the mainland. It now carries the north-south China core, while the Northeast and western frontier fragments remain visible as separate same-color blocks.", cn: "中华人民共和国本部始于1949年共产党在大陆取胜之后。它现在表示南北中国本部，东北与西部边疆片段以同色独立图块保留可见。" },
    prc_northeast: { en: "PRC Northeast keeps post-1949 Manchuria / Northeast China visible as its own mainland fragment, continuing from the Communist Northeast base rather than being swallowed by the China-proper block.", cn: "中华人民共和国东北把1949年后的满洲/东北中国作为独立大陆片段显示，接续中共东北根据地，而不是被中国本部图块吞没。" },
    tibetan_plateau_cultures: { en: "Tibetan Plateau cultures fill the highland lane before named states, compressing Neolithic and Bronze Age settlements, exchange routes, and pastoral-agricultural communities rather than treating the plateau as empty.", cn: "青藏高原文化填入具名国家出现前的高原栏，压缩新石器至青铜时代的聚落、交流路线和农牧社群，而不是把高原视为空白。" },
    zhangzhung_plateau: { en: "Zhangzhung / early highland polities marks the western Tibetan and plateau political field before the Tibetan Empire. The block is deliberately approximate because sources are fragmentary.", cn: "象雄/早期高原诸政权表示吐蕃帝国前的西藏西部与高原政治场。由于资料零散，此块有意保持近似表达。" },
    tibetan_empire: { en: "The Tibetan Empire makes the 7th-9th century plateau state visible as a major Central Asian power rather than leaving Tibet blank until the Qing period.", cn: "吐蕃帝国把7至9世纪的高原国家作为中亚重要强权显示出来，而不是让西藏一直空到清代。" },
    tibetan_fragmentation: { en: "Tibetan fragmentation covers the post-842 local-polity and religious-revival field before Mongol/Yuan-backed Sakya authority, avoiding a false continuous empire.", cn: "吐蕃分裂时期覆盖842年后地方政权与佛教复兴的场域，直到蒙古/元支持的萨迦权威出现，避免画成虚假的连续帝国。" },
    sakya_yuan_tibet: { en: "Sakya-Yuan Tibet marks Mongol/Yuan patronage and administration through the Sakya school, shown as a highland fragment rather than absorbed into a China-proper rectangle.", cn: "萨迦-元治藏表示蒙古/元经由萨迦派形成的护持与行政关系，作为高原片段显示，而非并入中国本部矩形。" },
    phagmodrupa_tsangpa: { en: "Phagmodrupa and Tsangpa Tibet compress the post-Yuan central Tibetan ruling houses before the Ganden Phodrang order, keeping indigenous highland politics visible.", cn: "帕木竹巴与藏巴时期压缩元后至甘丹颇章前的藏中统治家族，使高原本地政治保持可见。" },
    ganden_phodrang: { en: "Ganden Phodrang begins with the 1642 consolidation under the Fifth Dalai Lama and precedes the post-1720 Qing amban arrangement.", cn: "甘丹颇章始于1642年第五世达赖喇嘛时期的整合，并早于1720年后的清驻藏大臣安排。" },
    tibet_manchu_overlordship: { en: "Tibet under Manchu overlordship marks the post-1720 Qing amban and garrison arrangement in Lhasa while Tibet retained much local administration. It is separated from China proper to avoid a false solid rectangle.", cn: "清代驻藏/宗主权语境表示1720年后拉萨的驻藏大臣与驻军安排，同时西藏仍保留大量本地治理。它与中国本部分开，以避免虚假的整块矩形。" },
    tibet_lhasa_government: { en: "Tibet under the Lhasa Government keeps the post-Qing, pre-1951 highland polity visible as a distinct fragment before the PRC transition.", cn: "拉萨政府时期西藏保留清亡后、1951年前的高原政权可见性，作为进入中华人民共和国过渡前的独立片段。" },
    prc_tibet_transition: { en: "PRC Tibet Transition covers the post-1951 administrative transition before Tibet was formally designated an autonomous region in 1965.", cn: "中华人民共和国西藏过渡覆盖1951年后的行政过渡，早于1965年正式设立西藏自治区。" },
    tibet_autonomous_region: { en: "Tibet Autonomous Region appears from its 1965 formal designation, kept as a visible western highland fragment rather than merged into a single PRC rectangle.", cn: "西藏自治区自1965年正式设立后显示，作为可见的西部高原片段，而非并入一个中华人民共和国大矩形。" },
    tarim_basin_cultures: { en: "Tarim Basin cultures fill the oasis and desert-margin lane before historically named kingdoms, compressing early settlements, exchange corridors, and mobile-pastoral contact zones.", cn: "塔里木盆地文化填入有史料名称王国出现前的绿洲与沙漠边缘栏，压缩早期聚落、交流走廊和游牧接触带。" },
    western_regions_oasis_states: { en: "Western Regions oasis states represent Khotan, Kucha, Kashgar, Gaochang, and related Silk Road polities, plus Han/Xiongnu pressure, before Tang protectorates reshaped the lane.", cn: "西域绿洲诸国表示于阗、龟兹、疏勒、高昌等丝路政权，以及汉与匈奴压力，直到唐都护体系重塑此栏。" },
    tang_anxi_beiting: { en: "Tang Anxi and Beiting protectorates make Tang-era Chinese influence in the Tarim and northern routes explicit without stretching Tang China proper across the whole western frontier.", cn: "唐安西/北庭都护府明确显示唐代中国在塔里木与北道的影响，而不是把唐中国本部直接拉满整个西部边疆。" },
    uyghur_qocho_karakhanid: { en: "Qocho Uyghur and Kara-Khanid Tarim compress the post-Uyghur migration and Islamic/Turkic transformation of the oasis world before Mongol conquest.", cn: "高昌回鹘与喀喇汗塔里木压缩回鹘迁徙后绿洲世界的突厥化、伊斯兰化转型，直到蒙古征服。" },
    chagatai_moghulistan_tarim: { en: "Chagatai-Moghulistan Tarim marks Mongol successor and eastern Chagatai / Moghulistan influence over the oasis basin before the Yarkent Khanate.", cn: "察合台-蒙兀儿斯坦塔里木表示蒙古继承体系与东察合台/蒙兀儿斯坦对绿洲盆地的影响，早于叶尔羌汗国。" },
    yarkent_khanate: { en: "Yarkent Khanate shows the southern Tarim and Kashgar-Yarkent polity before Dzungar expansion into the basin.", cn: "叶尔羌汗国显示准噶尔进入盆地前，塔里木南缘与喀什噶尔-叶尔羌政权。" },
    moghulistan_oirat_frontier: { en: "Moghulistan / Oirat frontier keeps the northern Tian Shan and Dzungaria side visible after Yarkent took the southern oasis lane and before the Dzungar Khanate became the named northern owner.", cn: "蒙兀儿斯坦/卫拉特边疆在叶尔羌占据南疆绿洲后、准噶尔汗国成为北疆具名主人前，保留天山北侧与准噶尔盆地一侧的可见性。" },
    dzungar_khanate: { en: "Dzungar Khanate represents the Oirat / Dzungar power in the western Mongolian and northern Xinjiang zone before Qing conquest.", cn: "准噶尔汗国表示清征服前西蒙古与北疆一带的卫拉特/准噶尔力量。" },
    dzungar_tarim_rule: { en: "Dzungar Tarim rule separates the southern oasis basin from the northern Dzungar core after the late-17th-century conquest, while keeping both halves tied to the same Oirat power.", cn: "准噶尔治塔里木把17世纪后期征服后的南疆绿洲盆地与北疆准噶尔核心分开，同时保持二者同属卫拉特力量。" },
    qing_xinjiang_frontier: { en: "Qing Xinjiang Frontier marks Qing assertion of control in the Xinjiang region after the 18th-century conquest, before it was reorganized as a province in 1884.", cn: "清属新疆边疆表示18世纪征服后清在新疆地区确立控制、并在1884年改设行省前的阶段。" },
    qing_xinjiang_province: { en: "Qing Xinjiang Province begins with the 1884 provincial reorganization, separating late-Qing Xinjiang administration from both China proper and Mongolia.", cn: "清新疆省始于1884年设省，把晚清新疆行政与中国本部、蒙古分开显示。" },
    xinjiang_republican_province: { en: "Republican Xinjiang Province shows the post-1911 provincial and regional-ruler phase before the Communist victory in 1949.", cn: "民国新疆省表示1911年后新疆的省制与地方统治者更替阶段，止于1949年共产党胜利前。" },
    prc_xinjiang_province: { en: "PRC Xinjiang Province covers the post-1949 transition before the Xinjiang Uygur Autonomous Region was established in 1955.", cn: "中华人民共和国新疆省覆盖1949年后的过渡阶段，早于1955年新疆维吾尔自治区成立。" },
    xinjiang_autonomous_region: { en: "Xinjiang Uygur Autonomous Region begins with its 1955 establishment, kept as a western frontier fragment beside Tibet rather than hidden under PRC China Proper.", cn: "新疆维吾尔自治区始于1955年成立，作为与西藏并列的西部边疆片段，而不是隐藏在中华人民共和国本部之下。" },
    taiwan_indigenous: { en: "Indigenous Taiwan represents Austronesian communities and local societies before sustained European colonial administration. It prevents the island lane from beginning only with outside rule.", cn: "台湾原住民社会表示欧洲殖民行政持续进入前的南岛社群与地方社会，避免台湾栏只从外来统治开始。" },
    dutch_taiwan: { en: "Dutch Formosa represents the Dutch East India Company colony and trade base before Zheng Chenggong / Koxinga captured Fort Zeelandia.", cn: "荷治台湾表示郑成功攻取热兰遮城前，荷兰东印度公司建立的殖民地和贸易基地。" },
    tungning: { en: "Tungning / Zheng Taiwan was a Ming-loyalist island regime that sustained anti-Qing resistance until the Qing invasion of 1683. It stays whole in the Taiwan island lane across the Taiwan Strait from the Fujian/south-coast campaign lane, not as a cutout inside the Beijing or mainland core.", cn: "明郑台湾是延续反清抵抗的明遗民岛屿政权，持续到1683年清军攻台。它作为台湾岛屿栏的完整主人保留，隔台湾海峡对应福建/华南沿海推进栏，而不是北京或大陆核心里的缺口。" },
    qing_taiwan: { en: "Qing Taiwan begins after the fall of Tungning in 1683 and ends with cession to Japan in 1895. It is a separate island lane from mainland Qing China, so neighboring Vietnam does not carry any Taiwan cutout.", cn: "清治台湾始于1683年明郑灭亡，止于1895年割让日本。它是独立于大陆清朝的岛屿栏，因此相邻越南不承接任何台湾缺口。" },
    japanese_taiwan: { en: "Japanese Taiwan marks colonial rule after the Treaty of Shimonoseki. It appears in Taiwan's island lane, not inside Japan proper and not as a land bite owned by French Vietnam.", cn: "日治台湾表示《马关条约》后的日本殖民统治。它位于台湾岛屿栏，不放入日本本土，也不画成由法属越南承接的土地缺口。" },
    roc_taiwan: { en: "ROC Taiwan begins with postwar transfer from Japanese rule and becomes the Nationalist government's main base after the 1949 mainland retreat. The full island lane expresses continuity without inventing an adjacent owner.", cn: "中国台湾始于战后从日本统治转移，1949年大陆撤退后成为国民政府主要基地。完整岛屿栏表达这种连续性，而不虚构相邻承接者。" },
    jp_korea: { en: "Japanese Korea marks the 1910 annexation and colonial rule until Japan's defeat in 1945. It ends before the U.S. and Soviet occupation-zone transition.", cn: "日治朝鲜表示1910年日本吞并后至1945年日本战败前的殖民统治；它止于美苏分区占领过渡之前。" },
    korea_us_occupation: { en: "The U.S. Occupation Zone marks southern Korea under USAMGIK south of the 38th parallel after Japanese surrender and before the Republic of Korea was founded in 1948.", cn: "美军占领区表示日本投降后、1948年大韩民国建立前，三八线以南由美军政厅管理的南部朝鲜。" },
    korea_soviet_occupation: { en: "The Soviet Occupation Zone marks northern Korea under Soviet occupation and civil administration north of the 38th parallel before the DPRK was proclaimed in 1948.", cn: "苏军占领区表示1948年朝鲜民主主义人民共和国建立前，三八线以北由苏军占领和民政管理的北部朝鲜。" },
    south_korea: { en: "South Korea begins with the Republic of Korea founded in 1948 from the southern U.S. occupation zone. It is kept beside North Korea so partition is visible.", cn: "韩国从1948年南部美军占领区建立大韩民国开始显示，并与朝鲜并列，使半岛分裂可见。" },
    north_korea: { en: "North Korea begins with the DPRK founded in 1948 from the Soviet-backed northern occupation zone. It remains a half-lane beside South Korea after partition.", cn: "朝鲜从1948年苏联支持的北部占领区建立朝鲜民主主义人民共和国开始，并在分裂后与韩国半栏并列。" },
    taisho_japan: { en: "Taisho Japan keeps the 1912-26 imperial but parliamentary-leaning phase distinct from later militarist Showa expansion.", cn: "大正日本把1912-26年仍属帝国但带有议会政治色彩的阶段，与后来的昭和军国主义扩张区分开。" },
    showa_imperial_japan: { en: "Showa Imperial Japan marks Hirohito's pre-surrender reign through militarist expansion and World War II. Colonial Korea, Taiwan, Manchuria, and occupied China are shown outside Japan proper.", cn: "昭和帝国日本表示裕仁即位后至投降前的军国主义扩张和二战阶段；殖民朝鲜、台湾、满洲与日占中国不放入日本本土栏。" },
    allied_occupation_japan: { en: "Allied Occupation of Japan covers 1945-52, when the U.S.-led occupation demilitarized Japan and the 1947 constitution recast the emperor as a constitutional symbol.", cn: "盟军占领日本覆盖1945-52年；以美国为主导的占领推动非军事化，1947年宪法将天皇改造为宪政象征。" },
    postwar_showa_japan: { en: "Postwar Showa Japan begins after the occupation ended in 1952. It represents sovereign constitutional Japan and its high-growth era, not the wartime empire.", cn: "战后昭和日本始于1952年占领结束后，表示恢复主权后的宪政日本和高速增长时期，而非战时帝国。" },
    heisei: { en: "Heisei Japan continues the postwar constitutional monarchy after Emperor Akihito's accession in 1989, shown as a separate modern phase.", cn: "平成日本表示明仁天皇1989年即位后的战后宪政君主制延续，作为独立现代阶段显示。" },
    mongol_emp: { en: "The Mongol Empire under Genghis Khan and his heirs became the largest contiguous land empire in history. The Pax Mongolica enabled unprecedented cross-Eurasian exchange — the Black Death, gunpowder, paper money, and the compass all moved along its highways.", cn: "蒙古帝国在成吉思汗与其后裔治下成为史上最大的连续陆地帝国。蒙古和平促成了前所未有的欧亚交流——黑死病、火药、纸币与指南针皆沿其大道流通。" },
    achaemenid: { en: "The Achaemenid Persian core begins with Cyrus's takeover of Media and consolidation in Iran. The empire's later sweep into Lydia, Babylon, the Levant, and Egypt is now shown through dated fragments.", cn: "阿契美尼德波斯核心始于居鲁士夺取米底并在伊朗整合权力。帝国后来进入吕底亚、巴比伦、黎凡特和埃及的进程现在以分日期片段显示。" },
    achaemenid_anatolia: { en: "Achaemenid Anatolia begins after Cyrus captured Sardis and ended Lydia. It stays as a whole western satrapal lane paired to the Persian core by relationship, so Lydia remains visible until its actual fall without a land-bite fill.", cn: "阿契美尼德安纳托利亚始于居鲁士夺取萨第斯、终结吕底亚之后。它作为完整西部总督区栏通过关系与波斯核心成对，使吕底亚保留到实际灭亡时点，而不使用土地缺口填补。" },
    achaemenid_mesopotamia: { en: "Achaemenid Babylonia begins with the fall of Babylon in 539 BCE. It remains a whole Babylonia/Mesopotamia lane beside the Persian core, with imperial attachment shown by a political relationship rather than a cutout.", cn: "阿契美尼德巴比伦尼亚始于前539年巴比伦陷落。它在波斯核心旁保持完整巴比伦尼亚/美索不达米亚栏，帝国归属由政治关系表示，而不是由缺口表示。" },
    achaemenid_levant: { en: "The Achaemenid Levant appears after Babylon fell, when Phoenicia, Palestine-Syria, and related western provinces passed into the Persian imperial system. It remains a whole provincial lane linked to the Persian core.", cn: "阿契美尼德黎凡特在巴比伦陷落后出现，当时腓尼基、巴勒斯坦-叙利亚及相关西部行省进入波斯帝国体系。它保持为完整行省栏，并通过关系连接波斯核心。" },
    achaemenid_egypt: { en: "Achaemenid Egypt begins only after Cambyses II conquered Egypt in 525 BCE. This avoids implying Persian control while late Egyptian dynasties still ruled, and keeps Egypt whole rather than as a cutout of adjacent provinces.", cn: "阿契美尼德埃及只在冈比西斯二世前525年征服埃及后开始，避免在埃及晚期王朝仍统治时暗示波斯控制，并使埃及保持完整，而不是相邻行省的缺口。" },
    egypt_late_independent: { en: "Late independent Egypt marks the native dynasties that broke away between the first and second Achaemenid occupations.", cn: "埃及晚期独立表示第一次和第二次阿契美尼德占领之间恢复独立的本土王朝。" },
    achaemenid_egypt_late: { en: "The second Achaemenid Egypt fragment marks Artaxerxes III's reconquest shortly before Alexander's campaigns ended Persian rule. It is a whole late Persian Egypt block, paired to the imperial core by relationship.", cn: "第二段阿契美尼德埃及表示阿尔塔薛西斯三世在亚历山大东征终结波斯统治前不久的重新征服。它是完整的晚期波斯埃及块，并通过关系与帝国核心成对。" },
    alexander_babylonia: { en: "Alexander / Diadochi Babylonia marks Babylon and Mesopotamia after the Macedonian conquest, before Seleucus returned and made Babylonia the base of the Seleucid state.", cn: "亚历山大/继业者巴比伦尼亚表示马其顿征服后的巴比伦与美索不达米亚，在塞琉古回归并以巴比伦尼亚为塞琉古国家基础之前。" },
    alexander_persia: { en: "Alexander / Diadochi Persia is the Macedonian conquest and early successor bridge between Darius III and Seleucus. It is drawn as a transition owner rather than an empty pause between Achaemenid and Seleucid rule.", cn: "亚历山大/继业者波斯表示大流士三世之后、塞琉古之前的马其顿征服与早期继业者过渡。它被画作过渡主人，而不是阿契美尼德与塞琉古之间的空档。" },
    alexander_anatolia: { en: "Alexander / Diadochi Anatolia keeps Asia Minor visible after the Macedonian campaigns and before the Ipsus settlement pushed Seleucid claims into the Anatolian lane.", cn: "亚历山大/继业者安纳托利亚让马其顿东征后的小亚细亚保持可见，直到伊普苏斯后的安排把塞琉古主张带入安纳托利亚栏。" },
    alexander_egypt: { en: "Alexander / Diadochi Egypt covers the Macedonian takeover of Egypt and the early satrapal bridge before Ptolemy I declared kingship.", cn: "亚历山大/继业者埃及覆盖马其顿接管埃及及托勒密一世称王前的早期总督过渡。" },
    alexander_levant: { en: "Alexander / Diadochi Levant covers the Phoenician and Syrian-Palestinian corridor after Tyre, Gaza, and the Macedonian campaigns, before the Ptolemaic and Seleucid split after Ipsus.", cn: "亚历山大/继业者黎凡特表示推罗、加沙和马其顿战役之后的腓尼基与叙利亚-巴勒斯坦走廊，直到伊普苏斯后托勒密与塞琉古分割该地。" },
    roman_empire: { en: "At its peak the Roman Empire ruled 70 million people across three continents. Latin, Roman law, Christianity, straight roads, concrete, calendars and the notion of citizenship all trace back here. The Mediterranean became a Roman lake for four centuries.", cn: "罗马帝国鼎盛时期统治三大洲的7000万人口。拉丁语、罗马法、基督教、直线道路、混凝土、历法与公民身份观念皆源于此。地中海四个世纪以来是一片罗马内海。" },
    roman_republic_2: { en: "The Roman Republic core is now kept in the Italian lane while wars and provinces in Iberia, Greece, and Gaul appear separately. This preserves Rome's expansion without implying that every western region became Roman at the same moment.", cn: "罗马共和国核心现在保留在意大利栏，伊比利亚、希腊与高卢的战争和行省另行显示。这样既保留罗马扩张，又避免暗示整个西方同时成为罗马领土。" },
    roman_republic_iberia: { en: "Roman Hispania begins with Rome's Second Punic War foothold and subsequent provincial rule in Iberia. It is a whole regional province lane beside the Italian republic, not a cutout owned by another Roman province.", cn: "罗马希斯帕尼亚始于第二次布匿战争中的据点，并发展为伊比利亚行省统治。它是意大利共和核心旁的完整区域行省栏，不是由另一个罗马行省承接的缺口。" },
    roman_republic_3: { en: "Roman Greece marks the republic's eastern Mediterranean victory after Macedon and the Greek leagues were brought under Roman power. It stays a whole provincial lane beside the Roman Republic core, tying the region back to Italy without drawing an internal cutout.", cn: "罗马希腊表示共和国在东地中海取胜后，马其顿与希腊诸同盟被纳入罗马权力之下。它作为罗马共和核心旁的完整行省栏显示，把该区域接回意大利，而不绘制内部缺口。" },
    roman_transalpine_gaul: { en: "Roman Transalpine Gaul represents the southern Gallic foothold that later became Narbonensis. It sits beside late Celtic Gaul rather than erasing the still-independent Gallic polities.", cn: "罗马外阿尔卑斯高卢表示后来成为纳尔榜行省的南高卢据点。它与晚期凯尔特高卢并列，而不是抹去仍独立的高卢政权。" },
    celtic_gaul_late: { en: "Late Celtic Gaul keeps the independent northern and western Gallic world visible between Rome's southern foothold and Caesar's conquest.", cn: "晚期凯尔特高卢让罗马南部据点与凯撒征服之间仍独立的高卢北部、西部世界保持可见。" },
    roman_republic_gaul: { en: "Roman Gaul in the republican period begins with Caesar's campaigns. The fragment avoids backdating Caesar's conquest to the earlier southern province, while staying a whole Roman provincial lane beside Italy.", cn: "共和国时期的罗马高卢从凯撒战役开始。这个片段避免把凯撒征服回填到更早的南部行省阶段，同时作为意大利旁边的完整罗马行省栏显示。" },
    roman_empire_greece: { en: "Roman Greece and the Balkans are drawn as their own whole imperial province lane. That keeps the eastern provinces separate in the simplified grid while still owner-linked to the empire.", cn: "罗马希腊与巴尔干作为独立而完整的帝国行省栏显示。这样既在简化网格中保留东方行省的独立可见性，也显示其属于帝国体系。" },
    roman_empire_gaul: { en: "Roman Gaul shows the imperial provinces north of the Alps as a distinct whole lane, separate from Hispania, Italy, and Britain but not cut as if those Roman provinces owned each other's land.", cn: "罗马高卢表示阿尔卑斯以北的帝国行省，作为完整栏与希斯帕尼亚、意大利、不列颠分开，但不切成仿佛罗马行省彼此占地的缺口。" },
    roman_empire_hispania: { en: "Roman Hispania tracks the Iberian provinces under imperial administration, preserving Spain's lane through the Roman centuries as a parallel Roman provincial field.", cn: "罗马希斯帕尼亚跟踪帝国行政下的伊比利亚行省，在罗马世纪中以并列罗马行省场保留西班牙栏。" },
    roman_britain: { en: "Roman Britain starts only with Claudius's conquest in 43 CE and stops before the final withdrawal. It is a whole island provincial lane, not a bite into Roman Hispania or Gaul.", cn: "罗马不列颠只从公元43年克劳狄征服开始，并在最终撤离前结束。它是完整的岛屿行省栏，不是切入罗马希斯帕尼亚或高卢的缺口。" },
    roman_empire_2: { en: "The second Roman imperial core segment marks consolidation after Trajan and Hadrian. Provincial lanes carry the geography while this block carries the imperial center.", cn: "第二段罗马帝国核心表示图拉真与哈德良之后的整固。行省栏承担地理范围，此块承担帝国中心。" },
    roman_late: { en: "Late Roman Italy marks the western core before the 395 split. Late Gaul, Hispania, Balkans, and Britain are separate so the chart can show fragmentation clearly.", cn: "晚期罗马意大利表示395年分裂前的西方核心。晚期高卢、希斯帕尼亚、巴尔干和不列颠分开，便于清楚表现碎片化。" },
    roman_late_greece: { en: "Late Roman Balkans bridges the classical Roman period and the Byzantine line that begins after the formal east-west division. It stays whole as an eastern/Balkan provincial lane within the pre-395 imperial system.", cn: "晚期罗马巴尔干连接古典罗马时期与正式东西分治后开始的拜占庭线。它作为395年前帝国体系中的东方/巴尔干行省栏保持完整。" },
    roman_late_gaul: { en: "Late Roman Gaul remains visible as a whole provincial lane until the Western Roman order gives way to Frankish power.", cn: "晚期罗马高卢作为完整行省栏保持可见，直到西罗马秩序让位于法兰克权力。" },
    roman_late_hispania: { en: "Late Roman Hispania keeps Iberia's Roman administration distinct before Visigothic power dominates the peninsula, without treating neighboring Roman provinces as cutout owners.", cn: "晚期罗马希斯帕尼亚在西哥特权力主导半岛前，保留伊比利亚的罗马行政区分，但不把相邻罗马行省当作缺口主人。" },
    w_roman: { en: "Western Roman Italy is the late imperial center around Ravenna and Rome, not a block over Britain. The surrounding provinces are separate fragments.", cn: "西罗马意大利表示拉文纳与罗马周边的晚期帝国中心，而不是覆盖不列颠的大方块。周边行省以独立片段显示。" },
    w_roman_gaul: { en: "Western Roman Gaul marks the final Roman provincial order in Gaul before Frankish succession. It stays whole beside Western Roman Hispania; the later concrete Iberian loss is handled locally inside Hispania.", cn: "西罗马高卢表示法兰克继承前高卢最后的罗马行省秩序。它在西罗马希斯帕尼亚旁保持完整；后续具体的伊比利亚丧失在希斯帕尼亚内部本地处理。" },
    w_roman_hispania: { en: "Western Roman Hispania marks the late Roman Iberian lane, with its post-409 cut carried by local Iberian successor polities rather than by the unrelated Britain lane.", cn: "西罗马希斯帕尼亚表示晚期罗马伊比利亚栏；409年后的缺口由伊比利亚本地继承势力承接，而不是由不相邻的不列颠栏承接。" },
    hispania_successor_foederati: { en: "Iberian Successor Polities compresses Suebi, Vandal/Alan, and early Visigothic or federate pressure inside late Roman Hispania. It is a deliberately local composite owner for the missing strip, not a separate full-peninsula state.", cn: "伊比利亚继承诸政权压缩显示晚期罗马希斯帕尼亚内部的苏维汇、汪达尔/阿兰，以及早期西哥特或同盟军压力。它是有意设置的本地复合承接主人，不是一个占据全半岛的单一国家。" },
    w_roman_britain: { en: "Roman Britain Withdrawal marks the final administrative break from Britain around 410 CE, after which local post-Roman kingdoms and communities took shape.", cn: "罗马不列颠撤离表示约410年前后的最终行政断裂，此后地方后罗马王国与社群逐渐形成。" },
    sub_roman: { en: "Sub-Roman Britain begins after Roman central authority ceased. The shifted start keeps withdrawal and local continuity visible as adjacent phases.", cn: "后罗马不列颠始于罗马中央权威停止之后。起点后移让撤离与地方延续成为相邻阶段而非重叠方块。" },
    france_post: { en: "Modern France before 1940 is now separated from Vichy France and German occupation, so the World War II rupture is visible.", cn: "1940年前的现代法国现在与维希法国、德占区分开，因此二战断裂可见。" },
    france_vichy: { en: "Vichy France marks the French state under Marshal Petain after defeat in 1940. It is shown beside German occupation because collaboration and sovereignty were contested and limited.", cn: "维希法国表示1940年战败后贝当元帅领导下的法国国家。它与德占区并列，因为合作、主权与控制都存在争议且有限。" },
    france_postwar: { en: "Postwar France resumes the French lane after liberation and the collapse of Vichy and German occupation.", cn: "战后法国在解放以及维希和德占崩溃后重新接续法国栏。" },
    nazi_germany: { en: "Nazi Germany is narrowed to the German state core. Occupation zones in Poland, France, and Italy appear as separate fragments so neutral Spain and allied or occupied states are not hidden.", cn: "纳粹德国窄化为德国国家核心。波兰、法国和意大利的占领区以独立片段显示，因此中立西班牙以及同盟或被占国家不被隐藏。" },
    allied_occupied_germany: { en: "Allied-occupied Germany replaces the old single postwar rectangle for 1945-49. The block means four-power occupation and a reduced German territory after the eastern losses, before the FRG and GDR became separate states.", cn: "盟军占领德国替代1945-49年旧的战后单一矩形。该块表示四国占领以及东部领土丧失后的德国，而非东西德建国后的状态。" },
    west_germany: { en: "West Germany is the Federal Republic formed from the western occupation zones. It is drawn narrower than the old divided-Germany block, with West Berlin shown as a detached western-aligned fragment rather than ignored or merged into East Germany.", cn: "西德是由西方占领区形成的德意志联邦共和国。它比旧的分裂德国块更窄，西柏林作为不相邻的西方阵营片段另行显示，而不是被忽略或并入东德。" },
    east_germany: { en: "East Germany is the German Democratic Republic formed from the Soviet occupation zone. It receives the eastern part of the divided German lane, so West Germany's contraction has a concrete neighboring owner.", cn: "东德是由苏联占领区形成的德意志民主共和国。它承接德国分裂栏的东部，因此西德收窄对应明确的相邻主人。" },
    west_berlin: { en: "West Berlin is modeled as a non-contiguous western-aligned fragment inside the simplified German lane. This makes the enclave visible without leaving the surrounding East German space ownerless.", cn: "西柏林被建模为简化德国栏中的非相邻西方阵营片段。这样可以让飞地可见，同时不把周围东德空间留成无主空白。" },
    germany_unified: { en: "Unified Germany begins with the 1990 accession of the GDR and reunited Berlin into the Federal Republic. The full-width block returns only after the divided owners and the West Berlin enclave have been resolved.", cn: "统一德国始于1990年东德与统一后的柏林并入德意志联邦共和国。只有在东西德主人和西柏林飞地被解决后，图块才恢复全宽。" },
    nazi_peak: { en: "Nazi Occupied France is a German occupation fragment, not all of Europe. It sits beside Vichy France to show the divided French wartime situation.", cn: "纳粹占领法国是德国占领片段，不代表整个欧洲。它与维希法国并列，显示法国战时分裂局面。" },
    poland_resistance: { en: "Polish Resistance keeps the underground state, exile government claim, and Home Army world visible during German occupation.", cn: "波兰抵抗保留德国占领期间的地下国家、流亡政府合法性与家乡军世界。" },
    nazi_poland_occupation: { en: "Nazi-occupied Poland marks the German occupation and terror regime after the 1939 invasion, drawn beside Polish resistance rather than replacing Poland entirely.", cn: "纳粹占领波兰表示1939年入侵后的德国占领与恐怖统治，与波兰抵抗并列，而非完全替代波兰。" },
    sardinia_piedmont: { en: "Piedmont-Sardinia is separated from the generic Italian States because it became the Savoy-led engine of unification. The left-side fragment shows the restored, Genoa-enlarged kingdom that later supplied Victor Emmanuel II and Cavour.", cn: "皮埃蒙特-撒丁从泛称的意大利诸邦中拆出，因为它后来成为萨伏依王朝主导统一的发动机。左侧片段表示维也纳会议后复建并纳入热那亚的王国，后来提供了维托里奥·埃马努埃莱二世和加富尔。" },
    austrian_italy: { en: "Austrian Italy represents Lombardy-Venetia and the wider Austrian hegemony restored after Vienna. It fills the northeastern/right-side share of the restored Italian peninsula instead of leaving the anti-Risorgimento pressure invisible.", cn: "奥地利意大利表示维也纳会议后恢复的伦巴第-威尼西亚及更广泛的奥地利霸权。它填入复辟意大利半岛的东北/右侧份额，避免把压制复兴运动的压力隐藏起来。" },
    italy_states: { en: "Restored Italian States now means the Papal, Tuscan, Modenese, Parmese, Two Sicilies, and other central/southern rulers between Piedmont-Sardinia and Austrian Italy. Its interlocked edges make the peninsula a multi-owner field after 1815, not a full yellow rectangle.", cn: "复辟意大利诸邦现在表示夹在皮埃蒙特-撒丁与奥地利意大利之间的教皇、托斯卡纳、摩德纳、帕尔马、两西西里及其他中南部统治者。其咬合边缘说明1815年后半岛是多主人场域，而不是完整黄色矩形。" },
    italy_kingdom: { en: "The Kingdom of Italy begins with the 1861 Savoy-led unification but keeps an early owner-filled cut for Venetia and papal Rome, which were not fully incorporated until 1866-70. After that, the liberal-monarchical lane runs to Mussolini's takeover.", cn: "意大利王国始于1861年萨伏依主导的统一，但早期保留由威尼斯与教皇罗马承接的缺口，因为这些地区到1866-70年才完全并入。随后自由主义君主国栏一直延续到墨索里尼夺权。" },
    italy_unincorporated: { en: "Venetia + Papal Rome is a composite missing-share owner for the early Kingdom of Italy: Austrian Venetia and the remaining Papal temporal power are kept visible until the final Risorgimento settlement.", cn: "威尼斯+教皇罗马是早期意大利王国缺失份额的复合主人：奥地利控制的威尼西亚与残余教皇世俗权力一直可见，直到复兴运动最后完成。" },
    fascist_italy: { en: "Fascist Italy is Italy's own Axis regime, distinct from German occupation after the 1943 armistice. The territorial split is shown only after the surrender, where co-belligerent Italy and the German-backed RSI interlock.", cn: "法西斯意大利是意大利自身的轴心国政权，与1943年停战后的德国占领不同。领土分裂只在投降后显示，由共同交战意大利与德国扶持的意大利社会共和国咬合呈现。" },
    italy_cobelligerent: { en: "Co-belligerent Italy marks the royalist south and Allied-aligned Italian state after the 1943 armistice. Its German-facing cut is explicitly filled by the RSI / occupation owner, so the wartime north-south split has no blank middle.", cn: "共同交战意大利表示1943年停战后王室控制的南方及与盟军并肩作战的意大利国家。其面向德国的一侧缺口明确由意大利社会共和国/占领主人承接，所以战时南北分裂没有空白中间地带。" },
    nazi_italy_occupation: { en: "German-occupied Italy marks the northern and central occupation zone and Italian Social Republic dependency after Mussolini's fall. The reciprocal cut points back to co-belligerent Italy, making occupation and royalist continuity interlock.", cn: "德占意大利表示墨索里尼垮台后的北中部占领区和意大利社会共和国依附状态。反向缺口接回共同交战意大利，使占领区与王室连续性彼此咬合。" },
    italy_republic: { en: "The Italian Republic begins after liberation and the 1946 institutional referendum ended the Savoy monarchy. It carries postwar reconstruction, Christian Democratic dominance, the economic miracle, and European integration within the restored full Italian lane.", cn: "意大利共和国始于解放以及1946年制度公投终结萨伏依君主制之后。它在恢复的完整意大利栏中承接战后重建、基民党主导、经济奇迹与欧洲一体化。" },
    poland_people: { en: "The Polish People's Republic is the Polish state owner under communist rule. Warsaw Pact pressure sits beside it as an influence strip, not as a cutout owner of Polish land.", cn: "波兰人民共和国是共产主义统治下的波兰国家主人。华约压力作为相邻影响带显示，而不是承接波兰土地缺口的主人。" },
    ussr_warsaw_pact_poland: { en: "Soviet Bloc Poland marks Soviet-dominated Warsaw Pact political-military pressure around Poland. It is an influence and alliance layer, not Soviet annexation or a territorial owner.", cn: "苏联阵营波兰表示苏联主导的华约对波兰形成政治军事压力。它是影响与联盟层，不是苏联吞并，也不是领土主人。" },
    poland_mod: { en: "Post-1989 Poland resumes the full Polish lane after communist rule and Warsaw Pact dominance receded. The state succession and the fading bloc influence are deliberately separated.", cn: "1989年后的波兰在共产主义统治与华约支配退去后恢复完整波兰栏。国家继承与阵营影响消退被有意分开显示。" },
    ussr: { en: "The Soviet Union is now drawn in the Russian/Soviet core lane after 1945. Eastern European satellite influence is represented separately so the chart does not confuse hegemony with annexation.", cn: "1945年后的苏联现在绘于俄罗斯/苏联核心栏。对东欧卫星国的影响另行表示，避免把霸权误画为吞并。" },
    maurya_nw: { en: "Under Maurya rule, the northwest frontier brought India into contact with Hellenistic successor states of Alexander's empire. This cultural meeting gave rise to Gandharan art and carried Buddhism along trade routes into Central Asia and China.", cn: "孔雀王朝治下的西北前沿使印度与亚历山大帝国的希腊化继承国接触。这一文化交汇催生犍陀罗艺术，并将佛教沿贸易路线带入中亚与中国。" },
    xia: { en: "Xia is shown as the legendary and Erlitou-adjacent Yellow River kingship horizon between Neolithic cultures and the historically attested Shang. Southern cultures remain visible in their adjacent lane, so early China is not mistaken for a modern all-China rectangle or a land-bite map.", cn: "夏在这里表示介于新石器文化与有甲骨文可证商朝之间的传说/二里头邻近黄河王权视野。南方文化保留在相邻栏中，因此早期中国既不会被误画成现代全中国矩形，也不会被画成土地缺口拼图。" },
    shang: { en: "Shang is the first securely attested Chinese dynasty, anchored by Anyang/Yin, oracle bones, bronze ritual vessels, chariot warfare, and royal ancestor cults. It is drawn as a whole Central Plains royal lane beside southern cultural worlds rather than as a clipped polygon.", cn: "商是中国第一个有坚实文字与考古证据的王朝，以安阳/殷、甲骨文、青铜礼器、战车和王室祖先祭祀为核心。它绘为完整的中原王权栏，与南方文化世界并列，而不是被切成多边形。" },
    zhou_west: { en: "Western Zhou began after the Zhou conquest of Shang and built a royal, ritual, and enfeoffment order from the Wei and Yellow River world. The south remains an adjacent cultural lane; Zhou expansion and influence are expressed by text and relationships.", cn: "西周始于周灭商之后，从渭河与黄河世界建立王室、礼制和封建秩序。南方保留为相邻文化栏；周的扩张与影响由文字和联系表达。" },
    zhou_east: { en: "Eastern Zhou is a nominal Zhou kingship frame over the Spring and Autumn and Warring States age. Chu and the Qin southern conquest are adjacent regional-state records with explicit links, not cutout owners inserted into a Zhou edge.", cn: "东周是春秋战国时代名义上的周王室框架。楚与秦南方征服作为相邻区域国家记录并由明确联系表达，而不是嵌入周边缘的缺口主人。" },
    chu_state: { en: "Chu was a major southern Zhou and Warring States power centered in the middle Yangtze/Hubei-Hunan world. It fills the southern lane beside Eastern Zhou and Qin so territorial plurality is visible.", cn: "楚是周代南方和战国时代的重要强国，中心在长江中游、湖北湖南一带。它填充东周与秦旁侧的南方栏，使疆域多主人状态可见。" },
    qin_chu_conquest: { en: "Qin Southern Conquest marks the brief post-223 BCE transfer after Qin destroyed Chu and before the final 221 BCE imperial unification. The gap has an owner: Qin, not empty land.", cn: "秦南方征服表示前223年秦灭楚后、前221年最终统一前的短暂接管。这个缺口有主人：秦，而不是空地。" },
    xin: { en: "Xin was Wang Mang's short-lived usurpation between Western and Eastern Han. It is a real bridge in the imperial lane, not a blank pause between two Han blocks.", cn: "新朝是王莽在西汉与东汉之间建立的短暂篡立政权。它是帝国栏中的真实承接段，而不是两个汉朝方块之间的空白暂停。" }
};

