            { year: 1826, event: "Barakzai Kabul", eventCN: "巴拉克宰喀布尔" },
            { year: 1919, event: "Afghan Independence", eventCN: "阿富汗独立" },
            { year: 1991, event: "Independence", eventCN: "中亚独立" }
