// ============================================
// UTILITY FUNCTIONS
// ============================================

function yearToY(year) {
    return (year - CONFIG.timelineStart) * CONFIG.yearHeight;
}

function formatYear(year) {
    if (CONFIG.language === 'cn') return formatYearCN(year);
    if (year < 0) return `${Math.abs(year)} BC`;
    return `AD ${year}`;
}

function formatYearCN(year) {
    if (year < 0) return `公元前${Math.abs(year)}年`;
    return `公元${year}年`;
}

function getName(item) {
    return CONFIG.language === 'cn' ? (item.nameCN || item.name) : item.name;
}

function getBlockName(item) {
    return CONFIG.language === 'cn' ? (item.shortNameCN || item.nameCN || item.name) : (item.shortName || item.name);
}

function getOrderedRegionKeys() {
    const known = new Set(REGION_DISPLAY_ORDER);
    const ordered = REGION_DISPLAY_ORDER.filter(region => WORLD_HISTORY[region]);
    Object.keys(WORLD_HISTORY).forEach(region => {
        if (!known.has(region)) ordered.push(region);
    });
    return ordered;
}

function getVisibleRegions() {
    return getOrderedRegionKeys()
        .filter(region => CONFIG.visibleRegions[region]);
}

