// ============================================
// RENDERING
// ============================================

function renderYearScale() {
    elements.yearScale.innerHTML = '';
    const totalHeight = yearToY(CONFIG.timelineEnd);

    // Choose tick step based on zoom level
    let step;
    if (CONFIG.yearHeight < 0.3) step = 500;
    else if (CONFIG.yearHeight < 0.6) step = 250;
    else if (CONFIG.yearHeight < 1.5) step = 100;
    else if (CONFIG.yearHeight < 4) step = 50;
    else if (CONFIG.yearHeight < 8) step = 25;
    else step = 10;

    // Snap start to a multiple of step
    const startYear = Math.ceil(CONFIG.timelineStart / step) * step;

    for (let year = startYear; year <= CONFIG.timelineEnd; year += step) {
        const mark = document.createElement('div');
        const isMillennium = year % 1000 === 0;
        const isCentury = year % 100 === 0;
        let cls = 'year-mark';
        if (isMillennium) cls += ' millennium';
        else if (isCentury) cls += ' century';
        mark.className = cls;
        mark.style.top = `${yearToY(year) + 35}px`;
        mark.textContent = formatYear(year);
        elements.yearScale.appendChild(mark);
    }

    elements.yearScale.style.height = `${totalHeight + 35}px`;
}

/**
 * Detect and fix obvious data conflicts where two entities sharing the SAME
 * slot footprint also overlap in time (e.g. Babylon IV-V is "still going" while
 * the Assyrian Empire occupies the same Mesopotamian slot). The earlier-starting
 * entity is trimmed to end when the later one begins.
 *
 * Broad empires with partial occupation, vassalage, or frontier semantics should
 * be split into explicit fragments instead of relying on rectangular overlays.
 */
function normalizeOverlaps() {
    let trims = 0;
    Object.values(WORLD_HISTORY).forEach(region => {
        const entities = region.entities;
        for (const a of entities) {
            // Find the earliest later-starting entity that shares a's exact slot
            // footprint. Trim a's end so the two don't visually overlap.
            // (We accept that this loses any "a continued after b ended" history;
            // the slot grid only allows one polity per slot at a time.)
            let earliest = Infinity;
            for (const b of entities) {
                if (b === a) continue;
                if (b.start <= a.start) continue;
                if (b.start >= a.end) continue;
                if (b.slot !== a.slot || b.width !== a.width) continue;
                if (b.start < earliest) earliest = b.start;
            }
            if (earliest < a.end) {
                a.end = earliest;
                trims++;
            }
        }
    });
    return trims;
}

function renderTimeline() {
    clearActiveTimelinePreview();
    elements.timelineGrid.innerHTML = '';
    elements.timelineGrid.style.marginLeft = '';
    elements.timelineGrid.style.marginRight = '';
    entityPositions = {}; // Reset positions
    const totalHeight = yearToY(CONFIG.timelineEnd);

    const visibleRegions = getVisibleRegions();
    let currentSlotOffset = 0;

    let totalSlots = 0;
    visibleRegions.forEach((regionId, index) => {
        const region = WORLD_HISTORY[regionId];
        if (region) {
            totalSlots += getRegionSlotSpan(regionId, region);
            totalSlots += getRegionBoundaryGapAfter(regionId, visibleRegions, index);
        }
    });

    elements.timelineGrid.style.height = `${totalHeight + 50}px`;
    elements.timelineGrid.style.width = `${(totalSlots + 1) * CONFIG.baseColumnWidth + 40}px`;

    // Era backgrounds
    if (CONFIG.showEraBackgrounds) {
        renderEraBackgrounds(totalSlots);
    }

    const query = CONFIG.searchQuery ? CONFIG.searchQuery.toLowerCase() : '';
    let matchCount = 0;
    let visibleCount = 0;

    document.body.classList.toggle('search-active', !!query);

    visibleRegions.forEach((regionId, regionIndex) => {
        const region = WORLD_HISTORY[regionId];
        if (!region) return;
        const layout = getRegionLayout(regionId, region);
        const regionSpan = getRegionSlotSpan(regionId, region, layout);

        renderRegionHeader(region, regionId, currentSlotOffset, layout);
        renderRegionLayoutGaps(regionId, currentSlotOffset, layout);

        // Render order: smallest territorial footprints first for stable labels
        // and predictable hit targets. Known partial occupations should be
        // modeled as explicit narrow fragments, not broad overlay rectangles.
        const orderedEntities = region.entities
            .map((e, originalIdx) => ({ e, originalIdx }))
            .sort((x, y) => {
                if (x.e.width !== y.e.width) return x.e.width - y.e.width;
                if (x.e.start !== y.e.start) return x.e.start - y.e.start;
                return x.originalIdx - y.originalIdx;
            });

        orderedEntities.forEach(({ e: entity, originalIdx: idx }) => {
            // Category filter
            if (CONFIG.categoryFilter && entity.category !== CONFIG.categoryFilter) return;

            // Search match
            let isMatch = true;
            if (query) {
                const matchesName = entity.name.toLowerCase().includes(query);
                const matchesNameCN = (entity.nameCN || '').toLowerCase().includes(query);
                const matchesRulers = entity.rulers && entity.rulers.some(r => r.toLowerCase().includes(query));
                isMatch = matchesName || matchesNameCN || matchesRulers;
            }
            if (query && !isMatch) {
                // render dimmed anyway so user sees context
                renderEntity(entity, regionId, currentSlotOffset, { dim: true, animIndex: idx, region, layout });
                visibleCount++;
                return;
            }
            renderEntity(entity, regionId, currentSlotOffset, { match: query && isMatch, animIndex: idx, region, layout });
            if (query && isMatch) matchCount++;
            visibleCount++;
        });
        // End orderedEntities iteration

        // Mark moments when a polity gains/loses territory horizontally
        if (!CONFIG.categoryFilter && !query) {
            renderTerritorialTransitions(region, currentSlotOffset);
        }

        const boundaryGap = getRegionBoundaryGapAfter(regionId, visibleRegions, regionIndex);
        if (boundaryGap > 0) {
            renderRegionBoundaryGap(regionId, currentSlotOffset + regionSpan, boundaryGap);
        }
        currentSlotOffset += regionSpan + boundaryGap;
    });

    applySameColorSeams();

    // Render connections after all entities
    if (CONFIG.showConnections) {
        renderConnections();
    }

    // Stats
    updateStatsChip(visibleCount, matchCount);
    centerNarrowTimelineGrid();
    fitBlockFaceLabels();
    requestAnimationFrame(fitBlockFaceLabels);
    updateTimeRulerPosition();
    queueGlobalEventMarkerPositionUpdate();
}

function getRegionSlotSpan(regionId, region, layout = null) {
    if (!region) return 0;
    const baseSpan = Math.max(0, Number(region.slotEnd) || 0);
    const resolvedLayout = layout || getRegionLayout(regionId, region);
    return Math.max(baseSpan, resolvedLayout?.totalSlots || 0);
}

function getRegionBoundaryGapAfter(regionId, visibleRegions = getVisibleRegions(), index = -1) {
    const regionIndex = index >= 0 ? index : visibleRegions.indexOf(regionId);
    if (regionIndex < 0 || regionIndex >= visibleRegions.length - 1) return 0;
    const gap = REGION_BOUNDARY_GAPS_AFTER[regionId] ?? REGION_BOUNDARY_GAP_DEFAULT;
    return Math.max(0, Number(gap) || 0);
}

function centerNarrowTimelineGrid() {
    const wrapper = elements.timelineWrapper;
    const grid = elements.timelineGrid;
    if (!wrapper || !grid) return;

    const gridWidth = grid.getBoundingClientRect().width;
    const extraSpace = wrapper.clientWidth - gridWidth;
    const margin = extraSpace > 0 ? extraSpace / 2 : 0;
    grid.style.marginLeft = margin ? `${margin}px` : '';
    grid.style.marginRight = margin ? `${margin}px` : '';
}

function fitBlockFaceLabels() {
    if (!elements.timelineGrid) return;
    elements.timelineGrid.querySelectorAll('.dynasty-block.label-overflow-hidden')
        .forEach(block => block.classList.remove('label-overflow-hidden'));

    elements.timelineGrid.querySelectorAll('.dynasty-block .dynasty-name').forEach(label => {
        const block = label.closest('.dynasty-block');
        if (!block) return;
        const fullLabel = label.dataset.fullLabel || label.textContent;
        label.textContent = fullLabel;
        if (label.scrollWidth <= label.clientWidth + 1) return;

        const candidates = getCompactFaceLabelCandidates(fullLabel);
        for (const candidate of candidates) {
            label.textContent = candidate;
            if (label.scrollWidth <= label.clientWidth + 1) return;
        }
        block.classList.add('label-overflow-hidden');
    });
}

function getCompactFaceLabelCandidates(label) {
    const clean = String(label || '').trim();
    if (!clean) return [];

    if (CONFIG.language === 'cn') {
        const chars = Array.from(clean.replace(/\s+/g, ''));
        return [...new Set([chars.slice(0, 2).join(''), chars[0]].filter(Boolean))];
    }

    const words = clean
        .replace(/[()]/g, ' ')
        .split(/[\s/+–—-]+/)
        .map(word => word.replace(/[^A-Za-z0-9]/g, ''))
        .filter(Boolean);
    const significant = words.filter(word => !/^(of|the|and|in|for|to|de|la|le|du)$/i.test(word));
    const initials = significant.map(word => word[0]).join('').toUpperCase();
    const compactWords = significant.map(word => word.slice(0, 3)).join('/');
    const plain = clean.replace(/[^A-Za-z0-9]/g, '');

    return [...new Set([
        initials.slice(0, 4),
        initials.slice(0, 3),
        compactWords,
        plain.slice(0, 4),
        plain.slice(0, 3),
        plain.slice(0, 2),
        plain.slice(0, 1)
    ].filter(Boolean))];
}

function renderEraBackgrounds(totalSlots) {
    const gridWidth = (totalSlots + 1) * CONFIG.baseColumnWidth + 40;

    HISTORICAL_ERAS.forEach((era, idx) => {
        const top = yearToY(era.start) + 35;
        const height = yearToY(era.end) - yearToY(era.start);

        const eraDiv = document.createElement('div');
        eraDiv.className = 'era-background';
        const alternateTint = idx % 2 === 0 ? 'rgba(124, 95, 19, 0.04)' : 'rgba(43, 70, 119, 0.035)';
        eraDiv.style.cssText = `
            position: absolute;
            top: ${top}px;
            left: 0;
            width: ${gridWidth}px;
            height: ${height}px;
            background: ${alternateTint};
            pointer-events: none;
            z-index: 0;
        `;

        // Era boundary line (at the start)
        if (era.start > CONFIG.timelineStart) {
            const tick = document.createElement('div');
            tick.className = 'era-tick';
            tick.style.top = `${yearToY(era.start) + 35}px`;
            elements.timelineGrid.appendChild(tick);
        }

        // Era label — vertical on left side
        const label = document.createElement('div');
        label.className = 'era-label';
        label.style.cssText = `
            position: absolute;
            left: 6px;
            top: 50%;
            transform: translateY(-50%) rotate(-90deg);
            transform-origin: left center;
            font-size: 10px;
            pointer-events: none;
        `;
        label.textContent = CONFIG.language === 'cn' ? era.nameCN : era.name;
        eraDiv.appendChild(label);

        elements.timelineGrid.appendChild(eraDiv);
    });
}

function renderRegionHeader(region, regionId, slotOffset, layout = null) {
    const regionStyles = {
        eastAsia:       { base: 'var(--r-eastasia)',     ink: 'var(--r-eastasia-ink)',     tint: 'var(--r-eastasia-tint)' },
        europe:         { base: 'var(--r-europe)',       ink: 'var(--r-europe-ink)',       tint: 'var(--r-europe-tint)' },
        middleEast:     { base: 'var(--r-middleeast)',   ink: 'var(--r-middleeast-ink)',   tint: 'var(--r-middleeast-tint)' },
        southAsia:      { base: 'var(--r-southasia)',    ink: 'var(--r-southasia-ink)',    tint: 'var(--r-southasia-tint)' },
        centralAsia:    { base: 'var(--r-centralasia)',  ink: 'var(--r-centralasia-ink)',  tint: 'var(--r-centralasia-tint)' },
        africa:         { base: 'var(--r-africa)',       ink: 'var(--r-africa-ink)',       tint: 'var(--r-africa-tint)' },
        americas:       { base: 'var(--r-americas)',     ink: 'var(--r-americas-ink)',     tint: 'var(--r-americas-tint)' },
        southeastAsia:  { base: 'var(--r-seasia)',       ink: 'var(--r-seasia-ink)',       tint: 'var(--r-seasia-tint)' }
    };
    const style = regionStyles[regionId] || regionStyles.europe;

    const totalHeight = yearToY(CONFIG.timelineEnd);
    const headerSlotWidth = getRegionSlotSpan(regionId, region, layout);

    // Vertical separator for adjacent regions
    if (slotOffset > 0) {
        const separator = document.createElement('div');
        separator.className = 'region-separator';
        separator.style.cssText = `
            position: absolute;
            top: 35px;
            left: ${slotOffset * CONFIG.baseColumnWidth - 1}px;
            width: 1px;
            height: ${totalHeight}px;
            pointer-events: none;
        `;
        elements.timelineGrid.appendChild(separator);
    }

    const header = document.createElement('div');
    header.className = 'region-header';
    header.setAttribute('data-region', regionId);
    header.style.cssText = `
        position: absolute;
        top: 0;
        left: ${slotOffset * CONFIG.baseColumnWidth}px;
        width: ${headerSlotWidth * CONFIG.baseColumnWidth}px;
        height: 34px;
        display: flex;
        flex-direction: column;
        justify-content: center;
        padding-left: 14px;
        z-index: 15;
    `;
    // Dual-language subtitle via data attribute
    header.textContent = CONFIG.language === 'cn' ? (region.nameCN || region.name) : region.name;
    header.setAttribute('data-subtitle', CONFIG.language === 'cn' ? region.name : (region.nameCN || ''));
    elements.timelineGrid.appendChild(header);
}

function renderRegionLayoutGaps(regionId, slotOffset, layout) {
    if (!layout?.gaps?.length) return;
    const totalHeight = yearToY(CONFIG.timelineEnd);

    layout.gaps.forEach(gap => {
        const spacer = document.createElement('div');
        spacer.className = `layout-gap layout-gap-${regionId}`;
        spacer.setAttribute('aria-hidden', 'true');
        spacer.style.cssText = `
            position: absolute;
            top: 35px;
            left: ${(slotOffset + gap.start) * CONFIG.baseColumnWidth}px;
            width: ${gap.width * CONFIG.baseColumnWidth}px;
            height: ${totalHeight}px;
            pointer-events: none;
        `;
        elements.timelineGrid.appendChild(spacer);
    });
}

function renderRegionBoundaryGap(regionId, gapStartSlot, gapWidth) {
    const totalHeight = yearToY(CONFIG.timelineEnd);
    const spacer = document.createElement('div');
    spacer.className = `layout-gap region-boundary-gap region-boundary-gap-after-${regionId}`;
    spacer.setAttribute('aria-hidden', 'true');
    spacer.style.cssText = `
        position: absolute;
        top: 35px;
        left: ${gapStartSlot * CONFIG.baseColumnWidth}px;
        width: ${gapWidth * CONFIG.baseColumnWidth}px;
        height: ${totalHeight}px;
        pointer-events: none;
    `;
    elements.timelineGrid.appendChild(spacer);
}

function getRegionLayout(regionId, region) {
    if (!region) return null;
    const cached = regionLayoutCache.get(regionId);
    if (cached) return cached;

    const groups = buildLaneGroups(region);
    const guide = REGION_LAYOUT_GUIDES[regionId] || null;
    const groupOrder = optimizeLaneGroupOrder(regionId, groups, guide);
    const slotMap = new Map();
    let layoutStart = 0;
    const gaps = [];
    const gapsAfterSourceEnd = guide?.gapsAfterSourceEnd || {};

    groupOrder.forEach(groupIndex => {
        const group = groups[groupIndex];
        group.layoutStart = layoutStart;
        group.slots.forEach((slot, offset) => {
            slotMap.set(slot, layoutStart + offset);
        });
        layoutStart += group.length;
        const gap = Math.max(0, Number(gapsAfterSourceEnd[group.sourceEnd]) || 0);
        if (gap > 0) {
            gaps.push({
                start: layoutStart,
                width: gap,
                afterSourceStart: group.sourceStart,
                afterSourceEnd: group.sourceEnd
            });
            layoutStart += gap;
        }
    });

    const layout = { groups, groupOrder, slotMap, gaps, totalSlots: layoutStart };
    regionLayoutCache.set(regionId, layout);
    return layout;
}

function buildLaneGroups(region) {
    const slotCount = Math.max(0, Math.floor(region.slotEnd || 0));
    const parent = Array.from({ length: slotCount }, (_, index) => index);
    const find = index => {
        if (parent[index] === index) return index;
        parent[index] = find(parent[index]);
        return parent[index];
    };
    const unite = (a, b) => {
        const rootA = find(a);
        const rootB = find(b);
        if (rootA !== rootB) parent[rootB] = rootA;
    };

    region.entities.forEach(entity => {
        const start = Math.max(0, Math.floor(Number(entity.slot) + 0.000001));
        const end = Math.min(slotCount, Math.ceil(Number(entity.slot) + Number(entity.width) - 0.000001));
        for (let slot = start + 1; slot < end; slot += 1) {
            unite(start, slot);
        }
    });

    const grouped = new Map();
    for (let slot = 0; slot < slotCount; slot += 1) {
        const root = find(slot);
        if (!grouped.has(root)) grouped.set(root, []);
        grouped.get(root).push(slot);
    }

    return Array.from(grouped.values())
        .sort((a, b) => a[0] - b[0])
        .map((slots, index) => ({
            index,
            slots,
            sourceStart: slots[0],
            sourceEnd: slots[slots.length - 1] + 1,
            length: slots.length,
            originalIndex: index,
            layoutStart: slots[0]
        }));
}

function optimizeLaneGroupOrder(regionId, groups, guide) {
    const originalOrder = groups.map((_, index) => index);
    if (guide?.preserveOrder) return originalOrder;
    if (!guide || groups.length <= 1) return originalOrder;

    const targetOrder = normalizeLayoutGuideOrder(groups, guide.slotOrder);
    if (targetOrder.length !== groups.length) return originalOrder;
    if (groups.length > 8) return targetOrder;

    const relationWeights = buildLaneRelationWeights(regionId, groups);
    const targetPositions = orderToPositions(targetOrder);
    const guideWeight = Number.isFinite(guide.guideWeight) ? guide.guideWeight : 18;
    const originalWeight = Number.isFinite(guide.originalWeight) ? guide.originalWeight : 2;
    let bestOrder = targetOrder;
    let bestScore = scoreLaneGroupOrder(targetOrder, groups, relationWeights, targetPositions, guideWeight, originalWeight);

    permuteLaneOrder(originalOrder, candidate => {
        const score = scoreLaneGroupOrder(candidate, groups, relationWeights, targetPositions, guideWeight, originalWeight);
        if (score < bestScore) {
            bestScore = score;
            bestOrder = candidate.slice();
        }
    });

    return bestOrder;
}

function normalizeLayoutGuideOrder(groups, slotOrder = []) {
    const order = [];
    slotOrder.forEach(slot => {
        const index = getLaneGroupIndexForSlot(groups, Number(slot));
        if (index >= 0 && !order.includes(index)) order.push(index);
    });
    groups.forEach((_, index) => {
        if (!order.includes(index)) order.push(index);
    });
    return order;
}

function buildLaneRelationWeights(regionId, groups) {
    const weights = groups.map(() => groups.map(() => 0));
    CONNECTIONS.forEach(connection => {
        if (getEntityRegion(connection.from) !== regionId || getEntityRegion(connection.to) !== regionId) return;
        const from = findEntityById(connection.from);
        const to = findEntityById(connection.to);
        if (!from || !to) return;
        const fromGroup = getLaneGroupIndexForEntity(groups, from);
        const toGroup = getLaneGroupIndexForEntity(groups, to);
        if (fromGroup < 0 || toGroup < 0 || fromGroup === toGroup) return;

        const weight = LAYOUT_CONNECTION_WEIGHTS[connection.type] || 2;
        weights[fromGroup][toGroup] += weight;
        weights[toGroup][fromGroup] += weight;
    });
    return weights;
}

function getLaneGroupIndexForEntity(groups, entity) {
    return getLaneGroupIndexForSlot(groups, Number(entity.slot) + Number(entity.width || 0) / 2);
}

function getLaneGroupIndexForSlot(groups, slot) {
    return groups.findIndex(group => slot >= group.sourceStart && slot < group.sourceEnd);
}

function orderToPositions(order) {
    const positions = [];
    order.forEach((groupIndex, position) => {
        positions[groupIndex] = position;
    });
    return positions;
}

function scoreLaneGroupOrder(order, groups, relationWeights, targetPositions, guideWeight, originalWeight) {
    const positions = orderToPositions(order);
    let score = 0;

    groups.forEach((group, index) => {
        score += guideWeight * Math.abs(positions[index] - targetPositions[index]);
        score += originalWeight * Math.abs(positions[index] - group.originalIndex);
    });

    for (let i = 0; i < groups.length; i += 1) {
        for (let j = i + 1; j < groups.length; j += 1) {
            score += relationWeights[i][j] * Math.abs(positions[i] - positions[j]);
        }
    }

    return score;
}

function permuteLaneOrder(order, visit, start = 0) {
    if (start === order.length) {
        visit(order);
        return;
    }
    for (let index = start; index < order.length; index += 1) {
        [order[start], order[index]] = [order[index], order[start]];
        permuteLaneOrder(order, visit, start + 1);
        [order[start], order[index]] = [order[index], order[start]];
    }
}

function getLayoutSlot(entity, layout) {
    if (!layout) return Number(entity.slot) || 0;
    const rawSlot = Number(entity.slot) || 0;
    const baseSlot = Math.floor(rawSlot + 0.000001);
    const mappedSlot = layout.slotMap.get(baseSlot);
    if (mappedSlot === undefined) return rawSlot;
    return mappedSlot + (rawSlot - baseSlot);
}

const TERRITORY_SHAPE_NOTCHES = {
    'taper-right': [
        { side: 'right', x: 84, y: 48, width: 16, height: 52 }
    ],
    'taper-left': [
        { side: 'left', x: 0, y: 0, width: 16, height: 52 }
    ],
    'hourglass': [
        { side: 'right', x: 88, y: 36, width: 12, height: 28 },
        { side: 'left', x: 0, y: 36, width: 12, height: 28 }
    ]
};

function getTerritoryShapePlan(entity, region) {
    const notchSource = entity.notches || TERRITORY_SHAPE_NOTCHES[entity.shape];
    const notches = normalizeTerritoryNotches(notchSource);
    if (!notches || !region?.entities) return null;

    const notchFills = notches.map(notch => getTerritoryNotchFills(entity, region, notch));

    // A cutout is only valid when every missing piece has an owner, either by
    // adjacency or by an explicit non-contiguous/remote-fragment annotation.
    // Otherwise the block stays whole so the chart never creates ownerless land.
    if (notchFills.some(fills => fills.length === 0)) return null;

    return {
        className: entity.shape ? `shape-${entity.shape}` : 'shape-custom',
        clipPath: buildTerritoryClipPath(notches),
        fills: notchFills.flat()
    };
}

function normalizeTerritoryNotches(notches) {
    if (!Array.isArray(notches)) return null;

    const normalized = notches
        .map(notch => {
            const side = notch.side === 'left' ? 'left' : (notch.side === 'right' ? 'right' : null);
            if (!side) return null;

            const y = clampPercent(notch.y);
            const maxHeight = Math.max(0, 100 - y);
            const height = Math.min(clampPercent(notch.height), maxHeight);
            const rawWidth = Number.isFinite(Number(notch.width)) ? Number(notch.width) : 16;
            const width = Math.max(1, Math.min(50, rawWidth));
            const x = side === 'right'
                ? Math.max(0, Math.min(99, Number.isFinite(Number(notch.x)) ? Number(notch.x) : 100 - width))
                : 0;

            if (height <= 0) return null;
            return { ...notch, side, x, y, width };
        })
        .filter(Boolean);

    return normalized.length ? normalized : null;
}

function clampPercent(value) {
    const parsed = Number(value);
    if (!Number.isFinite(parsed)) return 0;
    return Math.max(0, Math.min(100, parsed));
}

function buildTerritoryClipPath(notches) {
    const rightNotches = notches
        .filter(notch => notch.side === 'right')
        .sort((a, b) => a.y - b.y);
    const leftNotches = notches
        .filter(notch => notch.side === 'left')
        .sort((a, b) => b.y - a.y);
    const points = [];

    const push = (x, y) => {
        const last = points[points.length - 1];
        if (last && Math.abs(last.x - x) < 0.001 && Math.abs(last.y - y) < 0.001) return;
        points.push({ x, y });
    };

    push(0, 0);
    push(100, 0);
    rightNotches.forEach(notch => {
        const bottom = notch.y + notch.height;
        push(100, notch.y);
        push(notch.x, notch.y);
        push(notch.x, bottom);
        push(100, bottom);
    });
    push(100, 100);
    push(0, 100);
    leftNotches.forEach(notch => {
        const bottom = notch.y + notch.height;
        const innerX = notch.x + notch.width;
        push(0, bottom);
        push(innerX, bottom);
        push(innerX, notch.y);
        push(0, notch.y);
    });

    return `polygon(${points.map(point => `${formatPercent(point.x)} ${formatPercent(point.y)}`).join(', ')})`;
}

function formatPercent(value) {
    const rounded = Math.round(value * 1000) / 1000;
    return rounded === 0 ? '0' : `${rounded}%`;
}

function getTerritoryNotchFills(entity, region, notch) {
    const explicitOwners = getExplicitNotchOwners(entity, region, notch);
    if (explicitOwners.length) {
        const explicitFills = buildExplicitNotchFills(entity, notch, explicitOwners);
        if (explicitFills.length) return explicitFills;
    }

    const adjacentFill = buildAdjacentNotchFill(entity, region, notch);
    return adjacentFill ? [adjacentFill] : [];
}

function getExplicitNotchOwners(entity, region, notch) {
    const sideOwners = notch.owners || entity.notchOwners?.[notch.side];
    if (!sideOwners) return [];

    const ownerIds = Array.isArray(sideOwners) ? sideOwners : [sideOwners];
    return ownerIds
        .map(ownerId => region.entities.find(candidate => candidate.id === ownerId))
        .filter(Boolean);
}

function getNotchTimeWindow(entity, notch) {
    const start = entity.start + (entity.end - entity.start) * (notch.y / 100);
    const end = entity.start + (entity.end - entity.start) * ((notch.y + notch.height) / 100);
    return { start, end, duration: Math.max(1, end - start) };
}

function buildExplicitNotchFills(entity, notch, owners) {
    const { start: notchStart, end: notchEnd, duration } = getNotchTimeWindow(entity, notch);
    const segments = owners
        .map(owner => {
            const start = Math.max(owner.start, notchStart);
            const end = Math.min(owner.end, notchEnd);
            return { owner, start, end };
        })
        .filter(segment => segment.end > segment.start)
        .sort((a, b) => a.start - b.start || a.end - b.end);

    if (!segments.length) return [];

    const coverage = segments.reduce((sum, segment) => sum + (segment.end - segment.start), 0) / duration;
    if (coverage < 0.82) return [];

    // Close tiny representation gaps between explicitly modeled owners. Larger
    // gaps suppress clipping instead of inventing an owner.
    const adjusted = segments.map(segment => ({ ...segment }));
    for (let i = 1; i < adjusted.length; i += 1) {
        const gap = adjusted[i].start - adjusted[i - 1].end;
        if (gap > 0 && gap / duration <= 0.05) {
            const midpoint = adjusted[i - 1].end + gap / 2;
            adjusted[i - 1].end = midpoint;
            adjusted[i].start = midpoint;
        }
    }
    if ((adjusted[0].start - notchStart) / duration <= 0.03) adjusted[0].start = notchStart;
    const last = adjusted[adjusted.length - 1];
    if ((notchEnd - last.end) / duration <= 0.03) last.end = notchEnd;

    const represented = adjusted.reduce((sum, segment) => sum + Math.max(0, segment.end - segment.start), 0) / duration;
    if (represented < 0.98) return [];

    return adjusted.map(segment => ({
        ...notch,
        y: notch.y + ((segment.start - notchStart) / duration) * notch.height,
        height: ((segment.end - segment.start) / duration) * notch.height,
        owner: segment.owner,
        source: 'explicit'
    }));
}

function buildAdjacentNotchFill(entity, region, notch) {
    const entityStart = entity.slot;
    const entityEnd = entity.slot + entity.width;
    const { start: notchStart, end: notchEnd, duration: notchDuration } = getNotchTimeWindow(entity, notch);
    const boundary = notch.side === 'right' ? entityEnd : entityStart;
    const EPS = 0.001;

    const candidates = region.entities
        .filter(candidate => {
            if (candidate.id === entity.id) return false;
            if (CONFIG.categoryFilter && candidate.category !== CONFIG.categoryFilter) return false;

            const candidateStart = candidate.slot;
            const candidateEnd = candidate.slot + candidate.width;
            const touchesBoundary = notch.side === 'right'
                ? Math.abs(candidateStart - boundary) < EPS
                : Math.abs(candidateEnd - boundary) < EPS;
            if (!touchesBoundary) return false;

            const overlap = Math.min(candidate.end, notchEnd) - Math.max(candidate.start, notchStart);
            return overlap > 0;
        })
        .map(candidate => {
            const overlap = Math.min(candidate.end, notchEnd) - Math.max(candidate.start, notchStart);
            return { candidate, overlap };
        })
        .sort((a, b) => b.overlap - a.overlap || a.candidate.start - b.candidate.start);

    const best = candidates[0];
    if (!best) return null;

    let start = Math.max(best.candidate.start, notchStart);
    let end = Math.min(best.candidate.end, notchEnd);
    if ((start - notchStart) / notchDuration <= 0.03) start = notchStart;
    if ((notchEnd - end) / notchDuration <= 0.03) end = notchEnd;

    const represented = (end - start) / notchDuration;
    if (represented < 0.98) return null;

    return {
        ...notch,
        y: notch.y + ((start - notchStart) / notchDuration) * notch.height,
        height: ((end - start) / notchDuration) * notch.height,
        owner: best.candidate,
        source: 'adjacent'
    };
}

function getTerritoryFillRange(entity, fill) {
    const start = entity.start + (entity.end - entity.start) * (fill.y / 100);
    const end = entity.start + (entity.end - entity.start) * ((fill.y + fill.height) / 100);
    return {
        start: Math.round(start),
        end: Math.round(end)
    };
}

function getTerritoryFillKind(fill, isCn) {
    if (fill.source === 'adjacent') {
        return isCn ? '相邻承接' : 'Adjacent owner';
    }
    return isCn ? '远程/复合承接' : 'Remote/composite owner';
}

function applyTerritoryFillHighlights(sourceId, ownerId) {
    clearTerritoryFillHighlights();
    document.querySelector(`.dynasty-block[data-id="${CSS.escape(sourceId)}"]`)?.classList.add('territory-source-highlight');
    document.querySelector(`.dynasty-block[data-id="${CSS.escape(ownerId)}"]`)?.classList.add('territory-owner-highlight');
}

function clearTerritoryFillHighlights() {
    document.querySelectorAll('.territory-source-highlight, .territory-owner-highlight').forEach(el => {
        el.classList.remove('territory-source-highlight', 'territory-owner-highlight');
    });
}

function showTerritoryFillTooltip(e, sourceEntity, fill) {
    const tooltip = elements.tooltip;
    const isCn = CONFIG.language === 'cn';
    const owner = fill.owner;
    const ownerName = isCn ? (owner.nameCN || owner.name) : owner.name;
    const ownerSecondary = isCn ? owner.name : (owner.nameCN || '');
    const sourceName = isCn ? (sourceEntity.nameCN || sourceEntity.name) : sourceEntity.name;
    const { start, end } = getTerritoryFillRange(sourceEntity, fill);
    const kind = getTerritoryFillKind(fill, isCn);
    const hint = isCn
        ? `填补 ${sourceName} 的缺口 · 点击或按 Enter/Space 打开主人详情`
        : `fills ${sourceName}'s cutout · click or press Enter/Space for owner details`;

    tooltip.querySelector('.tooltip-title').textContent = ownerName;
    tooltip.querySelector('.tooltip-title-cn').textContent = ownerSecondary;
    tooltip.querySelector('.tooltip-dates').textContent = `${formatYear(start)} — ${formatYear(end)}`;
    tooltip.querySelector('.tooltip-duration').textContent = kind;
    tooltip.querySelector('.tooltip-meta').textContent = hint;
    const rect = e.currentTarget.getBoundingClientRect();
    positionTooltip(rect.right + 10, rect.top);
    tooltip.classList.add('visible');
    syncTooltipOwner(e);
}

function renderTerritoryFillPieces({ entity, shapePlan, top, left, width, height }) {
    if (!shapePlan?.fills?.length) return;

    shapePlan.fills.forEach(fill => {
        const piece = document.createElement('div');
        piece.className = 'territory-fill-piece';
        const isCn = CONFIG.language === 'cn';
        const ownerName = isCn ? (fill.owner.nameCN || fill.owner.name) : fill.owner.name;
        const sourceName = isCn ? (entity.nameCN || entity.name) : entity.name;
        const { start, end } = getTerritoryFillRange(entity, fill);
        const kind = getTerritoryFillKind(fill, isCn);
        const ownerRegion = getEntityRegion(fill.owner.id) || getEntityRegion(entity.id) || '';
        piece.dataset.ownerId = fill.owner.id;
        piece.dataset.ownerName = fill.owner.name;
        piece.dataset.sourceId = entity.id;
        piece.dataset.sourceName = entity.name;
        piece.dataset.kind = fill.source;
        piece.dataset.region = ownerRegion;
        piece.dataset.color = normalizeColorKey(fill.owner.color);
        if (fill.owner.seamGroup) piece.dataset.seamGroup = String(fill.owner.seamGroup);
        piece.tabIndex = 0;
        piece.setAttribute('role', 'button');
        piece.setAttribute(
            'aria-label',
            isCn
                ? `${ownerName}，${kind}，填补 ${sourceName} 在 ${formatYear(start)} 至 ${formatYear(end)} 的缺口`
                : `${ownerName}, ${kind}, fills ${sourceName}'s cutout from ${formatYear(start)} to ${formatYear(end)}`
        );
        piece.style.cssText = `
            top: ${top + (height * fill.y / 100)}px;
            left: ${left + (width * fill.x / 100)}px;
            width: ${Math.max(width * fill.width / 100, 1)}px;
            height: ${Math.max(height * fill.height / 100, 1)}px;
            background: ${timelineBlockFill(fill.owner.color)};
        `;
        piece.addEventListener('mouseenter', e => {
            applyTerritoryFillHighlights(entity.id, fill.owner.id);
            showTerritoryFillTooltip(e, entity, fill);
        });
        piece.addEventListener('mouseleave', e => {
            clearTerritoryFillHighlights();
            hideTooltip(e);
        });
        piece.addEventListener('focus', e => {
            applyTerritoryFillHighlights(entity.id, fill.owner.id);
            showTerritoryFillTooltip(e, entity, fill);
        });
        piece.addEventListener('blur', e => {
            clearTerritoryFillHighlights();
            hideTooltip(e);
        });
        piece.addEventListener('click', () => showDetail(fill.owner));
        piece.addEventListener('keydown', e => {
            if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                showDetail(fill.owner);
            }
        });
        elements.timelineGrid.appendChild(piece);
    });
}

function renderEntity(entity, regionId, slotOffset, opts = {}) {
    const block = document.createElement('div');
    block.className = 'dynasty-block';
    if (opts.match) block.classList.add('search-match');
    if (opts.dim) block.classList.add('dim');
    const shapePlan = getTerritoryShapePlan(entity, opts.region);
    if (shapePlan) block.classList.add(shapePlan.className);

    const top = yearToY(entity.start) + 35;
    const rawHeight = yearToY(entity.end) - yearToY(entity.start);
    const height = Math.max(rawHeight, 3);

    // Slot semantics stay in the data; layoutSlot is the render-only order after
    // lane-group optimization.
    const layoutSlot = getLayoutSlot(entity, opts.layout);
    const slotLeft = (slotOffset + layoutSlot) * CONFIG.baseColumnWidth;
    const slotSpan = entity.width * CONFIG.baseColumnWidth;
    const visualWidth = shapePlan ? slotSpan : computeBlockWidth(entity.width);

    // Center ordinary wide-but-clamped empires inside their slot range. Blocks
    // with explicit cutouts keep the full slot span so fills align to neighbors.
    const left = slotLeft + (slotSpan - visualWidth) / 2;
    const width = visualWidth;

    entityPositions[entity.id] = {
        top, left, width, height,
        centerX: left + width / 2,
        centerY: top + height / 2
    };

    // Flat fill. Light mode stays paper-like; dark mode uses muted map colors.
    const baseColor = entity.color;
    const fill = timelineBlockFill(baseColor);
    const textColor = timelineBlockTextColor(baseColor, fill);

    // Size class based on block dimensions.
    let sizeClass = '';
    if (height < 8) sizeClass = 'block-micro';
    else if (height < 14) sizeClass = 'block-tiny';
    else if (height < 26) sizeClass = 'block-small';
    else if (width < 44 && height > 80) sizeClass = 'block-narrow';
    else if (height > 140 && width > 100) sizeClass = 'block-huge';
    else if (height > 80 && width > 80) sizeClass = 'block-large';
    if (sizeClass) block.classList.add(sizeClass);
    if (entity.shortName || entity.shortNameCN) block.classList.add('has-short-name');

    block.style.cssText = `
        top: ${top}px;
        left: ${left}px;
        width: ${width}px;
        height: ${height}px;
        background: ${fill};
        color: ${textColor};
        ${shapePlan?.clipPath ? `clip-path: ${shapePlan.clipPath};` : ''}
        --i: ${opts.animIndex || 0};
    `;

    const content = document.createElement('div');
    content.className = 'dynasty-content';

    if (entity.category && ENTITY_CATEGORIES[entity.category]) {
        block.classList.add(`category-${entity.category}`);
    }

    const nameEl = document.createElement('div');
    nameEl.className = 'dynasty-name';
    nameEl.textContent = getBlockName(entity);
    nameEl.dataset.fullLabel = nameEl.textContent;
    const miniLabelText = nameEl.textContent.trim();
    const canShowUltraNarrowMiniLabel = miniLabelText.length <= 3
        && (
            (CONFIG.language === 'cn' && width >= 5)
            || (CONFIG.language !== 'cn' && width >= 6)
        );
    const canShowMiniSuppressedLabel = Boolean(entity.suppressLabel)
        && Boolean(entity.shortName || entity.shortNameCN)
        && height >= 9
        && (width >= 9 || canShowUltraNarrowMiniLabel);
    if (canShowMiniSuppressedLabel) block.classList.add('mini-suppressed-label');
    if (canShowMiniSuppressedLabel && (width < 7 || height < 12)) block.classList.add('ultra-mini-label');
    if (!entity.suppressLabel || canShowMiniSuppressedLabel) content.appendChild(nameEl);

    // Only show years if block has enough space
    if (height > 50 && width > 52) {
        const yearsEl = document.createElement('div');
        yearsEl.className = 'dynasty-years';
        // Show compact form: just start year on small blocks; range on larger
        if (height > 90 && width > 80) {
            yearsEl.textContent = `${formatYear(entity.start)} – ${formatYear(entity.end)}`;
        } else {
            yearsEl.textContent = formatYear(entity.start);
        }
        content.appendChild(yearsEl);

        // Show top ruler if block is big enough
        if (height > 110 && entity.rulers && entity.rulers.length && width > 80) {
            const rulerEl = document.createElement('div');
            rulerEl.className = 'dynasty-rulers';
            rulerEl.textContent = `† ${entity.rulers[0]}`;
            content.appendChild(rulerEl);
        }
    }

    block.appendChild(content);

    block.dataset.id = entity.id;
    block.dataset.name = entity.name;
    block.dataset.nameCn = entity.nameCN || '';
    block.dataset.start = entity.start;
    block.dataset.end = entity.end;
    block.dataset.region = regionId;
    block.dataset.rawSlot = String(entity.slot);
    block.dataset.layoutSlot = String(layoutSlot);
    block.dataset.color = normalizeColorKey(entity.color);
    if (entity.seamGroup) block.dataset.seamGroup = String(entity.seamGroup);
    if (entity.category) block.dataset.category = entity.category;
    if (entity.territoryNote) block.dataset.territoryNote = entity.territoryNote;
    if (entity.territoryNoteCN) block.dataset.territoryNoteCn = entity.territoryNoteCN;
    block.tabIndex = 0;
    block.setAttribute('role', 'button');
    block.setAttribute('aria-label', `${getName(entity)}, ${formatYear(entity.start)} ${CONFIG.language === 'cn' ? '至' : 'to'} ${formatYear(entity.end)}`);

    block.addEventListener('mouseenter', handleHover);
    block.addEventListener('mouseleave', hideTooltip);
    block.addEventListener('focus', handleBlockFocus);
    block.addEventListener('blur', handleBlockBlur);
    block.addEventListener('click', () => showDetail(entity));
    block.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            showDetail(entity);
        }
    });

    elements.timelineGrid.appendChild(block);
    renderTerritoryFillPieces({ entity, shapePlan, top, left, width, height });
}

function normalizeColorKey(color) {
    return String(color || '').trim().toLowerCase();
}

function getRenderedSeamKey(block) {
    const explicitGroup = String(block.dataset.seamGroup || '').trim().toLowerCase();
    if (explicitGroup) return `group|${explicitGroup}`;

    const renderedColor = normalizeColorKey(
        getComputedStyle(block).backgroundColor
        || block.style.backgroundColor
        || block.dataset.color
        || ''
    );
    return [
        'color',
        block.dataset.region || '',
        renderedColor || block.dataset.color || ''
    ].join('|');
}

function applySameColorSeams() {
    if (!elements.timelineGrid) return;

    const seamClasses = [
        'same-color-seam-left',
        'same-color-seam-right',
        'same-color-seam-top',
        'same-color-seam-bottom'
    ];
    const allBlocks = Array.from(elements.timelineGrid.querySelectorAll('.dynasty-block, .territory-fill-piece'));
    allBlocks.forEach(block => block.classList.remove(...seamClasses));
    const blocks = allBlocks.filter(block => block.dataset.color);

    const groups = new Map();
    blocks.forEach(block => {
        const key = getRenderedSeamKey(block);
        if (!groups.has(key)) groups.set(key, []);
        groups.get(key).push(block);
    });

    const EPS = 1.5;
    const MIN_OVERLAP = 2;
    groups.forEach(group => {
        if (group.length < 2) return;
        const boxes = group.map(block => ({ block, rect: block.getBoundingClientRect() }));

        for (let i = 0; i < boxes.length; i += 1) {
            for (let j = i + 1; j < boxes.length; j += 1) {
                const a = boxes[i];
                const b = boxes[j];
                const verticalOverlap = Math.min(a.rect.bottom, b.rect.bottom) - Math.max(a.rect.top, b.rect.top);
                const horizontalOverlap = Math.min(a.rect.right, b.rect.right) - Math.max(a.rect.left, b.rect.left);

                if (verticalOverlap > MIN_OVERLAP) {
                    if (Math.abs(a.rect.right - b.rect.left) <= EPS) {
                        a.block.classList.add('same-color-seam-right');
                        b.block.classList.add('same-color-seam-left');
                    } else if (Math.abs(b.rect.right - a.rect.left) <= EPS) {
                        b.block.classList.add('same-color-seam-right');
                        a.block.classList.add('same-color-seam-left');
                    }
                }

                if (horizontalOverlap > MIN_OVERLAP) {
                    if (Math.abs(a.rect.bottom - b.rect.top) <= EPS) {
                        a.block.classList.add('same-color-seam-bottom');
                        b.block.classList.add('same-color-seam-top');
                    } else if (Math.abs(b.rect.bottom - a.rect.top) <= EPS) {
                        b.block.classList.add('same-color-seam-bottom');
                        a.block.classList.add('same-color-seam-top');
                    }
                }
            }
        }
    });
}

function handleBlockFocus(e) {
    handleHover(e);
    applyContemporaryHighlights(e.currentTarget);
}

function handleBlockBlur(e) {
    hideTooltip(e);
    clearContemporaryHighlights();
}

// Adjust a hex color by a given lightness delta (-50 to +50)
function adjustColor(hex, delta) {
    if (!hex || hex[0] !== '#') return hex;
    let h = hex.replace('#', '');
    if (h.length === 3) h = h.split('').map(c => c + c).join('');
    const r = Math.max(0, Math.min(255, parseInt(h.slice(0,2),16) + delta));
    const g = Math.max(0, Math.min(255, parseInt(h.slice(2,4),16) + delta));
    const b = Math.max(0, Math.min(255, parseInt(h.slice(4,6),16) + delta));
    return '#' + [r,g,b].map(n => n.toString(16).padStart(2,'0')).join('');
}

// Mix toward white for a clean pale tint suitable for flat backgrounds.
// Returns a CSS color string (rgb).
function paleTint(hex, mix = 0.34) {
    if (!hex || hex[0] !== '#') return hex;
    let h = hex.replace('#', '');
    if (h.length === 3) h = h.split('').map(c => c + c).join('');
    const r = parseInt(h.slice(0,2),16);
    const g = parseInt(h.slice(2,4),16);
    const b = parseInt(h.slice(4,6),16);
    const mr = Math.round(r + (255 - r) * mix);
    const mg = Math.round(g + (255 - g) * mix);
    const mb = Math.round(b + (255 - b) * mix);
    return `rgb(${mr}, ${mg}, ${mb})`;
}

function darkTint(hex, colorMix = 0.058, saturationMix = 0.32) {
    if (!hex || hex[0] !== '#') return hex;
    let h = hex.replace('#', '');
    if (h.length === 3) h = h.split('').map(c => c + c).join('');
    const r = parseInt(h.slice(0,2),16);
    const g = parseInt(h.slice(2,4),16);
    const b = parseInt(h.slice(4,6),16);
    const darkBase = [3, 5, 7];
    const luminance = r * 0.2126 + g * 0.7152 + b * 0.0722;
    const sr = luminance + (r - luminance) * saturationMix;
    const sg = luminance + (g - luminance) * saturationMix;
    const sb = luminance + (b - luminance) * saturationMix;
    const mr = Math.round(sr * colorMix + darkBase[0] * (1 - colorMix));
    const mg = Math.round(sg * colorMix + darkBase[1] * (1 - colorMix));
    const mb = Math.round(sb * colorMix + darkBase[2] * (1 - colorMix));
    return `rgb(${mr}, ${mg}, ${mb})`;
}

function timelineBlockFill(hex) {
    return CONFIG.darkMode ? darkTint(hex) : paleTint(hex);
}

function parseCssRgb(value) {
    const match = String(value || '').match(/rgba?\(([^)]+)\)/);
    if (!match) return null;
    const [r, g, b] = match[1].split(',').slice(0, 3).map(component => Number.parseFloat(component));
    if (![r, g, b].every(Number.isFinite)) return null;
    return { r, g, b };
}

function timelineBlockTextColor(hex, fill = timelineBlockFill(hex)) {
    if (CONFIG.darkMode) return '#F2EDE4';
    const rgb = parseCssRgb(fill);
    if (!rgb) return '#2A2520';
    const luminance = rgb.r * 0.2126 + rgb.g * 0.7152 + rgb.b * 0.0722;
    return luminance < 120 ? '#F8F2EA' : '#2A2520';
}

// After all entities in a region are rendered, walk through them in chronological
// order (per slot) and detect places where the SAME polity (matching name) gains
// or loses territory (i.e. transitions to a different width). Draw a thin
// horizontal "territorial tick" line at that moment to make the change visible.
function renderTerritorialTransitions(region, slotOffset) {
    if (!region || !region.entities) return;

    // Group entities by name (since IDs vary like roman_republic_1/2/3)
    const groupsByName = {};
    region.entities.forEach(e => {
        const key = e.name;
        if (!groupsByName[key]) groupsByName[key] = [];
        groupsByName[key].push(e);
    });

    Object.values(groupsByName).forEach(group => {
        if (group.length < 2) return;
        // Sort chronologically by start year
        group.sort((a, b) => a.start - b.start);
        for (let i = 1; i < group.length; i++) {
            const prev = group[i - 1];
            const curr = group[i];
            // Only draw if it's a contiguous transition (within 2 years tolerance)
            if (Math.abs(curr.start - prev.end) > 2) continue;
            // Only draw if territory actually changed
            const prevSlot = prev.slot;
            const prevEnd = prev.slot + prev.width;
            const currSlot = curr.slot;
            const currEnd = curr.slot + curr.width;
            if (prevSlot === currSlot && prevEnd === currEnd) continue;

            const yr = curr.start;
            const top = yearToY(yr) + 35;
            // Use the actual rendered positions of prev and curr for the tick
            const prevPos = entityPositions[prev.id];
            const currPos = entityPositions[curr.id];
            if (!prevPos || !currPos) continue;
            const fromX = Math.min(prevPos.left, currPos.left);
            const toX = Math.max(prevPos.left + prevPos.width, currPos.left + currPos.width);
            const tick = document.createElement('div');
            tick.className = 'territorial-tick';
            tick.style.cssText = `
                top: ${top}px;
                left: ${fromX}px;
                width: ${toX - fromX}px;
            `;
            elements.timelineGrid.appendChild(tick);
        }
    });
}

function showEventTooltip(e, event, number) {
    clearContemporaryHighlights();
    const tooltip = elements.tooltip;
    tooltip.querySelector('.tooltip-title').textContent = `#${number} · ${CONFIG.language === 'cn' ? event.labelCN : event.label}`;
    tooltip.querySelector('.tooltip-title-cn').textContent = CONFIG.language === 'cn' ? event.label : event.labelCN;
    tooltip.querySelector('.tooltip-dates').textContent = formatYear(event.year);
    tooltip.querySelector('.tooltip-duration').textContent = event.type ? eventTypeLabel(event.type) : '';
    const meta = tooltip.querySelector('.tooltip-meta');
    const description = event.desc ? (CONFIG.language === 'cn' ? event.desc.cn : event.desc.en) : '';
    const actionHint = CONFIG.language === 'cn' ? '点击或按 Enter/Space 查看详情' : 'click or press Enter/Space for details';
    meta.textContent = [description, actionHint].filter(Boolean).join(' · ');
    const rect = e.currentTarget.getBoundingClientRect();
    positionTooltip(rect.right + 12, rect.top - 12);
    syncTooltipOwner(e);
    tooltip.classList.add('visible');
}

function renderLegend() {
    elements.legend.innerHTML = '';

    const visibleRegions = getVisibleRegions();

    visibleRegions.forEach(regionId => {
        const region = WORLD_HISTORY[regionId];
        if (!region) return;

        const groupDiv = document.createElement('div');
        groupDiv.className = 'legend-group';

        const title = document.createElement('div');
        title.className = 'legend-group-title';
        title.textContent = getName(region);
        groupDiv.appendChild(title);

        region.entities.slice(0, 6).forEach(entity => {
            const item = document.createElement('div');
            item.className = 'legend-item';
            item.innerHTML = `
                <div class="legend-color" style="background: ${entity.color}"></div>
                <span class="legend-label">${getName(entity)}</span>
            `;
            groupDiv.appendChild(item);
        });

        if (region.entities.length > 6) {
            const more = document.createElement('div');
            more.className = 'legend-more';
            more.textContent = `+${region.entities.length - 6} ${uiText('more')}`;
            groupDiv.appendChild(more);
        }

        elements.legend.appendChild(groupDiv);
    });
}

// ============================================
// INTERACTIONS
// ============================================

function positionTooltip(left, top) {
    const tooltip = elements.tooltip;
    const tooltipWidth = tooltip.offsetWidth || TOOLTIP_MAX_WIDTH;
    const tooltipHeight = tooltip.offsetHeight || TOOLTIP_ESTIMATED_HEIGHT;
    const maxLeft = Math.max(TOOLTIP_VIEWPORT_MARGIN, window.innerWidth - tooltipWidth - TOOLTIP_VIEWPORT_MARGIN);
    const maxTop = Math.max(TOOLTIP_VIEWPORT_MARGIN, window.innerHeight - tooltipHeight - TOOLTIP_VIEWPORT_MARGIN);
    const safeLeft = Math.max(TOOLTIP_VIEWPORT_MARGIN, Math.min(maxLeft, left));
    const safeTop = Math.max(TOOLTIP_VIEWPORT_MARGIN, Math.min(maxTop, top));

    tooltip.style.left = `${safeLeft}px`;
    tooltip.style.top = `${safeTop}px`;
}

function handleHover(e) {
    const block = e.currentTarget;
    const tooltip = elements.tooltip;
    const isCn = CONFIG.language === 'cn';

    const start = parseInt(block.dataset.start);
    const end = parseInt(block.dataset.end);
    const dur = end - start;

    tooltip.querySelector('.tooltip-title').textContent = isCn ? (block.dataset.nameCn || block.dataset.name) : block.dataset.name;
    tooltip.querySelector('.tooltip-title-cn').textContent = isCn ? block.dataset.name : block.dataset.nameCn;
    tooltip.querySelector('.tooltip-dates').textContent = `${formatYear(start)} — ${formatYear(end)}`;
    tooltip.querySelector('.tooltip-duration').textContent = `${dur} ${isCn ? '年' : 'years'}`;

    // Meta: region · category · rulers
    const regionId = block.dataset.region;
    const region = WORLD_HISTORY[regionId];
    const regionName = region ? (isCn ? region.nameCN : region.name) : '';
    const category = block.dataset.category;
    const catLabel = category && ENTITY_CATEGORIES[category]
        ? (isCn ? ENTITY_CATEGORIES[category].labelCN : ENTITY_CATEGORIES[category].label)
        : '';
    const entity = findEntityById(block.dataset.id);
    const rulers = entity && entity.rulers && entity.rulers.length ? entity.rulers.slice(0, 2).join(' · ') : '';
    const meta = [regionName, catLabel, rulers].filter(Boolean).join(' · ');
    const actionHint = isCn ? '点击或按 Enter/Space 查看详情' : 'click or press Enter/Space for details';
    const territoryNote = isCn ? block.dataset.territoryNoteCn : block.dataset.territoryNote;
    tooltip.querySelector('.tooltip-meta').textContent = [meta, territoryNote, actionHint].filter(Boolean).join(' · ');

    const rect = block.getBoundingClientRect();
    positionTooltip(rect.right + 10, rect.top);
    syncTooltipOwner(e);
    tooltip.classList.add('visible');
}

function describedByTokens(el) {
    return (el?.getAttribute('aria-describedby') || '').split(/\s+/).filter(Boolean);
}

function setTooltipOwner(owner) {
    const tooltipId = elements.tooltip?.id || 'tooltip';
    if (tooltipOwner && tooltipOwner !== owner) {
        clearTooltipOwner();
    }
    tooltipOwner = owner;
    const tokens = describedByTokens(owner);
    if (!tokens.includes(tooltipId)) {
        owner.setAttribute('aria-describedby', [...tokens, tooltipId].join(' '));
    }
}

function clearTooltipOwner() {
    const tooltipId = elements.tooltip?.id || 'tooltip';
    if (!tooltipOwner) return;
    const tokens = describedByTokens(tooltipOwner).filter(token => token !== tooltipId);
    if (tokens.length) {
        tooltipOwner.setAttribute('aria-describedby', tokens.join(' '));
    } else {
        tooltipOwner.removeAttribute('aria-describedby');
    }
    tooltipOwner = null;
}

function syncTooltipOwner(e) {
    if (e?.type === 'focus' && e.currentTarget?.setAttribute) {
        setTooltipOwner(e.currentTarget);
    } else {
        clearTooltipOwner();
    }
}

function hideTooltip(e) {
    if (e?.type === 'mouseleave' && document.activeElement === e.currentTarget) return;
    elements.tooltip.classList.remove('visible');
    if (!e || e.type === 'blur' || tooltipOwner !== e.currentTarget) {
        clearTooltipOwner();
    }
}

function clearActiveTimelinePreview() {
    if (elements.tooltip) hideTooltip();
    clearContemporaryHighlights();
}

function clearContemporaryHighlights() {
    contemporaryHighlightSource = null;
    document.querySelectorAll('.dynasty-block.contemporary-highlight').forEach(el => {
        el.classList.remove('contemporary-highlight');
    });
}

