function wikiSearchUrl(term, language = CONFIG.language) {
    const lang = language === 'cn' ? 'zh' : 'en';
    return `https://${lang}.wikipedia.org/wiki/${encodeURIComponent(String(term).trim().replace(/\s+/g, '_'))}`;
}

function wikiArticleUrl(title, language = CONFIG.language) {
    return wikiSearchUrl(String(title || '').replace(/_/g, ' '), language);
}

function getKnownTermWikiUrl(term, { language = CONFIG.language, entityId = null } = {}) {
    const isCn = language === 'cn';
    const langKey = isCn ? 'cn' : 'en';
    const clean = String(term || '').trim();
    if (!clean) return null;

    const contextualTitle = entityId ? CONTEXTUAL_INLINE_WIKI_TITLE_OVERRIDES[langKey]?.[`${entityId}|${clean}`] : null;
    const title = contextualTitle || INLINE_WIKI_TITLE_OVERRIDES[langKey]?.[clean];
    if (title) return wikiArticleUrl(title, language);

    return null;
}

function wikiTermIsUseful(term, isCn) {
    const clean = String(term || '').trim();
    if (!clean) return false;
    if (isCn) return clean.length >= 2;
    if (clean.includes(' ') || clean.includes('-') || clean.includes('–')) return clean.length >= 5;
    return clean.length >= 4;
}

function inlineWikiCandidateForKnownTerm(term, { entityId = null, priority = 24 } = {}) {
    const clean = String(term || '').trim();
    const isCn = CONFIG.language === 'cn';
    if (!wikiTermIsUseful(clean, isCn)) return null;
    const url = getKnownTermWikiUrl(clean, { language: CONFIG.language, entityId });
    if (!url) return null;
    return {
        term: clean,
        url,
        score: clean.length + priority + (clean.includes(' ') ? 4 : 0)
    };
}

function collectInlineWikiCandidates({ excludeEntityId = null } = {}) {
    const isCn = CONFIG.language === 'cn';
    const candidates = [];
    const seen = new Set();

    const pushCandidate = (term, url, priority = 0) => {
        const clean = String(term || '').trim();
        if (!wikiTermIsUseful(clean, isCn) || !url) return;
        const key = `${clean.toLocaleLowerCase()}|${url}`;
        if (seen.has(key)) return;
        seen.add(key);
        candidates.push({
            term: clean,
            url,
            score: clean.length + priority + (clean.includes(' ') ? 4 : 0)
        });
    };

    const pushKnownTerm = term => {
        const candidate = inlineWikiCandidateForKnownTerm(term, { priority: 10 });
        if (candidate) pushCandidate(candidate.term, candidate.url, 10);
    };

    Object.values(WORLD_HISTORY).forEach(region => {
        region.entities.forEach(entity => {
            if (entity.id === excludeEntityId) return;
            const url = getWikiUrl(entity);
            if (isCn) {
                pushCandidate(entity.nameCN, url, 12);
                pushCandidate(entity.shortNameCN, url, 8);
                (entity.rulersCN || []).forEach(pushKnownTerm);
            } else {
                pushCandidate(entity.name, url, 12);
                pushCandidate(entity.shortName, url, 8);
                (entity.rulers || []).forEach(pushKnownTerm);
            }
        });
    });

    Object.values(ENTITY_DETAILS).forEach(details => {
        const rulerTerms = isCn ? details.rulersCN : details.rulers;
        (rulerTerms || []).forEach(pushKnownTerm);
    });

    HISTORICAL_EVENTS.forEach(event => {
        const label = isCn ? event.labelCN : event.label;
        pushCandidate(label, wikiSearchUrl(label));
    });

    return candidates.sort((a, b) => b.score - a.score);
}

function linkFirstWikiTerm(html, candidate) {
    const escapedTerm = escapeHTML(candidate.term);
    if (!escapedTerm) return { html, linked: false };

    const parts = html.split(/(<a\b[^>]*>.*?<\/a>)/gi);
    const isCn = CONFIG.language === 'cn';
    const termPattern = escapeRegExp(escapedTerm);
    const regex = isCn
        ? new RegExp(termPattern)
        : new RegExp(`(^|[^A-Za-z0-9_])(${termPattern})(?=$|[^A-Za-z0-9_])`);

    for (let i = 0; i < parts.length; i += 1) {
        if (/^<a\b/i.test(parts[i])) continue;
        if (!regex.test(parts[i])) continue;
        parts[i] = isCn
            ? parts[i].replace(regex, `<a href="${candidate.url}" target="_blank" rel="noopener noreferrer" class="inline-wiki-link">$&</a>`)
            : parts[i].replace(regex, `$1<a href="${candidate.url}" target="_blank" rel="noopener noreferrer" class="inline-wiki-link">$2</a>`);
        return { html: parts.join(''), linked: true };
    }

    return { html, linked: false };
}

function renderDescriptionHTML(text, { excludeEntityId = null, maxLinks = 7 } = {}) {
    let html = escapeHTML(text || '');
    let linkedCount = 0;

    for (const candidate of collectInlineWikiCandidates({ excludeEntityId })) {
        if (linkedCount >= maxLinks) break;
        const result = linkFirstWikiTerm(html, candidate);
        html = result.html;
        if (result.linked) linkedCount += 1;
    }

    return html;
}

function renderInlineWikiTextHTML(text, { excludeEntityId = null, entityId = null, maxLinks = 3 } = {}) {
    let html = escapeHTML(text || '');
    let linkedCount = 0;
    const focusedCandidate = inlineWikiCandidateForKnownTerm(text, { entityId, priority: 60 });
    const candidates = [
        ...(focusedCandidate ? [focusedCandidate] : []),
        ...collectInlineWikiCandidates({ excludeEntityId })
    ].sort((a, b) => b.score - a.score);

    for (const candidate of candidates) {
        if (linkedCount >= maxLinks) break;
        const result = linkFirstWikiTerm(html, candidate);
        html = result.html;
        if (result.linked) linkedCount += 1;
    }

    return html;
}

function capturePanelContentFocus() {
    const active = document.activeElement;
    if (!active || !elements.panelContent?.contains(active)) return null;
    if (active.dataset?.jumpId) return { type: 'jump', id: active.dataset.jumpId };
    if (active.classList.contains('wiki-link')) return { type: 'wiki' };
    return null;
}

function restorePanelContentFocus(snapshot) {
    if (!snapshot || !elements.panelContent) return;
    let target = null;
    if (snapshot.type === 'jump') {
        target = Array.from(elements.panelContent.querySelectorAll('[data-jump-id]'))
            .find(link => link.dataset.jumpId === snapshot.id);
    } else if (snapshot.type === 'wiki') {
        target = elements.panelContent.querySelector('.wiki-link');
    }
    target?.focus({ preventScroll: true });
}

function wirePanelJumpLinks() {
    elements.panelContent.querySelectorAll('[data-jump-id]').forEach(a => {
        a.addEventListener('click', (e) => {
            e.preventDefault();
            const id = a.dataset.jumpId;
            const target = findEntityById(id);
            if (target) {
                lastPanelTrigger = null;
                lastPanelTriggerDescriptor = { type: 'entity', id: target.id };
                hidePanel({ restoreFocus: false });
                setTimeout(() => {
                    const targetView = scrollToEntity(target, { smooth: true });
                    updateURLState({
                        viewYear: targetView?.year ?? currentViewYear(),
                        viewX: targetView?.x ?? currentViewX()
                    });
                    setTimeout(() => showDetail(target), 600);
                }, 250);
            }
        });
    });
}

function refreshOpenPanelContent() {
    if (elements.eventPanel?.dataset.open !== 'true' || !activePanelContext) return;

    const focusSnapshot = capturePanelContentFocus();
    if (activePanelContext.type === 'detail') {
        const entity = findEntityById(activePanelContext.entityId);
        if (entity) showDetail(entity, { openPanel: false });
    } else if (activePanelContext.type === 'event') {
        showEventDetail(activePanelContext.event, activePanelContext.number, { openPanel: false });
    } else if (activePanelContext.type === 'help') {
        renderHelpContent();
    }
    restorePanelContentFocus(focusSnapshot);
}

function showDetail(entity, { openPanel = true } = {}) {
    const isCn = CONFIG.language === 'cn';
    const category = entity.category ? ENTITY_CATEGORIES[entity.category] : null;
    const description = HISTORICAL_DESCRIPTIONS[entity.id];
    const wikiUrl = getWikiUrl(entity);
    const details = ENTITY_DETAILS[entity.id] || {};
    const primaryName = isCn ? (entity.nameCN || entity.name) : entity.name;
    const secondaryName = isCn ? entity.name : (entity.nameCN || '');
    const territoryNote = isCn ? entity.territoryNoteCN : entity.territoryNote;

    // Find which region this entity belongs to
    const regionKey = getEntityRegion(entity.id);
    const region = regionKey ? WORLD_HISTORY[regionKey] : null;
    const regionName = region ? (isCn ? region.nameCN : region.name) : '';
    const territoryOwnerFills = region ? getTerritoryOwnerFillRows(entity, region, isCn) : [];

    // Capital
    const capital = details.capital || CAPITALS[entity.id];
    const capitalName = capital ? (isCn ? (capital.cn || capital.nameCN || capital.name) : (capital.en || capital.name)) : '';

    // Rulers (merge entity.rulers + details.rulers)
    const mergeUnique = (...lists) => {
        const seen = new Set();
        return lists.flat().filter(item => {
            const clean = String(item || '').trim();
            if (!clean || seen.has(clean)) return false;
            seen.add(clean);
            return true;
        });
    };
    const rulersEn = mergeUnique(entity.rulers || [], details.rulers || []);
    const rulersCn = mergeUnique(entity.rulersCN || [], details.rulersCN || []);
    const rulers = isCn && rulersCn.length ? rulersCn : rulersEn;

    // Achievements
    const achievements = details.achievements;
    const achievementsList = achievements ? (isCn ? achievements.cn : achievements.en) : [];

    // Contemporary civilizations: overlapping in time, from visible regions
    const contemporaries = [];
    for (const rKey of getOrderedRegionKeys()) {
        if (rKey === regionKey) continue;
        for (const e of WORLD_HISTORY[rKey].entities) {
            if (e.start < entity.end && e.end > entity.start && ['empire','caliphate','kingdom'].includes(e.category)) {
                // overlap score: length of overlap
                const overlap = Math.min(entity.end, e.end) - Math.max(entity.start, e.start);
                contemporaries.push({ entity: e, region: rKey, overlap });
            }
        }
    }
    contemporaries.sort((a,b) => b.overlap - a.overlap);
    const topContemps = contemporaries.slice(0, 6);

    // Connections
    const relatedConnections = CONNECTIONS.filter(c => c.from === entity.id || c.to === entity.id);

    const duration = entity.end - entity.start;

    let html = `
        <div class="panel-hero">
            <div>
                <div class="panel-region">${regionName}${category ? ' · ' + (isCn ? category.labelCN : category.label) : ''}</div>
                <div class="panel-hero-title">${formatYear(entity.start)} — ${formatYear(entity.end)} · ${duration} ${isCn ? '年' : 'years'}</div>
            </div>
        </div>
        <h2>${primaryName}</h2>
        <h3>${secondaryName}</h3>
        ${category ? `<span class="category-badge" style="background: ${category.color}">${isCn ? category.labelCN : category.label}</span>` : ''}

        <div class="fact-grid">
            <div class="fact"><span class="fact-label">${isCn ? '时期' : 'Period'}</span><span class="fact-value">${formatYear(entity.start)} → ${formatYear(entity.end)}</span></div>
            <div class="fact"><span class="fact-label">${isCn ? '存续' : 'Duration'}</span><span class="fact-value">${duration} ${isCn ? '年' : 'yr'}</span></div>
            ${capitalName ? `<div class="fact"><span class="fact-label">${isCn ? '首都' : 'Capital'}</span><span class="fact-value">${capitalName}</span></div>` : ''}
            <div class="fact"><span class="fact-label">${isCn ? '地域' : 'Region'}</span><span class="fact-value">${regionName}</span></div>
        </div>
    `;

    if (description) {
        const descriptionText = isCn ? description.cn : description.en;
        html += `
            <h4>${isCn ? '历史背景' : 'Background'}</h4>
            <p class="entity-description">${renderDescriptionHTML(descriptionText, { excludeEntityId: entity.id })}</p>
        `;
    }

    if (territoryNote) {
        html += `
            <h4>${isCn ? '疆域语义' : 'Territorial Reading'}</h4>
            <p class="entity-description">${renderDescriptionHTML(territoryNote, { excludeEntityId: entity.id, maxLinks: 5 })}</p>
        `;
    }

    if (territoryOwnerFills.length) {
        html += `
            <h4>${isCn ? '缺口承接' : 'Cutout Owners'}</h4>
            <ul class="connections-list territory-owner-list">
                ${territoryOwnerFills.map(row => `<li><span class="connection-type cultural">${escapeHTML(row.kind)}</span><a href="#" data-jump-id="${row.id}">${escapeHTML(row.name)}</a> <span class="territory-owner-period">${row.period}</span></li>`).join('')}
            </ul>
        `;
    }

    if (rulers && rulers.length) {
        html += `
            <h4>${isCn ? '著名统治者' : 'Notable Rulers'}</h4>
            <ul class="rulers-list">
                ${rulers.map(r => `<li>${renderInlineWikiTextHTML(r, { excludeEntityId: entity.id, entityId: entity.id, maxLinks: 1 })}</li>`).join('')}
            </ul>
        `;
    }

    if (achievementsList.length) {
        html += `
            <h4>${isCn ? '主要成就' : 'Key Achievements'}</h4>
            <ul class="achievements-list">
                ${achievementsList.map(a => `<li>${renderInlineWikiTextHTML(a, { excludeEntityId: entity.id, maxLinks: 2 })}</li>`).join('')}
            </ul>
        `;
    }

    if (relatedConnections.length) {
        html += `
            <h4>${isCn ? '历史联系' : 'Historical Connections'}</h4>
            <ul class="connections-list">
                ${relatedConnections.map(c => {
                    const label = isCn ? c.labelCN : c.label;
                    const other = c.from === entity.id ? c.to : c.from;
                    const otherEntity = findEntityById(other);
                    const otherName = otherEntity ? (isCn ? (otherEntity.nameCN || otherEntity.name) : otherEntity.name) : other;
                    const renderedLabel = renderInlineWikiTextHTML(label, { excludeEntityId: entity.id, maxLinks: 2 });
                    const renderedOtherName = otherEntity
                        ? `<a href="#" data-jump-id="${otherEntity.id}">${escapeHTML(otherName)}</a>`
                        : escapeHTML(otherName);
                    return `<li><span class="connection-type ${c.type}">${connectionTypeLabel(c.type)}</span>${renderedLabel} · ${renderedOtherName} (${formatYear(c.year)})</li>`;
                }).join('')}
            </ul>
        `;
    }

    if (topContemps.length) {
        html += `
            <h4>${isCn ? '同时代' : 'Contemporaries'}</h4>
            <ul class="contemporaries-list">
                ${topContemps.map(c => {
                    const name = isCn ? (c.entity.nameCN || c.entity.name) : c.entity.name;
                    const rName = isCn ? (WORLD_HISTORY[c.region].nameCN) : WORLD_HISTORY[c.region].name;
                    return `<li><a href="#" data-jump-id="${c.entity.id}">${escapeHTML(name)}</a> — ${escapeHTML(rName)} (${formatYear(c.entity.start)}–${formatYear(c.entity.end)})</li>`;
                }).join('')}
            </ul>
        `;
    }

    html += `
        <div class="wiki-section">
            <a href="${wikiUrl}" target="_blank" rel="noopener noreferrer" class="wiki-link">
                ${isCn ? '在维基百科阅读' : 'Read on Wikipedia'}
            </a>
        </div>
    `;

    elements.panelContent.innerHTML = html;
    setText('#panelTitle', primaryName);

    wirePanelJumpLinks();

    activePanelContext = { type: 'detail', entityId: entity.id };
    if (openPanel) showPanel('detail');
}

function getTerritoryOwnerFillRows(entity, region, isCn) {
    const shapePlan = getTerritoryShapePlan(entity, region);
    if (!shapePlan?.fills?.length) return [];

    return shapePlan.fills.map(fill => {
        const ownerName = isCn ? (fill.owner.nameCN || fill.owner.name) : fill.owner.name;
        const { start, end } = getTerritoryFillRange(entity, fill);
        return {
            id: fill.owner.id,
            name: ownerName,
            kind: getTerritoryFillKind(fill, isCn),
            period: `${formatYear(start)} → ${formatYear(end)}`
        };
    });
}

function showPanel(kind = 'detail', { trigger = null } = {}) {
    const activeElement = trigger || document.activeElement;
    if (activeElement && activeElement !== document.body && !elements.eventPanel.contains(activeElement)) {
        lastPanelTrigger = activeElement;
        lastPanelTriggerDescriptor = getPanelTriggerDescriptor(activeElement);
    }
    clearActiveTimelinePreview();
    activePanelKind = kind;
    elements.helpBtn?.setAttribute('aria-expanded', String(kind === 'help'));

    let backdrop = document.querySelector('.panel-backdrop');
    if (!backdrop) {
        backdrop = document.createElement('div');
        backdrop.className = 'panel-backdrop';
        backdrop.addEventListener('click', hidePanel);
        document.body.appendChild(backdrop);
    }
    backdrop.classList.add('visible');
    elements.eventPanel.dataset.open = 'true';
    elements.eventPanel.setAttribute('aria-hidden', 'false');
    elements.eventPanel.classList.add('visible');
    setDialogFocusability(elements.eventPanel, false);
    elements.eventPanel.style.setProperty('opacity', '1', 'important');
    elements.eventPanel.style.setProperty('visibility', 'visible', 'important');
    elements.eventPanel.style.setProperty('transform', 'translate(-50%, -50%) scale(1)', 'important');
    if (panelFocusTimer) clearTimeout(panelFocusTimer);
    panelFocusTimer = setTimeout(() => {
        panelFocusTimer = null;
        if (elements.eventPanel?.dataset.open === 'true') {
            elements.panelClose?.focus({ preventScroll: true });
        }
    }, 250);
}

function hidePanel({ restoreFocus = true } = {}) {
    const wasOpen = elements.eventPanel?.dataset.open === 'true' || elements.eventPanel?.classList.contains('visible');

    if (panelFocusTimer) {
        clearTimeout(panelFocusTimer);
        panelFocusTimer = null;
    }
    document.querySelector('.panel-backdrop')?.classList.remove('visible');
    elements.eventPanel.dataset.open = 'false';
    elements.eventPanel.setAttribute('aria-hidden', 'true');
    elements.eventPanel.classList.remove('visible');
    setDialogFocusability(elements.eventPanel, true);
    elements.eventPanel.style.opacity = '';
    elements.eventPanel.style.visibility = '';
    elements.eventPanel.style.transform = '';
    activePanelKind = null;
    activePanelContext = null;
    elements.helpBtn?.setAttribute('aria-expanded', 'false');

    if (wasOpen && restoreFocus) {
        const restoreTarget = getPanelRestoreTarget();
        if (restoreTarget?.isConnected) {
            setTimeout(() => restoreTarget.focus({ preventScroll: true }), 0);
        }
    }
}

function getPanelTriggerDescriptor(trigger) {
    if (!trigger || trigger === document.body || !trigger.closest) return null;
    const entityBlock = trigger.closest('.dynasty-block[data-id]');
    if (entityBlock) return { type: 'entity', id: entityBlock.dataset.id };
    const eventMarker = trigger.closest('.global-event-marker[data-event-index]');
    if (eventMarker) return { type: 'event', index: eventMarker.dataset.eventIndex };
    if (trigger.id) return { type: 'id', id: trigger.id };
    return null;
}

function getPanelRestoreTarget() {
    if (lastPanelTrigger?.isConnected) return lastPanelTrigger;
    if (!lastPanelTriggerDescriptor) return null;

    if (lastPanelTriggerDescriptor.type === 'entity') {
        return Array.from(document.querySelectorAll('.dynasty-block[data-id]'))
            .find(block => block.dataset.id === lastPanelTriggerDescriptor.id) || null;
    }
    if (lastPanelTriggerDescriptor.type === 'event') {
        return Array.from(document.querySelectorAll('.global-event-marker[data-event-index]'))
            .find(marker => marker.dataset.eventIndex === lastPanelTriggerDescriptor.index) || null;
    }
    if (lastPanelTriggerDescriptor.type === 'id') {
        return document.getElementById(lastPanelTriggerDescriptor.id);
    }
    return null;
}

function getFocusableElements(container) {
    if (!container) return [];
    const selector = [
        'a[href]',
        'button:not([disabled])',
        'input:not([disabled])',
        'select:not([disabled])',
        'textarea:not([disabled])',
        '[tabindex]:not([tabindex="-1"])'
    ].join(',');

    return Array.from(container.querySelectorAll(selector)).filter(el => {
        const style = window.getComputedStyle(el);
        return style.display !== 'none' && style.visibility !== 'hidden' && el.getClientRects().length > 0;
    });
}

function setContainerFocusability(container, disabled, dataKey = 'savedTabindex') {
    if (!container) return;
    container.querySelectorAll(FOCUSABLE_SELECTOR).forEach(control => {
        if (disabled) {
            if (!Object.prototype.hasOwnProperty.call(control.dataset, dataKey)) {
                control.dataset[dataKey] = control.hasAttribute('tabindex')
                    ? control.getAttribute('tabindex')
                    : SAVED_TABINDEX_NONE;
            }
            control.setAttribute('tabindex', '-1');
            return;
        }

        if (!Object.prototype.hasOwnProperty.call(control.dataset, dataKey)) return;
        const previous = control.dataset[dataKey];
        if (previous === SAVED_TABINDEX_NONE) {
            control.removeAttribute('tabindex');
        } else {
            control.setAttribute('tabindex', previous);
        }
        delete control.dataset[dataKey];
    });
}

function setDialogFocusability(dialog, disabled) {
    setContainerFocusability(dialog, disabled, 'dialogTabindex');
}

function isDialogOpen() {
    return elements.eventPanel?.dataset.open === 'true' || elements.comparePanel?.dataset.open === 'true';
}

function handlePanelKeydown(e) {
    if (elements.eventPanel?.dataset.open !== 'true') return;

    if (e.key === 'Escape') {
        e.preventDefault();
        e.stopPropagation();
        hidePanel();
        return;
    }

    if (e.key !== 'Tab') return;

    const focusable = getFocusableElements(elements.eventPanel);
    if (!focusable.length) {
        e.preventDefault();
        return;
    }

    const first = focusable[0];
    const last = focusable[focusable.length - 1];

    if (e.shiftKey && document.activeElement === first) {
        e.preventDefault();
        last.focus({ preventScroll: true });
    } else if (!e.shiftKey && document.activeElement === last) {
        e.preventDefault();
        first.focus({ preventScroll: true });
    }
}

function toggleEvents(show) {
    CONFIG.showEvents = show;
    renderTimeline();
    renderGlobalEvents();
}

function toggleRegion(regionId, show) {
    const preservedView = captureCurrentViewState();
    setCompareMode(false);
    CONFIG.visibleRegions[regionId] = show;
    renderTimeline();
    renderGlobalEvents();
    renderLegend();
    restorePreservedViewState(preservedView);
}

function switchLanguage(lang) {
    const preservedView = captureCurrentViewState();

    CONFIG.language = lang;
    document.body.classList.toggle('lang-cn', lang === 'cn');
    elements.langButtons.forEach(btn => {
        const active = btn.dataset.lang === lang;
        btn.classList.toggle('active', active);
        btn.setAttribute('aria-pressed', String(active));
    });
    updateStaticText();
    renderYearScale();
    renderTimeline();
    renderLegend();
    renderGlobalEvents();
    renderConnectionLines();
    restorePreservedViewState(preservedView);
}

// ============================================
// ZOOM CONTROLS
// ============================================

const DEFAULT_YEAR_HEIGHT = 0.25;
const MIN_YEAR_HEIGHT = 0.1;
const MAX_YEAR_HEIGHT = 15;
const ZOOM_STEP = 0.05;

function roundZoomToStep(value) {
    return Number((Math.round(value / ZOOM_STEP) * ZOOM_STEP).toFixed(2));
}

function clampZoomValue(value, fallback = DEFAULT_YEAR_HEIGHT) {
    const numericValue = typeof value === 'number' ? value : parseFloat(value);
    const safeValue = Number.isFinite(numericValue) ? numericValue : fallback;
    return Math.max(MIN_YEAR_HEIGHT, Math.min(MAX_YEAR_HEIGHT, safeValue));
}

function timelineContentOffsetTop() {
    const container = elements.timelineContainer;
    if (!container) return 0;
    const paddingTop = parseFloat(getComputedStyle(container).paddingTop);
    return Number.isFinite(paddingTop) ? paddingTop : 0;
}

function timelineViewportTopClientY() {
    const header = document.querySelector('.chronicle-header');
    return document.body.classList.contains('full-page-mode')
        ? 16
        : (header ? header.getBoundingClientRect().height : 0) + 16;
}

function yearAtViewportY(clientY) {
    const container = elements.timelineContainer;
    if (!container) return null;
    const rect = container.getBoundingClientRect();
    const relativeY = clientY - rect.top - timelineContentOffsetTop() - 35;
    return CONFIG.timelineStart + relativeY / CONFIG.yearHeight;
}

function clampYearValue(value, fallback = null) {
    const numericValue = typeof value === 'number' ? value : parseFloat(value);
    if (!Number.isFinite(numericValue)) return fallback;
    return Math.max(CONFIG.timelineStart, Math.min(CONFIG.timelineEnd, numericValue));
}

function timelineFocusClientY() {
    const headerOffset = timelineViewportTopClientY();
    return headerOffset + (window.innerHeight - headerOffset) / 2;
}

function currentViewYear() {
    const year = yearAtViewportY(timelineFocusClientY());
    const clampedYear = clampYearValue(year);
    return Number.isFinite(clampedYear) ? Math.round(clampedYear) : CONFIG.viewYear;
}

function clampScrollRatio(value, fallback = null) {
    const numericValue = typeof value === 'number' ? value : parseFloat(value);
    if (!Number.isFinite(numericValue)) return fallback;
    return Math.max(0, Math.min(1, numericValue));
}

function horizontalScrollMax() {
    const wrapper = elements.timelineWrapper;
    if (!wrapper) return 0;
    return Math.max(0, wrapper.scrollWidth - wrapper.clientWidth);
}

function horizontalRatioForLeft(left) {
    const maxScroll = horizontalScrollMax();
    if (maxScroll <= 0) return 0;
    return clampScrollRatio(left / maxScroll, 0);
}

function formatScrollRatio(ratio) {
    return Number(ratio.toFixed(4)).toString();
}

function currentViewX() {
    const wrapper = elements.timelineWrapper;
    if (!wrapper) return CONFIG.viewX;
    return horizontalRatioForLeft(wrapper.scrollLeft);
}

function setTimelineHorizontalRatio(ratio) {
    const wrapper = elements.timelineWrapper;
    const safeRatio = clampScrollRatio(ratio, null);
    if (!wrapper || !Number.isFinite(safeRatio)) return null;
    const targetLeft = horizontalScrollMax() * safeRatio;
    wrapper.scrollLeft = targetLeft;
    CONFIG.viewX = currentViewX();
    return CONFIG.viewX;
}

function restoreHorizontalView() {
    if (Number.isFinite(CONFIG.viewX)) {
        setTimelineHorizontalRatio(CONFIG.viewX);
    }
}

function scrollWindowToTop(top, smooth = true) {
    if (smooth) {
        window.scrollTo({ top, behavior: 'smooth' });
        return;
    }

    const root = document.documentElement;
    const previousRootBehavior = root.style.scrollBehavior;
    const previousBodyBehavior = document.body.style.scrollBehavior;
    root.style.scrollBehavior = 'auto';
    document.body.style.scrollBehavior = 'auto';
    window.scrollTo(0, top);
    root.style.scrollBehavior = previousRootBehavior;
    document.body.style.scrollBehavior = previousBodyBehavior;
}

function setZoom(newYearHeight) {
    newYearHeight = clampZoomValue(newYearHeight, CONFIG.yearHeight);

    const anchorYear = yearAtViewportY(timelineFocusClientY());

    CONFIG.yearHeight = newYearHeight;

    if (elements.zoomSlider) elements.zoomSlider.value = newYearHeight;
    if (elements.zoomValue) elements.zoomValue.textContent = `${newYearHeight.toFixed(2)} px/yr`;
    updateZoomPresetState();

    renderYearScale();
    renderTimeline();
    renderGlobalEvents();

    if (Number.isFinite(anchorYear)) {
        scrollToYear(anchorYear, false);
    }
}

function zoomIn() {
    const step = CONFIG.yearHeight < 1 ? 0.25 : CONFIG.yearHeight < 3 ? 0.5 : 1;
    setZoom(CONFIG.yearHeight + step);
}
function zoomOut() {
    const step = CONFIG.yearHeight <= 1 ? 0.25 : CONFIG.yearHeight <= 3 ? 0.5 : 1;
    setZoom(CONFIG.yearHeight - step);
}
function resetZoom() { setZoom(DEFAULT_YEAR_HEIGHT); }
function handleZoomSlider(e) { setZoom(parseFloat(e.target.value)); }

function updateZoomPresetState() {
    if (!elements.presetBtns) return;
    elements.presetBtns.forEach(btn => {
        const presetZoom = parseFloat(btn.dataset.zoom);
        const active = Number.isFinite(presetZoom) && Math.abs(CONFIG.yearHeight - presetZoom) < ZOOM_STEP / 2;
        btn.classList.toggle('active', active);
        btn.setAttribute('aria-pressed', String(active));
    });
}

// ============================================
// CONNECTIONS RENDERING
// ============================================

function renderConnections() {
    // Remove existing
    document.querySelectorAll('.connection-line').forEach(el => el.remove());
    if (!CONFIG.showConnections) return;

    // One shared SVG for all connections
    const svg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
    svg.classList.add('connection-line');
    svg.setAttribute('xmlns', 'http://www.w3.org/2000/svg');
    svg.style.cssText = `
        position: absolute;
        top: 0; left: 0;
        width: 100%; height: 100%;
        pointer-events: none;
        z-index: 140;
        overflow: visible;
    `;

    const colors = CONFIG.darkMode ? {
        trade:      { stroke: '#A8BC78', dash: '4,3', icon: '' },
        conflict:   { stroke: '#E87961', dash: 'none', icon: '' },
        conquest:   { stroke: '#D5654E', dash: 'none', icon: '' },
        succession: { stroke: '#86B7DF', dash: 'none', icon: '' },
        political:  { stroke: '#B29BDC', dash: '5,3', icon: '' },
        colonial:   { stroke: '#D98A73', dash: '7,2', icon: '' },
        frontier:   { stroke: '#8EB8B9', dash: '3,3', icon: '' },
        cultural:   { stroke: '#C8BDAA', dash: '6,2,2,2', icon: '' }
    } : {
        trade:      { stroke: '#6E833A', dash: '4,3', icon: '' },
        conflict:   { stroke: '#B8361F', dash: 'none', icon: '' },
        conquest:   { stroke: '#5A1108', dash: 'none', icon: '' },
        succession: { stroke: '#1F4D7A', dash: 'none', icon: '' },
        political:  { stroke: '#6B4FA0', dash: '5,3', icon: '' },
        colonial:   { stroke: '#8F3F2C', dash: '7,2', icon: '' },
        frontier:   { stroke: '#4D6A70', dash: '3,3', icon: '' },
        cultural:   { stroke: '#5C544A', dash: '6,2,2,2', icon: '' }
    };

    CONNECTIONS.forEach((conn, idx) => {
        const fromPos = entityPositions[conn.from];
        const toPos = entityPositions[conn.to];
        if (!fromPos || !toPos) return;

        const y = yearToY(conn.year) + 35;
        const x1 = fromPos.centerX;
        const x2 = toPos.centerX;
        const midX = (x1 + x2) / 2;

        // Curvature — arcs scale with horizontal distance
        const distance = Math.abs(x2 - x1);
        const arcHeight = Math.min(40 + distance * 0.10, 80);

        const style = colors[conn.type] || colors.cultural;

        // Small square markers at ends
        const dot1 = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
        dot1.setAttribute('x', x1 - 2);
        dot1.setAttribute('y', y - 2);
        dot1.setAttribute('width', '4');
        dot1.setAttribute('height', '4');
        dot1.setAttribute('fill', style.stroke);
        svg.appendChild(dot1);

        const dot2 = document.createElementNS('http://www.w3.org/2000/svg', 'rect');
        dot2.setAttribute('x', x2 - 2);
        dot2.setAttribute('y', y - 2);
        dot2.setAttribute('width', '4');
        dot2.setAttribute('height', '4');
        dot2.setAttribute('fill', style.stroke);
        svg.appendChild(dot2);

        // Arced path
        const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
        const d = `M ${x1} ${y} Q ${midX} ${y - arcHeight} ${x2} ${y}`;
        path.setAttribute('d', d);
        path.setAttribute('stroke', style.stroke);
        path.setAttribute('stroke-width', '1');
        path.setAttribute('fill', 'none');
        path.setAttribute('opacity', CONFIG.darkMode ? '0.74' : '0.65');
        if (style.dash !== 'none') path.setAttribute('stroke-dasharray', style.dash);
        path.style.pointerEvents = 'stroke';
        path.style.cursor = 'pointer';
        path.addEventListener('mouseenter', (e) => showConnectionTooltip(e, conn));
        path.addEventListener('mouseleave', hideTooltip);
        svg.appendChild(path);

        // Label — render when the text layer is enabled; collision pruning keeps
        // overview zooms sparse instead of silently disabling the label toggle.
        if (CONFIG.showConnectionLabels) {
            const g = document.createElementNS('http://www.w3.org/2000/svg', 'g');
            g.classList.add('connection-label');
            g.dataset.connectionIndex = String(idx);
            g.dataset.connectionType = conn.type;
            g.dataset.distance = String(distance);
            const labelText = CONFIG.language === 'cn' ? conn.labelCN : conn.label;
            const labelFontSize = getConnectionLabelFontSize();
            const text = document.createElementNS('http://www.w3.org/2000/svg', 'text');
            text.setAttribute('x', midX);
            text.setAttribute('y', y - arcHeight - 4);
            text.setAttribute('text-anchor', 'middle');
            text.setAttribute('font-size', String(labelFontSize));
            text.setAttribute('font-family', 'system-ui, -apple-system, sans-serif');
            text.setAttribute('font-style', 'normal');
            text.setAttribute('font-weight', '500');
            text.setAttribute('fill', style.stroke);
            text.setAttribute('opacity', '0.95');
            text.textContent = labelText;
            const halo = text.cloneNode(true);
            halo.setAttribute('stroke', CONFIG.darkMode ? '#101213' : '#FFFFFF');
            halo.setAttribute('stroke-width', CONFIG.darkMode ? '3.4' : '3');
            halo.setAttribute('opacity', CONFIG.darkMode ? '0.94' : '0.9');
            g.appendChild(halo);
            g.appendChild(text);
            svg.appendChild(g);
        }
    });

    elements.timelineGrid.appendChild(svg);
    pruneConnectionLabelCollisions(svg);
}

function pruneConnectionLabelCollisions(svg) {
    if (!svg || !CONFIG.showConnectionLabels) return;
    const labels = Array.from(svg.querySelectorAll('.connection-label'));
    if (labels.length <= 1) return;
    const labelOffsets = getConnectionLabelOffsetCandidates();

    const candidates = labels
        .map(label => {
            const index = Number.parseInt(label.dataset.connectionIndex || '', 10);
            const conn = Number.isInteger(index) ? CONNECTIONS[index] : null;
            try {
                const box = label.getBBox();
                const rect = {
                    left: box.x - 4,
                    right: box.x + box.width + 4,
                    top: box.y - 3,
                    bottom: box.y + box.height + 3
                };
                return {
                    label,
                    rect,
                    score: scoreConnectionLabel(conn, Number.parseFloat(label.dataset.distance || '0'))
                };
            } catch {
                return null;
            }
        })
        .filter(Boolean)
        .sort((a, b) => b.score - a.score);

    const accepted = [];
    let hidden = 0;
    candidates.forEach(candidate => {
        const offsetY = labelOffsets.find(offset =>
            !accepted.some(rect => rectsOverlap(offsetRect(candidate.rect, 0, offset), rect))
        );

        if (Number.isFinite(offsetY)) {
            if (offsetY !== 0) {
                candidate.label.setAttribute('transform', `translate(0 ${offsetY})`);
                candidate.label.dataset.labelOffsetY = String(offsetY);
            }
            accepted.push(offsetRect(candidate.rect, 0, offsetY));
        } else {
            candidate.label.remove();
            hidden++;
        }
    });

    svg.dataset.labelCandidates = String(labels.length);
    svg.dataset.labelVisible = String(labels.length - hidden);
    svg.dataset.labelHidden = String(hidden);
}

function getConnectionLabelFontSize() {
    if (CONFIG.yearHeight < 0.35) return 8;
    if (CONFIG.yearHeight < 0.75) return 8.5;
    return 9.5;
}

function getConnectionLabelOffsetCandidates() {
    if (CONFIG.yearHeight >= 2) return [0, -12, 12, -24, 24, -36, 36];
    if (CONFIG.yearHeight >= 1.5) return [0, -12, 12, -24, 24];
    return [0];
}

function offsetRect(rect, dx = 0, dy = 0) {
    return {
        left: rect.left + dx,
        right: rect.right + dx,
        top: rect.top + dy,
        bottom: rect.bottom + dy
    };
}

function scoreConnectionLabel(conn, distance = 0) {
    const typeScore = {
        conquest: 120,
        succession: 110,
        conflict: 100,
        political: 82,
        colonial: 74,
        frontier: 68,
        cultural: 64,
        trade: 52
    }[conn?.type] || 60;
    const priorityBoost = Number.isFinite(Number(conn?.labelPriority)) ? Number(conn.labelPriority) : 0;
    const label = CONFIG.language === 'cn' ? conn?.labelCN : conn?.label;
    const lengthPenalty = Math.min(String(label || '').length, 48) * 0.35;
    const distancePenalty = Math.min(Math.max(distance, 0), 420) / 24;
    return typeScore + priorityBoost - lengthPenalty - distancePenalty;
}

function rectsOverlap(a, b) {
    return a.left < b.right && a.right > b.left && a.top < b.bottom && a.bottom > b.top;
}

// ============================================
// SEARCH FUNCTIONALITY
// ============================================

function normalizeSearchQuery(value) {
    return (value || '').trim();
}

function parseCategoryParam(value) {
    const normalized = (value || '').trim();
    if (!normalized) return null;

    const normalizedLower = normalized.toLowerCase();
    if (ENTITY_CATEGORIES[normalizedLower]) return normalizedLower;

    const match = Object.entries(ENTITY_CATEGORIES).find(([_, category]) =>
        [category.label, category.labelCN, ...(category.aliases || []), ...(category.aliasesCN || [])].some(alias => {
            const term = String(alias || '').trim();
            return term && (term.toLowerCase() === normalizedLower || term === normalized);
        })
    );
    return match ? match[0] : null;
}

function handleSearch(query) {
    CONFIG.searchQuery = normalizeSearchQuery(query);
    syncSearchClearState();

    renderTimeline();

    if (CONFIG.searchQuery) {
        requestAnimationFrame(() => {
            const target = scrollToFirstRenderedBlock({ selector: '.dynasty-block.search-match' });
            updateURLState({
                viewYear: target?.year ?? currentViewYear(),
                viewX: target?.x ?? currentViewX()
            });
        });
    } else {
        updateURLState();
    }
}

function clearPendingSearchDebounce() {
    if (!searchDebounceTimer) return;
    clearTimeout(searchDebounceTimer);
    searchDebounceTimer = null;
}

function queueSearch(query) {
    clearPendingSearchDebounce();
    searchDebounceTimer = setTimeout(() => {
        searchDebounceTimer = null;
        handleSearch(query);
    }, 300);
}

function syncSearchClearState() {
    if (!elements.searchClear) return;
    const visible = !!CONFIG.searchQuery;
    elements.searchClear.hidden = !visible;
    if (visible) {
        elements.searchClear.removeAttribute('tabindex');
    } else {
        elements.searchClear.setAttribute('tabindex', '-1');
    }
}

function clearSearch({ restoreFocus = false } = {}) {
    clearPendingSearchDebounce();
    if (elements.searchInput) {
        elements.searchInput.value = '';
    }
    handleSearch('');
    if (restoreFocus) {
        elements.searchInput?.focus({ preventScroll: true });
    }
}

// ============================================
// MINIMAP
// ============================================

// Stats chip — live counter of visible polities
function updateStatsChip(visibleCount, matchCount) {
    const entitiesEl = document.getElementById('statEntities');
    const regionsEl = document.getElementById('statRegions');
    const spanEl = document.getElementById('statSpan');
    if (!entitiesEl) return;

    let total = 0;
    getVisibleRegions().forEach(rid => {
        total += (WORLD_HISTORY[rid] ? WORLD_HISTORY[rid].entities.length : 0);
    });
    const activeRegions = getVisibleRegions().length;
    const categoryFiltered = CONFIG.categoryFilter ? visibleCount : total;

    entitiesEl.textContent = CONFIG.searchQuery && matchCount !== undefined
        ? `${matchCount} / ${categoryFiltered}`
        : `${categoryFiltered}`;
    regionsEl.textContent = `${activeRegions}`;
    spanEl.textContent = `${CONFIG.timelineEnd - CONFIG.timelineStart}`;
}

function isKnownRegion(region) {
    return Object.prototype.hasOwnProperty.call(WORLD_HISTORY, region);
}

function normalizeURLAlias(value) {
    return (value || '').trim().toLowerCase().replace(/[\s._-]+/g, '');
}

function parseLanguageParam(value, fallback = CONFIG.language) {
    const alias = normalizeURLAlias(value);
    const chineseAliases = new Set([
        'cn', 'zh', 'zhcn', 'zhhans', 'zhhanscn', 'chinese', 'mandarin',
        '中文', '简体中文', '繁體中文', '汉语', '漢語', '华语', '華語'
    ]);
    const englishAliases = new Set([
        'en', 'eng', 'enus', 'enusa', 'english', '英文', '英语', '英語'
    ]);

    if (chineseAliases.has(alias)) return 'cn';
    if (englishAliases.has(alias)) return 'en';
    return fallback;
}

function parseRegionToken(value) {
    const normalized = (value || '').trim();
    if (!normalized) return null;
    if (isKnownRegion(normalized)) return normalized;

    const alias = normalizeURLAlias(normalized);
    const match = Object.entries(WORLD_HISTORY).find(([regionKey, region]) => {
        const candidates = [
            regionKey,
            region.name,
            region.nameCN,
            REGION_SHORT_LABELS.en?.[regionKey],
            REGION_SHORT_LABELS.cn?.[regionKey]
        ];
        return candidates.some(candidate => normalizeURLAlias(candidate) === alias);
    });

    return match ? match[0] : null;
}

function parseRegionList(value) {
    return [...new Set((value || '')
        .split(',')
        .map(parseRegionToken)
        .filter(Boolean))];
}

function parseVisibleRegionsParam(value) {
    const normalized = (value || '').trim();
    if (normalized.toLowerCase() === 'none' || normalized === '') return [];

    const knownRegions = parseRegionList(normalized);
    return knownRegions.length ? knownRegions : null;
}

function parseBooleanURLFlag(value) {
    if (value === '1') return true;
    if (value === '0') return false;
    return null;
}

function isValidCompareRegions(regions) {
    return Array.isArray(regions)
        && regions.length === 2
        && new Set(regions).size === 2
        && regions.every(isKnownRegion);
}

function syncCompareButtonState() {
    const active = CONFIG.compareMode && isValidCompareRegions(CONFIG.compareRegions);
    if (!active) {
        CONFIG.compareMode = false;
        CONFIG.compareRegions = [];
    }
    elements.compareBtn?.classList.toggle('active', active);
    elements.compareBtn?.setAttribute('aria-pressed', String(active));
}

function setCompareMode(active, regions = []) {
    if (active && isValidCompareRegions(regions)) {
        CONFIG.compareMode = true;
        CONFIG.compareRegions = [...regions];
    } else {
        CONFIG.compareMode = false;
        CONFIG.compareRegions = [];
    }
    syncCompareButtonState();
}

function setVisibleRegionSet(regionKeys) {
    const activeRegions = new Set(regionKeys);
    Object.keys(CONFIG.visibleRegions).forEach(region => {
        CONFIG.visibleRegions[region] = activeRegions.has(region);
    });
}

function showAllRegions() {
    Object.keys(CONFIG.visibleRegions).forEach(region => {
        CONFIG.visibleRegions[region] = true;
    });
}

function syncRegionCheckboxes() {
    elements.regionCheckboxes?.forEach(checkbox => {
        const region = checkbox.dataset.region;
        if (region && CONFIG.visibleRegions.hasOwnProperty(region)) {
            checkbox.checked = CONFIG.visibleRegions[region];
        }
    });
}

// ============================================
// URL STATE MANAGEMENT
// ============================================

function updateURLState({ viewYear = currentViewYear(), viewX = currentViewX() } = {}) {
    const activeRegions = getVisibleRegions();
    const safeViewYear = clampYearValue(viewYear, null);
    const safeViewX = clampScrollRatio(viewX, null);
    rememberViewState({ viewYear: safeViewYear, viewX: safeViewX });
    const state = {
        zoom: CONFIG.yearHeight,
        lang: CONFIG.language,
        year: Number.isFinite(safeViewYear) ? Math.round(safeViewYear) : undefined,
        x: Number.isFinite(safeViewX) && safeViewX > 0 ? formatScrollRatio(safeViewX) : undefined,
        regions: activeRegions.length ? activeRegions.join(',') : 'none',
        compare: CONFIG.compareMode && isValidCompareRegions(CONFIG.compareRegions)
            ? CONFIG.compareRegions.join(',')
            : undefined,
        search: CONFIG.searchQuery || undefined,
        category: CONFIG.categoryFilter || undefined,
        dark: document.body.classList.contains('dark-mode') ? '1' : '0',
        events: CONFIG.showEvents ? '1' : '0',
        connections: CONFIG.showConnections ? '1' : '0',
        linkLabels: CONFIG.showConnectionLabels ? '1' : '0',
        eras: CONFIG.showEraBackgrounds ? '1' : '0',
        ruler: CONFIG.showTimeRuler ? '1' : '0',
        rulerYear: CONFIG.showTimeRuler ? normalizeTimeRulerYear() : undefined
    };

    const params = new URLSearchParams();
    Object.entries(state).forEach(([k, v]) => {
        if (v !== undefined && v !== '') params.set(k, v);
    });

    const newURL = `${window.location.pathname}${params.toString() ? '?' + params.toString() : ''}`;
    window.history.replaceState(null, '', newURL);
}

function rememberViewState({ viewYear = currentViewYear(), viewX = currentViewX() } = {}) {
    const safeViewYear = clampYearValue(viewYear, null);
    const safeViewX = clampScrollRatio(viewX, null);
    if (Number.isFinite(safeViewYear)) CONFIG.viewYear = safeViewYear;
    if (Number.isFinite(safeViewX)) CONFIG.viewX = safeViewX;
}

function captureCurrentViewState() {
    return {
        viewYear: currentViewYear(),
        viewX: currentViewX()
    };
}

function restorePreservedViewState(viewState) {
    if (!viewState) return;
    const safeViewYear = clampYearValue(viewState.viewYear, null);
    const safeViewX = clampScrollRatio(viewState.viewX, null);

    if (Number.isFinite(safeViewYear)) {
        scrollToYear(safeViewYear, false, { flash: false });
    }
    if (Number.isFinite(safeViewX)) {
        setTimelineHorizontalRatio(safeViewX);
    }
    rememberViewState({
        viewYear: safeViewYear,
        viewX: safeViewX
    });
}

function queueViewStateMemory() {
    if (restoringViewAfterResize || viewStateMemoryFrame) return;
    viewStateMemoryFrame = window.requestAnimationFrame(() => {
        viewStateMemoryFrame = null;
        if (!restoringViewAfterResize) rememberViewState();
    });
}

function handleTrackedViewStateScroll(target) {
    queueViewStateMemory();
    if (!viewStateURLTrackingReady || restoringViewAfterResize) return;
    scheduleViewStateURLUpdate({ target, fallbackDelay: 520 });
}

function handleWindowViewStateScroll() {
    queueGlobalEventMarkerPositionUpdate();
    handleTrackedViewStateScroll(window);
}

function handleTimelineViewStateScroll() {
    queueGlobalEventMarkerPositionUpdate();
    handleTrackedViewStateScroll(elements.timelineWrapper);
}

function restoreViewAfterResize() {
    if (!resizePreservedViewState) return;
    const { viewYear, viewX } = resizePreservedViewState;

    if (Number.isFinite(viewYear)) {
        scrollToYear(viewYear, false, { flash: false });
    }
    if (Number.isFinite(viewX)) {
        setTimelineHorizontalRatio(viewX);
    }

    updateURLState({ viewYear, viewX });
    resizePreservedViewState = null;
    restoringViewAfterResize = false;
}

function handleViewportResize() {
    if (!resizePreservedViewState) {
        resizePreservedViewState = {
            viewYear: CONFIG.viewYear,
            viewX: CONFIG.viewX
        };
    }

    restoringViewAfterResize = true;

    if (resizeViewRestoreTimer) {
        window.clearTimeout(resizeViewRestoreTimer);
    }
    resizeViewRestoreTimer = window.setTimeout(() => {
        resizeViewRestoreTimer = null;
        renderGlobalEvents();
        window.requestAnimationFrame(restoreViewAfterResize);
    }, 140);
}

function setupViewStateTracking() {
    window.addEventListener('scroll', handleWindowViewStateScroll, { passive: true });
    elements.timelineWrapper?.addEventListener('scroll', handleTimelineViewStateScroll, { passive: true });
    window.addEventListener('resize', handleViewportResize);
}

function scheduleViewStateURLUpdate({ target = null, fallbackDelay = 650 } = {}) {
    viewStateURLSyncToken += 1;
    const token = viewStateURLSyncToken;

    if (viewStateURLTimer) {
        window.clearTimeout(viewStateURLTimer);
        viewStateURLTimer = null;
    }
    if (viewStateURLScrollCleanup) {
        viewStateURLScrollCleanup();
        viewStateURLScrollCleanup = null;
    }

    const commit = () => {
        if (token !== viewStateURLSyncToken) return;
        if (viewStateURLTimer) {
            window.clearTimeout(viewStateURLTimer);
            viewStateURLTimer = null;
        }
        if (viewStateURLScrollCleanup) {
            viewStateURLScrollCleanup();
            viewStateURLScrollCleanup = null;
        }
        updateURLState();
    };

    if (target && typeof target.addEventListener === 'function') {
        target.addEventListener('scrollend', commit, { once: true });
        viewStateURLScrollCleanup = () => {
            target.removeEventListener('scrollend', commit);
        };
    }

    viewStateURLTimer = window.setTimeout(commit, fallbackDelay);
}

function loadURLState() {
    const params = new URLSearchParams(window.location.search);
    urlViewYearProvided = false;
    urlViewXProvided = false;
    urlCategoryNeedsNormalization = false;

    if (params.has('zoom')) {
        CONFIG.yearHeight = clampZoomValue(params.get('zoom'));
    }

    if (params.has('year')) {
        const viewYear = clampYearValue(params.get('year'), null);
        if (Number.isFinite(viewYear)) {
            CONFIG.viewYear = viewYear;
            urlViewYearProvided = true;
        }
    }

    if (params.has('x')) {
        const viewX = clampScrollRatio(params.get('x'), null);
        if (Number.isFinite(viewX)) {
            CONFIG.viewX = viewX;
            urlViewXProvided = true;
        }
    }

    if (params.has('lang')) {
        CONFIG.language = parseLanguageParam(params.get('lang'));
    }

    if (params.has('regions')) {
        const regionsParam = params.get('regions');
        const activeRegions = parseVisibleRegionsParam(regionsParam);
        if (activeRegions !== null) {
            setVisibleRegionSet(activeRegions);
        }
    }

    if (params.has('compare')) {
        const compareRegions = parseRegionList(params.get('compare'));
        if (isValidCompareRegions(compareRegions)) {
            setCompareMode(true, compareRegions);
            setVisibleRegionSet(compareRegions);
        } else {
            setCompareMode(false);
        }
    }

    if (params.has('search')) {
        CONFIG.searchQuery = normalizeSearchQuery(params.get('search'));
    }

    if (params.has('category')) {
        const rawCategory = params.get('category');
        CONFIG.categoryFilter = parseCategoryParam(rawCategory);
        urlCategoryNeedsNormalization = (rawCategory || '').trim() !== (CONFIG.categoryFilter || '');
    }

    if (params.has('dark')) {
        const darkMode = parseBooleanURLFlag(params.get('dark'));
        if (darkMode !== null) CONFIG.darkMode = darkMode;
    }

    if (params.has('events')) {
        const showEvents = parseBooleanURLFlag(params.get('events'));
        if (showEvents !== null) CONFIG.showEvents = showEvents;
    }

    if (params.has('connections')) {
        const showConnections = parseBooleanURLFlag(params.get('connections'));
        if (showConnections !== null) CONFIG.showConnections = showConnections;
    }

    if (params.has('linkLabels')) {
        const showConnectionLabels = parseBooleanURLFlag(params.get('linkLabels'));
        if (showConnectionLabels !== null) CONFIG.showConnectionLabels = showConnectionLabels;
    }

    if (params.has('eras')) {
        const showEras = parseBooleanURLFlag(params.get('eras'));
        if (showEras !== null) CONFIG.showEraBackgrounds = showEras;
    }

    if (params.has('ruler')) {
        const showRuler = parseBooleanURLFlag(params.get('ruler'));
        if (showRuler !== null) CONFIG.showTimeRuler = showRuler;
    }

    if (params.has('rulerYear')) {
        CONFIG.timeRulerYear = normalizeTimeRulerYear(params.get('rulerYear'));
    }
}

// ============================================
// KEYBOARD NAVIGATION
// ============================================

function setupKeyboardNavigation() {
    document.addEventListener('keydown', e => {
        const container = elements.timelineContainer;
        if (!container) return;
        if (isDialogOpen()) return;

        const activeTag = document.activeElement?.tagName;
        const isTyping = activeTag === 'INPUT' || activeTag === 'TEXTAREA';
        if (isTyping && e.key !== 'Escape') return;

        // Arrow key navigation
        const scrollAmount = 100;
        const horizontalScroller = elements.timelineWrapper || container;
        let handledNavigation = false;
        let syncTarget = window;
        let fallbackDelay = 650;

        switch(e.key) {
            case 'ArrowUp':
                if (!e.ctrlKey && !e.metaKey) {
                    window.scrollBy({ top: -scrollAmount, behavior: 'smooth' });
                    handledNavigation = true;
                    e.preventDefault();
                }
                break;
            case 'ArrowDown':
                if (!e.ctrlKey && !e.metaKey) {
                    window.scrollBy({ top: scrollAmount, behavior: 'smooth' });
                    handledNavigation = true;
                    e.preventDefault();
                }
                break;
            case 'ArrowLeft':
                horizontalScroller.scrollLeft -= scrollAmount;
                handledNavigation = true;
                syncTarget = horizontalScroller;
                fallbackDelay = 180;
                e.preventDefault();
                break;
            case 'ArrowRight':
                horizontalScroller.scrollLeft += scrollAmount;
                handledNavigation = true;
                syncTarget = horizontalScroller;
                fallbackDelay = 180;
                e.preventDefault();
                break;
            case 'Home':
                window.scrollTo({ top: 0, behavior: 'smooth' });
                handledNavigation = true;
                e.preventDefault();
                break;
            case 'End':
                window.scrollTo({ top: document.documentElement.scrollHeight, behavior: 'smooth' });
                handledNavigation = true;
                e.preventDefault();
                break;
            case 'PageUp':
                window.scrollBy({ top: -window.innerHeight * 0.85, behavior: 'smooth' });
                handledNavigation = true;
                e.preventDefault();
                break;
            case 'PageDown':
                window.scrollBy({ top: window.innerHeight * 0.85, behavior: 'smooth' });
                handledNavigation = true;
                e.preventDefault();
                break;
            case '/':
                // Focus search on '/'
                if (elements.searchInput && document.activeElement !== elements.searchInput) {
                    elements.searchInput.focus();
                    e.preventDefault();
                }
                break;
        }

        if (handledNavigation) {
            scheduleViewStateURLUpdate({ target: syncTarget, fallbackDelay });
        }

    });
}

// ============================================
// TOUCH GESTURES (MOBILE)
// ============================================

let touchState = {
    startX: 0,
    startY: 0,
    startDistance: 0,
    startZoom: CONFIG.yearHeight,
    didPinch: false
};

function setupTouchGestures() {
    const container = elements.timelineContainer;
    if (!container) return;

    container.addEventListener('touchstart', handleTouchStart, { passive: false });
    container.addEventListener('touchmove', handleTouchMove, { passive: false });
    container.addEventListener('touchend', handleTouchEnd, { passive: true });
}

function handleTouchStart(e) {
    if (e.touches.length === 2) {
        // Pinch gesture start
        const touch1 = e.touches[0];
        const touch2 = e.touches[1];
        touchState.startDistance = Math.hypot(
            touch2.clientX - touch1.clientX,
            touch2.clientY - touch1.clientY
        );
        touchState.startZoom = CONFIG.yearHeight;
        touchState.didPinch = false;
        e.preventDefault();
    } else if (e.touches.length === 1) {
        touchState.startX = e.touches[0].clientX;
        touchState.startY = e.touches[0].clientY;
    }
}

function handleTouchMove(e) {
    if (e.touches.length === 2 && touchState.startDistance > 0) {
        // Pinch to zoom
        const touch1 = e.touches[0];
        const touch2 = e.touches[1];
        const currentDistance = Math.hypot(
            touch2.clientX - touch1.clientX,
            touch2.clientY - touch1.clientY
        );

        const scale = currentDistance / touchState.startDistance;
        const newZoom = roundZoomToStep(touchState.startZoom * scale);

        if (newZoom !== CONFIG.yearHeight) {
            setZoom(newZoom);
            touchState.didPinch = true;
        }

        e.preventDefault();
    }
}

function handleTouchEnd(e) {
    const remainingTouches = e.touches?.length || 0;
    if (touchState.didPinch && remainingTouches < 2) {
        updateURLState();
    }
    if (remainingTouches < 2) {
        touchState.startDistance = 0;
        touchState.didPinch = false;
    }
}

// ============================================
// TOGGLE FUNCTIONS
// ============================================

function toggleConnections(show) {
    CONFIG.showConnections = show;
    renderTimeline();
    updateURLState();
}

function toggleConnectionLabels(show) {
    CONFIG.showConnectionLabels = show;
    renderConnections();
    updateURLState();
}

function toggleEras(show) {
    CONFIG.showEraBackgrounds = show;
    renderTimeline();
    updateURLState();
}

// ============================================
// MOVABLE TIME RULER
// ============================================

function normalizeTimeRulerYear(value = CONFIG.timeRulerYear) {
    const year = clampYearValue(value, 0);
    return Number.isFinite(year) ? Math.round(year) : 0;
}

function timeRulerTopForYear(year) {
    return timelineContentOffsetTop() + yearToY(year) + 35;
}

function updateTimeRulerPosition() {
    const ruler = elements.timeRuler;
    if (!ruler) return;

    const show = !!CONFIG.showTimeRuler;
    const year = normalizeTimeRulerYear();
    CONFIG.timeRulerYear = year;

    ruler.hidden = !show;
    ruler.classList.toggle('visible', show);
    ruler.setAttribute('aria-hidden', String(!show));
    ruler.tabIndex = show ? 0 : -1;
    ruler.style.top = `${timeRulerTopForYear(year)}px`;
    ruler.setAttribute('aria-valuenow', String(year));
    ruler.setAttribute('aria-valuetext', formatYear(year));
    ruler.setAttribute('aria-label', uiText('timeRulerLayerLabel'));
    ruler.setAttribute('title', uiText('timeRulerLayerLabel'));

    const label = ruler.querySelector('.time-ruler-year');
    if (label) label.textContent = formatYear(year);

    if (elements.timeRulerToggle) {
        elements.timeRulerToggle.checked = show;
    }
}

function setTimeRulerYear(year, { syncURL = false } = {}) {
    CONFIG.timeRulerYear = normalizeTimeRulerYear(year);
    updateTimeRulerPosition();
    if (syncURL) updateURLState();
}

function toggleTimeRuler(show, { alignToView = false } = {}) {
    CONFIG.showTimeRuler = !!show;
    if (CONFIG.showTimeRuler && alignToView) {
        CONFIG.timeRulerYear = normalizeTimeRulerYear(currentViewYear());
    }
    updateTimeRulerPosition();
}

function moveTimeRulerFromPointer(event) {
    const year = yearAtViewportY(event.clientY);
    if (!Number.isFinite(year)) return;
    setTimeRulerYear(year);
}

function setupTimeRuler() {
    const ruler = elements.timeRuler;
    if (!ruler) return;

    ruler.addEventListener('pointerdown', event => {
        if (!CONFIG.showTimeRuler) return;
        event.preventDefault();
        timeRulerPointerId = event.pointerId;
        ruler.setPointerCapture?.(event.pointerId);
        ruler.classList.add('dragging');
        moveTimeRulerFromPointer(event);
    });

    ruler.addEventListener('pointermove', event => {
        if (timeRulerPointerId !== event.pointerId) return;
        moveTimeRulerFromPointer(event);
    });

    const endDrag = event => {
        if (timeRulerPointerId !== event.pointerId) return;
        timeRulerPointerId = null;
        ruler.releasePointerCapture?.(event.pointerId);
        ruler.classList.remove('dragging');
        updateURLState();
    };
    ruler.addEventListener('pointerup', endDrag);
    ruler.addEventListener('pointercancel', endDrag);

    ruler.addEventListener('keydown', event => {
        if (!CONFIG.showTimeRuler) return;

        let nextYear = CONFIG.timeRulerYear;
        if (event.key === 'ArrowUp') nextYear -= event.shiftKey ? 10 : 1;
        else if (event.key === 'ArrowDown') nextYear += event.shiftKey ? 10 : 1;
        else if (event.key === 'PageUp') nextYear -= 25;
        else if (event.key === 'PageDown') nextYear += 25;
        else if (event.key === 'Home') nextYear = CONFIG.timelineStart;
        else if (event.key === 'End') nextYear = CONFIG.timelineEnd;
        else return;

        event.preventDefault();
        setTimeRulerYear(nextYear, { syncURL: true });
    });
}

// ============================================
// YEAR CURSOR
// ============================================

function setupYearCursor() {
    const container = elements.timelineContainer;
    if (!container || !elements.yearCursor) return;

    const cursorYear = elements.yearCursor.querySelector('.cursor-year');

    container.addEventListener('mousemove', (e) => {
        const year = Math.round(yearAtViewportY(e.clientY));

        if (Number.isFinite(year) && year >= CONFIG.timelineStart && year <= CONFIG.timelineEnd) {
            elements.yearCursor.style.top = `${e.clientY}px`;
            elements.yearCursor.classList.add('visible');
            if (cursorYear) {
                cursorYear.textContent = formatYear(year);
            }
        } else {
            elements.yearCursor.classList.remove('visible');
        }
    });

    container.addEventListener('mouseleave', () => {
        elements.yearCursor.classList.remove('visible');
    });
}

// ============================================
// ZOOM PRESETS
// ============================================

function setupZoomPresets() {
    if (!elements.presetBtns) return;

    elements.presetBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            const zoom = parseFloat(btn.dataset.zoom);
            if (!isNaN(zoom)) {
                setZoom(zoom);
                updateURLState();
            }
        });
    });
    updateZoomPresetState();
}

function jumpToYear(year) {
    scrollToYear(year, true);
}

// ============================================
// CONNECTION LINES VISUALIZATION
// ============================================

function renderConnectionLines() {
    // Remove old inline SVGs from grid (renderConnections also runs)
    document.querySelectorAll('.connection-line').forEach(el => el.remove());
    if (!CONFIG.showConnections) return;
    renderConnections();
}

function findEntityById(id) {
    for (const region of Object.values(WORLD_HISTORY)) {
        const entity = region.entities.find(e => e.id === id);
        if (entity) return entity;
    }
    return null;
}

function getEntityRegion(entityId) {
    for (const [regionKey, region] of Object.entries(WORLD_HISTORY)) {
        if (region.entities.some(e => e.id === entityId)) {
            return regionKey;
        }
    }
    return null;
}

function showConnectionTooltip(e, conn) {
    clearContemporaryHighlights();
    const tooltip = elements.tooltip;
    tooltip.querySelector('.tooltip-title').textContent = CONFIG.language === 'cn' ? conn.labelCN : conn.label;
    tooltip.querySelector('.tooltip-title-cn').textContent = CONFIG.language === 'cn' ? conn.label : conn.labelCN;
    tooltip.querySelector('.tooltip-dates').textContent = formatYear(conn.year);
    tooltip.querySelector('.tooltip-duration').textContent = connectionTypeLabel(conn.type);
    tooltip.querySelector('.tooltip-meta').textContent = '';
    clearTooltipOwner();

    positionTooltip(e.clientX + 10, e.clientY + 10);
    tooltip.classList.add('visible');
}

// ============================================
// GLOBAL EVENTS MARKERS
// ============================================

function getVisibleGlobalEventEntries() {
    const visibleRegions = new Set(getVisibleRegions());
    return HISTORICAL_EVENTS
        .map((event, index) => ({ event, index }))
        .filter(({ event }) => !event.region || visibleRegions.has(event.region));
}

function renderGlobalEvents() {
    if (!elements.globalEventsTrack) return;
    elements.globalEventsTrack.innerHTML = '';
    elements.globalEventsTrack.hidden = !CONFIG.showEvents;
    elements.globalEventsTrack.classList.remove('dense-event-rail');
    elements.globalEventsTrack.classList.remove('dense-event-rail-compact');
    delete elements.globalEventsTrack.dataset.eventCount;
    delete elements.globalEventsTrack.dataset.laneCount;
    if (!CONFIG.showEvents) return;

    const visibleEventEntries = getVisibleGlobalEventEntries()
        .filter(({ event }) => event.year >= CONFIG.timelineStart && event.year <= CONFIG.timelineEnd);
    const denseRail = shouldUseDenseEventRail(visibleEventEntries.length);
    const compactDenseRail = denseRail && isMobileToolbarViewport();
    const markerMinGap = denseRail ? (compactDenseRail ? 8 : 10) : 24;
    const collapsedLaneOffset = denseRail ? (compactDenseRail ? 1.5 : 2.2) : 20;
    const expandedLaneOffset = denseRail ? (compactDenseRail ? 9 : 12) : 28;
    const collapsedTrackBaseWidth = denseRail ? (compactDenseRail ? 10 : 12) : 26;
    const expandedTrackBaseWidth = denseRail ? (compactDenseRail ? 24 : 32) : 34;

    const laneLastY = [];
    let maxLane = 0;
    elements.globalEventsTrack.classList.toggle('dense-event-rail', denseRail);
    elements.globalEventsTrack.classList.toggle('dense-event-rail-compact', compactDenseRail);
    elements.globalEventsTrack.dataset.eventCount = String(visibleEventEntries.length);

    visibleEventEntries.forEach(({ event, index }) => {
        const y = yearToY(event.year) + 35;
        let lane = 0;
        while (Number.isFinite(laneLastY[lane]) && Math.abs(y - laneLastY[lane]) < markerMinGap) {
            lane++;
        }
        laneLastY[lane] = y;
        maxLane = Math.max(maxLane, lane);

        const marker = document.createElement('button');
        marker.type = 'button';
        marker.className = `global-event-marker ${event.type}`;
        marker.dataset.eventIndex = String(index);
        marker.dataset.eventNumber = String(index + 1);
        marker.dataset.contentY = String(y);
        marker.dataset.lane = String(lane);
        marker.dataset.eventLabel = `${formatYear(event.year)} · ${CONFIG.language === 'cn' ? event.labelCN : event.label}`;
        marker.style.top = `${eventContentYToViewportY(y)}px`;
        marker.style.setProperty('--event-collapsed-right', `${lane * collapsedLaneOffset}px`);
        marker.style.setProperty('--event-expanded-right', `${lane * expandedLaneOffset}px`);
        marker.textContent = denseRail ? '' : String(index + 1);
        marker.title = `#${index+1} · ${formatYear(event.year)}: ${CONFIG.language === 'cn' ? event.labelCN : event.label}`;
        marker.setAttribute('aria-label', marker.title);
        marker.style.animationDelay = `${index * 0.015}s`;

        marker.addEventListener('click', (e) => {
            e.stopPropagation();
            expandEventRail(2200);
            showEventDetail(event, index + 1);
        });
        marker.addEventListener('mouseenter', (e) => showEventTooltip(e, event, index + 1));
        marker.addEventListener('mouseleave', hideTooltip);
        marker.addEventListener('focus', (e) => showEventTooltip(e, event, index + 1));
        marker.addEventListener('blur', hideTooltip);
        marker.addEventListener('keydown', (e) => {
            if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                showEventDetail(event, index + 1);
            }
        });

        elements.globalEventsTrack.appendChild(marker);
    });

    elements.globalEventsTrack.dataset.laneCount = String(maxLane + 1);
    elements.globalEventsTrack.style.setProperty('--event-rail-width', `${collapsedTrackBaseWidth + maxLane * collapsedLaneOffset}px`);
    elements.globalEventsTrack.style.setProperty('--event-rail-expanded-width', `${expandedTrackBaseWidth + maxLane * expandedLaneOffset}px`);
    updateGlobalEventMarkerPositions();
}

function shouldUseDenseEventRail(eventCount) {
    if (eventCount < DENSE_EVENT_RAIL_THRESHOLD) return false;

    const timelineHeight = Math.max(1, yearToY(CONFIG.timelineEnd) - yearToY(CONFIG.timelineStart));
    const averageEventGap = timelineHeight / eventCount;
    return averageEventGap < DENSE_EVENT_AVERAGE_GAP_PX;
}

function eventContentYToViewportY(contentY) {
    const gridRect = elements.timelineGrid?.getBoundingClientRect();
    return (gridRect?.top || 0) + contentY;
}

function queueGlobalEventMarkerPositionUpdate() {
    if (globalEventPositionFrame) return;
    globalEventPositionFrame = window.requestAnimationFrame(() => {
        globalEventPositionFrame = null;
        updateGlobalEventMarkerPositions();
    });
}

function updateGlobalEventMarkerPositions() {
    const track = elements.globalEventsTrack;
    const grid = elements.timelineGrid;
    if (!track || !grid || track.hidden) return;

    const gridRect = grid.getBoundingClientRect();
    const headerRect = document.querySelector('.chronicle-header')?.getBoundingClientRect();
    const visibleTop = Math.max(0, headerRect?.bottom || 0);
    const timelineVisible = gridRect.bottom >= 0 && gridRect.top <= window.innerHeight;
    track.classList.toggle('timeline-offscreen', !timelineVisible);

    track.querySelectorAll('.global-event-marker').forEach(marker => {
        const contentY = Number.parseFloat(marker.dataset.contentY || '');
        if (!Number.isFinite(contentY)) return;

        const viewportY = gridRect.top + contentY;
        marker.style.top = `${viewportY}px`;

        const markerVisible = viewportY >= visibleTop + 8 && viewportY <= window.innerHeight + 24;
        marker.style.visibility = markerVisible ? '' : 'hidden';
        marker.tabIndex = markerVisible ? 0 : -1;
        marker.setAttribute('aria-hidden', String(!markerVisible));
    });
}

function expandEventRail(duration = 1800) {
    const track = elements.globalEventsTrack;
    if (!track) return;

    track.classList.add('event-rail-expanded');
    if (eventRailExpandTimer) {
        window.clearTimeout(eventRailExpandTimer);
    }
    eventRailExpandTimer = window.setTimeout(() => {
        track.classList.remove('event-rail-expanded');
        eventRailExpandTimer = null;
    }, duration);
}

function showEventDetail(event, number, { openPanel = true } = {}) {
    const isCn = CONFIG.language === 'cn';
    const typeLabel = eventTypeLabel(event.type);

    const regionName = event.region && WORLD_HISTORY[event.region]
        ? (isCn ? WORLD_HISTORY[event.region].nameCN : WORLD_HISTORY[event.region].name)
        : '';

    // Find entities active at this year
    const active = [];
    Object.entries(WORLD_HISTORY).forEach(([regionKey, region]) => {
        region.entities.forEach(e => {
            if (e.start <= event.year && e.end >= event.year && ['empire','caliphate','kingdom','republic'].includes(e.category)) {
                active.push({ entity: e, region: regionKey });
            }
        });
    });
    const majorPowers = active.slice(0, 8);

    let html = `
        <div class="panel-hero">
            <div>
                <div class="panel-region">${isCn ? '世界大事' : 'World Event'} · ${typeLabel}</div>
                <div class="panel-hero-title">${number ? '№ ' + number + ' · ' : ''}${formatYear(event.year)}</div>
            </div>
        </div>
        <h2>${isCn ? event.labelCN : event.label}</h2>
        <h3>${isCn ? event.label : event.labelCN}</h3>

        <div class="fact-grid">
            <div class="fact"><span class="fact-label">${isCn ? '年份' : 'Year'}</span><span class="fact-value">${formatYear(event.year)}</span></div>
            <div class="fact"><span class="fact-label">${isCn ? '类型' : 'Type'}</span><span class="fact-value">${typeLabel}</span></div>
            ${regionName ? `<div class="fact"><span class="fact-label">${isCn ? '地域' : 'Region'}</span><span class="fact-value">${regionName}</span></div>` : ''}
        </div>
    `;

    if (event.desc) {
        const descriptionText = isCn ? event.desc.cn : event.desc.en;
        html += `
            <h4>${isCn ? '事件背景' : 'Context'}</h4>
            <p class="entity-description">${renderDescriptionHTML(descriptionText)}</p>
        `;
    }

    if (majorPowers.length) {
        html += `
            <h4>${isCn ? '同期强权' : 'Powers at this Moment'}</h4>
            <ul class="contemporaries-list">
                ${majorPowers.map(p => {
                    const name = isCn ? (p.entity.nameCN || p.entity.name) : p.entity.name;
                    const rName = isCn ? WORLD_HISTORY[p.region].nameCN : WORLD_HISTORY[p.region].name;
                    return `<li><a href="#" data-jump-id="${p.entity.id}">${escapeHTML(name)}</a> — ${escapeHTML(rName)}</li>`;
                }).join('')}
            </ul>
        `;
    }

    elements.panelContent.innerHTML = html;
    setText('#panelTitle', isCn ? event.labelCN : event.label);

    wirePanelJumpLinks();

    activePanelContext = { type: 'event', event, number };
    if (openPanel) showPanel('event');
}

// ============================================
// JUMP TO YEAR
// ============================================

function setupJumpToYear() {
    if (!elements.jumpToYear || !elements.jumpBtn) return;

    const doJump = () => {
        let input = elements.jumpToYear.value.trim().toLowerCase();
        let year;
        const numericMatch = input.match(/-?\d+/);

        // Parse input - handle BC/AD notation
        if (!numericMatch) {
            showToast(uiText('invalidYear'));
            return;
        }

        const value = parseInt(numericMatch[0], 10);
        if (input.includes('bc') || input.includes('bce') || input.includes('公元前') || input.startsWith('前')) {
            year = -Math.abs(value);
        } else if (input.includes('ad') || input.includes('ce') || input.includes('公元')) {
            year = Math.abs(value);
        } else {
            year = value;
            // Assume negative for large numbers suggesting ancient times
            if (year > 2100) year = -year;
        }

        if (isNaN(year)) {
            showToast(uiText('invalidYear'));
            return;
        }

        // Clamp to timeline bounds
        year = Math.max(CONFIG.timelineStart, Math.min(CONFIG.timelineEnd, year));

        scrollToYear(year, true);
        updateURLState({ viewYear: year });
        showToast(`${uiText('jumpedTo')} ${formatYear(year)}`);
        elements.jumpToYear.value = '';
    };

    elements.jumpBtn.addEventListener('click', doJump);
    elements.jumpToYear.addEventListener('keydown', e => {
        if (e.key === 'Enter') doJump();
    });
}

function scrollToYear(year, smooth = true, { flash = true } = {}) {
    const container = elements.timelineContainer;
    if (!container) return;

    const safeYear = clampYearValue(year, CONFIG.timelineStart);
    CONFIG.viewYear = safeYear;
    const y = yearToY(safeYear) + 35;
    const containerRect = container.getBoundingClientRect();
    const containerTop = containerRect.top + window.scrollY;
    const targetClientY = timelineFocusClientY();
    const scrollTarget = Math.max(0, containerTop + timelineContentOffsetTop() + y - targetClientY);

    scrollWindowToTop(scrollTarget, smooth);

    // Also flash a highlight at that year for explicit navigation actions.
    if (flash) flashYearBeacon(safeYear);
}

function scrollToTimelineContentStart() {
    const container = elements.timelineContainer;
    if (!container) return;

    const containerTop = container.getBoundingClientRect().top + window.scrollY;
    const scrollTarget = Math.max(
        0,
        containerTop + timelineContentOffsetTop() - timelineViewportTopClientY()
    );
    scrollWindowToTop(scrollTarget, false);
}

function shouldAutoScrollDefaultTimelineStart() {
    const header = document.querySelector('.chronicle-header');
    if (!header) return true;
    const headerPosition = getComputedStyle(header).position;
    return headerPosition === 'sticky' || headerPosition === 'fixed';
}

function scrollBlockIntoHorizontalView(block, { smooth = true } = {}) {
    const wrapper = elements.timelineWrapper;
    if (!block || !wrapper) return currentViewX();

    const blockLeft = block.offsetLeft;
    const blockWidth = block.offsetWidth;
    const maxScroll = horizontalScrollMax();
    const targetLeft = Math.min(
        maxScroll,
        Math.max(0, blockLeft - Math.max(24, (wrapper.clientWidth - blockWidth) / 2))
    );
    const targetX = horizontalRatioForLeft(targetLeft);
    CONFIG.viewX = targetX;

    if (smooth) {
        wrapper.scrollTo({ left: targetLeft, behavior: 'smooth' });
    } else {
        wrapper.scrollLeft = targetLeft;
    }

    return targetX;
}

function findRenderedEntityBlock(entityId) {
    return Array.from(elements.timelineGrid?.querySelectorAll('.dynasty-block[data-id]') || [])
        .find(block => block.dataset.id === entityId) || null;
}

function scrollToEntity(entity, { smooth = true, flash = true } = {}) {
    if (!entity) return null;

    const targetYear = (entity.start + entity.end) / 2;
    const block = findRenderedEntityBlock(entity.id);
    const targetX = block
        ? scrollBlockIntoHorizontalView(block, { smooth })
        : currentViewX();

    scrollToYear(targetYear, smooth, { flash });
    return { year: targetYear, x: targetX, rendered: !!block };
}

function scrollToFirstRenderedBlock({ smooth = true, selector = '.dynasty-block' } = {}) {
    const block = elements.timelineGrid?.querySelector(selector);
    if (!block) return null;

    const targetX = scrollBlockIntoHorizontalView(block, { smooth });

    const start = Number(block.dataset.start);
    const end = Number(block.dataset.end);
    if (Number.isFinite(start) && Number.isFinite(end)) {
        const targetYear = (start + end) / 2;
        scrollToYear(targetYear, smooth);
        return { year: targetYear, x: targetX };
    }

    return { year: null, x: targetX };
}

function flashYearBeacon(year) {
    const beacon = document.createElement('div');
    beacon.style.cssText = `
        position: absolute;
        left: 0;
        right: 0;
        top: ${yearToY(year) + 35}px;
        height: 2px;
        background: linear-gradient(90deg, transparent, var(--accent), transparent);
        box-shadow: 0 0 12px var(--accent);
        pointer-events: none;
        z-index: 300;
        animation: beacon-flash 1.6s ease-out forwards;
    `;
    elements.timelineGrid.appendChild(beacon);
    setTimeout(() => beacon.remove(), 1700);
}
// Inject beacon animation if not in CSS
if (!document.getElementById('beacon-style')) {
    const s = document.createElement('style');
    s.id = 'beacon-style';
    s.textContent = `@keyframes beacon-flash { 0% { opacity: 0; transform: scaleY(1); } 15% { opacity: 1; transform: scaleY(4); } 100% { opacity: 0; transform: scaleY(1); } }`;
    document.head.appendChild(s);
}

// ============================================
// TOAST NOTIFICATIONS
// ============================================

function showToast(message, duration = 2500) {
    if (!elements.toast) return;

    if (toastTimer) {
        clearTimeout(toastTimer);
        toastTimer = null;
    }

    elements.toast.textContent = message;
    elements.toast.classList.add('visible');

    toastTimer = setTimeout(() => {
        elements.toast.classList.remove('visible');
        toastTimer = null;
    }, duration);
}

// ============================================
// CONTEMPORANEOUS HIGHLIGHTING
// ============================================

function setupContemporaryHighlight() {
    document.addEventListener('mouseover', e => {
        const block = e.target?.closest?.('.dynasty-block');
        if (!block) return;

        if (e.relatedTarget instanceof Node && block.contains(e.relatedTarget)) return;
        applyContemporaryHighlights(block);
    });

    document.addEventListener('mouseout', e => {
        const block = e.target?.closest?.('.dynasty-block');
        if (!block) return;
        if (block !== contemporaryHighlightSource) return;
        if (e.relatedTarget instanceof Node && block.contains(e.relatedTarget)) return;
        if (document.activeElement === block) return;

        clearContemporaryHighlights();
    });

    document.addEventListener('focusin', e => {
        const block = e.target?.closest?.('.dynasty-block');
        if (!block && contemporaryHighlightSource) {
            clearContemporaryHighlights();
        }
    });
}

function applyContemporaryHighlights(block) {
    if (!block || block === contemporaryHighlightSource) return;

    const start = parseInt(block.dataset.start, 10);
    const end = parseInt(block.dataset.end, 10);
    if (!Number.isFinite(start) || !Number.isFinite(end)) return;

    clearContemporaryHighlights();
    contemporaryHighlightSource = block;

    // Find and highlight all contemporaneous blocks.
    document.querySelectorAll('.dynasty-block').forEach(other => {
        if (other === block) return;
        const otherStart = parseInt(other.dataset.start, 10);
        const otherEnd = parseInt(other.dataset.end, 10);

        // Check for overlap.
        if (start < otherEnd && end > otherStart) {
            other.classList.add('contemporary-highlight');
        }
    });
}

// ============================================
// COMPARE MODE
// ============================================

function setupCompareMode() {
    if (!elements.compareBtn || !elements.comparePanel) return;

    let selectedRegions = [];

    const getCompareBackdrop = () => {
        let backdrop = document.querySelector('.compare-backdrop');
        if (!backdrop) {
            backdrop = document.createElement('div');
            backdrop.className = 'compare-backdrop';
            backdrop.addEventListener('click', () => closeComparePanel());
            document.body.appendChild(backdrop);
        }
        return backdrop;
    };

    const closeComparePanel = ({ restoreFocus = true } = {}) => {
        const wasOpen = elements.comparePanel.classList.contains('visible');
        if (compareFocusTimer) {
            clearTimeout(compareFocusTimer);
            compareFocusTimer = null;
        }
        document.querySelector('.compare-backdrop')?.classList.remove('visible');
        elements.comparePanel.classList.remove('visible');
        elements.comparePanel.dataset.open = 'false';
        elements.comparePanel.setAttribute('aria-hidden', 'true');
        setDialogFocusability(elements.comparePanel, true);
        elements.compareBtn.setAttribute('aria-expanded', 'false');

        if (wasOpen && restoreFocus && lastCompareTrigger?.isConnected) {
            setTimeout(() => lastCompareTrigger?.focus({ preventScroll: true }), 0);
        }
    };
    closeComparePanelHandler = closeComparePanel;

    const openComparePanel = ({ trigger = null } = {}) => {
        const activeElement = trigger || document.activeElement;
        lastCompareTrigger = activeElement && activeElement !== document.body
            ? activeElement
            : elements.compareBtn;
        clearActiveTimelinePreview();

        getCompareBackdrop().classList.add('visible');
        elements.comparePanel.classList.add('visible');
        elements.comparePanel.dataset.open = 'true';
        elements.comparePanel.setAttribute('aria-hidden', 'false');
        setDialogFocusability(elements.comparePanel, false);
        elements.compareBtn.setAttribute('aria-expanded', 'true');

        if (compareFocusTimer) clearTimeout(compareFocusTimer);
        compareFocusTimer = setTimeout(() => {
            compareFocusTimer = null;
            if (elements.comparePanel?.dataset.open !== 'true') return;
            const firstOption = elements.compareOptions.querySelector('.compare-option');
            (firstOption || elements.compareClose)?.focus({ preventScroll: true });
        }, 160);
    };

    const handleCompareKeydown = (e) => {
        if (elements.comparePanel.dataset.open !== 'true') return;

        if (e.key === 'Escape') {
            e.preventDefault();
            e.stopPropagation();
            closeComparePanel();
            return;
        }

        if (e.key !== 'Tab') return;

        const focusable = getFocusableElements(elements.comparePanel);
        if (!focusable.length) {
            e.preventDefault();
            return;
        }

        const first = focusable[0];
        const last = focusable[focusable.length - 1];
        if (e.shiftKey && document.activeElement === first) {
            e.preventDefault();
            last.focus({ preventScroll: true });
        } else if (!e.shiftKey && document.activeElement === last) {
            e.preventDefault();
            first.focus({ preventScroll: true });
        }
    };

    const renderCompareOptions = () => {
        elements.compareOptions.innerHTML = '';
        selectedRegions = CONFIG.compareMode && isValidCompareRegions(CONFIG.compareRegions)
            ? [...CONFIG.compareRegions]
            : [];

        getOrderedRegionKeys().forEach(key => {
            const region = WORLD_HISTORY[key];
            if (!region) return;
            const selected = selectedRegions.includes(key);
            const option = document.createElement('button');
            option.type = 'button';
            option.className = 'compare-option';
            option.textContent = CONFIG.language === 'cn' ? region.nameCN : region.name;
            option.dataset.region = key;
            option.classList.toggle('selected', selected);
            option.setAttribute('aria-pressed', String(selected));

            option.addEventListener('click', () => {
                if (option.classList.contains('selected')) {
                    option.classList.remove('selected');
                    option.setAttribute('aria-pressed', 'false');
                    selectedRegions = selectedRegions.filter(r => r !== key);
                } else if (selectedRegions.length < 2) {
                    option.classList.add('selected');
                    option.setAttribute('aria-pressed', 'true');
                    selectedRegions.push(key);
                }
            });

            elements.compareOptions.appendChild(option);
        });
    };

    const refreshCompareOptionLabels = () => {
        elements.compareOptions.querySelectorAll('.compare-option[data-region]').forEach(option => {
            const region = WORLD_HISTORY[option.dataset.region];
            if (region) {
                option.textContent = CONFIG.language === 'cn' ? region.nameCN : region.name;
            }
        });
    };
    refreshCompareOptionLabelsHandler = refreshCompareOptionLabels;

    syncCompareButtonState();

    elements.compareBtn.addEventListener('click', () => {
        if (CONFIG.compareMode) {
            // Turn compare mode off
            setCompareMode(false);
            closeComparePanel({ restoreFocus: false });
            // Restore all regions
            showAllRegions();
            syncRegionCheckboxes();
            renderTimeline();
            renderLegend();
            renderConnectionLines();
            updateURLState();
            showToast(uiText('compareOff'));
            return;
        }
        if (elements.comparePanel.dataset.open === 'true') {
            closeComparePanel();
            return;
        }
        // Open compare panel
        renderCompareOptions();
        openComparePanel({ trigger: elements.compareBtn });
    });

    elements.compareClose?.addEventListener('click', () => {
        closeComparePanel();
    });

    elements.comparePanel.addEventListener('keydown', handleCompareKeydown);

    elements.compareApply?.addEventListener('click', () => {
        if (selectedRegions.length !== 2) {
            showToast(uiText('selectTwoRegions'));
            return;
        }

        setCompareMode(true, selectedRegions);

        // Show only selected regions
        setVisibleRegionSet(CONFIG.compareRegions);
        syncRegionCheckboxes();

        renderTimeline();
        renderLegend();
        renderConnectionLines();
        updateURLState();
        closeComparePanel();

        const names = CONFIG.compareRegions.map(k => CONFIG.language === 'cn' ? WORLD_HISTORY[k].nameCN : WORLD_HISTORY[k].name).join(' ↔ ');
        showToast(`${uiText('comparing')}: ${names}`);
    });
}

// ============================================
// CATEGORY FILTER
// ============================================
function setupCategoryFilter() {
    const chips = document.querySelectorAll('#categoryFilter .cat-chip');
    chips.forEach(chip => {
        chip.addEventListener('click', () => {
            const cat = chip.dataset.category || null;
            CONFIG.categoryFilter = cat;
            chips.forEach(c => c.classList.remove('active'));
            chips.forEach(c => c.setAttribute('aria-pressed', 'false'));
            chip.classList.add('active');
            chip.setAttribute('aria-pressed', 'true');
            renderTimeline();
            renderLegend();
            renderConnectionLines();
            if (cat) {
                requestAnimationFrame(() => {
                    const target = scrollToFirstRenderedBlock();
                    updateURLState({
                        viewYear: target?.year ?? currentViewYear(),
                        viewX: target?.x ?? currentViewX()
                    });
                });
                const categoryLabel = ENTITY_CATEGORIES[cat] ? (CONFIG.language === 'cn' ? ENTITY_CATEGORIES[cat].labelCN : ENTITY_CATEGORIES[cat].label) : cat;
                showToast(`${uiText('filter')}: ${categoryLabel}`);
            } else {
                updateURLState();
                showToast(uiText('filterCleared'));
            }
        });
    });

    const activeChip = document.querySelector(`#categoryFilter .cat-chip[data-category="${CONFIG.categoryFilter || ''}"]`);
    activeChip?.classList.add('active');
    chips.forEach(c => c.setAttribute('aria-pressed', c === activeChip ? 'true' : 'false'));
}

