// ============================================
// DARK MODE
// ============================================

function setupDarkMode() {
    if (!elements.darkModeBtn) return;

    const setDarkMode = (enabled) => {
        CONFIG.darkMode = enabled;
        document.body.classList.toggle('dark-mode', enabled);
        elements.darkModeBtn.classList.toggle('active', enabled);
        elements.darkModeBtn.textContent = enabled ? uiText('lightMode') : uiText('darkMode');
        elements.darkModeBtn.setAttribute('aria-label', uiText('darkTitle'));
        elements.darkModeBtn.setAttribute('aria-pressed', String(enabled));
        try {
            localStorage.setItem('darkMode', String(enabled));
        } catch (_) {}
        if (elements.timelineGrid) {
            renderTimeline();
        }
    };

    let darkMode = CONFIG.darkMode;
    if (darkMode === null) {
        try {
            darkMode = localStorage.getItem('darkMode') === 'true';
        } catch (_) {
            darkMode = false;
        }
    }
    if (darkMode) {
        setDarkMode(true);
    } else {
        setDarkMode(false);
    }

    elements.darkModeBtn.addEventListener('click', () => {
        setDarkMode(!document.body.classList.contains('dark-mode'));
        updateURLState();
    });
}

// ============================================
// FULL PAGE MODE
// ============================================

function setupFullPageMode() {
    if (!elements.fullPageBtn) return;

    const toggleFullPage = (enable, { restoreFocus = true, trigger = elements.fullPageBtn } = {}) => {
        const wasFullPage = document.body.classList.contains('full-page-mode');
        const preservedView = captureCurrentViewState();

        if (enable && !wasFullPage) {
            lastFullPageTrigger = trigger?.isConnected ? trigger : elements.fullPageBtn;
            clearActiveTimelinePreview();
        }

        document.body.classList.toggle('full-page-mode', enable);
        elements.fullPageBtn.classList.toggle('active', enable);
        elements.fullPageBtn.setAttribute('aria-pressed', String(enable));
        elements.exitFullPage?.setAttribute('aria-hidden', String(!enable));
        elements.exitFullPage?.setAttribute('tabindex', enable ? '0' : '-1');

        restorePreservedViewState(preservedView);
        updateURLState(preservedView);

        if (fullPageFocusTimer) {
            clearTimeout(fullPageFocusTimer);
            fullPageFocusTimer = null;
        }
        if (enable) {
            showToast(uiText('fullPageToast'));
            fullPageFocusTimer = setTimeout(() => {
                fullPageFocusTimer = null;
                if (document.body.classList.contains('full-page-mode')) {
                    elements.exitFullPage?.focus({ preventScroll: true });
                }
            }, 220);
        } else if (restoreFocus && lastFullPageTrigger?.isConnected) {
            setTimeout(() => lastFullPageTrigger?.focus({ preventScroll: true }), 0);
        }
    };

    elements.fullPageBtn.addEventListener('click', () => {
        toggleFullPage(true, { trigger: elements.fullPageBtn });
    });

    elements.exitFullPage?.addEventListener('click', () => {
        toggleFullPage(false);
    });

    // Esc key to exit full page mode
    document.addEventListener('keydown', e => {
        if (e.key === 'Escape' && document.body.classList.contains('full-page-mode')) {
            e.preventDefault();
            toggleFullPage(false);
            e.stopImmediatePropagation();
        }
    });
}

// ============================================
// MOBILE TOOLBAR
// ============================================

function setupMobileToolbar() {
    if (!elements.mobileToolbarToggle || !elements.toolbarRows) return;

    syncMobileToolbarState();

    elements.mobileToolbarToggle.addEventListener('click', () => {
        const preservedView = captureCurrentViewState();
        const open = !document.body.classList.contains('mobile-controls-open');
        const hadToolbarFocus = elements.toolbarRows.contains(document.activeElement);
        document.body.classList.toggle('mobile-controls-open', open);
        syncMobileToolbarState({ restoreFocusFromToolbar: hadToolbarFocus });
        restorePreservedViewState(preservedView);
        updateURLState(preservedView);
    });

    const mobileQuery = window.matchMedia?.(MOBILE_TOOLBAR_MEDIA_QUERY);
    if (mobileQuery?.addEventListener) {
        mobileQuery.addEventListener('change', syncMobileToolbarState);
    } else if (mobileQuery?.addListener) {
        mobileQuery.addListener(syncMobileToolbarState);
    } else {
        window.addEventListener('resize', syncMobileToolbarState);
    }
}

function isMobileToolbarViewport() {
    return window.matchMedia
        ? window.matchMedia(MOBILE_TOOLBAR_MEDIA_QUERY).matches
        : window.innerWidth <= 600;
}

function setToolbarRowsFocusability(disabled) {
    setContainerFocusability(elements.toolbarRows, disabled, 'toolbarTabindex');
}

function syncMobileToolbarState(options = {}) {
    if (!elements.mobileToolbarToggle || !elements.toolbarRows) return;

    const isMobile = isMobileToolbarViewport();
    const open = document.body.classList.contains('mobile-controls-open');
    const label = open ? uiText('hideControls') : uiText('controls');
    elements.mobileToolbarToggle.textContent = label;
    elements.mobileToolbarToggle.setAttribute('title', label);
    elements.mobileToolbarToggle.setAttribute('aria-label', label);
    elements.mobileToolbarToggle.setAttribute('aria-expanded', String(open));
    elements.mobileToolbarToggle.setAttribute('aria-hidden', String(!isMobile));
    elements.mobileToolbarToggle.setAttribute('tabindex', isMobile ? '0' : '-1');
    const toolbarHidden = isMobile && !open;
    elements.toolbarRows.setAttribute('aria-hidden', String(toolbarHidden));
    setToolbarRowsFocusability(toolbarHidden);
    if (toolbarHidden && (options.restoreFocusFromToolbar || elements.toolbarRows.contains(document.activeElement))) {
        elements.mobileToolbarToggle.focus({ preventScroll: true });
    }
}

// ============================================
// EXPORT FUNCTIONALITY
// ============================================

function setupExport() {
    if (!elements.exportBtn) return;

    elements.exportBtn.addEventListener('click', async () => {
        showToast(uiText('exportPreparing'));

        try {
            const renderer = await loadHtml2Canvas();
            if (renderer) {
                // Export the timeline-wrapper (entire grid + year scale)
                const target = elements.timelineContainer;
                const canvas = await renderer(target, {
                    backgroundColor: document.body.classList.contains('dark-mode') ? '#1F190F' : '#F1DFB4',
                    scale: Math.min(2, window.devicePixelRatio || 1),
                    windowWidth: target.scrollWidth,
                    windowHeight: target.scrollHeight,
                    logging: false,
                    useCORS: true
                });

                const link = document.createElement('a');
                link.download = `illuminated-chronicle-${new Date().toISOString().slice(0,10)}.png`;
                link.href = canvas.toDataURL('image/png');
                link.click();
                showToast(uiText('exportSaved'));
            } else {
                showPrintFallback();
            }
        } catch (err) {
            showPrintFallback(uiText('exportFailed'));
        }
    });
}

function loadHtml2Canvas() {
    if (typeof window.html2canvas === 'function') {
        return Promise.resolve(window.html2canvas);
    }

    const existingScript = document.querySelector(`script[src="${HTML2CANVAS_SRC}"]`);
    if (!existingScript && !html2canvasLoadPromise) {
        showToast(uiText('exportRendererLoading'));
    }

    if (!html2canvasLoadPromise) {
        html2canvasLoadPromise = new Promise(resolve => {
            const script = existingScript || document.createElement('script');
            let settled = false;

            const finish = () => {
                if (settled) return;
                settled = true;
                resolve(typeof window.html2canvas === 'function' ? window.html2canvas : null);
            };

            const timeout = window.setTimeout(finish, 7000);
            script.addEventListener('load', () => {
                window.clearTimeout(timeout);
                finish();
            }, { once: true });
            script.addEventListener('error', () => {
                window.clearTimeout(timeout);
                finish();
            }, { once: true });

            if (!existingScript) {
                script.src = HTML2CANVAS_SRC;
                script.async = true;
                document.head.appendChild(script);
            }
        });
    }

    return html2canvasLoadPromise;
}

function showPrintFallback(message = uiText('exportPrint')) {
    showToast(message);
    window.setTimeout(() => window.print(), 100);
}

// ============================================
// SHARE/URL STATE
// ============================================

function setupShare() {
    if (!elements.shareBtn) return;

    elements.shareBtn.addEventListener('click', async () => {
        updateURLState();
        const url = window.location.href;

        const copied = await copyTextToClipboard(url);
        showToast(copied ? uiText('linkCopied') : uiText('linkCopyFailed'));
    });
}

async function copyTextToClipboard(text) {
    if (navigator.clipboard?.writeText) {
        try {
            await navigator.clipboard.writeText(text);
            return true;
        } catch (_) {
            // Fall through to the legacy command path.
        }
    }

    const activeElement = document.activeElement;
    const textarea = document.createElement('textarea');
    textarea.value = text;
    textarea.setAttribute('readonly', '');
    textarea.style.position = 'fixed';
    textarea.style.left = '-9999px';
    textarea.style.top = '0';
    document.body.appendChild(textarea);
    textarea.select();

    let copied = false;
    try {
        copied = document.execCommand('copy');
    } catch (_) {
        copied = false;
    } finally {
        textarea.remove();
        if (activeElement?.isConnected && typeof activeElement.focus === 'function') {
            activeElement.focus({ preventScroll: true });
        }
    }

    return copied;
}

// ============================================
// ERA BUTTONS
// ============================================

function setupEraNavigation() {
    if (!elements.eraBtns || elements.eraBtns.length === 0) return;

    elements.eraBtns.forEach(btn => {
        btn.addEventListener('click', () => {
            const year = parseInt(btn.dataset.year);
            if (isNaN(year)) return;

            scrollToYear(year, true);
            updateURLState({ viewYear: year });
            showToast(`${uiText('jumpedTo')} ${formatYear(year)}`);

            // Highlight active era button briefly
            elements.eraBtns.forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            setTimeout(() => btn.classList.remove('active'), 1000);
        });
    });
}

// ============================================
// STAGGERED ANIMATION ON LOAD
// ============================================

function applyStaggeredAnimation() {
    const blocks = document.querySelectorAll('.dynasty-block');
    blocks.forEach((block, index) => {
        block.style.animationDelay = `${index * 0.015}s`;
    });
}

// ============================================
// LEGEND TOGGLE
// ============================================

function setupLegendToggle() {
    if (!elements.legendToggle || !elements.legendPanel) return;

    // Start collapsed
    elements.legendPanel.classList.add('collapsed');
    updateLegendToggleLabel();

    elements.legendToggle.addEventListener('click', () => {
        elements.legendPanel.classList.toggle('collapsed');
        updateLegendToggleLabel();
    });
}

// ============================================
// DOUBLE-CLICK TO ZOOM
// ============================================

function isInteractiveTimelineTarget(target) {
    if (!(target instanceof Element)) return false;
    return !!target.closest([
        '.dynasty-block',
        '.global-event-marker',
        '.connection-line',
        'a[href]',
        'button',
        'input',
        'select',
        'textarea',
        '[role="button"]',
        '[tabindex]'
    ].join(','));
}

function setupDoubleClickZoom() {
    const container = elements.timelineContainer;
    if (!container) return;

    container.addEventListener('dblclick', (e) => {
        // Only blank timeline space should trigger background zoom.
        if (isInteractiveTimelineTarget(e.target)) return;

        const clickedYear = yearAtViewportY(e.clientY);
        if (!Number.isFinite(clickedYear)) return;

        // Zoom in
        const newZoom = Math.min(CONFIG.yearHeight * 2, MAX_YEAR_HEIGHT);
        setZoom(newZoom);

        // Recalculate and scroll to keep clicked year centered
        setTimeout(() => {
            scrollToYear(clickedYear, false);
        }, 50);

        updateURLState({ viewYear: clickedYear });
    });
}

// ============================================
// INIT
// ============================================

function init() {
    initElements();

    // One-time data normalization: trim same-slot polities that overlap in time
    // (e.g. Babylon IV-V truncated when Assyrian Empire takes over Mesopotamia).
    normalizeOverlaps();

    // Load URL state first
    loadURLState();

    // Apply language class to body
    document.body.classList.toggle('lang-cn', CONFIG.language === 'cn');

    if (elements.zoomSlider) {
        elements.zoomSlider.min = MIN_YEAR_HEIGHT;
        elements.zoomSlider.max = MAX_YEAR_HEIGHT;
        elements.zoomSlider.value = CONFIG.yearHeight;
    }
    if (elements.zoomValue) {
        elements.zoomValue.textContent = `${CONFIG.yearHeight.toFixed(2)} px/yr`;
    }
    updateZoomPresetState();

    // Update UI to reflect loaded state
    if (elements.searchInput && CONFIG.searchQuery) {
        elements.searchInput.value = CONFIG.searchQuery;
    }
    if (elements.eventsCheckbox) {
        elements.eventsCheckbox.checked = CONFIG.showEvents;
    }
    if (elements.connectionsToggle) {
        elements.connectionsToggle.checked = CONFIG.showConnections;
    }
    if (elements.connectionLabelsToggle) {
        elements.connectionLabelsToggle.checked = CONFIG.showConnectionLabels;
    }
    if (elements.erasToggle) {
        elements.erasToggle.checked = CONFIG.showEraBackgrounds;
    }
    if (elements.timeRulerToggle) {
        elements.timeRulerToggle.checked = CONFIG.showTimeRuler;
    }

    // Update language buttons
    elements.langButtons.forEach(btn => {
        const active = btn.dataset.lang === CONFIG.language;
        btn.classList.toggle('active', active);
        btn.setAttribute('aria-pressed', String(active));
    });

    // Update region checkboxes
    syncRegionCheckboxes();

    renderYearScale();
    renderTimeline();
    renderLegend();

    setDialogFocusability(elements.eventPanel, true);
    setDialogFocusability(elements.comparePanel, true);

    // Panel close
    elements.panelClose?.addEventListener('click', () => hidePanel());
    elements.eventPanel?.addEventListener('keydown', handlePanelKeydown);

    // Language buttons
    elements.langButtons.forEach(btn => {
        btn.addEventListener('click', () => {
            switchLanguage(btn.dataset.lang);
            updateURLState();
        });
    });

    // Events toggle
    elements.eventsCheckbox?.addEventListener('change', e => {
        toggleEvents(e.target.checked);
        updateURLState();
    });

    // Region checkboxes
    elements.regionCheckboxes.forEach(checkbox => {
        checkbox.addEventListener('change', e => {
            toggleRegion(e.target.dataset.region, e.target.checked);
            updateURLState();
        });
    });

    // Zoom controls
    elements.zoomIn?.addEventListener('click', () => { zoomIn(); updateURLState(); });
    elements.zoomOut?.addEventListener('click', () => { zoomOut(); updateURLState(); });
    elements.zoomReset?.addEventListener('click', () => { resetZoom(); updateURLState(); });
    elements.zoomSlider?.addEventListener('input', e => { handleZoomSlider(e); updateURLState(); });

    // Search functionality
    if (elements.searchInput) {
        elements.searchInput.addEventListener('input', e => {
            queueSearch(e.target.value);
        });

        elements.searchInput.addEventListener('keydown', e => {
            if (e.key === 'Escape') {
                clearSearch();
                elements.searchInput.blur();
            }
        });
    }
    elements.searchClear?.addEventListener('click', () => clearSearch({ restoreFocus: true }));

    // Connections toggle
    elements.connectionsToggle?.addEventListener('change', e => toggleConnections(e.target.checked));

    // Connection label toggle
    elements.connectionLabelsToggle?.addEventListener('change', e => toggleConnectionLabels(e.target.checked));

    // Eras toggle
    elements.erasToggle?.addEventListener('change', e => toggleEras(e.target.checked));

    // Time ruler toggle
    elements.timeRulerToggle?.addEventListener('change', e => {
        toggleTimeRuler(e.target.checked, { alignToView: e.target.checked });
        updateURLState();
    });

    // Keyboard navigation
    setupKeyboardNavigation();

    // Keep the current view state available for resize/orientation recovery.
    setupViewStateTracking();

    // Touch gestures
    setupTouchGestures();

    // Year cursor tracking
    setupYearCursor();
    setupTimeRuler();

    // Zoom presets
    setupZoomPresets();

    // Double-click to zoom
    setupDoubleClickZoom();

    // Legend toggle
    setupLegendToggle();

    // New feature setups
    setupJumpToYear();
    setupDarkMode();
    setupFullPageMode();
    setupMobileToolbar();
    setupExport();
    setupShare();
    setupCompareMode();
    setupContemporaryHighlight();
    setupEraNavigation();
    setupCategoryFilter();
    setupHelpDialog();
    updateStaticText();

    // Render connection lines and global events
    renderConnectionLines();
    renderGlobalEvents();

    requestAnimationFrame(() => {
        const explicitViewX = urlViewXProvided ? CONFIG.viewX : null;
        let initialPositionTarget = null;

        if (urlViewYearProvided && Number.isFinite(CONFIG.viewYear)) {
            scrollToYear(CONFIG.viewYear, false);
        } else if (CONFIG.searchQuery) {
            initialPositionTarget = scrollToFirstRenderedBlock({
                smooth: false,
                selector: '.dynasty-block.search-match'
            });
        } else if (CONFIG.categoryFilter) {
            initialPositionTarget = scrollToFirstRenderedBlock({ smooth: false });
        } else if (shouldAutoScrollDefaultTimelineStart()) {
            scrollToTimelineContentStart();
        }

        if (Number.isFinite(explicitViewX)) {
            CONFIG.viewX = explicitViewX;
        }
        restoreHorizontalView();
        rememberViewState();
        if (urlCategoryNeedsNormalization) {
            updateURLState({
                viewYear: initialPositionTarget?.year ?? currentViewYear(),
                viewX: initialPositionTarget?.x ?? currentViewX()
            });
            urlCategoryNeedsNormalization = false;
        }
        window.setTimeout(() => {
            viewStateURLTrackingReady = true;
        }, 250);
    });

    // Apply staggered animation
    setTimeout(applyStaggeredAnimation, 100);

    // Escape key to close panel
    document.addEventListener('keydown', e => {
        if (e.key === 'Escape') {
            hidePanel();
            clearActiveTimelinePreview();
            if (elements.comparePanel?.classList.contains('visible')) {
                closeComparePanelHandler?.();
            }
        }
        if (isDialogOpen()) return;
        if ((e.ctrlKey || e.metaKey) && (e.key === '=' || e.key === '+')) { e.preventDefault(); zoomIn(); updateURLState(); }
        if ((e.ctrlKey || e.metaKey) && e.key === '-') { e.preventDefault(); zoomOut(); updateURLState(); }
        if ((e.ctrlKey || e.metaKey) && e.key === '0') { e.preventDefault(); resetZoom(); updateURLState(); }
    });

}

document.addEventListener('DOMContentLoaded', init);
